function normalizeBrowserTeachPhase(phase) {
  const value = String(phase || '').trim().toLowerCase();
  if (value === 'recording' || value === 'approval_pending' || value === 'verifying' || value === 'verified') return value;
  return 'idle';
}

function normalizeBrowserTeachRisk(risk) {
  return String(risk || '').trim().toLowerCase() === 'high' ? 'high' : 'none';
}

function createEmptyBrowserTeachSession() {
  return {
    active: false,
    phase: 'idle',
    startedAt: 0,
    completedAt: 0,
    approvalRequestedAt: 0,
    reviewRequestedAt: 0,
    startUrl: '',
    startTitle: '',
    steps: [],
    pendingStep: null,
    pendingSelectionIntent: null,
    executingStepId: '',
    verification: null,
  };
}

function snapshotBrowserTeachStep(step) {
  if (!step || typeof step !== 'object') return null;
  const selection = step.selection && typeof step.selection === 'object'
    ? {
        selector: String(step.selection.selector || '').trim(),
        tagName: String(step.selection.tagName || '').trim(),
        id: String(step.selection.id || '').trim(),
        text: String(step.selection.text || '').trim(),
        bounds: step.selection.bounds || null,
      }
    : null;
  const input = step.input && typeof step.input === 'object' ? { ...step.input } : {};
  const args = step.args && typeof step.args === 'object' ? { ...step.args } : {};
  return {
    id: String(step.id || '').trim(),
    kind: String(step.kind || '').trim(),
    toolName: String(step.toolName || '').trim(),
    title: String(step.title || '').trim(),
    summary: String(step.summary || '').trim(),
    toolPreview: String(step.toolPreview || '').trim(),
    targetName: String(step.targetName || '').trim(),
    risk: normalizeBrowserTeachRisk(step.risk),
    status: String(step.status || '').trim() || 'recorded',
    createdAt: Number(step.createdAt || 0) || 0,
    executedAt: Number(step.executedAt || 0) || 0,
    pageUrl: String(step.pageUrl || '').trim(),
    pageTitle: String(step.pageTitle || '').trim(),
    resultSummary: String(step.resultSummary || '').trim(),
    selection,
    input,
    args,
  };
}

function snapshotBrowserTeachSession(session) {
  const teach = session && typeof session === 'object' ? session : createEmptyBrowserTeachSession();
  return {
    active: teach.active === true,
    phase: normalizeBrowserTeachPhase(teach.phase),
    startedAt: Number(teach.startedAt || 0) || 0,
    completedAt: Number(teach.completedAt || 0) || 0,
    approvalRequestedAt: Number(teach.approvalRequestedAt || 0) || 0,
    reviewRequestedAt: Number(teach.reviewRequestedAt || 0) || 0,
    startUrl: String(teach.startUrl || '').trim(),
    startTitle: String(teach.startTitle || '').trim(),
    executingStepId: String(teach.executingStepId || '').trim(),
    steps: Array.isArray(teach.steps)
      ? teach.steps.map((step) => snapshotBrowserTeachStep(step)).filter(Boolean)
      : [],
    pendingStep: snapshotBrowserTeachStep(teach.pendingStep),
    verification: teach.verification && typeof teach.verification === 'object'
      ? {
          status: String(teach.verification.status || '').trim(),
          mode: String(teach.verification.mode || '').trim(),
          boundaryLabel: String(teach.verification.boundaryLabel || '').trim(),
          stopBeforeStep: Number(teach.verification.stopBeforeStep || 0) || 0,
          verifierSessionId: String(teach.verification.verifierSessionId || '').trim(),
          executedCount: Number(teach.verification.executedCount || 0) || 0,
          totalRecordedSteps: Number(teach.verification.totalRecordedSteps || 0) || 0,
          riskyStepIndexes: Array.isArray(teach.verification.riskyStepIndexes)
            ? teach.verification.riskyStepIndexes.map((value) => Number(value || 0) || 0).filter(Boolean)
            : [],
          failedStep: Number(teach.verification.failedStep || 0) || 0,
          failureSummary: String(teach.verification.failureSummary || '').trim(),
          finalUrl: String(teach.verification.finalUrl || '').trim(),
          finalTitle: String(teach.verification.finalTitle || '').trim(),
          startedAt: Number(teach.verification.startedAt || 0) || 0,
          completedAt: Number(teach.verification.completedAt || 0) || 0,
        }
      : null,
  };
}

function restoreBrowserTeachSessionState(saved) {
  const teach = createEmptyBrowserTeachSession();
  const restored = saved && typeof saved === 'object' ? saved : {};
  teach.active = restored.active === true;
  teach.phase = normalizeBrowserTeachPhase(restored.phase);
  teach.startedAt = Number(restored.startedAt || 0) || 0;
  teach.completedAt = Number(restored.completedAt || 0) || 0;
  teach.approvalRequestedAt = Number(restored.approvalRequestedAt || 0) || 0;
  teach.reviewRequestedAt = Number(restored.reviewRequestedAt || 0) || 0;
  teach.startUrl = String(restored.startUrl || '').trim();
  teach.startTitle = String(restored.startTitle || '').trim();
  teach.executingStepId = String(restored.executingStepId || '').trim();
  teach.steps = Array.isArray(restored.steps)
    ? restored.steps.map((step) => snapshotBrowserTeachStep(step)).filter(Boolean)
    : [];
  teach.pendingStep = snapshotBrowserTeachStep(restored.pendingStep);
  teach.verification = restored.verification && typeof restored.verification === 'object'
    ? {
        status: String(restored.verification.status || '').trim(),
        mode: String(restored.verification.mode || '').trim(),
        boundaryLabel: String(restored.verification.boundaryLabel || '').trim(),
        stopBeforeStep: Number(restored.verification.stopBeforeStep || 0) || 0,
        verifierSessionId: String(restored.verification.verifierSessionId || '').trim(),
        executedCount: Number(restored.verification.executedCount || 0) || 0,
        totalRecordedSteps: Number(restored.verification.totalRecordedSteps || 0) || 0,
        riskyStepIndexes: Array.isArray(restored.verification.riskyStepIndexes)
          ? restored.verification.riskyStepIndexes.map((value) => Number(value || 0) || 0).filter(Boolean)
          : [],
        failedStep: Number(restored.verification.failedStep || 0) || 0,
        failureSummary: String(restored.verification.failureSummary || '').trim(),
        finalUrl: String(restored.verification.finalUrl || '').trim(),
        finalTitle: String(restored.verification.finalTitle || '').trim(),
        startedAt: Number(restored.verification.startedAt || 0) || 0,
        completedAt: Number(restored.verification.completedAt || 0) || 0,
      }
    : null;
  teach.pendingSelectionIntent = null;
  if (!teach.active || teach.phase === 'idle') {
    teach.active = false;
    teach.phase = 'idle';
    teach.executingStepId = '';
    teach.pendingStep = null;
  }
  return teach;
}

function syncBrowserTeachSessionToBackend() {
  const sessionId = String(window.activeChatSessionId || window.agentSessionId || '').trim();
  if (!sessionId) return;
  if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) return;
  const teach = snapshotBrowserTeachSession(getBrowserTeachSession());
  wsSend({
    type: 'browser:teach:sync',
    sessionId,
    teachSession: teach.active ? teach : { active: false, phase: 'idle' },
  });
}

function getViewportBoundPanelWidth(desiredWidth, minimumWidth = 760) {
  if (typeof window === 'undefined') return Math.max(minimumWidth, desiredWidth);
  const viewportWidth = Math.max(0, Number(window.innerWidth) || 0);
  const maxWidth = viewportWidth > 0 ? Math.max(minimumWidth, viewportWidth - 40) : desiredWidth;
  return Math.max(minimumWidth, Math.min(desiredWidth, maxWidth));
}

function setRightPanelWidth(width, options = {}) {
  const rightPanel = document.getElementById('right-panel');
  if (!rightPanel) return;
  const boundedWidth = getViewportBoundPanelWidth(width, options.minimumWidth || 760);
  rightPanel.style.width = `${boundedWidth}px`;
  rightPanel.style.minWidth = `${boundedWidth}px`;
  if (options.lockMax) rightPanel.style.maxWidth = `${boundedWidth}px`;
  else rightPanel.style.removeProperty('max-width');
}

function normalizeCreativeMode(mode) {
  const key = String(mode || '').trim().toLowerCase();
  if (key === 'canvas') return 'image';
  return Object.prototype.hasOwnProperty.call(CREATIVE_MODE_META, key) ? key : null;
}

function getCreativeModeMeta(mode) {
  const key = normalizeCreativeMode(mode);
  return key ? CREATIVE_MODE_META[key] : null;
}

function getActiveCanvasTab() {
  return canvasTabs.find((tab) => tab.id === activeCanvasTabId) || null;
}

function isPreviewLikeCanvasTab(tab) {
  if (!tab) return false;
  if (tab.isImage || tab.isBinary) return true;
  return String(tab.mode || '').toLowerCase() === 'preview';
}

