function snapshotBrowserCanvasSessionState(state = getBrowserCanvasState()) {
  const browserSessions = {};
  Object.entries(getBrowserSessionRegistry(state)).forEach(([sessionId, record]) => {
    if (!record || typeof record !== 'object') return;
    const { frameBase64, ...rest } = record;
    browserSessions[sessionId] = {
      ...rest,
      frameBase64: '',
    };
  });
  return {
    surface: String(state.surface || 'files') === 'browser' ? 'browser' : 'files',
    interactionMode: normalizeBrowserInteractionMode(state.interactionMode),
    active: state.active === true,
    browserSessions,
    sessionId: String(state.sessionId || '').trim(),
    followSessionId: String(state.followSessionId || '').trim(),
    url: String(state.url || '').trim(),
    title: String(state.title || '').trim(),
    lastRestorableUrl: String(state.lastRestorableUrl || '').trim(),
    lastRestorableTitle: String(state.lastRestorableTitle || '').trim(),
    lastTool: String(state.lastTool || '').trim(),
    statusLabel: String(state.statusLabel || '').trim(),
    selectedElement: state.selectedElement && typeof state.selectedElement === 'object'
      ? {
          selector: String(state.selectedElement.selector || '').trim(),
          tagName: String(state.selectedElement.tagName || '').trim(),
          id: String(state.selectedElement.id || '').trim(),
          text: String(state.selectedElement.text || '').trim(),
          bounds: state.selectedElement.bounds || null,
        }
      : null,
    namedElements: Array.isArray(state.namedElements)
      ? state.namedElements.map((entry) => ({
          name: String(entry?.name || '').trim(),
          selector: String(entry?.selector || '').trim(),
          tagName: String(entry?.tagName || '').trim(),
          id: String(entry?.id || '').trim(),
          text: String(entry?.text || '').trim(),
          url: String(entry?.url || '').trim(),
          savedAt: Number(entry?.savedAt || 0) || 0,
        })).filter((entry) => entry.name)
      : [],
    itemRoots: Array.isArray(state.itemRoots)
      ? state.itemRoots.map((entry) => ({
          name: String(entry?.name || '').trim(),
          selector: String(entry?.selector || '').trim(),
          tagName: String(entry?.tagName || '').trim(),
          id: String(entry?.id || '').trim(),
          text: String(entry?.text || '').trim(),
          url: String(entry?.url || '').trim(),
          savedAt: Number(entry?.savedAt || 0) || 0,
        })).filter((entry) => entry.name)
      : [],
    extractionSchemas: Array.isArray(state.extractionSchemas)
      ? state.extractionSchemas.map((entry) => ({
          name: String(entry?.name || '').trim(),
          itemRoot: String(entry?.itemRoot || '').trim(),
          containerSelector: String(entry?.containerSelector || '').trim(),
          dedupeKey: String(entry?.dedupeKey || '').trim(),
          limit: Number(entry?.limit || 0) || 0,
          fields: entry?.fields && typeof entry.fields === 'object' ? { ...entry.fields } : {},
          savedAt: Number(entry?.savedAt || 0) || 0,
        })).filter((entry) => entry.name)
      : [],
    knowledgeSite: String(state.knowledgeSite || '').trim(),
    selectionPending: state.selectionPending === true,
    teachSession: snapshotBrowserTeachSession(state.teachSession),
    updatedAt: Number(state.updatedAt || 0) || 0,
  };
}

function restoreBrowserCanvasSessionState(saved) {
  const state = getBrowserCanvasState();
  const restored = saved && typeof saved === 'object' ? saved : {};
  state.surface = String(restored.surface || 'files') === 'browser' ? 'browser' : 'files';
  state.interactionMode = normalizeBrowserInteractionMode(restored.interactionMode);
  state.controlCaptured = false;
  state.controlOwner = 'agent';
  state.streamActive = false;
  state.streamTransport = '';
  state.streamFocus = 'passive';
  state.streamStatus = '';
  state.streamLastFrameAt = 0;
  state.frameFormat = 'png';
  state.active = restored.active === true;
  state.browserSessions = restored.browserSessions && typeof restored.browserSessions === 'object' && !Array.isArray(restored.browserSessions)
    ? Object.fromEntries(Object.entries(restored.browserSessions).map(([sessionId, record]) => {
        const clean = record && typeof record === 'object' ? { ...record } : {};
        clean.frameBase64 = '';
        return [sessionId, clean];
      }))
    : {};
  state.sessionId = String(restored.sessionId || '').trim();
  state.followSessionId = String(restored.followSessionId || '').trim();
  state.url = String(restored.url || '').trim();
  state.title = String(restored.title || '').trim();
  state.lastRestorableUrl = String(restored.lastRestorableUrl || '').trim();
  state.lastRestorableTitle = String(restored.lastRestorableTitle || '').trim();
  state.lastTool = String(restored.lastTool || '').trim();
  state.statusLabel = String(restored.statusLabel || '').trim() || (state.active ? 'Browser active' : 'Browser idle');
  state.agentCursor = null;
  state.selectedElement = restored.selectedElement && typeof restored.selectedElement === 'object'
    ? {
        selector: String(restored.selectedElement.selector || '').trim(),
        tagName: String(restored.selectedElement.tagName || '').trim(),
        id: String(restored.selectedElement.id || '').trim(),
        text: String(restored.selectedElement.text || '').trim(),
        bounds: restored.selectedElement.bounds || null,
      }
    : null;
  state.namedElements = Array.isArray(restored.namedElements)
    ? restored.namedElements.map((entry) => ({
        name: String(entry?.name || '').trim(),
        selector: String(entry?.selector || '').trim(),
        tagName: String(entry?.tagName || '').trim(),
        id: String(entry?.id || '').trim(),
        text: String(entry?.text || '').trim(),
        url: String(entry?.url || '').trim(),
        savedAt: Number(entry?.savedAt || 0) || 0,
      })).filter((entry) => entry.name)
    : [];
  state.itemRoots = Array.isArray(restored.itemRoots)
    ? restored.itemRoots.map((entry) => ({
        name: String(entry?.name || '').trim(),
        selector: String(entry?.selector || '').trim(),
        tagName: String(entry?.tagName || '').trim(),
        id: String(entry?.id || '').trim(),
        text: String(entry?.text || '').trim(),
        url: String(entry?.url || '').trim(),
        savedAt: Number(entry?.savedAt || 0) || 0,
      })).filter((entry) => entry.name)
    : [];
  state.extractionSchemas = Array.isArray(restored.extractionSchemas)
    ? restored.extractionSchemas.map((entry) => ({
        name: String(entry?.name || '').trim(),
        itemRoot: String(entry?.itemRoot || '').trim(),
        containerSelector: String(entry?.containerSelector || '').trim(),
        dedupeKey: String(entry?.dedupeKey || '').trim(),
        limit: Number(entry?.limit || 0) || 0,
        fields: entry?.fields && typeof entry.fields === 'object' ? { ...entry.fields } : {},
        savedAt: Number(entry?.savedAt || 0) || 0,
      })).filter((entry) => entry.name)
    : [];
  state.knowledgeSite = String(restored.knowledgeSite || '').trim();
  state.knowledgeRequestedFor = '';
  state.elementNameDraft = '';
  state.elementNameDraftKey = '';
  state.transientHighlight = null;
  state.selectionPending = false;
  state.teachSession = restoreBrowserTeachSessionState(restored.teachSession);
  state.updatedAt = Number(restored.updatedAt || 0) || 0;
  state.frameBase64 = '';
  state.frameWidth = 0;
  state.frameHeight = 0;
  return state;
}

function normalizeBrowserInteractionMode(mode) {
  const key = String(mode || '').trim().toLowerCase();
  if (key === 'review') return 'agent';
  return Object.prototype.hasOwnProperty.call(BROWSER_INTERACTION_META, key) ? key : 'agent';
}

function getBrowserInteractionMeta(mode) {
  return BROWSER_INTERACTION_META[normalizeBrowserInteractionMode(mode)] || BROWSER_INTERACTION_META.agent;
}

function getBrowserTeachSession(state = getBrowserCanvasState()) {
  if (!state.teachSession || typeof state.teachSession !== 'object') {
    state.teachSession = createEmptyBrowserTeachSession();
  }
  return state.teachSession;
}

function hasActiveBrowserTeachSession(state = getBrowserCanvasState()) {
  const teach = getBrowserTeachSession(state);
  return teach.active === true && normalizeBrowserTeachPhase(teach.phase) !== 'idle';
}

function isBrowserTeachRecording(state = getBrowserCanvasState()) {
  const teach = getBrowserTeachSession(state);
  return teach.active === true && normalizeBrowserTeachPhase(teach.phase) === 'recording';
}

function isBrowserTeachAwaitingApproval(state = getBrowserCanvasState()) {
  const teach = getBrowserTeachSession(state);
  return teach.active === true && normalizeBrowserTeachPhase(teach.phase) === 'approval_pending';
}

function isBrowserTeachVerified(state = getBrowserCanvasState()) {
  const teach = getBrowserTeachSession(state);
  return teach.active === true && normalizeBrowserTeachPhase(teach.phase) === 'verified' && !!teach.verification;
}

function buildBrowserTeachStepId() {
  return `teach_step_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

function getBrowserTeachSelectionKey(selection) {
  if (!selection || typeof selection !== 'object') return '';
  return [
    String(selection.selector || '').trim(),
    String(selection.id || '').trim(),
    String(selection.tagName || '').trim(),
    String(selection.text || '').trim().slice(0, 80),
  ].join('|');
}

function cloneBrowserTeachSelection(selection) {
  if (!selection || typeof selection !== 'object') return null;
  return {
    selector: String(selection.selector || '').trim(),
    tagName: String(selection.tagName || '').trim(),
    id: String(selection.id || '').trim(),
    text: String(selection.text || '').trim(),
    bounds: selection.bounds || null,
  };
}

function matchNamedBrowserElementForSelection(selection, state = getBrowserCanvasState()) {
  if (!selection || typeof selection !== 'object') return null;
  const selector = String(selection.selector || '').trim();
  const id = String(selection.id || '').trim();
  const selectionKey = getBrowserTeachSelectionKey(selection);
  const items = Array.isArray(state.namedElements) ? state.namedElements : [];
  return items.find((entry) => {
    const entrySelector = String(entry?.selector || '').trim();
    const entryId = String(entry?.id || '').trim();
    if (selector && entrySelector && selector === entrySelector) return true;
    if (id && entryId && id === entryId) return true;
    return getBrowserTeachSelectionKey(entry) === selectionKey;
  }) || null;
}

function resolveBrowserTeachTargetName(selection, state = getBrowserCanvasState()) {
  const selectedKey = getSelectedBrowserElementKey(selection);
  if (selectedKey && selectedKey === state.elementNameDraftKey) {
    const draft = String(state.elementNameDraft || '').trim();
    if (draft) return draft;
  }
  const matched = matchNamedBrowserElementForSelection(selection, state);
  return String(matched?.name || '').trim();
}

function summarizeBrowserTeachTarget(selection, state = getBrowserCanvasState()) {
  const targetName = resolveBrowserTeachTargetName(selection, state);
  if (targetName) return targetName;
  const text = String(selection?.text || '').replace(/\s+/g, ' ').trim();
  if (text) return text.slice(0, 72);
  const id = String(selection?.id || '').trim();
  if (id) return id;
  const tagName = String(selection?.tagName || '').trim();
  return tagName || 'selected element';
}

function classifyBrowserTeachRisk(text) {
  const source = String(text || '').trim().toLowerCase();
  if (!source) return 'none';
  return /\b(post|tweet|send|publish|submit|delete|remove|archive|buy|purchase|checkout|pay|save(?: changes)?|confirm|place order|apply|update settings)\b/i.test(source)
    ? 'high'
    : 'none';
}

function browserTeachStepToolPreview(step) {
  if (!step || typeof step !== 'object') return '';
  const args = step.args && typeof step.args === 'object' ? step.args : {};
  switch (String(step.toolName || '').trim()) {
    case 'browser_click':
      return `browser_click(${JSON.stringify(args)})`;
    case 'browser_fill':
      return `browser_fill(${JSON.stringify(args)})`;
    case 'browser_type':
      return `browser_type(${JSON.stringify(args)})`;
    case 'browser_press_key':
      return `browser_press_key(${JSON.stringify(args)})`;
    case 'browser_scroll':
      return `browser_scroll(${JSON.stringify(args)})`;
    default:
      return `${String(step.toolName || 'browser_step')}(${JSON.stringify(args)})`;
  }
}

function isEditableBrowserTeachSelection(selection) {
  const tagName = String(selection?.tagName || '').trim().toLowerCase();
  if (tagName === 'input' || tagName === 'textarea' || tagName === 'select') return true;
  const selector = String(selection?.selector || '').trim().toLowerCase();
  return selector.includes('contenteditable');
}

function createBrowserTeachClickStep(selection, point, state = getBrowserCanvasState()) {
  const clonedSelection = cloneBrowserTeachSelection(selection);
  const targetLabel = summarizeBrowserTeachTarget(clonedSelection, state);
  const targetName = resolveBrowserTeachTargetName(clonedSelection, state);
  const args = targetName
    ? { element: targetName }
    : { selector: String(clonedSelection?.selector || '').trim() };
  const summary = `Click ${targetLabel}`;
  return {
    id: buildBrowserTeachStepId(),
    kind: 'click',
    toolName: 'browser_click',
    title: summary,
    summary,
    toolPreview: browserTeachStepToolPreview({ toolName: 'browser_click', args }),
    targetName,
    risk: classifyBrowserTeachRisk(`${targetLabel} ${clonedSelection?.text || ''}`),
    status: 'pending',
    createdAt: Date.now(),
    executedAt: 0,
    pageUrl: String(state.url || '').trim(),
    pageTitle: String(state.title || '').trim(),
    resultSummary: '',
    selection: clonedSelection,
    input: {
      action: 'click',
      x: Number(point?.x || 0),
      y: Number(point?.y || 0),
      button: 'left',
    },
    args,
  };
}

function createBrowserTeachTextStep(text, state = getBrowserCanvasState()) {
  const value = String(text || '');
  const selection = cloneBrowserTeachSelection(state.selectedElement);
  const targetLabel = summarizeBrowserTeachTarget(selection, state);
  const targetName = resolveBrowserTeachTargetName(selection, state);
  const toolName = selection ? 'browser_fill' : 'browser_type';
  const args = toolName === 'browser_fill'
    ? (targetName ? { element: targetName, text: value } : { selector: String(selection?.selector || '').trim(), text: value })
    : { text: value };
  const summary = toolName === 'browser_fill'
    ? `Type into ${targetLabel}`
    : `Type "${value.replace(/\s+/g, ' ').trim().slice(0, 48)}"`;
  return {
    id: buildBrowserTeachStepId(),
    kind: toolName === 'browser_fill' ? 'fill' : 'text',
    toolName,
    title: summary,
    summary,
    toolPreview: browserTeachStepToolPreview({ toolName, args }),
    targetName,
    risk: 'none',
    status: 'pending',
    createdAt: Date.now(),
    executedAt: 0,
    pageUrl: String(state.url || '').trim(),
    pageTitle: String(state.title || '').trim(),
    resultSummary: '',
    selection,
    input: {
      action: 'text',
      text: value,
    },
    args,
  };
}

function createBrowserTeachKeyStep(key, modifiers = {}, state = getBrowserCanvasState()) {
  const comboParts = [
    modifiers.ctrlKey ? 'Control' : '',
    modifiers.altKey ? 'Alt' : '',
    modifiers.metaKey ? 'Meta' : '',
    modifiers.shiftKey ? 'Shift' : '',
    String(key || '').trim(),
  ].filter(Boolean);
  const combo = comboParts.join('+');
  const args = { key: combo };
  const summary = `Press ${combo}`;
  return {
    id: buildBrowserTeachStepId(),
    kind: 'key',
    toolName: 'browser_press_key',
    title: summary,
    summary,
    toolPreview: browserTeachStepToolPreview({ toolName: 'browser_press_key', args }),
    targetName: '',
    risk: classifyBrowserTeachRisk(combo),
    status: 'pending',
    createdAt: Date.now(),
    executedAt: 0,
    pageUrl: String(state.url || '').trim(),
    pageTitle: String(state.title || '').trim(),
    resultSummary: '',
    selection: cloneBrowserTeachSelection(state.selectedElement),
    input: {
      action: 'key',
      key: String(key || '').trim(),
      ctrlKey: modifiers.ctrlKey === true,
      altKey: modifiers.altKey === true,
      metaKey: modifiers.metaKey === true,
      shiftKey: modifiers.shiftKey === true,
    },
    args,
  };
}

function createBrowserTeachScrollStep(point, deltaX, deltaY, state = getBrowserCanvasState()) {
  const verticalMagnitude = Math.abs(Number(deltaY || 0));
  const horizontalMagnitude = Math.abs(Number(deltaX || 0));
  const direction = verticalMagnitude >= horizontalMagnitude
    ? (Number(deltaY || 0) < 0 ? 'up' : 'down')
    : (Number(deltaX || 0) < 0 ? 'left' : 'right');
  const multiplier = Math.max(1, Math.min(6, Math.round(Math.max(verticalMagnitude, horizontalMagnitude) / 560) || 1));
  const args = {
    direction: direction === 'up' ? 'up' : 'down',
    multiplier,
  };
  const summary = direction === 'up' || direction === 'down'
    ? `Scroll ${direction}`
    : `Scroll ${direction === 'left' ? 'left' : 'right'}`;
  return {
    id: buildBrowserTeachStepId(),
    kind: 'scroll',
    toolName: 'browser_scroll',
    title: summary,
    summary,
    toolPreview: browserTeachStepToolPreview({ toolName: 'browser_scroll', args }),
    targetName: '',
    risk: 'none',
    status: 'pending',
    createdAt: Date.now(),
    executedAt: 0,
    pageUrl: String(state.url || '').trim(),
    pageTitle: String(state.title || '').trim(),
    resultSummary: '',
    selection: cloneBrowserTeachSelection(state.selectedElement),
    input: {
      action: 'wheel',
      x: Number(point?.x || 0),
      y: Number(point?.y || 0),
      deltaX: Number(deltaX || 0),
      deltaY: Number(deltaY || 0),
    },
    args,
  };
}

function refreshBrowserTeachStepMetadata(step, state = getBrowserCanvasState()) {
  if (!step || typeof step !== 'object') return step;
  const next = { ...step };
  if (next.selection) {
    next.selection = cloneBrowserTeachSelection(next.selection);
  }
  if (next.kind === 'click' && next.selection) {
    const targetLabel = summarizeBrowserTeachTarget(next.selection, state);
    next.targetName = resolveBrowserTeachTargetName(next.selection, state);
    next.args = next.targetName ? { element: next.targetName } : { selector: String(next.selection.selector || '').trim() };
    next.summary = `Click ${targetLabel}`;
    next.title = next.summary;
    next.risk = classifyBrowserTeachRisk(`${targetLabel} ${next.selection.text || ''}`);
  } else if ((next.kind === 'fill' || next.kind === 'text') && next.input?.text != null) {
    const text = String(next.input.text || '');
    if (next.selection) {
      const targetLabel = summarizeBrowserTeachTarget(next.selection, state);
      next.targetName = resolveBrowserTeachTargetName(next.selection, state);
      next.toolName = 'browser_fill';
      next.args = next.targetName ? { element: next.targetName, text } : { selector: String(next.selection.selector || '').trim(), text };
      next.summary = `Type into ${targetLabel}`;
    } else {
      next.toolName = 'browser_type';
      next.args = { text };
      next.summary = `Type "${text.replace(/\s+/g, ' ').trim().slice(0, 48)}"`;
    }
    next.title = next.summary;
    next.risk = 'none';
  } else if (next.kind === 'scroll') {
    const deltaX = Number(next.input?.deltaX || 0);
    const deltaY = Number(next.input?.deltaY || 0);
    const rebuilt = createBrowserTeachScrollStep({ x: next.input?.x, y: next.input?.y }, deltaX, deltaY, state);
    next.summary = rebuilt.summary;
    next.title = rebuilt.title;
    next.args = rebuilt.args;
  } else if (next.kind === 'key') {
    next.summary = next.title || next.summary || 'Press key';
  }
  next.toolPreview = browserTeachStepToolPreview(next);
  return next;
}

function isBrowserCanvasSurfaceActive() {
  return String(getBrowserCanvasState().surface || 'files') === 'browser';
}

function getCurrentChatModeSessionId() {
  return String(window.activeChatSessionId || window.agentSessionId || '').trim();
}

function getBrowserCanvasPrimarySessionId() {
  return String(window.activeChatSessionId || window.agentSessionId || getBrowserCanvasState().sessionId || '').trim();
}

function getBrowserSessionRegistry(state = getBrowserCanvasState()) {
  if (!state.browserSessions || typeof state.browserSessions !== 'object' || Array.isArray(state.browserSessions)) {
    state.browserSessions = {};
  }
  return state.browserSessions;
}

function getBrowserSessionRecord(sessionId, state = getBrowserCanvasState()) {
  const sid = String(sessionId || '').trim();
  if (!sid) return null;
  return getBrowserSessionRegistry(state)[sid] || null;
}

function getBrowserSessionLabel(record, index = 0) {
  const ownerType = String(record?.browserOwnerType || record?.ownerType || '').trim().toLowerCase();
  const rawLabel = String(record?.browserLabel || record?.label || '').trim();
  if (ownerType === 'background') return `Browser ${Math.max(2, index + 1)}: ${rawLabel || 'Subagent'}`;
  return rawLabel || 'Main Agent';
}

function upsertBrowserSessionRecord(msg, options = {}) {
  const state = getBrowserCanvasState();
  const sid = String(msg?.sessionId || '').trim();
  if (!sid) return null;
  const registry = getBrowserSessionRegistry(state);
  const previous = registry[sid] || {};
  const primarySessionId = getBrowserCanvasPrimarySessionId();
  const ownerType = String(msg?.browserOwnerType || previous.browserOwnerType || (sid === primarySessionId ? 'main' : '') || '').trim().toLowerCase();
  const next = {
    ...previous,
    sessionId: sid,
    browserOwnerType: ownerType || 'main',
    browserOwnerId: String(msg?.browserOwnerId || previous.browserOwnerId || '').trim(),
    browserLabel: String(msg?.browserLabel || previous.browserLabel || (ownerType === 'background' ? 'Subagent' : 'Main Agent')).trim(),
    browserTaskPrompt: String(msg?.browserTaskPrompt || previous.browserTaskPrompt || '').trim(),
    browserSpawnerSessionId: String(msg?.browserSpawnerSessionId || previous.browserSpawnerSessionId || '').trim(),
    active: typeof msg?.active === 'boolean' ? msg.active === true : previous.active === true,
    url: String(msg?.url || previous.url || '').trim(),
    title: String(msg?.title || previous.title || '').trim(),
    tool: String(msg?.tool || msg?.lastTool || previous.tool || '').trim(),
    statusLabel: String(msg?.statusLabel || previous.statusLabel || '').trim(),
    streamActive: typeof msg?.streamActive === 'boolean' ? msg.streamActive === true : previous.streamActive === true,
    frameBase64: typeof msg?.frameBase64 === 'string' && msg.frameBase64.trim() ? msg.frameBase64 : previous.frameBase64,
    frameWidth: Number.isFinite(Number(msg?.frameWidth)) ? Number(msg.frameWidth) : (Number(previous.frameWidth) || 0),
    frameHeight: Number.isFinite(Number(msg?.frameHeight)) ? Number(msg.frameHeight) : (Number(previous.frameHeight) || 0),
    frameFormat: String(msg?.frameFormat || previous.frameFormat || 'png').trim().toLowerCase() === 'jpeg' ? 'jpeg' : 'png',
    updatedAt: Number(msg?.timestamp || Date.now()) || Date.now(),
    registeredAt: Number(previous.registeredAt || Date.now()) || Date.now(),
  };
  registry[sid] = next;
  if (options.copyToCanvas === true) {
    state.sessionId = sid;
    state.active = next.active;
    state.url = next.url || state.url;
    state.title = next.title || state.title;
    state.lastTool = next.tool || state.lastTool;
    state.statusLabel = next.statusLabel || state.statusLabel;
    state.streamActive = next.streamActive;
    if (next.frameBase64) {
      state.frameBase64 = next.frameBase64;
      state.frameWidth = next.frameWidth;
      state.frameHeight = next.frameHeight;
      state.frameFormat = next.frameFormat;
    }
    state.updatedAt = next.updatedAt;
  }
  return next;
}

function getBrowserCanvasSessionTabs(state = getBrowserCanvasState()) {
  const primarySessionId = getBrowserCanvasPrimarySessionId();
  const registry = getBrowserSessionRegistry(state);
  if (primarySessionId && !registry[primarySessionId]) {
    upsertBrowserSessionRecord({
      sessionId: primarySessionId,
      browserOwnerType: 'main',
      browserLabel: 'Main Agent',
      active: state.active,
      url: state.url,
      title: state.title,
      tool: state.lastTool,
      statusLabel: state.statusLabel,
      frameBase64: state.frameBase64,
      frameWidth: state.frameWidth,
      frameHeight: state.frameHeight,
      frameFormat: state.frameFormat,
      timestamp: state.updatedAt || Date.now(),
    });
  }
  const records = Object.values(registry)
    .filter((record) => record && record.sessionId)
    .sort((a, b) => {
      if (a.sessionId === primarySessionId) return -1;
      if (b.sessionId === primarySessionId) return 1;
      return Number(a.registeredAt || a.updatedAt || 0) - Number(b.registeredAt || b.updatedAt || 0);
    });
  return records.length ? records : [];
}

function getBrowserCanvasVisibleSessionId() {
  const state = getBrowserCanvasState();
  const followSessionId = String(state.followSessionId || '').trim();
  if (followSessionId) return followSessionId;
  const visibleSessionId = String(state.sessionId || '').trim();
  return visibleSessionId || getBrowserCanvasPrimarySessionId();
}

function isFollowingDetachedBrowserCanvasSession(state = getBrowserCanvasState()) {
  const followSessionId = String(state.followSessionId || '').trim();
  const primarySessionId = getBrowserCanvasPrimarySessionId();
  return !!followSessionId && followSessionId !== primarySessionId;
}

function followBrowserCanvasSession(sessionId, options = {}) {
  const state = getBrowserCanvasState();
  const nextSessionId = String(sessionId || '').trim();
  if (!nextSessionId) return false;
  const primarySessionId = getBrowserCanvasPrimarySessionId();
  if (!primarySessionId || nextSessionId === primarySessionId) {
    return returnBrowserCanvasToPrimarySession(options);
  }
  state.followSessionId = nextSessionId;
  state.sessionId = nextSessionId;
  const record = getBrowserSessionRecord(nextSessionId, state);
  if (record) {
    state.active = record.active === true;
    state.url = record.url || '';
    state.title = record.title || '';
    state.lastTool = record.tool || '';
    state.statusLabel = record.statusLabel || state.statusLabel;
    state.streamActive = record.streamActive === true;
    state.frameBase64 = record.frameBase64 || '';
    state.frameWidth = Number(record.frameWidth || 0) || 0;
    state.frameHeight = Number(record.frameHeight || 0) || 0;
    state.frameFormat = record.frameFormat || 'png';
    state.updatedAt = Number(record.updatedAt || Date.now()) || Date.now();
  }
  state.controlCaptured = false;
  state.controlOwner = 'agent';
  state.selectionPending = false;
  clearBrowserTransientHighlight();
  clearQueuedBrowserControlInputs();
  if (options.statusLabel) state.statusLabel = String(options.statusLabel || '').trim();
  if (options.render !== false) renderBrowserCanvasSurface();
  if (options.requestData !== false) {
    requestBrowserKnowledge(true);
    syncBrowserCanvasStream({ force: true });
  }
  persistActiveChat();
  return true;
}

function returnBrowserCanvasToPrimarySession(options = {}) {
  const state = getBrowserCanvasState();
  const primarySessionId = getBrowserCanvasPrimarySessionId();
  const wasFollowing = isFollowingDetachedBrowserCanvasSession(state);
  state.followSessionId = '';
  if (primarySessionId) state.sessionId = primarySessionId;
  const record = getBrowserSessionRecord(primarySessionId, state);
  if (record) {
    state.active = record.active === true;
    state.url = record.url || '';
    state.title = record.title || '';
    state.lastTool = record.tool || '';
    state.statusLabel = record.statusLabel || state.statusLabel;
    state.streamActive = record.streamActive === true;
    state.frameBase64 = record.frameBase64 || '';
    state.frameWidth = Number(record.frameWidth || 0) || 0;
    state.frameHeight = Number(record.frameHeight || 0) || 0;
    state.frameFormat = record.frameFormat || 'png';
    state.updatedAt = Number(record.updatedAt || Date.now()) || Date.now();
  }
  state.controlCaptured = false;
  state.controlOwner = 'agent';
  state.selectionPending = false;
  clearBrowserTransientHighlight();
  clearQueuedBrowserControlInputs();
  if (options.statusLabel) state.statusLabel = String(options.statusLabel || '').trim();
  if (options.render !== false) renderBrowserCanvasSurface();
  if ((wasFollowing || options.force === true) && options.requestData !== false) {
    requestBrowserKnowledge(true);
    syncBrowserCanvasStream({ force: true });
  }
  persistActiveChat();
  return true;
}

function closeBrowserModeForCreativeSwitch(options = {}) {
  const state = getBrowserCanvasState();
  const surfaceActive = isBrowserCanvasSurfaceActive();
  const interactionMode = normalizeBrowserInteractionMode(state.interactionMode);
  const captureActive = state.controlCaptured === true;
  if (!surfaceActive && interactionMode === 'agent' && !captureActive) return false;

  if (captureActive) {
    syncBrowserControlCapture(false, {
      owner: 'agent',
      reason: String(options.reason || 'Creative workspace opened.').trim(),
      statusLabel: String(options.statusLabel || 'Browser control returned to agent.').trim(),
      render: false,
      syncRemote: options.syncRemote !== false,
      flushPending: false,
    });
  }

  if (interactionMode !== 'agent') {
    state.interactionMode = 'agent';
    if (options.syncRemote !== false) {
      const sessionId = getBrowserCanvasPrimarySessionId();
      if (sessionId) wsSend({ type: 'browser:mode:set', sessionId, mode: 'agent' });
    }
  }

  if (surfaceActive) {
    setBrowserCanvasSurface('files', { autoOpen: false });
  } else {
    renderBrowserCanvasSurface();
    syncCanvasSurfaceWidthLock(getActiveCanvasTab());
  }

  if (options.persist !== false) persistActiveChat();
  return true;
}

async function exitCreativeModeForBrowserSwitch(options = {}) {
  const sid = String(options.sessionId || getCurrentChatModeSessionId()).trim();
  const activeMode = normalizeCreativeMode(options.mode === undefined ? window.currentCreativeMode : options.mode);
  if (!sid || !activeMode) return false;
  const savedMode = await persistCreativeMode(sid, null);
  applySessionCreativeMode(sid, savedMode);
  return true;
}

function getBrowserCanvasControlSessionId() {
  return getBrowserCanvasPrimarySessionId();
}

function focusBrowserCanvasFrameWrap() {
  const frameWrap = document.getElementById('browser-canvas-frame-wrap');
  if (!frameWrap || typeof frameWrap.focus !== 'function') return;
  try {
    if (document.activeElement && document.activeElement !== frameWrap && typeof document.activeElement.blur === 'function') {
      document.activeElement.blur();
    }
  } catch {}
  try {
    frameWrap.focus({ preventScroll: true });
  } catch {
    try { frameWrap.focus(); } catch {}
  }
}

function resolveBrowserCanvasViewportPointFromClient(clientX, clientY) {
  const state = getBrowserCanvasState();
  const frame = document.getElementById('browser-canvas-frame');
  if (!frame || !String(state.frameBase64 || '').trim()) return null;
  const rect = frame.getBoundingClientRect();
  if (!rect.width || !rect.height) return null;
  const localX = Number(clientX || 0) - rect.left;
  const localY = Number(clientY || 0) - rect.top;
  if (localX < 0 || localY < 0 || localX > rect.width || localY > rect.height) return null;
  return {
    x: Math.round((localX / rect.width) * Number(state.frameWidth || rect.width)),
    y: Math.round((localY / rect.height) * Number(state.frameHeight || rect.height)),
  };
}

function convertBrowserWheelDelta(event) {
  const deltaMode = Number(event?.deltaMode || 0);
  const factor = deltaMode === 1 ? 16 : (deltaMode === 2 ? 320 : 1);
  return {
    deltaX: Number(event?.deltaX || 0) * factor,
    deltaY: Number(event?.deltaY || 0) * factor,
  };
}

function normalizeBrowserForwardedKey(event) {
  const raw = String(event?.key || '').trim();
  if (!raw || raw === 'Dead' || raw === 'Process') return '';
  if (raw === ' ') return 'Space';
  return raw;
}

function flushQueuedBrowserWheelInput(options = {}) {
  if (browserQueuedWheelFlushTimer) {
    clearTimeout(browserQueuedWheelFlushTimer);
    browserQueuedWheelFlushTimer = 0;
  }
  const pending = browserQueuedWheelInput;
  browserQueuedWheelInput = null;
  if (!pending || options.clearOnly === true) return;
  const state = getBrowserCanvasState();
  if (isBrowserTeachRecording(state)) {
    upsertPendingBrowserTeachStep(
      createBrowserTeachScrollStep(pending, pending.deltaX, pending.deltaY, state),
      { merge: true },
    );
    return;
  }
  const sessionId = getBrowserCanvasControlSessionId();
  if (!sessionId || !(window.ws && window.ws.readyState === WebSocket.OPEN)) return;
  wsSend({
    type: 'browser:input',
    sessionId,
    action: 'wheel',
    x: pending.x,
    y: pending.y,
    deltaX: pending.deltaX,
    deltaY: pending.deltaY,
  });
}

function queueBrowserWheelInput(point, deltaX, deltaY) {
  if (!point) return;
  if (!browserQueuedWheelInput) {
    browserQueuedWheelInput = { x: point.x, y: point.y, deltaX: 0, deltaY: 0 };
  }
  browserQueuedWheelInput.x = point.x;
  browserQueuedWheelInput.y = point.y;
  browserQueuedWheelInput.deltaX += Number(deltaX || 0);
  browserQueuedWheelInput.deltaY += Number(deltaY || 0);
  if (browserQueuedWheelFlushTimer) clearTimeout(browserQueuedWheelFlushTimer);
  browserQueuedWheelFlushTimer = window.setTimeout(() => flushQueuedBrowserWheelInput(), 90);
}

function flushQueuedBrowserTextInput(options = {}) {
  if (browserQueuedTextFlushTimer) {
    clearTimeout(browserQueuedTextFlushTimer);
    browserQueuedTextFlushTimer = 0;
  }
  const text = browserQueuedTextInput;
  browserQueuedTextInput = '';
  if (!text || options.clearOnly === true) return;
  const state = getBrowserCanvasState();
  if (isBrowserTeachRecording(state)) {
    upsertPendingBrowserTeachStep(createBrowserTeachTextStep(text, state), { merge: true });
    return;
  }
  const sessionId = getBrowserCanvasControlSessionId();
  if (!sessionId || !(window.ws && window.ws.readyState === WebSocket.OPEN)) return;
  wsSend({
    type: 'browser:input',
    sessionId,
    action: 'text',
    text,
  });
}

function queueBrowserTextInput(text) {
  const value = String(text || '');
  if (!value) return;
  browserQueuedTextInput += value;
  if (browserQueuedTextFlushTimer) clearTimeout(browserQueuedTextFlushTimer);
  browserQueuedTextFlushTimer = window.setTimeout(() => flushQueuedBrowserTextInput(), 80);
}

function clearQueuedBrowserControlInputs() {
  flushQueuedBrowserTextInput({ clearOnly: true });
  flushQueuedBrowserWheelInput({ clearOnly: true });
}

function syncBrowserControlCapture(captured, options = {}) {
  const state = getBrowserCanvasState();
  const nextCaptured = captured === true;
  const nextOwner = nextCaptured ? (String(options.owner || '').trim().toLowerCase() === 'agent' ? 'agent' : 'user') : 'agent';
  state.controlCaptured = nextCaptured;
  state.controlOwner = nextOwner;
  if (nextCaptured) {
    state.statusLabel = String(options.statusLabel || state.statusLabel || 'You are controlling the browser.').trim();
    if (options.focusFrame !== false) focusBrowserCanvasFrameWrap();
  } else {
    if (options.flushPending !== false) {
      flushQueuedBrowserTextInput();
      flushQueuedBrowserWheelInput();
    } else {
      clearQueuedBrowserControlInputs();
    }
    if (options.statusLabel) {
      state.statusLabel = String(options.statusLabel || '').trim();
    }
  }
  if (options.render !== false) renderBrowserCanvasSurface();
  if (options.syncRemote === false) return;
  const sessionId = getBrowserCanvasControlSessionId();
  if (!sessionId || !(window.ws && window.ws.readyState === WebSocket.OPEN)) return;
  wsSend({
    type: 'browser:control:set',
    sessionId,
    captured: nextCaptured,
    owner: nextOwner,
    reason: String(options.reason || '').trim(),
  });
}

function captureBrowserCanvasControl(reason = 'User clicked into the browser canvas.') {
  const state = getBrowserCanvasState();
  const mode = normalizeBrowserInteractionMode(state.interactionMode);
  if (mode !== 'copilot' && mode !== 'teach') return false;
  if (isFollowingDetachedBrowserCanvasSession(state)) {
    showToast('The canvas is following the detached Teach verifier tab. Return to Main Tab to control the live browser again.', 'info');
    return false;
  }
  syncBrowserControlCapture(true, {
    owner: 'user',
    reason,
    statusLabel: mode === 'teach'
      ? 'Teach mode is recording. Stage the next step, then continue it when you are ready.'
      : 'You are controlling the browser.',
    render: true,
    syncRemote: true,
    focusFrame: true,
  });
  return true;
}

function releaseBrowserCanvasControl(options = {}) {
  const state = getBrowserCanvasState();
  if (!state.controlCaptured && options.force !== true) return false;
  syncBrowserControlCapture(false, {
    owner: 'agent',
    reason: String(options.reason || 'Browser control returned to Prometheus.').trim(),
    statusLabel: String(options.statusLabel || 'Browser control returned to Prometheus.').trim(),
    render: options.render !== false,
    syncRemote: options.syncRemote !== false,
    flushPending: options.flushPending !== false,
  });
  return true;
}

function handleCapturedBrowserKeydown(event) {
  const state = getBrowserCanvasState();
  const mode = normalizeBrowserInteractionMode(state.interactionMode);
  if (mode !== 'copilot' && mode !== 'teach') return;
  if (!state.controlCaptured || state.controlOwner !== 'user') return;
  if (event?.isComposing) return;
  const normalizedKey = normalizeBrowserForwardedKey(event);
  if (!normalizedKey) return;
  if (mode === 'teach' && !isBrowserTeachRecording(state)) {
    if (normalizedKey !== 'Escape') return;
  }
  if (normalizedKey === 'Escape') {
    event.preventDefault();
    event.stopPropagation();
    releaseBrowserCanvasControl({
      reason: 'User released browser control with Escape.',
      statusLabel: 'Browser control returned to Prometheus.',
    });
    return;
  }
  const noModifiers = !event.ctrlKey && !event.altKey && !event.metaKey;
  const teachPlainText = mode === 'teach'
    && noModifiers
    && (normalizedKey.length === 1 || (normalizedKey === 'Space' && (isEditableBrowserTeachSelection(state.selectedElement) || ((getBrowserTeachSession(state).pendingStep?.kind === 'fill') || (getBrowserTeachSession(state).pendingStep?.kind === 'text')))));
  const isPlainText = normalizedKey.length === 1 && noModifiers;
  event.preventDefault();
  event.stopPropagation();
  if (isPlainText || teachPlainText) {
    queueBrowserTextInput(normalizedKey === 'Space' ? ' ' : event.key);
    return;
  }
  if (['Shift', 'Control', 'Alt', 'Meta'].includes(normalizedKey)) return;
  if (mode === 'teach' && isBrowserTeachRecording(state)) {
    upsertPendingBrowserTeachStep(createBrowserTeachKeyStep(normalizedKey, {
      ctrlKey: event.ctrlKey === true,
      altKey: event.altKey === true,
      metaKey: event.metaKey === true,
      shiftKey: event.shiftKey === true,
    }, state));
    return;
  }
  flushQueuedBrowserTextInput();
  const sessionId = getBrowserCanvasControlSessionId();
  if (!sessionId || !(window.ws && window.ws.readyState === WebSocket.OPEN)) return;
  wsSend({
    type: 'browser:input',
    sessionId,
    action: 'key',
    key: normalizedKey,
    ctrlKey: event.ctrlKey === true,
    altKey: event.altKey === true,
    metaKey: event.metaKey === true,
    shiftKey: event.shiftKey === true,
  });
}

function handleCapturedBrowserWheel(event) {
  const state = getBrowserCanvasState();
  const mode = normalizeBrowserInteractionMode(state.interactionMode);
  if (mode !== 'copilot' && mode !== 'teach') return;
  if (mode === 'teach' && !isBrowserTeachRecording(state)) return;
  if (!state.controlCaptured || state.controlOwner !== 'user') return;
  const point = resolveBrowserCanvasViewportPointFromClient(event?.clientX, event?.clientY);
  if (!point) return;
  const { deltaX, deltaY } = convertBrowserWheelDelta(event);
  if (!deltaX && !deltaY) return;
  event.preventDefault();
  event.stopPropagation();
  queueBrowserWheelInput(point, deltaX, deltaY);
}

function ensureBrowserCanvasControlBindings() {
  const frameWrap = document.getElementById('browser-canvas-frame-wrap');
  if (!frameWrap || frameWrap.dataset.browserControlBound === '1') return;
  frameWrap.addEventListener('keydown', handleCapturedBrowserKeydown);
  frameWrap.addEventListener('wheel', handleCapturedBrowserWheel, { passive: false });
  frameWrap.dataset.browserControlBound = '1';
}

function ensureBrowserCanvasGlobalControlBindings() {
  if (window.__promBrowserControlGlobalsBound) return;
  document.addEventListener('pointerdown', (event) => {
    const state = getBrowserCanvasState();
    const mode = normalizeBrowserInteractionMode(state.interactionMode);
    if (mode !== 'copilot' && mode !== 'teach') return;
    if (!state.controlCaptured || state.controlOwner !== 'user') return;
    const target = event?.target instanceof Element ? event.target : null;
    const frameWrap = document.getElementById('browser-canvas-frame-wrap');
    if (target && frameWrap?.contains(target)) return;
    releaseBrowserCanvasControl({
      reason: 'Browser control released when focus moved back to the app.',
      statusLabel: 'Browser control returned to Prometheus.',
    });
  }, true);
  window.__promBrowserControlGlobalsBound = true;
}

function clearBrowserCanvasStreamHeartbeat() {
  if (!browserStreamHeartbeatTimer) return;
  clearInterval(browserStreamHeartbeatTimer);
  browserStreamHeartbeatTimer = 0;
}

function startBrowserCanvasStreamHeartbeat() {
  if (browserStreamHeartbeatTimer) return;
  browserStreamHeartbeatTimer = window.setInterval(() => {
    const desired = window.__promBrowserCanvasStreamDesired;
    if (!desired?.active || !desired?.sessionId) {
      clearBrowserCanvasStreamHeartbeat();
      return;
    }
    if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) return;
	    wsSend({
	      type: 'browser:stream:set',
	      sessionId: desired.sessionId,
	      active: true,
	      focus: desired.focus,
	      preferCdp: true,
	      restoreUrl: getBrowserCanvasRestoreHint(getBrowserCanvasState()).restoreUrl,
	      restoreTitle: getBrowserCanvasRestoreHint(getBrowserCanvasState()).restoreTitle,
	    });
  }, 5000);
}

function syncBrowserCanvasStream(options = {}) {
  const state = getBrowserCanvasState();
  const currentMode = normalizeBrowserInteractionMode(state.interactionMode);
  const sessionId = getBrowserCanvasVisibleSessionId();
  const desired = {
    sessionId: String(sessionId || '').trim(),
    active: !!(canvasOpen && isBrowserCanvasSurfaceActive() && state.active && sessionId),
    focus: isBrowserCanvasSurfaceActive() ? 'interactive' : ((currentMode === 'copilot' || currentMode === 'teach') ? 'interactive' : 'passive'),
  };
  const previous = window.__promBrowserCanvasStreamDesired || { sessionId: '', active: false, focus: 'passive' };
  window.__promBrowserCanvasStreamDesired = desired;
  if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) {
    clearBrowserCanvasStreamHeartbeat();
    return;
  }
  const shouldStopPrevious = previous.active && previous.sessionId && (
    !desired.active || previous.sessionId !== desired.sessionId
  );
  if (shouldStopPrevious) {
    wsSend({
      type: 'browser:stream:set',
      sessionId: previous.sessionId,
      active: false,
      reason: 'Browser canvas moved away from this session.',
    });
  }
  const shouldStartOrRefresh = desired.active && (
    options.force === true
    || !previous.active
    || previous.sessionId !== desired.sessionId
    || previous.focus !== desired.focus
  );
  if (shouldStartOrRefresh) {
    const { restoreUrl, restoreTitle } = getBrowserCanvasRestoreHint(state);
    wsSend({
      type: 'browser:stream:set',
      sessionId: desired.sessionId,
      active: true,
      focus: desired.focus,
      preferCdp: true,
      restoreUrl,
      restoreTitle,
    });
  }
  if (!desired.active) {
    clearBrowserCanvasStreamHeartbeat();
  } else {
    startBrowserCanvasStreamHeartbeat();
  }
}

function truncateBrowserPreview(value, max = 80) {
  const str = String(value ?? '');
  if (str.length <= max) return str;
  const parenIdx = str.indexOf('(');
  if (parenIdx > 0 && parenIdx < max) {
    const head = str.slice(0, parenIdx).trim();
    return `${head}(…)`;
  }
  return `${str.slice(0, max - 1).trim()}…`;
}

function formatBrowserCanvasTimestamp(value) {
  const timestamp = Number(value || 0);
  if (!timestamp) return 'Waiting for browser activity';
  const date = new Date(timestamp);
  if (Number.isNaN(date.getTime())) return 'Waiting for browser activity';
  return `Updated ${date.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit', second: '2-digit' })}`;
}

function suggestBrowserElementName(element) {
  if (!element || typeof element !== 'object') return '';
  const id = String(element.id || '').trim();
  if (id) return id.replace(/[-_]+/g, ' ').trim();
  const selector = String(element.selector || '').trim();
  const selectorMatch = selector.match(/([a-z0-9_-]+)(?::nth-of-type\(\d+\))?$/i);
  if (selectorMatch?.[1]) return selectorMatch[1].replace(/[-_]+/g, ' ').trim();
  const text = String(element.text || '').replace(/\s+/g, ' ').trim();
  if (text) return text.slice(0, 48);
  return String(element.tagName || 'element').trim();
}

function getSelectedBrowserElementKey(element = getBrowserCanvasState().selectedElement) {
  if (!element || typeof element !== 'object') return '';
  return [
    String(element.selector || '').trim(),
    String(element.id || '').trim(),
    String(element.tagName || '').trim(),
    String(element.text || '').trim().slice(0, 80),
  ].join('|');
}

function getCanvasWidthLockMessage(tab = getActiveCanvasTab()) {
  const creativeMeta = getCreativeModeMeta(window.currentCreativeMode);
  if (creativeMeta) return `Exit ${creativeMeta.title} to resize the canvas.`;
  if (canvasOpen && isBrowserCanvasSurfaceActive()) {
    return 'Switch the browser surface back to files to resize the panel.';
  }
  if (canvasOpen && isPreviewLikeCanvasTab(tab)) {
    return 'Switch the canvas back to code to resize the panel.';
  }
  return '';
}

function isCanvasWidthLocked(tab = getActiveCanvasTab()) {
  return !!getCanvasWidthLockMessage(tab);
}

function syncCanvasSurfaceWidthLock(tab = getActiveCanvasTab()) {
  const rightPanel = document.getElementById('right-panel');
  if (!rightPanel) return;
  if (isCreativeModeLocked()) {
    updateCreativeModeControls();
    if (typeof window._syncPageViewPositions === 'function') window._syncPageViewPositions();
    return;
  }
  const shouldLock = !!(canvasOpen && (isBrowserCanvasSurfaceActive() || isPreviewLikeCanvasTab(tab)));
  if (shouldLock) {
    if (canvasPreviewSavedPanelWidth === null) {
      const measuredWidth = rightPanel.offsetWidth || 0;
      canvasPreviewSavedPanelWidth =
        rightPanel.style.width
        || rightPanel.style.minWidth
        || (measuredWidth ? `${measuredWidth}px` : '');
    }
    setRightPanelWidth(IMMERSIVE_CANVAS_PANEL_WIDTH, { minimumWidth: 960, lockMax: true });
  } else if (canvasPreviewSavedPanelWidth !== null) {
    if (canvasPreviewSavedPanelWidth && !/^0px$/i.test(canvasPreviewSavedPanelWidth)) {
      rightPanel.style.width = canvasPreviewSavedPanelWidth;
      rightPanel.style.minWidth = canvasPreviewSavedPanelWidth;
    } else {
      rightPanel.style.removeProperty('width');
      rightPanel.style.removeProperty('min-width');
    }
    rightPanel.style.removeProperty('max-width');
    canvasPreviewSavedPanelWidth = null;
  }
  updateCreativeModeControls();
  if (typeof window._syncPageViewPositions === 'function') window._syncPageViewPositions();
}

function getCanvasPreviewDevice() {
  return CANVAS_PREVIEW_DEVICES[canvasPreviewDevice] ? canvasPreviewDevice : 'responsive';
}

function setCanvasPreviewDevice(deviceKey) {
  canvasPreviewDevice = CANVAS_PREVIEW_DEVICES[deviceKey] ? deviceKey : 'responsive';
  syncCanvasPreviewDeviceFrame();
  const tab = getActiveCanvasTab();
  if (tab?.mode === 'preview' || tab?.isImage || tab?.isBinary) {
    addProcessEntry('info', `Preview device: ${CANVAS_PREVIEW_DEVICES[canvasPreviewDevice].label}.`);
  }
}

function syncCanvasPreviewDeviceFrame() {
  const shell = document.getElementById('canvas-preview-shell');
  const stage = document.getElementById('canvas-preview-stage');
  const deviceFrame = document.getElementById('canvas-preview-device-frame');
  const iframe = document.getElementById('canvas-preview-frame');
  const sizeLabel = document.getElementById('canvas-preview-size-label');
  if (!shell || !stage || !deviceFrame || !iframe) return;

  const key = getCanvasPreviewDevice();
  const device = CANVAS_PREVIEW_DEVICES[key];
  shell.dataset.device = key;
  document.querySelectorAll('[data-canvas-preview-device]').forEach((button) => {
    button.classList.toggle('active', button.getAttribute('data-canvas-preview-device') === key);
  });

  if (key === 'responsive') {
    stage.style.overflow = 'hidden';
    deviceFrame.style.width = '100%';
    deviceFrame.style.height = '100%';
    deviceFrame.style.padding = '0';
    iframe.style.width = '100%';
    iframe.style.height = '100%';
    iframe.style.transform = '';
    iframe.style.borderRadius = '0';
    iframe.style.boxShadow = '';
    if (sizeLabel) sizeLabel.textContent = 'Fluid viewport';
    return;
  }

  const stageRect = stage.getBoundingClientRect();
  const availableWidth = Math.max(240, stageRect.width - 48);
  const availableHeight = Math.max(320, stageRect.height - 48);
  const scale = Math.min(1, availableWidth / device.width, availableHeight / device.height);
  const scaledWidth = Math.round(device.width * scale);
  const scaledHeight = Math.round(device.height * scale);
  stage.style.overflow = 'auto';
  deviceFrame.style.width = `${scaledWidth}px`;
  deviceFrame.style.height = `${scaledHeight}px`;
  deviceFrame.style.padding = '0';
  iframe.style.width = `${device.width}px`;
  iframe.style.height = `${device.height}px`;
  iframe.style.transform = `scale(${scale})`;
  iframe.style.borderRadius = '28px';
  iframe.style.boxShadow = '0 24px 70px rgba(0,0,0,0.45)';
  if (sizeLabel) sizeLabel.textContent = `${device.width} x ${device.height}`;
}

function getActiveChatSessionRecord() {
  return (window.chatSessions || []).find(s => s.id === window.activeChatSessionId) || null;
}

function isCreativeModeLocked() {
  return !!normalizeCreativeMode(window.currentCreativeMode);
}

function shouldHideCenterColumnForImmersivePanels() {
  if (String(window.currentMode || 'chat') !== 'chat') return false;
  const sidebar = document.getElementById('sidebar');
  const rightPanel = document.getElementById('right-panel');
  const workspace = document.getElementById('workspace');
  if (!sidebar || !rightPanel || !workspace) return false;
  if (sidebar.classList.contains('collapsed')) return false;
  if (!rightPanel.classList.contains('open')) return false;
  const immersiveRightPanelActive = isCreativeModeLocked() || (canvasOpen && isBrowserCanvasSurfaceActive());
  if (!immersiveRightPanelActive) return false;
  const workspaceWidth = workspace.getBoundingClientRect().width || workspace.clientWidth || 0;
  const rightPanelWidth =
    rightPanel.getBoundingClientRect().width
    || rightPanel.offsetWidth
    || Number.parseFloat(rightPanel.style.width)
    || Number.parseFloat(rightPanel.style.minWidth)
    || 0;
  return (workspaceWidth - rightPanelWidth) < IMMERSIVE_CENTER_COL_MIN_WIDTH;
}

function syncCenterColumnVisibility() {
  const body = document.body;
  const centerCol = document.getElementById('centerCol');
  const shouldHide = shouldHideCenterColumnForImmersivePanels();
  if (body) body.classList.toggle('immersive-center-hidden', shouldHide);
  if (centerCol) {
    if (shouldHide) centerCol.setAttribute('aria-hidden', 'true');
    else centerCol.removeAttribute('aria-hidden');
  }
}

function updateCreativeModeControls() {
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  const meta = getCreativeModeMeta(mode);
  const widthLockMessage = getCanvasWidthLockMessage();
  const browserState = getBrowserCanvasState();
  const browserSurfaceActive = isBrowserCanvasSurfaceActive();
  const browserMeta = getBrowserInteractionMeta(browserState.interactionMode);
  const badge = document.getElementById('creative-mode-badge');
  const canvasToggleBtn = document.getElementById('canvas-toggle-btn');
  const backBtn = document.getElementById('canvas-context-btn');
  const resizeHandle = document.getElementById('rp-resize');
  const exitButtons = document.querySelectorAll('[data-creative-mode-exit]');
  const modeButtons = document.querySelectorAll('[data-creative-mode-btn]');
  const browserSurfaceButtons = [
    document.getElementById('canvas-browser-surface-btn'),
    document.getElementById('right-panel-browser-surface-btn'),
  ].filter(Boolean);
  const browserModeRail = document.getElementById('canvas-browser-mode-rail');
  const browserStatusPill = document.getElementById('canvas-browser-status-pill');
  const browserStatusLabel = document.getElementById('canvas-browser-status-label');
  const browserStatusDot = document.getElementById('canvas-browser-status-dot');
  const browserLiveDots = [
    document.getElementById('canvas-browser-live-dot'),
    document.getElementById('right-panel-browser-live-dot'),
  ].filter(Boolean);
  const browserModeButtons = document.querySelectorAll('[data-browser-mode-btn]');
  const root = document.documentElement;

  if (root) root.dataset.creativeMode = mode || '';
  if (document.body) document.body.classList.toggle('browser-surface-active', browserSurfaceActive);

  if (badge) {
    if (meta) {
      badge.style.display = 'inline-flex';
      badge.style.borderColor = meta.accent;
      badge.style.background = meta.glow;
      badge.style.color = meta.accent;
      badge.textContent = `${meta.title} active`;
    } else {
      badge.style.display = 'none';
      badge.textContent = '';
    }
  }

  modeButtons.forEach((btn) => {
    const btnMode = normalizeCreativeMode(btn.dataset.creativeModeBtn);
    const active = !!mode && btnMode === mode;
    btn.dataset.active = active ? 'true' : 'false';
    btn.style.borderColor = active ? (meta?.accent || 'rgba(255,255,255,0.18)') : 'rgba(255,255,255,0.12)';
    btn.style.background = active ? (meta?.glow || 'rgba(255,255,255,0.06)') : 'rgba(255,255,255,0.06)';
    btn.style.color = active ? (meta?.accent || '#e8e6e1') : '#9a9890';
  });

  exitButtons.forEach((btn) => {
    btn.style.display = meta ? 'inline-flex' : 'none';
  });
  browserSurfaceButtons.forEach((btn) => {
    btn.dataset.active = browserSurfaceActive ? 'true' : 'false';
    btn.title = browserSurfaceActive ? 'Hide browser activity' : 'Show browser activity';
  });
  browserModeButtons.forEach((btn) => {
    const btnMode = normalizeBrowserInteractionMode(btn.dataset.browserModeBtn);
    const active = browserSurfaceActive && btnMode === normalizeBrowserInteractionMode(browserState.interactionMode);
    btn.dataset.active = active ? 'true' : 'false';
  });
  browserLiveDots.forEach((dot) => {
    dot.style.display = browserState.active ? 'inline-flex' : 'none';
  });
  if (browserModeRail) browserModeRail.style.display = browserSurfaceActive ? 'inline-flex' : 'none';
  if (browserStatusPill) browserStatusPill.style.display = browserSurfaceActive ? 'inline-flex' : 'none';
  if (browserStatusLabel) {
    browserStatusLabel.textContent = browserState.active ? `${browserMeta.label} mode` : 'Browser idle';
  }
  if (browserStatusDot) {
    browserStatusDot.style.background = browserState.active ? '#22c55e' : '#94a3b8';
    browserStatusDot.style.boxShadow = browserState.active ? '0 0 0 3px rgba(34,197,94,0.14)' : '0 0 0 3px rgba(148,163,184,0.12)';
  }

  if (canvasToggleBtn) {
    canvasToggleBtn.title = meta ? `${meta.title} is active` : 'Open Canvas';
  }
  if (backBtn) {
    backBtn.title = meta ? `Exit ${meta.title} to close the canvas` : 'Back to Context';
  }
  if (resizeHandle) {
    resizeHandle.style.opacity = widthLockMessage ? '0.45' : '';
    resizeHandle.style.cursor = widthLockMessage ? 'not-allowed' : '';
    resizeHandle.title = widthLockMessage || 'Drag to resize';
  }
}

function renderBrowserCanvasSurface() {
  const state = getBrowserCanvasState();
  const mode = normalizeBrowserInteractionMode(state.interactionMode);
  const meta = getBrowserInteractionMeta(mode);
  const selectedKey = getSelectedBrowserElementKey(state.selectedElement);
  if (selectedKey && state.elementNameDraftKey !== selectedKey) {
    state.elementNameDraftKey = selectedKey;
    state.elementNameDraft = suggestBrowserElementName(state.selectedElement);
  } else if (!selectedKey && state.elementNameDraftKey) {
    state.elementNameDraftKey = '';
    state.elementNameDraft = '';
  }
  const title = document.getElementById('browser-canvas-title');
  const subtitle = document.getElementById('browser-canvas-subtitle');
  const tabsWrap = document.getElementById('browser-canvas-agent-tabs');
  const urlEl = document.getElementById('browser-canvas-url');
  const stageTitle = document.getElementById('browser-canvas-stage-title');
  const stageCopy = document.getElementById('browser-canvas-stage-copy');
  const emptyState = document.getElementById('browser-canvas-empty');
  const frameWrap = document.getElementById('browser-canvas-frame-wrap');
  const frameEl = document.getElementById('browser-canvas-frame');
  const frameMeta = document.getElementById('browser-canvas-frame-meta');
  const frameCaption = document.getElementById('browser-canvas-frame-caption');
  const frameSize = document.getElementById('browser-canvas-frame-size');
  const selectionBox = document.getElementById('browser-canvas-selection-box');
  const clickHighlight = document.getElementById('browser-canvas-click-highlight');
  const agentCursor = document.getElementById('browser-canvas-agent-cursor');
  const selectionCard = document.getElementById('browser-canvas-selection-card');
  const selectionLabel = document.getElementById('browser-canvas-selection-label');
  const selectionText = document.getElementById('browser-canvas-selection-text');
  const modeTitleEl = document.getElementById('browser-canvas-mode-title');
  const controlRow = document.getElementById('browser-canvas-control-row');
  const controlBadge = document.getElementById('browser-canvas-control-badge');
  const releaseBtn = document.getElementById('browser-canvas-release-btn');
  const returnBtn = document.getElementById('browser-canvas-return-btn');
  const reopenBtn = document.getElementById('browser-canvas-reopen-btn');
  const backBtn = document.getElementById('browser-canvas-back-btn');
  const forwardBtn = document.getElementById('browser-canvas-forward-btn');
  const reloadBtn = document.getElementById('browser-canvas-reload-btn');
  const openBtn = document.getElementById('browser-canvas-open-btn');
  const addressInput = document.getElementById('browser-canvas-address-input');
  const chromeSessionChip = document.getElementById('browser-canvas-session-chip');
  const chromeStreamChip = document.getElementById('browser-canvas-stream-chip');
  const namePanel = document.getElementById('browser-canvas-name-panel');
  const nameInput = document.getElementById('browser-canvas-name-input');
  const savedWrap = document.getElementById('browser-canvas-saved-elements');
  const sessionEl = document.getElementById('browser-canvas-session');
  const pageTitleEl = document.getElementById('browser-canvas-page-title');
  const lastToolEl = document.getElementById('browser-canvas-last-tool');
  const lastUpdatedEl = document.getElementById('browser-canvas-last-updated');
  const modeCopyEl = document.getElementById('browser-canvas-mode-copy');
  const taskPanel = document.getElementById('browser-canvas-task-panel');
  const taskCopyEl = document.getElementById('browser-canvas-task-copy');
  const teachPanel = document.getElementById('browser-canvas-teach-panel');
  const teachStatusEl = document.getElementById('browser-canvas-teach-status');
  const teachStartBtn = document.getElementById('browser-canvas-teach-start-btn');
  const teachCompleteBtn = document.getElementById('browser-canvas-teach-complete-btn');
  const teachCancelBtn = document.getElementById('browser-canvas-teach-cancel-btn');
  const teachApprovalActions = document.getElementById('browser-canvas-teach-approval-actions');
  const teachStopStepInput = document.getElementById('browser-canvas-teach-stop-step-input');
  const teachPendingCard = document.getElementById('browser-canvas-teach-pending');
  const teachPendingTitle = document.getElementById('browser-canvas-teach-pending-title');
  const teachPendingCopy = document.getElementById('browser-canvas-teach-pending-copy');
  const teachContinueBtn = document.getElementById('browser-canvas-teach-continue-btn');
  const teachDiscardBtn = document.getElementById('browser-canvas-teach-discard-btn');
  const teachStepsWrap = document.getElementById('browser-canvas-teach-steps');
  const visibleSessionId = getBrowserCanvasVisibleSessionId();
  const visibleRecord = getBrowserSessionRecord(visibleSessionId, state);
  const visibleTaskPrompt = String(visibleRecord?.browserTaskPrompt || '').trim();
  if (taskPanel) taskPanel.style.display = visibleTaskPrompt ? 'block' : 'none';
  // Sidebar order: (1) Task when watching a subagent, (2) Mode Notes, (3) Selected element, (4) Last Tool Call.
  if (modeTitleEl && sessionEl && selectionCard) {
    const modeCard = modeTitleEl.parentElement;
    const lastToolCard = sessionEl.closest('div[style*="border"]') || sessionEl.parentElement;
    const sidebar = lastToolCard?.parentElement;
    if (sidebar && modeCard && lastToolCard) {
      if (taskPanel && taskPanel.style.display !== 'none') {
        if (sidebar.firstElementChild !== taskPanel) sidebar.insertBefore(taskPanel, sidebar.firstElementChild);
        if (taskPanel.nextElementSibling !== modeCard) sidebar.insertBefore(modeCard, taskPanel.nextElementSibling);
      } else if (sidebar.firstElementChild !== modeCard) {
        sidebar.insertBefore(modeCard, sidebar.firstElementChild);
      }
      if (modeCard.nextElementSibling !== selectionCard) sidebar.insertBefore(selectionCard, modeCard.nextElementSibling);
      if (selectionCard.nextElementSibling !== lastToolCard) sidebar.insertBefore(lastToolCard, selectionCard.nextElementSibling);
    }
  }
  if (teachPendingCard && modeTitleEl) {
    const modeCard = modeTitleEl.parentElement;
    if (modeCard && (teachPendingCard.parentElement !== modeCard || modeCard.firstElementChild !== teachPendingCard)) {
      modeCard.insertBefore(teachPendingCard, modeCard.firstElementChild);
    }
    teachPendingCard.style.marginTop = '0';
    teachPendingCard.style.marginBottom = '12px';
  }
  const hasFrame = !!String(state.frameBase64 || '').trim();
  const controlCaptured = state.controlCaptured === true && state.controlOwner === 'user';
  const followingDetachedSession = isFollowingDetachedBrowserCanvasSession(state);
  const restoreHint = getBrowserCanvasRestoreHint(state);
  const canReopenLastPage = !followingDetachedSession && isRestorableBrowserCanvasUrl(restoreHint.restoreUrl);
  const teach = getBrowserTeachSession(state);
  const teachActive = hasActiveBrowserTeachSession(state);
  const teachRecording = isBrowserTeachRecording(state);
  const teachAwaitingApproval = isBrowserTeachAwaitingApproval(state);
  const teachVerified = isBrowserTeachVerified(state);
  const pendingTeachStep = teach.pendingStep && typeof teach.pendingStep === 'object' ? teach.pendingStep : null;
  const recordedTeachSteps = Array.isArray(teach.steps) ? teach.steps : [];
  const teachVerification = teachVerified && teach.verification && typeof teach.verification === 'object' ? teach.verification : null;
  const streamDescriptor = state.streamActive
    ? `${String(state.streamTransport || 'stream').toUpperCase()} live`
    : '';
  const browserTabs = getBrowserCanvasSessionTabs(state);

  ensureBrowserCanvasControlBindings();
  ensureBrowserCanvasGlobalControlBindings();
  if (tabsWrap) {
    tabsWrap.style.display = browserTabs.length > 1 ? 'flex' : 'none';
    tabsWrap.innerHTML = browserTabs.map((record, index) => {
      const sid = String(record.sessionId || '').trim();
      const active = sid === visibleSessionId;
      const label = getBrowserSessionLabel(record, index);
      const statusDot = record.active ? '#22c55e' : '#64748b';
      const sidArg = JSON.stringify(sid).replace(/"/g, '&quot;');
      const statusArg = JSON.stringify({ statusLabel: `Watching ${label}.` }).replace(/"/g, '&quot;');
      return `
        <button type="button" onclick="followBrowserCanvasSession(${sidArg}, ${statusArg})" title="${escHtml(record.title || record.url || label)}" style="display:inline-flex;align-items:center;gap:7px;border:1px solid ${active ? 'rgba(56,189,248,0.42)' : 'rgba(148,163,184,0.16)'};background:${active ? 'rgba(56,189,248,0.16)' : 'rgba(15,23,42,0.52)'};color:${active ? '#e0f2fe' : '#cbd5e1'};border-radius:8px;padding:7px 10px;font-size:11px;font-weight:800;cursor:pointer;font-family:'Manrope',sans-serif;max-width:220px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">
          <span style="width:7px;height:7px;border-radius:999px;background:${statusDot};box-shadow:${record.active ? '0 0 0 3px rgba(34,197,94,0.12)' : 'none'};flex-shrink:0"></span>
          <span style="overflow:hidden;text-overflow:ellipsis">${escHtml(label)}</span>
        </button>
      `;
    }).join('');
  }
  if (title) title.textContent = state.active ? `${meta.label} Browser` : 'Live Browser';
  if (subtitle) {
    subtitle.textContent = state.active
      ? (followingDetachedSession
        ? `Watching Teach verifier tab${state.streamActive ? ` · ${streamDescriptor}` : ''}${state.streamStatus ? ` · ${state.streamStatus}` : ''}`
        : (state.streamActive
          ? `${streamDescriptor}${state.streamStatus ? ` · ${state.streamStatus}` : ''}`
          : (state.statusLabel || `Watching ${state.title || state.url || 'the active page'}`)))
      : 'Waiting for browser activity in this chat';
  }
  if (urlEl) urlEl.textContent = state.url || restoreHint.restoreUrl || 'No active browser session';
  if (addressInput && document.activeElement !== addressInput) {
    addressInput.value = state.url || restoreHint.restoreUrl || '';
    addressInput.placeholder = state.active ? 'Search or enter URL' : 'Open a URL...';
  }
  [backBtn, forwardBtn, reloadBtn, openBtn].forEach((btn) => {
    if (!btn) return;
    btn.disabled = !state.active && btn !== openBtn;
    btn.style.opacity = btn.disabled ? '0.45' : '1';
    btn.style.cursor = btn.disabled ? 'not-allowed' : 'pointer';
  });
  if (chromeSessionChip) {
    chromeSessionChip.textContent = followingDetachedSession
      ? 'Verifier tab'
      : (state.active ? (visibleSessionId ? `Session ${String(visibleSessionId).slice(0, 8)}` : 'Session ready') : 'No session');
  }
  if (chromeStreamChip) {
    chromeStreamChip.textContent = state.streamActive
      ? `${String(state.streamTransport || 'stream').toUpperCase()} ${String(state.streamFocus || 'passive')}`
      : 'Stream idle';
  }
  if (stageTitle) {
    stageTitle.textContent = state.active
      ? (state.title || state.url || 'Browser session active')
      : 'Browser canvas is standing by';
  }
  if (stageCopy) {
    stageCopy.textContent = state.active
      ? (followingDetachedSession
        ? `Teach verification is running in a detached browser tab so your original page stays intact. You can watch it here, then jump back to the main tab whenever you want.`
        : `${meta.label} mode is active for this browser session. ${state.lastTool ? `Last tool: ${state.lastTool}.` : ''}`)
      : 'When Prometheus opens or updates a browser session, the browser canvas will follow it here and keep the current session, page title, and interaction mode in sync.';
  }
  if (sessionEl) {
    const fullLastTool = followingDetachedSession
      ? `Following verifier session ${visibleSessionId}`
      : (state.lastTool || 'No browser tools used yet');
    sessionEl.textContent = truncateBrowserPreview(fullLastTool, 80);
    sessionEl.title = fullLastTool;
    sessionEl.style.wordBreak = 'break-word';
  }
  if (pageTitleEl) {
    pageTitleEl.textContent = state.active
      ? (state.title || state.url || 'Browser session active')
      : 'Open a site with the browser tools to wake this surface up.';
  }
  if (lastToolEl) {
    if (state.streamActive) lastToolEl.textContent = `${state.statusLabel || 'Browser active'} · ${streamDescriptor}`;
    else if (state.statusLabel) lastToolEl.textContent = state.statusLabel;
    else lastToolEl.textContent = state.active ? 'Browser active' : 'Browser idle';
  }
  if (lastUpdatedEl) {
    lastUpdatedEl.textContent = formatBrowserCanvasTimestamp(
      state.streamActive && state.streamLastFrameAt ? state.streamLastFrameAt : state.updatedAt,
    );
  }
  if (taskPanel) taskPanel.style.display = visibleTaskPrompt ? 'block' : 'none';
  if (taskCopyEl) {
    taskCopyEl.textContent = visibleTaskPrompt || '';
    taskCopyEl.title = visibleTaskPrompt;
  }
  updateBrowserAgentCursorOverlay(agentCursor, frameEl, state);
  const showTeachNaming = mode === 'teach' && !!state.selectedElement && !followingDetachedSession;
  if (modeTitleEl) {
    if (mode === 'teach' && pendingTeachStep) modeTitleEl.textContent = 'Confirm This Step';
    else if (mode === 'teach' && showTeachNaming) modeTitleEl.textContent = 'Name This Element';
    else if (mode === 'teach' && teachAwaitingApproval) modeTitleEl.textContent = 'Teach Review';
    else if (mode === 'teach' && teachVerified) modeTitleEl.textContent = 'Teach Verification';
    else if (mode === 'teach' && teachActive) modeTitleEl.textContent = 'Teach Session';
    else modeTitleEl.textContent = 'Mode Notes';
  }
  if (modeCopyEl) {
    if (mode === 'teach' && pendingTeachStep) {
      modeCopyEl.textContent = 'Teach pauses each step before it reaches the live browser. Rename, save, or discard anything you want, then continue when the step looks right.';
    } else if (mode === 'teach' && showTeachNaming) {
      modeCopyEl.textContent = 'Give this element a name you would naturally use later. Prometheus will keep it as reusable browser memory for this site.';
    } else if (mode === 'teach' && teachAwaitingApproval) {
      modeCopyEl.textContent = 'The workflow is recorded. Prometheus will summarize it, flag risky steps, and ask how far you want verification to go before it runs anything.';
    } else if (mode === 'teach' && teachVerified) {
      modeCopyEl.textContent = 'Prometheus has replayed the taught workflow. The next response should explain what happened, what the workflow appears to be for, and ask you to confirm that understanding before anything gets packaged.';
    } else if (mode === 'teach' && teachActive) {
      modeCopyEl.textContent = 'Teach mode is capturing a reusable workflow. Start from the current page, stage each step, and keep the log clean enough for Prometheus to replay later.';
    } else {
      modeCopyEl.textContent = meta.copy;
    }
  }
  if (controlRow) controlRow.style.display = mode === 'copilot' || mode === 'teach' || canReopenLastPage ? 'flex' : 'none';
  if (controlBadge) {
    if (followingDetachedSession) {
      controlBadge.textContent = 'The canvas is following the detached Teach verifier tab. Return to Main Tab to resume direct control and element selection.';
    } else if (canReopenLastPage && (!state.active || /^about:/i.test(String(state.url || '').trim()))) {
      controlBadge.textContent = `Last browser page: ${restoreHint.restoreTitle || restoreHint.restoreUrl}`;
    } else if (mode === 'teach') {
      controlBadge.textContent = controlCaptured
        ? 'Teach mode has the browser captured. Your next click, scroll, or shortcut becomes a pending step until you continue it.'
        : 'Click the browser to stage a teach step. Press Esc or use Release to Agent when you want Prometheus to stop watching your inputs.';
    } else {
      controlBadge.textContent = controlCaptured
        ? 'You are controlling the browser. Keystrokes and scroll go there until you release.'
        : 'Click the browser to take control. Press Esc or use Release to Agent when you want Prometheus to continue.';
    }
  }
  if (releaseBtn) releaseBtn.style.display = controlCaptured && !followingDetachedSession ? 'inline-flex' : 'none';
  if (returnBtn) returnBtn.style.display = followingDetachedSession ? 'inline-flex' : 'none';
  if (reopenBtn) {
    reopenBtn.style.display = canReopenLastPage && !controlCaptured ? 'inline-flex' : 'none';
    reopenBtn.title = canReopenLastPage ? `Reopen ${restoreHint.restoreTitle || restoreHint.restoreUrl}` : 'No saved browser page for this chat yet';
  }
  if (namePanel) namePanel.style.display = showTeachNaming ? 'block' : 'none';
  if (nameInput && nameInput.value !== state.elementNameDraft) nameInput.value = state.elementNameDraft || '';
  if (teachPanel) teachPanel.style.display = mode === 'teach' ? 'block' : 'none';
  if (teachStatusEl) {
    if (!teachActive) {
      teachStatusEl.textContent = state.active
        ? 'Capture the current page as the starting point, then stage each browser action one step at a time.'
        : 'Open a browser session first, then start Teach mode from the page you want to teach.';
    } else if (teachRecording) {
      teachStatusEl.textContent = `Recording from ${teach.startTitle || teach.startUrl || 'the current page'} with ${recordedTeachSteps.length} confirmed step${recordedTeachSteps.length === 1 ? '' : 's'}.`;
    } else if (teachAwaitingApproval) {
      teachStatusEl.textContent = `Recorded ${recordedTeachSteps.length} step${recordedTeachSteps.length === 1 ? '' : 's'} from ${teach.startTitle || teach.startUrl || 'the starting page'}. Waiting for verification approval.`;
    } else if (teachVerified && teachVerification) {
      const label = String(teachVerification.status || 'verified').trim().toLowerCase();
      const readable = label === 'partial' ? 'completed with issues' : (label === 'failed' ? 'failed' : 'passed');
      teachStatusEl.textContent = `Verification ${readable}. Prometheus should now summarize what happened and ask you to confirm what this workflow is for before creating anything reusable.`;
    } else {
      teachStatusEl.textContent = 'Teach mode is ready.';
    }
  }
  if (teachStartBtn) {
    teachStartBtn.textContent = teachAwaitingApproval ? 'Resume Recording' : (teachActive ? 'Restart Teach' : 'Start Teach');
    teachStartBtn.style.display = teachRecording ? 'none' : 'inline-flex';
    teachStartBtn.disabled = !state.active;
    teachStartBtn.style.opacity = state.active ? '1' : '0.55';
  }
  if (teachCompleteBtn) {
    teachCompleteBtn.style.display = teachRecording ? 'inline-flex' : 'none';
    teachCompleteBtn.disabled = !teachRecording || !!pendingTeachStep || !!teach.executingStepId || recordedTeachSteps.length === 0;
    teachCompleteBtn.style.opacity = teachCompleteBtn.disabled ? '0.55' : '1';
  }
  if (teachCancelBtn) teachCancelBtn.style.display = teachActive ? 'inline-flex' : 'none';
  if (teachApprovalActions) teachApprovalActions.style.display = teachAwaitingApproval ? 'block' : 'none';
  if (teachStopStepInput) {
    const maxSteps = Math.max(1, recordedTeachSteps.length || 1);
    teachStopStepInput.max = String(maxSteps);
    if (!teachAwaitingApproval) teachStopStepInput.value = '';
  }
  if (teachPendingCard) teachPendingCard.style.display = mode === 'teach' && pendingTeachStep ? 'block' : 'none';
  if (teachPendingTitle) {
    teachPendingTitle.textContent = pendingTeachStep
      ? (pendingTeachStep.summary || pendingTeachStep.title || 'Pending teach step')
      : 'No pending teach step';
  }
  if (teachPendingCopy) {
    const toolPreviewFull = pendingTeachStep?.toolPreview || pendingTeachStep?.toolName || 'browser step';
    const selectorFull = pendingTeachStep?.selection?.selector || pendingTeachStep?.selection?.text || pendingTeachStep?.pageUrl || 'Use Continue to send this step to the browser.';
    teachPendingCopy.innerHTML = pendingTeachStep
      ? `<div style="font-size:11px;color:#f8fafc;font-weight:700;word-break:break-word" title="${escHtml(toolPreviewFull)}">${escHtml(truncateBrowserPreview(toolPreviewFull, 70))}</div>
         <div style="margin-top:6px;font-size:11px;line-height:1.6;color:#cbd5e1;word-break:break-word" title="${escHtml(selectorFull)}">${escHtml(truncateBrowserPreview(selectorFull, 80))}</div>
         ${pendingTeachStep.risk === 'high' ? '<div style="margin-top:8px;font-size:10px;font-weight:700;color:#fca5a5;letter-spacing:0.04em;text-transform:uppercase">Risky step</div>' : ''}`
      : 'Stage a click, scroll, shortcut, or text input to see it here before it runs.';
  }
  if (teachContinueBtn) teachContinueBtn.style.display = pendingTeachStep ? 'inline-flex' : 'none';
  if (teachDiscardBtn) teachDiscardBtn.style.display = pendingTeachStep ? 'inline-flex' : 'none';
  if (teachStepsWrap) {
    if (mode === 'teach' && recordedTeachSteps.length) {
      teachStepsWrap.style.display = 'block';
      teachStepsWrap.innerHTML = `
        <div style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#94a3b8">Teach Steps</div>
        <div style="display:flex;flex-direction:column;gap:10px;margin-top:10px">
          ${recordedTeachSteps.map((step, idx) => {
            const stepId = String(step?.id || '').trim();
            const status = String(step?.status || 'recorded').trim().toLowerCase();
            const statusColor = status === 'error' ? '#fca5a5' : (status === 'executing' ? '#fde68a' : '#86efac');
            const removeAttr = JSON.stringify(stepId);
            return `
              <div style="border:1px solid rgba(148,163,184,0.14);border-radius:8px;padding:10px;background:rgba(15,23,42,0.42)">
                <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:10px">
                  <div style="min-width:0">
                    <div style="font-size:12px;font-weight:800;color:#f8fafc;word-break:break-word">${escHtml(`${idx + 1}. ${step.summary || step.title || step.toolName || 'Teach step'}`)}</div>
                    <div style="margin-top:5px;font-size:11px;color:#93c5fd;word-break:break-word">${escHtml(step.toolPreview || step.toolName || 'browser step')}</div>
                  </div>
                  <button onclick="removeBrowserTeachStep(${removeAttr})" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(248,113,113,0.2);background:rgba(248,113,113,0.08);color:#fda4af;border-radius:8px;padding:5px 8px;font-size:10px;font-weight:700;cursor:pointer;font-family:'Manrope',sans-serif;flex-shrink:0">Remove</button>
                </div>
                <div style="margin-top:8px;font-size:10px;font-weight:800;letter-spacing:0.04em;text-transform:uppercase;color:${statusColor}">${escHtml(status.replace(/_/g, ' '))}${step.risk === 'high' ? ' · high risk' : ''}</div>
                ${step.resultSummary ? `<div style="margin-top:6px;font-size:11px;line-height:1.6;color:#cbd5e1;word-break:break-word">${escHtml(step.resultSummary)}</div>` : ''}
              </div>
            `;
          }).join('')}
        </div>
      `;
    } else {
      teachStepsWrap.style.display = 'none';
      teachStepsWrap.innerHTML = '';
    }
  }
  if (savedWrap) {
    const saved = Array.isArray(state.namedElements) ? state.namedElements : [];
    const itemRoots = Array.isArray(state.itemRoots) ? state.itemRoots : [];
    const extractionSchemas = Array.isArray(state.extractionSchemas) ? state.extractionSchemas : [];
    if (saved.length || itemRoots.length || extractionSchemas.length) {
      savedWrap.style.display = 'block';
      const renderMemoryList = (title, items, accentColor = '#93c5fd') => `
        <div style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#94a3b8">${escHtml(title)}</div>
        <div style="display:flex;flex-direction:column;gap:8px;margin-top:10px">
          ${items.map((entry) => `
            <div style="border:1px solid rgba(148,163,184,0.14);border-radius:8px;padding:8px 10px;background:rgba(15,23,42,0.42)">
              <div style="font-size:12px;font-weight:700;color:#f8fafc;word-break:break-word">${escHtml(entry.name)}</div>
              <div style="margin-top:4px;font-size:11px;color:${accentColor};word-break:break-word">${escHtml(entry.selector || entry.tagName || 'element')}</div>
            </div>
          `).join('')}
        </div>
      `;
      const renderSchemaList = (title, items) => `
        <div style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#94a3b8">${escHtml(title)}</div>
        <div style="display:flex;flex-direction:column;gap:8px;margin-top:10px">
          ${items.map((entry) => {
            const fields = entry?.fields && typeof entry.fields === 'object' ? Object.keys(entry.fields) : [];
            const detailBits = [
              entry.itemRoot ? `root: ${entry.itemRoot}` : '',
              entry.dedupeKey ? `dedupe: ${entry.dedupeKey}` : '',
              entry.limit ? `limit: ${entry.limit}` : '',
            ].filter(Boolean);
            return `
              <div style="border:1px solid rgba(148,163,184,0.14);border-radius:8px;padding:8px 10px;background:rgba(15,23,42,0.42)">
                <div style="font-size:12px;font-weight:700;color:#f8fafc;word-break:break-word">${escHtml(entry.name)}</div>
                <div style="margin-top:4px;font-size:11px;color:#67e8f9;word-break:break-word">${escHtml(fields.join(', ') || 'No fields')}</div>
                ${detailBits.length ? `<div style="margin-top:4px;font-size:10px;color:#94a3b8;word-break:break-word">${escHtml(detailBits.join(' • '))}</div>` : ''}
              </div>
            `;
          }).join('')}
        </div>
      `;
      savedWrap.innerHTML = `
        ${saved.length ? renderMemoryList('Saved Elements For This Site', saved, '#93c5fd') : ''}
        ${saved.length && (itemRoots.length || extractionSchemas.length) ? '<div style="height:12px"></div>' : ''}
        ${itemRoots.length ? renderMemoryList('Saved Item Roots For This Site', itemRoots, '#c4b5fd') : ''}
        ${itemRoots.length && extractionSchemas.length ? '<div style="height:12px"></div>' : ''}
        ${extractionSchemas.length ? renderSchemaList('Saved Extraction Schemas For This Site', extractionSchemas) : ''}
      `;
    } else {
      savedWrap.style.display = 'none';
      savedWrap.innerHTML = '';
    }
  }
  if (frameWrap) frameWrap.style.display = hasFrame ? 'flex' : 'none';
  if (emptyState) emptyState.style.display = hasFrame ? 'none' : 'block';
  if (frameEl) {
    frameEl.style.cursor = mode === 'teach'
      ? (followingDetachedSession ? 'default' : 'crosshair')
      : (mode === 'copilot' ? ((controlCaptured && !followingDetachedSession) ? 'text' : 'pointer') : 'default');
  }
  if (frameEl && hasFrame) {
    const mime = String(state.frameFormat || 'png').toLowerCase() === 'jpeg' ? 'image/jpeg' : 'image/png';
    frameEl.src = `data:${mime};base64,${state.frameBase64}`;
  }
  if (frameMeta) frameMeta.style.display = hasFrame ? 'flex' : 'none';
  if (frameCaption) {
    frameCaption.textContent = state.streamActive
      ? `${streamDescriptor} browser feed`
      : (state.title || state.url || 'Latest browser frame');
  }
  if (frameSize) {
    const width = Number(state.frameWidth || 0);
    const height = Number(state.frameHeight || 0);
    frameSize.textContent = width > 0 && height > 0 ? `${width} × ${height}` : 'Viewport frame';
  }
  if (selectionCard) selectionCard.style.display = mode === 'teach' && state.selectedElement && !followingDetachedSession ? 'block' : 'none';
  if (frameSize && state.streamActive) {
    const width = Number(state.frameWidth || 0);
    const height = Number(state.frameHeight || 0);
    if (width > 0 && height > 0) {
      frameSize.textContent = `${width} x ${height} · ${String(state.streamFocus || 'passive')}`;
    }
  }
  if (selectionLabel) {
    selectionLabel.textContent = state.selectedElement
      ? (state.selectedElement.text || state.selectedElement.id || state.selectedElement.tagName || 'Element selected')
      : 'No browser element selected';
  }
  if (selectionText) {
    const fullSelectorText = state.selectedElement
      ? (state.selectedElement.selector || (state.selectedElement.id ? `#${state.selectedElement.id}` : state.selectedElement.tagName || 'element'))
      : 'Enter Teach mode and click the live browser frame to capture a real page element.';
    selectionText.textContent = state.selectedElement ? truncateBrowserPreview(fullSelectorText, 80) : fullSelectorText;
    selectionText.title = fullSelectorText;
  }
  syncBrowserCanvasFrameLayout(frameWrap, frameMeta, frameEl);
  updateBrowserSelectionOverlay(selectionBox, frameEl, state);
  updateBrowserTransientHighlight(clickHighlight, frameEl, state);
  syncBrowserCanvasStream();
  updateDesignSelectionChip();
  updateCreativeModeControls();
}

function setBrowserCanvasSurface(surface, options = {}) {
  const nextSurface = String(surface || '').trim().toLowerCase() === 'browser' ? 'browser' : 'files';
  const state = getBrowserCanvasState();
  const changed = state.surface !== nextSurface;
  state.surface = nextSurface;
  if (nextSurface === 'browser' && options.autoOpen !== false && !canvasOpen) {
    toggleCanvas(true, { force: true });
  }
  const activeTab = getActiveCanvasTab();
  if (canvasOpen || nextSurface === 'browser') {
    applyCanvasViewMode(activeTab?.mode || 'code', activeTab || null);
    canvasRenderTabs();
  } else if (changed) {
    updateCreativeModeControls();
  }
  renderBrowserCanvasSurface();
  syncCanvasSurfaceWidthLock(activeTab || null);
}

async function openBrowserCanvasSurface() {
  try {
    await exitCreativeModeForBrowserSwitch();
  } catch (err) {
    showToast(`Could not open Browser mode: ${err.message}`, 'error');
    return;
  }
  setBrowserCanvasSurface('browser');
}

async function toggleBrowserCanvasSurface() {
  if (isBrowserCanvasSurfaceActive()) {
    showCanvasFilesSurface();
    if (canvasOpen) toggleCanvas(false);
    else updateCreativeModeControls();
    return;
  }
  await openBrowserCanvasSurface();
}

function showCanvasFilesSurface() {
  setBrowserCanvasSurface('files', { autoOpen: false });
}

async function setBrowserInteractionMode(mode) {
  try {
    await exitCreativeModeForBrowserSwitch();
  } catch (err) {
    showToast(`Could not switch Browser mode: ${err.message}`, 'error');
    return;
  }
  const state = getBrowserCanvasState();
  const nextMode = normalizeBrowserInteractionMode(mode);
  if (state.interactionMode === nextMode && isBrowserCanvasSurfaceActive()) {
    renderBrowserCanvasSurface();
    return;
  }
  state.interactionMode = nextMode;
  if (nextMode !== 'copilot' && nextMode !== 'teach' && state.controlCaptured) {
    syncBrowserControlCapture(false, {
      owner: 'agent',
      reason: `Browser interaction mode changed to ${nextMode}.`,
      statusLabel: `Browser interaction mode is now ${nextMode}.`,
      render: false,
      syncRemote: true,
      flushPending: false,
    });
  }
  renderBrowserCanvasSurface();
  if (!isBrowserCanvasSurfaceActive()) setBrowserCanvasSurface('browser');
  const sessionId = getBrowserCanvasPrimarySessionId();
  if (sessionId) {
    wsSend({ type: 'browser:mode:set', sessionId, mode: nextMode });
  }
}

function syncBrowserCanvasFrameLayout(frameWrap, frameMeta, frameEl) {
  if (frameWrap) {
    frameWrap.style.flexDirection = 'column';
    frameWrap.style.alignItems = 'center';
    frameWrap.style.justifyContent = 'flex-start';
  }
  if (!frameMeta || !frameEl) return;
  const frameWidth = Math.round(frameEl.getBoundingClientRect().width || frameEl.clientWidth || 0);
  if (frameWidth > 0) {
    frameMeta.style.width = `${frameWidth}px`;
    frameMeta.style.maxWidth = '100%';
  } else {
    frameMeta.style.width = '';
    frameMeta.style.maxWidth = '';
  }
}

function positionBrowserOverlayElement(overlayEl, frameEl, bounds) {
  if (!overlayEl || !frameEl || !bounds) return false;
  const state = getBrowserCanvasState();
  const viewportWidth = Number(state?.frameWidth || 0);
  const viewportHeight = Number(state?.frameHeight || 0);
  const frameWrap = frameEl.parentElement;
  const frameRect = frameEl.getBoundingClientRect();
  const wrapRect = frameWrap?.getBoundingClientRect?.();
  if (!viewportWidth || !viewportHeight || !frameRect.width || !frameRect.height || !wrapRect?.width || !wrapRect?.height) {
    overlayEl.style.display = 'none';
    return false;
  }
  // The <img> has a 1px border + border-radius; getBoundingClientRect includes the border,
  // but the actual bitmap content starts at the inner edge. Also compensate for a small
  // CDP screencast drift (overlays consistently land a few px up-left of the real element).
  const computed = window.getComputedStyle(frameEl);
  const borderLeft = parseFloat(computed.borderLeftWidth) || 0;
  const borderTop = parseFloat(computed.borderTopWidth) || 0;
  const horizontalOverlayNudgePx = 10;
  const verticalOverlayNudgePx = 6;
  const scaleX = (frameRect.width - borderLeft * 2) / viewportWidth;
  const scaleY = (frameRect.height - borderTop * 2) / viewportHeight;
  const originLeft = frameRect.left - wrapRect.left + borderLeft;
  const originTop = frameRect.top - wrapRect.top + borderTop;
  overlayEl.style.left = `${originLeft + (Number(bounds.x || 0) * scaleX) + horizontalOverlayNudgePx}px`;
  overlayEl.style.top = `${originTop + (Number(bounds.y || 0) * scaleY) + verticalOverlayNudgePx}px`;
  overlayEl.style.width = `${Math.max(18, Number(bounds.width || 0) * scaleX)}px`;
  overlayEl.style.height = `${Math.max(18, Number(bounds.height || 0) * scaleY)}px`;
  return true;
}

function updateBrowserSelectionOverlay(selectionBox, frameEl, state = getBrowserCanvasState()) {
  if (!selectionBox || !frameEl) return;
  const bounds = normalizeBrowserInteractionMode(state?.interactionMode) === 'teach' && !isFollowingDetachedBrowserCanvasSession(state)
    ? state?.selectedElement?.bounds
    : null;
  if (!bounds || !positionBrowserOverlayElement(selectionBox, frameEl, bounds)) {
    selectionBox.style.display = 'none';
    return;
  }
  selectionBox.style.display = 'block';
}

function updateBrowserTransientHighlight(highlightEl, frameEl, state = getBrowserCanvasState()) {
  if (!highlightEl || !frameEl) return;
  if (isFollowingDetachedBrowserCanvasSession(state)) {
    highlightEl.style.display = 'none';
    return;
  }
  const highlight = state?.transientHighlight;
  if (!highlight?.bounds || Number(highlight?.expiresAt || 0) <= Date.now()) {
    highlightEl.style.display = 'none';
    return;
  }
  if (!positionBrowserOverlayElement(highlightEl, frameEl, highlight.bounds)) {
    highlightEl.style.display = 'none';
    return;
  }
  highlightEl.style.display = 'block';
}

function updateBrowserAgentCursorOverlay(cursorEl, frameEl, state = getBrowserCanvasState()) {
  if (!cursorEl || !frameEl) return;
  const cursor = state?.agentCursor;
  const viewportWidth = Number(cursor?.viewportWidth || state?.frameWidth || 0);
  const viewportHeight = Number(cursor?.viewportHeight || state?.frameHeight || 0);
  const x = Number(cursor?.x);
  const y = Number(cursor?.y);
  if (!cursor || !Number.isFinite(x) || !Number.isFinite(y) || !viewportWidth || !viewportHeight) {
    cursorEl.style.display = 'none';
    return;
  }
  if (Number(cursor.expiresAt || 0) <= Date.now()) {
    cursorEl.style.opacity = '0';
    return;
  }
  const frameWrap = frameEl.parentElement;
  const frameRect = frameEl.getBoundingClientRect();
  const wrapRect = frameWrap?.getBoundingClientRect?.();
  if (!frameRect.width || !frameRect.height || !wrapRect?.width || !wrapRect?.height) {
    cursorEl.style.display = 'none';
    return;
  }
  const originLeft = frameRect.left - wrapRect.left;
  const originTop = frameRect.top - wrapRect.top;
  const left = originLeft + (x * (frameRect.width / viewportWidth));
  const top = originTop + (y * (frameRect.height / viewportHeight));
  cursorEl.style.display = 'block';
  cursorEl.style.left = `${left}px`;
  cursorEl.style.top = `${top}px`;
  cursorEl.style.opacity = '1';
  cursorEl.dataset.kind = String(cursor.kind || 'move');
  cursorEl.dataset.phase = String(cursor.phase || 'active');
  const label = cursorEl.querySelector('[data-browser-agent-cursor-label]');
  if (label) {
    const text = String(cursor.label || '').trim();
    label.textContent = text ? truncateBrowserPreview(text, 42) : 'Prometheus';
  }
}

function receiveBrowserAgentCursor(msg) {
  if (!isBrowserEventForActiveSession(msg, { scope: 'visible' })) return;
  const state = getBrowserCanvasState();
  const now = Date.now();
  state.agentCursor = {
    x: Math.round(Number(msg?.x || 0)),
    y: Math.round(Number(msg?.y || 0)),
    viewportWidth: Number(msg?.viewportWidth || state.frameWidth || 0) || 0,
    viewportHeight: Number(msg?.viewportHeight || state.frameHeight || 0) || 0,
    kind: String(msg?.kind || 'move').trim(),
    phase: String(msg?.phase || 'active').trim(),
    label: String(msg?.label || '').trim(),
    updatedAt: Number(msg?.timestamp || now) || now,
    expiresAt: now + 2200,
  };
  const cursorEl = document.getElementById('browser-canvas-agent-cursor');
  const frameEl = document.getElementById('browser-canvas-frame');
  updateBrowserAgentCursorOverlay(cursorEl, frameEl, state);
  window.clearTimeout(window.__browserAgentCursorFadeTimer || 0);
  window.__browserAgentCursorFadeTimer = window.setTimeout(() => {
    const latest = getBrowserCanvasState().agentCursor;
    if (!latest || latest.updatedAt !== state.agentCursor?.updatedAt) return;
    const el = document.getElementById('browser-canvas-agent-cursor');
    if (el) el.style.opacity = '0';
  }, 1800);
}

function clearBrowserTransientHighlight(options = {}) {
  const state = getBrowserCanvasState();
  if (browserTransientHighlightFadeTimer) {
    clearTimeout(browserTransientHighlightFadeTimer);
    browserTransientHighlightFadeTimer = 0;
  }
  if (browserTransientHighlightCleanupTimer) {
    clearTimeout(browserTransientHighlightCleanupTimer);
    browserTransientHighlightCleanupTimer = 0;
  }
  state.transientHighlight = null;
  const highlightEl = document.getElementById('browser-canvas-click-highlight');
  if (highlightEl) {
    highlightEl.style.opacity = '0';
    highlightEl.style.transform = 'scale(1)';
    highlightEl.style.display = 'none';
  }
  if (options.render === true) renderBrowserCanvasSurface();
}

function triggerBrowserTransientHighlight(selection) {
  if (!selection?.bounds) return;
  const state = getBrowserCanvasState();
  const now = Date.now();
  state.transientHighlight = {
    selector: String(selection.selector || '').trim(),
    tagName: String(selection.tagName || '').trim(),
    id: String(selection.id || '').trim(),
    text: String(selection.text || '').trim(),
    bounds: selection.bounds,
    startedAt: now,
    expiresAt: now + 720,
  };
  const highlightEl = document.getElementById('browser-canvas-click-highlight');
  const frameEl = document.getElementById('browser-canvas-frame');
  if (!highlightEl || !frameEl) {
    renderBrowserCanvasSurface();
    return;
  }
  if (browserTransientHighlightFadeTimer) clearTimeout(browserTransientHighlightFadeTimer);
  if (browserTransientHighlightCleanupTimer) clearTimeout(browserTransientHighlightCleanupTimer);
  updateBrowserTransientHighlight(highlightEl, frameEl, state);
  highlightEl.style.opacity = '0';
  highlightEl.style.transform = 'scale(0.985)';
  requestAnimationFrame(() => {
    updateBrowserTransientHighlight(highlightEl, frameEl, state);
    highlightEl.style.opacity = '1';
    highlightEl.style.transform = 'scale(1)';
  });
  browserTransientHighlightFadeTimer = window.setTimeout(() => {
    highlightEl.style.opacity = '0';
    highlightEl.style.transform = 'scale(1.012)';
  }, 360);
  browserTransientHighlightCleanupTimer = window.setTimeout(() => {
    clearBrowserTransientHighlight();
  }, 760);
}

function handleBrowserCanvasFrameLoad() {
  const selectionBox = document.getElementById('browser-canvas-selection-box');
  const clickHighlight = document.getElementById('browser-canvas-click-highlight');
  const agentCursor = document.getElementById('browser-canvas-agent-cursor');
  const frameEl = document.getElementById('browser-canvas-frame');
  const frameWrap = document.getElementById('browser-canvas-frame-wrap');
  const frameMeta = document.getElementById('browser-canvas-frame-meta');
  syncBrowserCanvasFrameLayout(frameWrap, frameMeta, frameEl);
  updateBrowserSelectionOverlay(selectionBox, frameEl, getBrowserCanvasState());
  updateBrowserTransientHighlight(clickHighlight, frameEl, getBrowserCanvasState());
  updateBrowserAgentCursorOverlay(agentCursor, frameEl, getBrowserCanvasState());
}

function inspectBrowserCanvasPoint(event) {
  const state = getBrowserCanvasState();
  if (event?.button && Number(event.button) !== 0) return;
  if (!isBrowserCanvasSurfaceActive()) return;
  const mode = normalizeBrowserInteractionMode(state.interactionMode);
  if (mode !== 'teach' && mode !== 'copilot') return;
  if (isFollowingDetachedBrowserCanvasSession(state)) {
    showToast('The canvas is currently following the detached Teach verifier tab. Return to Main Tab before controlling or selecting the live browser.', 'info');
    return;
  }
  if (typeof event?.preventDefault === 'function') event.preventDefault();
  if (typeof event?.stopPropagation === 'function') event.stopPropagation();
  const point = resolveBrowserCanvasViewportPointFromClient(event?.clientX, event?.clientY);
  if (!point) return;
  const viewportX = point.x;
  const viewportY = point.y;
  const sessionId = String(window.activeChatSessionId || window.agentSessionId || '').trim();
  if (!sessionId) return;
  if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) {
    showToast('Browser connection is reconnecting. Try again in a second.', 'info');
    return;
  }
  if (mode === 'copilot') {
    captureBrowserCanvasControl('User clicked into the browser canvas.');
    state.statusLabel = 'Sending click to browser...';
    renderBrowserCanvasSurface();
    wsSend({
      type: 'browser:input',
      sessionId,
      action: 'click',
      x: viewportX,
      y: viewportY,
      button: 'left',
    });
    return;
  }
  const teach = getBrowserTeachSession(state);
  if (isBrowserTeachRecording(state) && teach.pendingStep) {
    showToast('Continue or discard the current teach step first.', 'info');
    return;
  }
  if (isBrowserTeachRecording(state)) {
    captureBrowserCanvasControl('Teach mode is capturing the next browser step.');
    teach.pendingSelectionIntent = {
      action: 'click',
      x: viewportX,
      y: viewportY,
      button: 'left',
      createdAt: Date.now(),
    };
    state.statusLabel = 'Inspecting the next teach step...';
  } else {
    teach.pendingSelectionIntent = null;
    state.statusLabel = 'Inspecting browser element...';
  }
  state.selectionPending = true;
  renderBrowserCanvasSurface();
  wsSend({ type: 'browser:inspect_point', sessionId, x: viewportX, y: viewportY });
}

function updateBrowserElementNameDraft(value) {
  const state = getBrowserCanvasState();
  state.elementNameDraft = String(value || '');
  syncPendingBrowserTeachStepFromDraft(state);
  renderBrowserCanvasSurface();
  persistActiveChat();
}

function getBrowserKnowledgeHost(url) {
  try {
    const raw = String(url || '').trim();
    if (!raw) return '';
    const parsed = new URL(raw.startsWith('http://') || raw.startsWith('https://') ? raw : `https://${raw}`);
    return String(parsed.hostname || '').replace(/^www\./i, '').toLowerCase();
  } catch {
    return '';
  }
}

function isRestorableBrowserCanvasUrl(url) {
  const value = String(url || '').trim();
  if (!value) return false;
  if (/^(about|chrome|devtools):/i.test(value)) return false;
  return /^https?:\/\//i.test(value);
}

function rememberBrowserCanvasRestorablePage(url, title = '', state = getBrowserCanvasState()) {
  const nextUrl = String(url || '').trim();
  if (!isRestorableBrowserCanvasUrl(nextUrl)) return false;
  state.lastRestorableUrl = nextUrl;
  const nextTitle = String(title || '').trim();
  if (nextTitle) state.lastRestorableTitle = nextTitle;
  return true;
}

function getBrowserCanvasRestoreHint(state = getBrowserCanvasState()) {
  const currentUrl = String(state.url || '').trim();
  const currentTitle = String(state.title || '').trim();
  const savedUrl = String(state.lastRestorableUrl || '').trim();
  const savedTitle = String(state.lastRestorableTitle || '').trim();
  const restoreUrl = isRestorableBrowserCanvasUrl(currentUrl) ? currentUrl : savedUrl;
  const restoreTitle = isRestorableBrowserCanvasUrl(currentUrl) ? currentTitle : savedTitle;
  return { restoreUrl, restoreTitle };
}

function requestBrowserKnowledge(force = false) {
  const state = getBrowserCanvasState();
  const sessionId = getBrowserCanvasVisibleSessionId();
  const { restoreUrl, restoreTitle } = getBrowserCanvasRestoreHint(state);
  const host = getBrowserKnowledgeHost(state.url) || getBrowserKnowledgeHost(restoreUrl);
  if (!sessionId || !state.active || !host) return;
  if (!force && state.knowledgeRequestedFor === host) return;
  if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) return;
  state.knowledgeRequestedFor = host;
  wsSend({
    type: 'browser:knowledge:request',
    sessionId,
    restoreUrl,
    restoreTitle,
  });
}

function reopenBrowserCanvasLastPage() {
  const state = getBrowserCanvasState();
  const sessionId = getBrowserCanvasPrimarySessionId();
  const { restoreUrl, restoreTitle } = getBrowserCanvasRestoreHint(state);
  if (!sessionId) {
    showToast('No chat session is available for browser reopen.', 'error');
    return false;
  }
  if (!isRestorableBrowserCanvasUrl(restoreUrl)) {
    showToast('No last browser page is saved for this chat yet.', 'info');
    return false;
  }
  if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) {
    showToast('Browser connection is reconnecting. Try again in a second.', 'info');
    return false;
  }
  returnBrowserCanvasToPrimarySession({ render: false, requestData: false });
  state.active = true;
  state.statusLabel = `Reopening ${restoreTitle || restoreUrl}`;
  state.url = restoreUrl;
  if (restoreTitle) state.title = restoreTitle;
  setBrowserCanvasSurface('browser');
  renderBrowserCanvasSurface();
  wsSend({
    type: 'browser:reopen',
    sessionId,
    restoreUrl,
    restoreTitle,
  });
  return true;
}

function sendBrowserCanvasNavigation(action, url = '') {
  const state = getBrowserCanvasState();
  const sessionId = getBrowserCanvasPrimarySessionId();
  if (!sessionId) {
    showToast('No chat session is available for browser navigation.', 'error');
    return false;
  }
  if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) {
    showToast('Browser connection is reconnecting. Try again in a second.', 'info');
    return false;
  }
  const normalizedAction = String(action || '').trim().toLowerCase();
  const address = String(url || '').trim();
  if (normalizedAction === 'open' && !address) {
    showToast('Enter a URL to open.', 'info');
    return false;
  }
  returnBrowserCanvasToPrimarySession({ render: false, requestData: false });
  state.active = true;
  state.statusLabel = normalizedAction === 'open'
    ? `Opening ${address}`
    : `${normalizedAction.charAt(0).toUpperCase()}${normalizedAction.slice(1)} requested.`;
  setBrowserCanvasSurface('browser');
  renderBrowserCanvasSurface();
  wsSend({
    type: 'browser:navigation',
    sessionId,
    action: normalizedAction,
    url: address,
  });
  return true;
}

function openBrowserCanvasAddress() {
  const input = document.getElementById('browser-canvas-address-input');
  return sendBrowserCanvasNavigation('open', input?.value || '');
}

function handleBrowserCanvasAddressKeydown(event) {
  if (event?.key !== 'Enter') return;
  if (typeof event.preventDefault === 'function') event.preventDefault();
  openBrowserCanvasAddress();
}

function syncPendingBrowserTeachStepFromDraft(state = getBrowserCanvasState()) {
  const teach = getBrowserTeachSession(state);
  if (!teach.pendingStep || !teach.pendingStep.selection) return;
  const pendingKey = getBrowserTeachSelectionKey(teach.pendingStep.selection);
  const selectedKey = getSelectedBrowserElementKey(state.selectedElement);
  if (!pendingKey || !selectedKey || pendingKey !== selectedKey) return;
  teach.pendingStep = refreshBrowserTeachStepMetadata(teach.pendingStep, state);
}

function upsertPendingBrowserTeachStep(step, options = {}) {
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  if (!isBrowserTeachRecording(state)) return false;
  const nextStep = refreshBrowserTeachStepMetadata(step, state);
  const existing = teach.pendingStep && typeof teach.pendingStep === 'object' ? { ...teach.pendingStep } : null;
  if (existing && options.merge !== true) {
    showToast('Continue or discard the current teach step first.', 'info');
    return false;
  }
  if (existing && options.merge === true && existing.kind === nextStep.kind) {
    if ((existing.kind === 'fill' || existing.kind === 'text') && nextStep.input?.text != null) {
      existing.input = { ...existing.input, text: `${String(existing.input?.text || '')}${String(nextStep.input.text || '')}` };
      teach.pendingStep = refreshBrowserTeachStepMetadata(existing, state);
    } else if (existing.kind === 'scroll') {
      existing.input = {
        ...existing.input,
        x: Number(nextStep.input?.x || existing.input?.x || 0),
        y: Number(nextStep.input?.y || existing.input?.y || 0),
        deltaX: Number(existing.input?.deltaX || 0) + Number(nextStep.input?.deltaX || 0),
        deltaY: Number(existing.input?.deltaY || 0) + Number(nextStep.input?.deltaY || 0),
      };
      teach.pendingStep = refreshBrowserTeachStepMetadata(existing, state);
    } else {
      showToast('Continue or discard the current teach step first.', 'info');
      return false;
    }
  } else {
    teach.pendingStep = nextStep;
  }
  state.statusLabel = 'Review the pending teach step, rename anything you want, then continue.';
  renderBrowserCanvasSurface();
  persistActiveChat();
  return true;
}

function discardBrowserTeachPendingStep(options = {}) {
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  teach.pendingStep = null;
  teach.pendingSelectionIntent = null;
  state.selectionPending = false;
  if (options.clearSelection === true) {
    state.selectedElement = null;
    state.elementNameDraft = '';
    state.elementNameDraftKey = '';
  }
  state.statusLabel = isBrowserTeachRecording(state)
    ? 'Teach mode is recording. Inspect the next step when you are ready.'
    : (state.statusLabel || 'Browser idle');
  renderBrowserCanvasSurface();
  persistActiveChat();
}

function markBrowserTeachExecutionError(errorText) {
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  const executingId = String(teach.executingStepId || '').trim();
  if (!executingId) return;
  teach.steps = Array.isArray(teach.steps)
    ? teach.steps.map((step) => {
        if (String(step?.id || '').trim() !== executingId) return step;
        return {
          ...step,
          status: 'error',
          resultSummary: String(errorText || 'Teach step failed.').trim(),
        };
      })
    : [];
  teach.executingStepId = '';
  state.statusLabel = String(errorText || 'Teach step failed.').trim() || 'Teach step failed.';
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
}

function finalizeBrowserTeachExecution(msg) {
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  const executingId = String(teach.executingStepId || '').trim();
  if (!executingId) return;
  const timestamp = Number(msg?.timestamp || Date.now()) || Date.now();
  teach.steps = Array.isArray(teach.steps)
    ? teach.steps.map((step) => {
        if (String(step?.id || '').trim() !== executingId) return step;
        return {
          ...step,
          status: 'recorded',
          executedAt: timestamp,
          resultSummary: String(msg?.userAction?.summary || '').trim(),
          pageUrl: String(msg?.url || step?.pageUrl || '').trim(),
          pageTitle: String(msg?.title || step?.pageTitle || '').trim(),
        };
      })
    : [];
  teach.executingStepId = '';
  state.statusLabel = 'Teach step recorded.';
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
}

function continueBrowserTeachPendingStep() {
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  if (!isBrowserTeachRecording(state)) {
    showToast('Start a Teach session first.', 'info');
    return;
  }
  if (teach.executingStepId) {
    showToast('A teach step is still running. Give it a moment.', 'info');
    return;
  }
  if (!teach.pendingStep) {
    showToast('Stage a teach step first.', 'info');
    return;
  }
  const sessionId = getBrowserCanvasControlSessionId();
  if (!sessionId) {
    showToast('No active browser session is linked to this chat yet.', 'info');
    return;
  }
  if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) {
    showToast('Browser connection is reconnecting. Try again in a second.', 'info');
    return;
  }
  const finalizedStep = refreshBrowserTeachStepMetadata(teach.pendingStep, state);
  const executionPayload = finalizedStep.input && typeof finalizedStep.input === 'object'
    ? { ...finalizedStep.input }
    : null;
  if (!executionPayload?.action) {
    showToast('This teach step is missing its browser action payload.', 'error');
    return;
  }
  teach.executingStepId = String(finalizedStep.id || '').trim();
  teach.steps = [...(Array.isArray(teach.steps) ? teach.steps : []), {
    ...finalizedStep,
    status: 'executing',
  }];
  teach.pendingStep = null;
  teach.pendingSelectionIntent = null;
  state.selectionPending = false;
  state.statusLabel = `Running teach step: ${finalizedStep.summary || finalizedStep.title || finalizedStep.toolName || 'browser step'}`;
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
  addProcessEntry('info', `Teach: executing ${finalizedStep.summary || finalizedStep.toolName || 'browser step'}.`);
  wsSend({
    type: 'browser:input',
    sessionId,
    ...executionPayload,
  });
}

function removeBrowserTeachStep(stepId) {
  const teach = getBrowserTeachSession();
  const targetId = String(stepId || '').trim();
  if (!targetId) return;
  teach.steps = Array.isArray(teach.steps)
    ? teach.steps.filter((step) => String(step?.id || '').trim() !== targetId)
    : [];
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
}

function startBrowserTeachSession(options = {}) {
  const state = getBrowserCanvasState();
  if (!state.active || !String(state.url || '').trim()) {
    showToast('Open a live browser session first, then start Teach mode.', 'info');
    return;
  }
  const teach = getBrowserTeachSession(state);
  const shouldPreserveSteps = options.resume === true || normalizeBrowserTeachPhase(teach.phase) === 'approval_pending';
  const preserveSteps = shouldPreserveSteps && Array.isArray(teach.steps) ? teach.steps.slice() : [];
  state.interactionMode = 'teach';
  Object.assign(teach, createEmptyBrowserTeachSession(), {
    active: true,
    phase: 'recording',
    startedAt: Date.now(),
    startUrl: String(state.url || '').trim(),
    startTitle: String(state.title || '').trim(),
    steps: preserveSteps,
  });
  captureBrowserCanvasControl('Teach mode is recording workflow steps.');
  state.statusLabel = 'Teach mode started. Click the browser to stage the first step.';
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
  addProcessEntry('info', `Teach: recording started from ${teach.startTitle || teach.startUrl || 'the current page'}.`);
}

function cancelBrowserTeachSession() {
  const state = getBrowserCanvasState();
  state.teachSession = createEmptyBrowserTeachSession();
  state.selectionPending = false;
  state.statusLabel = 'Teach mode reset.';
  releaseBrowserCanvasControl({
    reason: 'Teach mode ended.',
    statusLabel: 'Teach mode reset.',
    render: false,
  });
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
  addProcessEntry('info', 'Teach: session cleared.');
}

function buildBrowserTeachReviewPrompt() {
  return 'Teach mode recording complete. Review the captured workflow, summarize what it appears to do, call out any risky steps, and ask whether you should run the full verification or stop before a specific step. Do not run any browser tools yet.';
}

function completeBrowserTeachSession() {
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  if (!isBrowserTeachRecording(state)) {
    showToast('Start a Teach session before completing it.', 'info');
    return;
  }
  if (teach.pendingStep) {
    showToast('Continue or discard the pending teach step before completing the workflow.', 'info');
    return;
  }
  if (teach.executingStepId) {
    showToast('A teach step is still running. Give it a moment.', 'info');
    return;
  }
  if (!Array.isArray(teach.steps) || !teach.steps.length) {
    showToast('Record at least one teach step first.', 'info');
    return;
  }
  teach.phase = 'approval_pending';
  teach.completedAt = Date.now();
  teach.approvalRequestedAt = teach.completedAt;
  teach.reviewRequestedAt = teach.completedAt;
  state.statusLabel = 'Teach workflow recorded. Asking Prometheus to review it.';
  releaseBrowserCanvasControl({
    reason: 'Teach recording complete. Waiting for verification approval.',
    statusLabel: 'Teach workflow recorded. Waiting for verification approval.',
    render: false,
  });
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
  addProcessEntry('info', 'Teach: sent the recorded workflow to Prometheus for review.');
  sendChat(buildBrowserTeachReviewPrompt());
}

function parseBrowserTeachVerificationApproval(message) {
  const source = String(message || '').trim();
  if (!source) return { approved: false, mode: 'full', stopBeforeStep: 0 };
  const text = source.toLowerCase();
  if (/\b(don't run|do not run|hold off|wait on verification|not yet|skip verification)\b/i.test(text)) {
    return { approved: false, mode: 'full', stopBeforeStep: 0 };
  }
  const stopStepMatch = text.match(/\bstop(?:ping)?\s+before\s+step\s+(\d+)\b/i);
  if (stopStepMatch) {
    return {
      approved: true,
      mode: 'step',
      stopBeforeStep: Math.max(1, Number(stopStepMatch[1] || 0) || 0),
    };
  }
  if (/\b(stop(?:ping)?\s+before\s+(?:the\s+)?(?:last|final)\s+(?:risky\s+)?step|stop before final action|safe verification|run safe)\b/i.test(text)) {
    return { approved: true, mode: 'safe', stopBeforeStep: 0 };
  }
  if (/\b(run\s+(?:the\s+)?full(?:\s+test)?|full verification|run it|go ahead|proceed|verify it|test it)\b/i.test(text)) {
    return { approved: true, mode: 'full', stopBeforeStep: 0 };
  }
  return { approved: false, mode: 'full', stopBeforeStep: 0 };
}

function requestBrowserTeachVerification(mode = 'full', stopBeforeStep = 0) {
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  if (!isBrowserTeachAwaitingApproval(state)) {
    showToast('Record and complete a Teach workflow first.', 'info');
    return;
  }
  let message = '';
  let statusLabel = '';
  if (mode === 'safe') {
    message = 'Teach mode verification approved. Run the verification now, but stop before the final risky step. Use browser_teach_verify, then explain what you actually replayed, what worked, what needed adjustment, and what you think this workflow is for. Ask me to confirm that understanding before creating anything.';
    statusLabel = 'Teach verification requested: stop before the final risky step.';
  } else if (mode === 'step') {
    const targetStep = Math.max(1, Number(stopBeforeStep || 0) || 0);
    if (!targetStep) {
      showToast('Pick a step number to stop before.', 'info');
      return;
    }
    message = `Teach mode verification approved. Run the verification now, but stop before step ${targetStep}. Use browser_teach_verify with that boundary, then explain what you actually replayed, what worked, what needed adjustment, and what you think this workflow is for. Ask me to confirm that understanding before creating anything.`;
    statusLabel = `Teach verification requested: stop before step ${targetStep}.`;
  } else {
    message = 'Teach mode verification approved. Run the full verification now using browser_teach_verify, then explain what you actually replayed, what worked, what needed adjustment, and what you think this workflow is for. Ask me to confirm that understanding before creating anything.';
    statusLabel = 'Teach verification requested: full replay.';
  }
  state.statusLabel = statusLabel;
  renderBrowserCanvasSurface();
  persistActiveChat();
  addProcessEntry('info', statusLabel);
  sendChat(message);
}

function requestBrowserTeachVerificationFromInput() {
  const input = document.getElementById('browser-canvas-teach-stop-step-input');
  const stepValue = Math.max(1, Number(input?.value || 0) || 0);
  if (input) input.value = stepValue ? String(stepValue) : '';
  requestBrowserTeachVerification('step', stepValue);
}

function saveSelectedBrowserMemory(kind = 'element') {
  const state = getBrowserCanvasState();
  const selected = state.selectedElement;
  const rawName = String(state.elementNameDraft || '').trim();
  const normalizedKind = String(kind || '').trim().toLowerCase() === 'item_root' ? 'item_root' : 'element';
  const label = normalizedKind === 'item_root' ? 'item root' : 'element';
  if (!selected) {
    showToast('Select a browser element first.', 'info');
    return;
  }
  if (!rawName) {
    showToast(`Give the ${label} a name first.`, 'info');
    return;
  }
  const sessionId = String(window.activeChatSessionId || window.agentSessionId || '').trim();
  if (!sessionId) {
    showToast('No active browser session is linked to this chat yet.', 'info');
    return;
  }
  if (!(window.ws && window.ws.readyState === WebSocket.OPEN)) {
    showToast('Browser memory is reconnecting. Try again in a second.', 'info');
    return;
  }
  state.statusLabel = `Saving "${rawName}" as a browser ${label}...`;
  renderBrowserCanvasSurface();
  wsSend({
    type: 'browser:element:save',
    sessionId,
    kind: normalizedKind,
    name: rawName,
    selection: {
      selector: String(selected.selector || '').trim(),
      tagName: String(selected.tagName || '').trim(),
      id: String(selected.id || '').trim(),
      text: String(selected.text || '').trim(),
      url: String(state.url || '').trim(),
    },
  });
}

function saveNamedBrowserElement() {
  saveSelectedBrowserMemory('element');
}

function saveNamedBrowserItemRoot() {
  saveSelectedBrowserMemory('item_root');
}

function isBrowserEventForActiveSession(msg, options = {}) {
  const incoming = String(msg?.sessionId || '').trim();
  if (!incoming) return true;
  const scope = String(options.scope || 'visible').trim().toLowerCase() === 'primary' ? 'primary' : 'visible';
  const primarySessionId = getBrowserCanvasPrimarySessionId();
  const visibleSessionId = getBrowserCanvasVisibleSessionId();
  if (scope === 'primary') return incoming === primarySessionId;
  return incoming === visibleSessionId || (!visibleSessionId && incoming === primarySessionId);
}

function applyBrowserEventState(msg, options = {}) {
  if (!msg) return;
  upsertBrowserSessionRecord(msg);
  if (!isBrowserEventForActiveSession(msg, { scope: 'visible' })) {
    renderBrowserCanvasSurface();
    persistActiveChat();
    return;
  }
  const state = getBrowserCanvasState();
  const creativeLocked = isCreativeModeLocked();
  const previousHost = getBrowserKnowledgeHost(state.url);
  const incomingSessionId = String(msg.sessionId || state.sessionId || '').trim();
  const allowInteractionSync = !isFollowingDetachedBrowserCanvasSession(state) || incomingSessionId === getBrowserCanvasPrimarySessionId();
  state.sessionId = incomingSessionId;
  state.active = msg.active !== false;
  state.url = String(msg.url || state.url || '').trim();
  state.title = String(msg.title || state.title || '').trim();
  rememberBrowserCanvasRestorablePage(state.url, state.title, state);
  state.lastTool = String(msg.tool || msg.lastTool || state.lastTool || '').trim();
  state.statusLabel = String(msg.statusLabel || state.statusLabel || '').trim() || (state.active ? 'Browser active' : 'Browser idle');
  if (allowInteractionSync && typeof msg.captured === 'boolean') state.controlCaptured = msg.captured === true;
  if (allowInteractionSync && msg.controlOwner) state.controlOwner = String(msg.controlOwner || '').trim().toLowerCase() === 'user' ? 'user' : 'agent';
  if (typeof msg.streamActive === 'boolean') state.streamActive = msg.streamActive === true;
  if (typeof msg.streamTransport === 'string') state.streamTransport = String(msg.streamTransport || '').trim().toLowerCase();
  if (typeof msg.streamFocus === 'string') state.streamFocus = String(msg.streamFocus || 'passive').trim().toLowerCase() === 'interactive' ? 'interactive' : 'passive';
  if (typeof msg.streamStatus === 'string') state.streamStatus = String(msg.streamStatus || '').trim();
  if (state.active === false) {
    clearBrowserTransientHighlight();
    clearQueuedBrowserControlInputs();
    clearBrowserCanvasStreamHeartbeat();
    state.frameBase64 = '';
    state.frameWidth = 0;
    state.frameHeight = 0;
    state.frameFormat = 'png';
    state.selectedElement = null;
    state.agentCursor = null;
    state.controlCaptured = false;
    state.controlOwner = 'agent';
    state.streamActive = false;
    state.streamTransport = '';
    state.streamFocus = 'passive';
    state.streamStatus = '';
    state.streamLastFrameAt = 0;
    state.elementNameDraft = '';
    state.elementNameDraftKey = '';
    state.knowledgeRequestedFor = '';
    state.selectionPending = false;
  } else if (typeof msg.frameBase64 === 'string' && msg.frameBase64.trim()) {
    state.frameBase64 = msg.frameBase64;
    if (Number.isFinite(Number(msg.frameWidth))) state.frameWidth = Number(msg.frameWidth);
    if (Number.isFinite(Number(msg.frameHeight))) state.frameHeight = Number(msg.frameHeight);
    state.frameFormat = String(msg.frameFormat || 'png').trim().toLowerCase() === 'jpeg' ? 'jpeg' : 'png';
  }
  upsertBrowserSessionRecord(msg, { copyToCanvas: true });
  const nextHost = getBrowserKnowledgeHost(state.url);
  if (state.active && nextHost && nextHost !== previousHost) {
    clearBrowserTransientHighlight();
    state.namedElements = [];
    state.itemRoots = [];
    state.extractionSchemas = [];
    state.knowledgeSite = '';
    state.knowledgeRequestedFor = '';
  }
  state.updatedAt = Number(msg.timestamp || Date.now()) || Date.now();
  if (allowInteractionSync && msg.mode) state.interactionMode = creativeLocked ? 'agent' : normalizeBrowserInteractionMode(msg.mode);
  if (state.interactionMode !== 'copilot' && state.interactionMode !== 'teach' && state.controlCaptured) {
    state.controlCaptured = false;
    state.controlOwner = 'agent';
    clearQueuedBrowserControlInputs();
  }
  persistActiveChat();
  if (state.active && nextHost) requestBrowserKnowledge();
  if (options.autoOpen && state.active && !creativeLocked) {
    setBrowserCanvasSurface('browser');
  } else {
    renderBrowserCanvasSurface();
  }
}

function applyCreativeModeUI() {
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  const rightPanel = document.getElementById('right-panel');
  const panel = document.getElementById('canvas-panel');
  const topbar = document.getElementById('right-panel-topbar');
  const body = document.body;
  if (mode) {
    if (isStructuredCreativeMode(mode)) ensureCreativeSceneForMode(mode);
    if (rightPanel && !rightPanel.classList.contains('open')) {
      if (typeof window.toggleRightPanel === 'function') window.toggleRightPanel();
    }
    if (body) body.classList.remove('right-collapsed');
    if (rightPanel && !creativeModeSavedPanelWidth) {
      creativeModeSavedPanelWidth = rightPanel.style.width || `${rightPanel.offsetWidth || 0}px`;
    }
    setRightPanelWidth(CREATIVE_MODE_PANEL_WIDTH, { minimumWidth: 960, lockMax: true });
    if (!canvasOpen) toggleCanvas(true, { force: true });
  } else if (rightPanel) {
    if (creativeModeSavedPanelWidth && !/^0px$/i.test(creativeModeSavedPanelWidth)) {
      rightPanel.style.width = creativeModeSavedPanelWidth;
      rightPanel.style.minWidth = creativeModeSavedPanelWidth;
    } else {
      rightPanel.style.removeProperty('width');
      rightPanel.style.removeProperty('min-width');
    }
    rightPanel.style.removeProperty('max-width');
    creativeModeSavedPanelWidth = null;
  }
  if (canvasOpen && rightPanel && panel) {
    rightPanel.classList.add('canvas-open');
    rightPanel.scrollTop = 0;
    panel.style.display = 'flex';
    if (topbar) topbar.style.display = 'none';
  }
  updateCreativeModeControls();
  if (canvasOpen) canvasRenderTabs();
  renderCanvasPublishControls();
  syncCanvasSurfaceWidthLock();
  if (typeof window._syncPageViewPositions === 'function') window._syncPageViewPositions();
}

function createBlankCreativeScene(mode = window.currentCreativeMode) {
  const normalized = normalizeCreativeMode(mode);
  return createSceneDocument({
    width: normalized === 'video' ? 1080 : 1080,
    height: normalized === 'video' ? 1920 : 1080,
    background: normalized === 'video' ? '#050816' : '#ffffff',
    durationMs: normalized === 'video' ? 8000 : 12000,
    frameRate: 60,
  });
}

function applySessionCreativeMode(sessionId, mode, options = {}) {
  const sid = String(sessionId || window.activeChatSessionId || window.agentSessionId || '').trim();
  if (!sid) return;
  const normalizedMode = normalizeCreativeMode(mode);
  const session = (window.chatSessions || []).find((s) => s.id === sid);
  if (session) session.creativeMode = normalizedMode;
  if (sid === window.activeChatSessionId || sid === window.agentSessionId) {
    if (normalizedMode) {
      closeBrowserModeForCreativeSwitch({
        persist: false,
        reason: `${getCreativeModeMeta(normalizedMode)?.title || 'Creative workspace'} opened.`,
        statusLabel: 'Browser mode closed.',
      });
    }
    window.currentCreativeMode = normalizedMode;
    if (options.resetScene === true && isStructuredCreativeMode(normalizedMode)) {
      creativeSceneDoc = createBlankCreativeScene(normalizedMode);
      creativeSelectedId = null;
      creativeTimelineMs = 0;
      creativeHistoryPast = [];
      creativeHistoryFuture = [];
      creativeHtmlMotionClip = null;
      window.prometheusCreativeScene = creativeSceneDoc;
      window.prometheusCreativeSelectionId = null;
      if (session) {
        session.creativeSceneDoc = creativeSceneDoc;
        session.creativeSelectedId = null;
        session.creativeTimelineMs = 0;
        session.creativeHistoryPast = [];
        session.creativeHistoryFuture = [];
        session.creativeHtmlMotionClip = null;
      }
    }
    applyCreativeModeUI();
    updateDesignSelectionChip();
    syncHeaderCanvasChrome();
  }
  if (options.persist !== false) saveChatSessions();
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
}

async function persistCreativeMode(sessionId, mode) {
  const res = await fetch('/api/creative-mode', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sessionId, mode: normalizeCreativeMode(mode) }),
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok || data.success === false) {
    throw new Error(data.error || `HTTP ${res.status}`);
  }
  return normalizeCreativeMode(data.creativeMode);
}

async function setCreativeModeFromUI(mode) {
  const sid = getCurrentChatModeSessionId();
  const nextMode = normalizeCreativeMode(mode);
  if (!sid || !nextMode) return;
  try {
    const savedMode = await persistCreativeMode(sid, nextMode);
    applySessionCreativeMode(sid, savedMode);
    const meta = getCreativeModeMeta(savedMode);
    addProcessEntry('info', `${meta?.title || 'Creative workspace'} opened for this chat.`);
    showToast(`${meta?.title || 'Creative workspace'} opened`);
  } catch (err) {
    showToast(`Could not open Creative workspace: ${err.message}`, 'error');
  }
}

async function exitCreativeModeFromUI() {
  const sid = getCurrentChatModeSessionId();
  if (!sid || !isCreativeModeLocked()) return;
  try {
    await persistCreativeMode(sid, null);
    applySessionCreativeMode(sid, null);
    addProcessEntry('info', 'Creative workspace closed for this chat.');
    showToast('Creative workspace closed');
  } catch (err) {
    showToast(`Could not close Creative workspace: ${err.message}`, 'error');
  }
}

function renderQueuedPromptsPanel() {
  const panel = document.getElementById('queued-prompts-panel');
  const list = document.getElementById('queued-prompts-list');
  const title = document.getElementById('queued-prompts-title');
  if (!panel || !list || !title) return;
  const queue = getActiveQueuedPrompts();
  window.queuedPrompts = queue;
  const count = queue.length;
  if (count === 0) {
    panel.style.display = 'none';
    list.innerHTML = '';
    return;
  }
  panel.style.display = 'block';
  title.textContent = `Queued prompts (${count})`;
  list.innerHTML = queue.map((q, i) => `
    <div class="queued-item">
      <div class="queued-item-text">${escHtml(getQueuedTurnMessage(q))}${getQueuedTurnFiles(q).length ? `<span class="queued-item-attachments"> +${getQueuedTurnFiles(q).length} file(s)</span>` : ''}</div>
      <button class="queued-item-btn" onclick="removeQueuedPrompt(${i})">Remove</button>
    </div>
  `).join('');
}

function removeQueuedPrompt(index) {
  const queue = getActiveQueuedPrompts();
  if (!Number.isInteger(index) || index < 0 || index >= queue.length) return;
  queue.splice(index, 1);
  window.queuedPrompts = queue;
  updateQueuedPromptUI();
}

function clearQueuedPrompts() {
  const queue = getActiveQueuedPrompts();
  if (!queue.length) return;
  queue.length = 0;
  window.queuedPrompts = queue;
  addProcessEntry('info', 'Cleared queued prompts.');
  updateQueuedPromptUI();
}

function updateQueuedPromptUI() {
  const badge = document.getElementById('queued-prompts-indicator');
  const sendBtn = document.getElementById('send-btn');
  const input = document.getElementById('chat-input');
  const queue = getActiveQueuedPrompts();
  window.queuedPrompts = queue;
  const count = queue.length;
  if (badge) {
    if (count > 0) {
      badge.style.display = 'inline';
      badge.textContent = `Queued: ${count}`;
    } else {
      badge.style.display = 'none';
      badge.textContent = '';
    }
  }
  if (sendBtn) {
    sendBtn.disabled = false;
    sendBtn.title = window.isThinking ? `Queue next prompt${count ? ` (${count} queued)` : ''}` : 'Send';
  }
  if (input) {
    input.placeholder = window.isThinking
      ? 'Assistant is responding. Press Enter/Send to queue next prompt.'
      : 'Type a message... (Enter to send, Shift+Enter for newline)';
  }
  renderQueuedPromptsPanel();
}

function getVoicePendingTurns() {
  if (!Array.isArray(window._voicePendingTurns)) window._voicePendingTurns = [];
  return window._voicePendingTurns;
}

function getActiveVoicePendingTurns() {
  const sid = String(window.activeChatSessionId || '').trim();
  if (!sid) return [];
  return getVoicePendingTurns().filter((turn) => String(turn?.sessionId || '') === sid);
}

function removeVoicePendingTurnInternal(id) {
  const key = String(id || '');
  if (!key) return null;
  const turns = getVoicePendingTurns();
  const index = turns.findIndex((turn) => String(turn?.id || '') === key);
  if (index < 0) return null;
  return turns.splice(index, 1)[0] || null;
}

function markVoicePendingTurn(id, patch = {}) {
  const key = String(id || '');
  if (!key) return null;
  const turn = getVoicePendingTurns().find((entry) => String(entry?.id || '') === key);
  if (!turn) return null;
  Object.assign(turn, patch);
  return turn;
}

function renderVoicePendingTurns() {
  const turns = getActiveVoicePendingTurns();
  if (!turns.length) return '';
  return turns.map((turn) => {
    const idArg = encodeInlineJsString(turn.id);
    const files = Array.isArray(turn.files) ? turn.files : [];
    const state = String(turn.state || 'queued');
    const isLocked = state !== 'queued';
    const label = state === 'sending' ? 'Sending voice message' : 'Queued voice message';
    return `
      <div class="msg-shell user voice-pending-shell">
        <div class="msg user voice-pending-msg">
          <div class="msg-body voice-pending-body">
            <div class="msg-content">${escHtml(turn.text || '')}</div>
            <div class="voice-pending-meta">
              <span>${escHtml(label)}${files.length ? ` +${files.length} file(s)` : ''}</span>
              <span class="voice-pending-actions">
                <button class="voice-pending-btn" onclick="editVoicePendingTurn(${idArg})" ${isLocked ? 'disabled' : ''}>Edit</button>
                <button class="voice-pending-btn" onclick="removeVoicePendingTurn(${idArg})" ${isLocked ? 'disabled' : ''}>Remove</button>
              </span>
            </div>
          </div>
        </div>
      </div>`;
  }).join('');
}

function enqueueVoicePendingTurn(text, files = [], source = 'voice') {
  const message = String(text || '').trim();
  if (!message) return '';
  ensureActiveChatSessionExists();
  const turn = {
    id: `voice_${Date.now()}_${++voicePendingTurnSeq}`,
    sessionId: String(window.activeChatSessionId || ''),
    text: message,
    files: Array.isArray(files) ? files.slice() : [],
    source: String(source || 'voice'),
    state: 'queued',
    createdAt: Date.now(),
  };
  getVoicePendingTurns().push(turn);
  renderChatMessages();
  setTimeout(processVoicePendingTurns, 0);
  return turn.id;
}

function removeVoicePendingTurn(id) {
  const turn = getVoicePendingTurns().find((entry) => String(entry?.id || '') === String(id || ''));
  if (!turn) return;
  if (String(turn.state || 'queued') !== 'queued') {
    showToast('Voice message is already sending', 'Wait for it to appear as a chat bubble.', 'info');
    return;
  }
  removeVoicePendingTurnInternal(id);
  renderChatMessages();
}

function editVoicePendingTurn(id) {
  const turn = getVoicePendingTurns().find((entry) => String(entry?.id || '') === String(id || ''));
  if (!turn) return;
  if (String(turn.state || 'queued') !== 'queued') {
    showToast('Voice message is already sending', 'Wait for it to appear as a chat bubble before editing.', 'info');
    return;
  }
  removeVoicePendingTurnInternal(id);
  const input = document.getElementById('chat-input');
  if (input) {
    input.value = String(turn.text || '');
    resizeChatInput(input);
    input.focus();
  }
  const files = Array.isArray(turn.files) ? turn.files : [];
  if (files.length) {
    pendingChatFiles = pendingChatFiles.concat(files);
    renderChatFilePills();
  }
  renderChatMessages();
}

async function processVoicePendingTurns() {
  if (voicePendingProcessing) return;
  const sid = String(window.activeChatSessionId || '').trim();
  if (!sid || isSessionThinking(sid)) return;
  const turn = getVoicePendingTurns().find((entry) => String(entry?.sessionId || '') === sid && String(entry?.state || 'queued') === 'queued');
  if (!turn) return;
  voicePendingProcessing = true;
  markVoicePendingTurn(turn.id, { state: 'sending' });
  renderChatMessages();
  try {
    await sendChat(makeQueuedChatTurn(turn.text, turn.files), { voicePendingTurnId: turn.id });
  } catch (err) {
    markVoicePendingTurn(turn.id, { state: 'queued' });
    showToast('Voice message send failed', String(err?.message || err), 'error');
  } finally {
    voicePendingProcessing = false;
    setTimeout(processVoicePendingTurns, 0);
  }
}

function sanitizeBrowserCanvasStateForStorage(browserCanvasState) {
  if (!browserCanvasState || typeof browserCanvasState !== 'object') return browserCanvasState;
  const clean = { ...browserCanvasState };
  clean.frameBase64 = '';
  const registry = clean.browserSessions && typeof clean.browserSessions === 'object' && !Array.isArray(clean.browserSessions)
    ? clean.browserSessions
    : {};
  clean.browserSessions = Object.fromEntries(Object.entries(registry).map(([sessionId, record]) => {
    const next = record && typeof record === 'object' ? { ...record } : {};
    next.frameBase64 = '';
    return [sessionId, next];
  }));
  return clean;
}

function sanitizeChatSessionForStorage(session) {
  if (!session || typeof session !== 'object') return session;
  return {
    ...session,
    browserCanvasState: sanitizeBrowserCanvasStateForStorage(session.browserCanvasState),
  };
}

function sanitizeChatSessionsForStorage(sessions) {
  return Array.isArray(sessions)
    ? sessions.filter(hasPersistableChatSessionContent).map((session) => sanitizeChatSessionForStorage(session))
    : [];
}

function saveChatSessions() {
  const sanitized = sanitizeChatSessionsForStorage(window.chatSessions);
  try {
    localStorage.setItem(CHAT_SESSIONS_KEY, JSON.stringify(sanitized));
  } catch (err) {
    if (err && (err.name === 'QuotaExceededError' || /quota/i.test(String(err.message || err)))) {
      console.warn('[ChatPage] localStorage quota exceeded; saving compact session index without browser frames.');
      const compact = sanitized.map((session) => ({
        ...session,
        history: Array.isArray(session.history) ? session.history.slice(-24) : [],
        processLog: Array.isArray(session.processLog) ? session.processLog.slice(-80) : [],
        creativeCheckpoints: Array.isArray(session.creativeCheckpoints) ? session.creativeCheckpoints.slice(-6) : undefined,
      }));
      try {
        localStorage.setItem(CHAT_SESSIONS_KEY, JSON.stringify(compact));
        window.chatSessions = compact;
      } catch (fallbackErr) {
        console.warn('[ChatPage] compact session save also exceeded quota; saving minimal recent session index.', fallbackErr);
        const minimal = compact.slice(-8).map((session) => ({
          id: session.id,
          title: session.title,
          createdAt: session.createdAt,
          updatedAt: session.updatedAt,
          unread: session.unread,
          automated: session.automated,
          history: Array.isArray(session.history) ? session.history.slice(-4) : [],
          processLog: [],
          browserCanvasState: null,
        }));
        try {
          localStorage.setItem(CHAT_SESSIONS_KEY, JSON.stringify(minimal));
          window.chatSessions = minimal;
        } catch (minimalErr) {
          console.error('[ChatPage] unable to persist chat sessions after quota compaction; continuing without local persistence.', minimalErr);
        }
      }
      return;
    }
    throw err;
  }
}

async function deleteSessionFromServer(id) {
  const res = await fetch(`/api/sessions/${encodeURIComponent(id)}`, { method: 'DELETE' });
  if (!res.ok && res.status !== 404) {
    const body = await res.text().catch(() => '');
    throw new Error(body || `Delete failed (${res.status})`);
  }
}

function isSessionTitleCommandMessage(msg) {
  if (!msg || msg.role !== 'user') return false;
  const text = String(msg.content || '').trim();
  return /^\/[a-z][\w-]*(?:@\w+)?(?:\s|$)/i.test(text);
}

function isCommandSessionTitle(value) {
  return /^\/[a-z][\w-]*(?:@\w+)?(?:\s|$)/i.test(String(value || '').trim());
}

function makeSessionTitle(history) {
  const firstUser = (history || []).find(m => m.role === 'user' && !isSessionTitleCommandMessage(m));
  return firstUser ? String(firstUser.content || '').trim().slice(0, 42) || 'New chat' : 'New chat';
}

function createEmptyChatSession(id = generateSessionId()) {
  const now = Date.now();
  return {
    id,
    title: 'New chat',
    history: [],
    processLog: [],
    creativeMode: null,
    canvasProjectRoot: null,
    canvasProjectLabel: null,
    canvasProjectLink: null,
    creativeSceneDoc: null,
    creativeSelectedId: null,
    creativeTimelineMs: 0,
    creativeHistoryPast: [],
    creativeHistoryFuture: [],
    creativeHtmlMotionClip: null,
    creativeComposition: null,
    mainChatGoal: null,
    mainChatGoalHistory: [],
    createdAt: now,
    updatedAt: now,
  };
}

function hasPersistableChatSessionContent(session) {
  if (!session || typeof session !== 'object') return false;
  if (session._needsServerLoad || session.automated) return true;
  if (session.source && session.source !== 'web') return true;
  if (Array.isArray(session.history) && session.history.length > 0) return true;
  if (Array.isArray(session.processLog) && session.processLog.length > 0) return true;
  return false;
}

function ensureActiveChatSessionExists() {
  let id = String(window.activeChatSessionId || '').trim();
  if (!id) {
    id = generateSessionId();
    window.activeChatSessionId = id;
    setAgentSessionId(id);
  }
  let sess = getChatSessionById(id);
  if (!sess) {
    sess = createEmptyChatSession(id);
    window.chatSessions.unshift(sess);
  }
  return sess;
}

function isAssistantLikeMessage(msg) {
  return msg?.role === 'ai' || msg?.role === 'assistant';
}

function cloneChatMessageForBranch(msg) {
  if (!msg || typeof msg !== 'object') return null;
  const clone = JSON.parse(JSON.stringify(msg));
  delete clone._promptVariants;
  delete clone._promptVariantActive;
  delete clone._editingDraft;
  return clone;
}

function getMessageCopyText(msg) {
  return String(msg?.content || '').trim();
}

function findAssistantResponseIndex(history, userIndex) {
  const list = Array.isArray(history) ? history : [];
  for (let i = userIndex + 1; i < list.length; i++) {
    const msg = list[i];
    if (!msg) continue;
    if (msg.role === 'user') return -1;
    if (isAssistantLikeMessage(msg)) return i;
  }
  return -1;
}

function getBranchTailStartIndex(history, userIndex) {
  const assistantIndex = findAssistantResponseIndex(history, userIndex);
  return assistantIndex >= 0 ? assistantIndex + 1 : userIndex + 1;
}

function getPromptVariants(userIndex) {
  const msg = (window.chatHistory || [])[userIndex];
  return Array.isArray(msg?._promptVariants) ? msg._promptVariants : [];
}

function getPromptVariantActiveIndex(userIndex) {
  const variants = getPromptVariants(userIndex);
  const raw = Number((window.chatHistory || [])[userIndex]?._promptVariantActive);
  if (!variants.length) return -1;
  return Number.isFinite(raw) ? clamp(Math.floor(raw), 0, variants.length - 1) : 0;
}

function makePromptVariantFromTimeline(userIndex) {
  const history = window.chatHistory || [];
  const user = cloneChatMessageForBranch(history[userIndex]);
  if (!user) return null;
  const assistantIndex = findAssistantResponseIndex(history, userIndex);
  const assistant = assistantIndex >= 0 ? cloneChatMessageForBranch(history[assistantIndex]) : null;
  const tailStart = assistantIndex >= 0 ? assistantIndex + 1 : userIndex + 1;
  const tail = history.slice(tailStart).map(cloneChatMessageForBranch).filter(Boolean);
  return { user, assistant, tail };
}

function attachPromptVariantsToUserMessage(user, variants, activeIndex) {
  const next = cloneChatMessageForBranch(user) || { role: 'user', content: '', timestamp: Date.now() };
  next._promptVariants = variants;
  next._promptVariantActive = activeIndex;
  return next;
}

function saveActivePromptVariant(userIndex) {
  const history = window.chatHistory || [];
  const msg = history[userIndex];
  const variants = Array.isArray(msg?._promptVariants) ? msg._promptVariants : null;
  if (!variants || !variants.length) return variants || [];
  const activeIndex = getPromptVariantActiveIndex(userIndex);
  const current = makePromptVariantFromTimeline(userIndex);
  if (current) variants[activeIndex] = current;
  msg._promptVariants = variants;
  msg._promptVariantActive = activeIndex;
  return variants;
}

function ensurePromptVariantsForEdit(userIndex) {
  const history = window.chatHistory || [];
  const msg = history[userIndex];
  if (!msg || msg.role !== 'user') return null;
  if (Array.isArray(msg._promptVariants) && msg._promptVariants.length) {
    saveActivePromptVariant(userIndex);
    return msg._promptVariants;
  }
  const original = makePromptVariantFromTimeline(userIndex);
  msg._promptVariants = original ? [original] : [];
  msg._promptVariantActive = 0;
  return msg._promptVariants;
}

function historyForServer(history = window.chatHistory || []) {
  return (Array.isArray(history) ? history : [])
    .filter((msg) => msg && (msg.role === 'user' || isAssistantLikeMessage(msg)))
    .map((msg) => ({
      ...cloneChatMessageForBranch(msg),
      role: msg.role === 'user' ? 'user' : 'assistant',
      content: String(msg.content || ''),
      timestamp: Number(msg.timestamp) || Date.now(),
    }))
    .filter((msg) => msg.content.trim());
}

async function syncActiveSessionHistoryToServer(history = window.chatHistory || []) {
  const sid = String(window.activeChatSessionId || '').trim();
  if (!sid) return;
  try {
    const res = await fetch(`/api/sessions/${encodeURIComponent(sid)}/history`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ history: historyForServer(history) }),
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
  } catch (err) {
    console.warn('[ChatPage] failed to sync edited session history:', err);
  }
}

async function markEditRerunResetOnServer(sessionId) {
  const sid = String(sessionId || '').trim();
  if (!sid) return;
  try {
    await fetch(`/api/sessions/${encodeURIComponent(sid)}/edit-rerun-reset`, { method: 'POST' });
  } catch {}
}

function waitForSessionIdle(sessionId, timeoutMs = 1800) {
  const sid = String(sessionId || '').trim();
  const start = Date.now();
  return new Promise((resolve) => {
    const tick = () => {
      if (!isSessionThinking(sid) || Date.now() - start >= timeoutMs) {
        resolve();
        return;
      }
      setTimeout(tick, 50);
    };
    tick();
  });
}

function renderMessageActions(msg, originalIndex) {
  if (contextPinMode) return '';
  const isUser = msg?.role === 'user';
  const copyTitle = isUser ? 'Copy prompt' : 'Copy response';
  const editOrFork = isUser
    ? `<button class="msg-action-btn" type="button" title="Edit prompt" onclick="startEditUserMessage(${originalIndex}, event)"><iconify-icon icon="solar:pen-2-linear" width="14" height="14"></iconify-icon></button>`
    : `<button class="msg-action-btn" type="button" title="Fork conversation" onclick="forkConversationFromAssistantMessage(${originalIndex}, event)"><iconify-icon icon="solar:branching-paths-up-linear" width="14" height="14"></iconify-icon></button>`;
  return `<div class="msg-actions">
    <button class="msg-action-btn" type="button" title="${copyTitle}" onclick="copyChatMessage(${originalIndex}, event)"><iconify-icon icon="solar:copy-linear" width="14" height="14"></iconify-icon></button>
    ${editOrFork}
    ${isUser ? renderPromptVariantNav(originalIndex) : ''}
  </div>`;
}

function renderPromptVariantNav(originalIndex) {
  const variants = getPromptVariants(originalIndex);
  if (variants.length < 2) return '';
  const active = getPromptVariantActiveIndex(originalIndex);
  return `<div class="msg-variant-nav" title="Prompt variants">
    <button class="msg-action-btn" type="button" title="Previous variant" ${active <= 0 ? 'disabled' : ''} onclick="switchPromptVariant(${originalIndex}, ${active - 1}, event)"><iconify-icon icon="solar:alt-arrow-left-linear" width="14" height="14"></iconify-icon></button>
    <span>${active + 1}/${variants.length}</span>
    <button class="msg-action-btn" type="button" title="Next variant" ${active >= variants.length - 1 ? 'disabled' : ''} onclick="switchPromptVariant(${originalIndex}, ${active + 1}, event)"><iconify-icon icon="solar:alt-arrow-right-linear" width="14" height="14"></iconify-icon></button>
  </div>`;
}

function renderUserEditComposer(msg, originalIndex) {
  const value = escHtml(String(msg?.content || ''));
  return `<div class="msg-edit-composer" onclick="event.stopPropagation()">
    <textarea id="msg-edit-input-${originalIndex}" class="msg-edit-input" rows="4">${value}</textarea>
    <div class="msg-edit-actions">
      <button type="button" class="msg-edit-btn" onclick="cancelEditUserMessage(event)">Cancel</button>
      <button type="button" class="msg-edit-btn msg-edit-btn-primary" onclick="submitEditedUserMessage(${originalIndex}, event)">Send</button>
    </div>
  </div>`;
}

function isInternalChatSession(session) {
  return /^(brain_thought_|brain_dream_|brain_dream_cleanup_|subagent_chat_)/i.test(String(session?.id || ''));
}

function isInternalChatMessage(msg) {
  const text = String(msg?.content || '').trim();
  return /^\[BACKGROUND_TASK_RESULT\b/i.test(text);
}

function setChatSessions(next) {
  const sessions = (Array.isArray(next) ? next : [])
    .filter((session) => !isInternalChatSession(session))
    .filter(hasPersistableChatSessionContent);
  if (typeof window.setChatSessionsRef === 'function') {
    return window.setChatSessionsRef(sessions);
  }
  window.chatSessions = sessions;
  return window.chatSessions;
}

function normalizeStoredSession(session) {
  const history = Array.isArray(session?.history) ? session.history.filter((msg) => !isInternalChatMessage(msg)) : [];
  const title = isCommandSessionTitle(session?.title)
    ? makeSessionTitle(history)
    : session?.title;
  return {
    ...session,
    title,
    history,
    creativeMode: normalizeCreativeMode(session?.creativeMode),
    canvasProjectRoot: normalizeCanvasPath(session?.canvasProjectRoot) || null,
    canvasProjectLabel: session?.canvasProjectLabel || null,
    canvasProjectLink: normalizeCanvasProjectLink(session?.canvasProjectLink),
    creativeSceneDoc: session?.creativeSceneDoc || null,
    creativeSelectedId: session?.creativeSelectedId || null,
    creativeTimelineMs: Number.isFinite(Number(session?.creativeTimelineMs)) ? Number(session.creativeTimelineMs) : 0,
    creativeHistoryPast: Array.isArray(session?.creativeHistoryPast) ? session.creativeHistoryPast : [],
    creativeHistoryFuture: Array.isArray(session?.creativeHistoryFuture) ? session.creativeHistoryFuture : [],
    creativeHtmlMotionClip: session?.creativeHtmlMotionClip || null,
    mainChatGoal: session?.mainChatGoal || null,
    mainChatGoalHistory: Array.isArray(session?.mainChatGoalHistory) ? session.mainChatGoalHistory : [],
  };
}

function sessionStubFromServer(s) {
  const channel = String(s.channel || 'web');
  return normalizeStoredSession({
    id: s.id,
    title: s.title || s.preview || s.id,
    history: [],
    processLog: [],
    creativeMode: s.creativeMode,
    canvasProjectRoot: s.canvasProjectRoot,
    canvasProjectLabel: s.canvasProjectLabel,
    canvasProjectLink: s.canvasProjectLink,
    creativeSceneDoc: s.creativeSceneDoc,
    creativeSelectedId: s.creativeSelectedId,
    creativeTimelineMs: s.creativeTimelineMs,
    creativeHistoryPast: Array.isArray(s.creativeHistoryPast) ? s.creativeHistoryPast : [],
    creativeHistoryFuture: Array.isArray(s.creativeHistoryFuture) ? s.creativeHistoryFuture : [],
    creativeHtmlMotionClip: s.creativeHtmlMotionClip || null,
    mainChatGoal: s.mainChatGoal || null,
    createdAt: s.createdAt || Date.now(),
    updatedAt: s.lastActiveAt || s.createdAt || Date.now(),
    source: channel !== 'web' ? channel : undefined,
    automated: channel !== 'web',
    _needsServerLoad: true,
  });
}

// Fetch a single session's full history from the server and populate the stub.
async function _loadSessionFromServer(id) {
  if (/^(brain_thought_|brain_dream_|brain_dream_cleanup_)/i.test(String(id || ''))) return;
  const sess = window.chatSessions.find(s => s.id === id);
  if (!sess || !sess._needsServerLoad) return;
  try {
    const data = await fetchJsonWithTimeout(`/api/sessions/${encodeURIComponent(id)}`, 2000);
    const s = data.session;
    if (!s) return;
    sess.history = (s.history || [])
      .filter((m) => !isInternalChatMessage(m))
      .map(m => ({
        ...m,
        role: m.role,
        content: m.content || '',
        timestamp: m.timestamp,
      }));
    sess.processLog = s.processLog || [];
    sess.creativeMode = normalizeCreativeMode(s.creativeMode);
    sess.canvasProjectRoot = normalizeCanvasPath(s.canvasProjectRoot) || null;
    sess.canvasProjectLabel = s.canvasProjectLabel || null;
    sess.canvasProjectLink = normalizeCanvasProjectLink(s.canvasProjectLink);
    sess.creativeSceneDoc = s.creativeSceneDoc || null;
    sess.creativeSelectedId = s.creativeSelectedId || null;
    sess.creativeTimelineMs = Number.isFinite(Number(s.creativeTimelineMs)) ? Number(s.creativeTimelineMs) : 0;
    sess.creativeHtmlMotionClip = s.creativeHtmlMotionClip || null;
    sess.mainChatGoal = s.mainChatGoal || null;
    sess.mainChatGoalHistory = Array.isArray(s.mainChatGoalHistory) ? s.mainChatGoalHistory : [];
    if (sess.history.length > 0) sess.title = makeSessionTitle(sess.history) || sess.title;
    sess.createdAt = s.createdAt || sess.createdAt;
    sess.updatedAt = s.lastActiveAt || sess.updatedAt;
    delete sess._needsServerLoad;
    saveChatSessions();
  } catch {}
}

async function loadChatSessions() {
  let storedSessions = [];
  try {
    storedSessions = JSON.parse(localStorage.getItem(CHAT_SESSIONS_KEY) || '[]');
  } catch {
    storedSessions = [];
  }
  if (!Array.isArray(storedSessions)) storedSessions = [];
  setChatSessions(storedSessions.map(normalizeStoredSession));
  let serverSessions = [];
  try {
    const data = await fetchJsonWithTimeout('/api/sessions', 2000);
    if (data) {
      serverSessions = Array.isArray(data.sessions) ? data.sessions : [];
    }
  } catch {}

  if (serverSessions.length > 0) {
    const byId = new Map(window.chatSessions.map(s => [s.id, s]));
    for (const serverSession of serverSessions) {
      if (!serverSession?.id) continue;
      if (isInternalChatSession(serverSession)) continue;
      const existing = byId.get(serverSession.id);
      const serverStub = sessionStubFromServer(serverSession);
      if (existing) {
        Object.assign(existing, {
          title: existing.title || serverStub.title,
          createdAt: existing.createdAt || serverStub.createdAt,
          updatedAt: Math.max(Number(existing.updatedAt) || 0, Number(serverStub.updatedAt) || 0) || serverStub.updatedAt,
          source: existing.source || serverStub.source,
          automated: existing.automated || serverStub.automated,
          creativeMode: existing.creativeMode ?? serverStub.creativeMode,
          canvasProjectRoot: existing.canvasProjectRoot || serverStub.canvasProjectRoot,
          canvasProjectLabel: existing.canvasProjectLabel || serverStub.canvasProjectLabel,
          canvasProjectLink: existing.canvasProjectLink || serverStub.canvasProjectLink,
          creativeSceneDoc: existing.creativeSceneDoc || serverStub.creativeSceneDoc,
          creativeSelectedId: existing.creativeSelectedId || serverStub.creativeSelectedId,
          creativeTimelineMs: existing.creativeTimelineMs || serverStub.creativeTimelineMs,
          creativeHtmlMotionClip: existing.creativeHtmlMotionClip || serverStub.creativeHtmlMotionClip,
          mainChatGoal: serverStub.mainChatGoal || existing.mainChatGoal || null,
        });
        if (!Array.isArray(existing.history) || existing.history.length === 0) existing._needsServerLoad = true;
      } else {
        window.chatSessions.push(serverStub);
        byId.set(serverSession.id, serverStub);
      }
    }
    window.chatSessions.sort((a, b) => (b.updatedAt || b.createdAt || 0) - (a.updatedAt || a.createdAt || 0));
  }

  if (window.chatSessions.length === 0) {
    // localStorage is empty — try to recover sessions from disk via server
    let recovered = false;
    try {
      const data = await fetchJsonWithTimeout('/api/sessions', 2000);
      if (data) {
        const serverSessions = Array.isArray(data.sessions) ? data.sessions : [];
        if (serverSessions.length > 0) {
          setChatSessions(serverSessions.filter((s) => !isInternalChatSession(s)).map(s => ({
            id: s.id,
            title: s.title || s.preview || s.id,
            history: [],
            processLog: [],
            creativeMode: normalizeCreativeMode(s.creativeMode),
            canvasProjectRoot: normalizeCanvasPath(s.canvasProjectRoot) || null,
            canvasProjectLabel: s.canvasProjectLabel || null,
            canvasProjectLink: normalizeCanvasProjectLink(s.canvasProjectLink),
            creativeSceneDoc: s.creativeSceneDoc || null,
            creativeSelectedId: s.creativeSelectedId || null,
            creativeTimelineMs: Number.isFinite(Number(s.creativeTimelineMs)) ? Number(s.creativeTimelineMs) : 0,
            creativeHistoryPast: Array.isArray(s.creativeHistoryPast) ? s.creativeHistoryPast : [],
            creativeHistoryFuture: Array.isArray(s.creativeHistoryFuture) ? s.creativeHistoryFuture : [],
            creativeHtmlMotionClip: s.creativeHtmlMotionClip || null,
            mainChatGoal: s.mainChatGoal || null,
            createdAt: s.createdAt || Date.now(),
            updatedAt: s.lastActiveAt || s.createdAt || Date.now(),
            // Preserve channel so _isChannelSession works on stubs
            source: (s.channel && s.channel !== 'web') ? s.channel : undefined,
            automated: !!(s.channel && s.channel !== 'web'),
            _needsServerLoad: true,
          })));
          window.activeChatSessionId = window.chatSessions[0].id;
          setAgentSessionId(window.activeChatSessionId);
          saveChatSessions();
          // Eagerly load the active session's history so it renders immediately
          await _loadSessionFromServer(window.activeChatSessionId);
          recovered = true;
        }
      }
    } catch {}

    if (!recovered) {
      const id = generateSessionId();
      window.activeChatSessionId = id;
      setAgentSessionId(id);
      saveChatSessions();
    }
  } else if (!window.activeChatSessionId || !window.chatSessions.some(s => s.id === window.activeChatSessionId)) {
    window.activeChatSessionId = window.chatSessions[0].id;
    setAgentSessionId(window.activeChatSessionId);
  }
  if (!window.agentSessionId || window.agentSessionId !== window.activeChatSessionId) setAgentSessionId(window.activeChatSessionId);
  saveChatSessions();
  if (window.activeChatSessionId) await _loadSessionFromServer(window.activeChatSessionId);
  syncActiveChat();

  // Load terminal sessions from the server
  loadTerminalSessions();

  // Set up 30-second refresh interval for terminal sessions
  if (window.terminalSessionRefreshTimer) clearInterval(window.terminalSessionRefreshTimer);
  window.terminalSessionRefreshTimer = setInterval(() => {
    loadTerminalSessions();
  }, 30000);
}

function getActiveMainChatGoal() {
  const sess = window.chatSessions.find(s => s.id === window.activeChatSessionId);
  return sess?.mainChatGoal || null;
}

function renderMainGoalStrip() {
  const strip = document.getElementById('main-goal-strip');
  if (!strip) return;
  const goal = getActiveMainChatGoal();
  if (!goal || goal.status === 'cleared') {
    strip.style.display = 'none';
    strip.innerHTML = '';
    return;
  }
  const status = String(goal.status || 'active');
  const isActive = status === 'active';
  const canResume = ['paused', 'blocked', 'failed'].includes(status);
  const reason = goal.blockedReason || goal.pausedReason || goal.failureReason || goal.lastReason || '';
  const deniedActions = Array.isArray(goal.deniedActions) ? goal.deniedActions : [];
  const latestDenial = deniedActions[deniedActions.length - 1] || null;
  const policyMeta = [
    `${Number(goal.turnsUsed || 0)} turns`,
    'Autonomous',
    'Hard policy active',
    deniedActions.length ? `${deniedActions.length} denied` : '',
    reason,
  ].filter(Boolean).join(' · ');
  strip.style.display = 'flex';
  strip.setAttribute('data-status', status);
  strip.innerHTML = `
    <div class="main-goal-main">
      <div class="main-goal-kicker">Main chat goal · ${escHtml(status)}</div>
      <div class="main-goal-title" title="${escHtml(goal.goal || '')}">${escHtml(goal.goal || 'Untitled goal')}</div>
      <div class="main-goal-meta">${escHtml(policyMeta)}</div>
      ${latestDenial ? `<div class="main-goal-denial">${escHtml(`Latest denied: ${latestDenial.category || 'policy'} - ${latestDenial.reason || 'Blocked by hard policy.'}`)}</div>` : ''}
    </div>
    <div class="main-goal-actions">
      ${isActive ? `<button class="main-goal-action" type="button" onclick="mainGoalAction('pause')" title="Pause goal">Pause</button>` : ''}
      ${canResume ? `<button class="main-goal-action" type="button" onclick="mainGoalAction('resume')" title="Resume goal">Resume</button>` : ''}
      <button class="main-goal-action" type="button" onclick="mainGoalAction('status')" title="Refresh goal">Status</button>
      <button class="main-goal-action" type="button" onclick="mainGoalAction('clear')" title="Clear goal">Clear</button>
    </div>
  `;
}

async function mainGoalAction(action) {
  const sid = String(window.activeChatSessionId || '').trim();
  if (!sid) return;
  try {
    const result = await api(`/api/sessions/${encodeURIComponent(sid)}/main-goal/${encodeURIComponent(action)}`, { method: 'POST', body: {} });
    const sess = window.chatSessions.find(s => s.id === sid);
    if (sess) sess.mainChatGoal = result?.goal || null;
    renderMainGoalStrip();
    if (action === 'status' && result?.message) showToast('Goal status', result.message.slice(0, 240), 'info');
    if (action !== 'status') showToast('Goal updated', result?.message || action, 'success');
  } catch (err) {
    showToast('Goal action failed', err?.message || String(err), 'error');
  }
}

function syncActiveChat() {
  const sess = window.chatSessions.find(s => s.id === window.activeChatSessionId);
  window.chatHistory = sess ? (sess.history || []) : [];
  window.processLogEntries = sess ? (sess.processLog || []) : [];
  window.currentCreativeMode = normalizeCreativeMode(sess?.creativeMode);
  canvasProjectRoot = normalizeCanvasPath(sess?.canvasProjectRoot) || null;
  canvasProjectLabel = sess?.canvasProjectLabel || null;
  canvasProjectLink = normalizeCanvasProjectLink(sess?.canvasProjectLink);
  creativeSceneDoc = sess?.creativeSceneDoc ? createSceneDocument(sess.creativeSceneDoc) : createSceneDocument();
  creativeSelectedId = sess?.creativeSelectedId || null;
  creativeTimelineMs = Number.isFinite(Number(sess?.creativeTimelineMs)) ? Number(sess.creativeTimelineMs) : 0;
  creativeHistoryPast = Array.isArray(sess?.creativeHistoryPast) ? sess.creativeHistoryPast.slice() : [];
  creativeHistoryFuture = Array.isArray(sess?.creativeHistoryFuture) ? sess.creativeHistoryFuture.slice() : [];
  creativeHtmlMotionClip = sess?.creativeHtmlMotionClip || null;
  creativeComposition = sess?.creativeComposition || null;
  restoreBrowserCanvasSessionState(sess?.browserCanvasState);
  if (window.currentCreativeMode) {
    closeBrowserModeForCreativeSwitch({ persist: false, syncRemote: false });
  }
  window.prometheusCreativeScene = creativeSceneDoc;
  window.prometheusCreativeSelectionId = creativeSelectedId;
  canvasWorkspaceTree = [];
  canvasWorkspaceRootPath = '';
  canvasFolderExpanded.clear();
  window.runtimeProgressState = sess && sess.progressState
    ? { source: String(sess.progressState.source || 'none'), activeIndex: Number(sess.progressState.activeIndex || -1), items: Array.isArray(sess.progressState.items) ? sess.progressState.items : [] }
    : { source: 'none', activeIndex: -1, items: [] };
  if (sess) {
    if (window._sessionThinking && window._sessionThinking[sess.id]) {
      applyStreamStateToWindow(sess.id);
    } else {
      window.streamingAIText = '';
      window.streamingThinkingText = '';
      window.currentPreflightStatus = '';
      window.currentProgressLines = [];
      window.currentProgressThinkingActive = false;
      window.currentProgressThinkingText = '';
      window.currentTurnStartIndex = -1;
      window.activeModelBadge = null;
    }
  }
  // Mark session as read when opening it
  if (sess) sess.unread = false;
  renderMainGoalStrip();
  renderChatMessages();
  renderProcessLog();
  renderProgressPanel();
  // Reset session list pagination when loading fresh sessions
  if (typeof window._sessionShowCount !== 'undefined') window._sessionShowCount = 20;
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
  if (typeof window.updateStats === 'function') window.updateStats([]);
  // Restore canvas tabs for this session (re-fetch content from disk)
  canvasTabs = [];
  activeCanvasTabId = null;
  if (canvasEditor) canvasEditor.setValue('');
  canvasRenderTabs();
  applyCanvasViewMode('code', null);
  const savedPaths = sess && Array.isArray(sess.canvasFiles) ? sess.canvasFiles : [];
  if (savedPaths.length > 0) {
    // Show notify dot so user knows canvas has files for this session
    const dot = document.getElementById('canvas-notify-dot');
    if (dot && !canvasOpen) dot.style.display = 'block';
    // Silently load tabs in background (don't auto-open canvas)
    savedPaths.forEach(f => {
      canvasPresentFile(f.diskPath, f.name, { autoOpen: false }).catch(() => {});
    });
  } else {
    const dot = document.getElementById('canvas-notify-dot');
    if (dot) dot.style.display = 'none';
  }
  if (canvasProjectRoot) {
    canvasLoadWorkspaceFiles(canvasProjectRoot).catch(() => {});
    loadCanvasPublishState().catch(() => {});
  } else {
    updateCanvasWorkspaceChrome();
    renderCanvasPublishControls();
  }
  applyCreativeModeUI();
  renderBrowserCanvasSurface();
  // Instantly refresh pending actions for the new session
  if (typeof window.loadSessionApprovals === 'function') window.loadSessionApprovals();
  // Sync button/input state for the newly active session
  const activeSessThinking = syncActiveSessionRunState();
  if (typeof window.setButtonState === 'function') window.setButtonState(activeSessThinking);
  updateQueuedPromptUI();
}

function refreshVisibleChannelsList() {
  const channelPanel = document.getElementById('sidebar-channels');
  if (!channelPanel || channelPanel.style.display === 'none') return;
  if (typeof window.renderChannelsList === 'function') window.renderChannelsList();
}

function persistActiveChat() {
  const idx = window.chatSessions.findIndex(s => s.id === window.activeChatSessionId);
  if (idx === -1) return;
  window.chatSessions[idx].history = window.chatHistory;
  window.chatSessions[idx].processLog = window.processLogEntries;
  window.chatSessions[idx].progressState = window.runtimeProgressState;
  window.chatSessions[idx].title = makeSessionTitle(window.chatHistory);
  window.chatSessions[idx].updatedAt = Date.now();
  window.chatSessions[idx].creativeMode = normalizeCreativeMode(window.currentCreativeMode);
  window.chatSessions[idx].canvasProjectRoot = canvasProjectRoot || null;
  window.chatSessions[idx].canvasProjectLabel = canvasProjectLabel || null;
  window.chatSessions[idx].canvasProjectLink = normalizeCanvasProjectLink(canvasProjectLink);
  window.chatSessions[idx].creativeSceneDoc = creativeSceneDoc || null;
  window.chatSessions[idx].creativeSelectedId = creativeSelectedId || null;
  window.chatSessions[idx].creativeTimelineMs = Number.isFinite(Number(creativeTimelineMs)) ? Number(creativeTimelineMs) : 0;
  window.chatSessions[idx].creativeHistoryPast = creativeHistoryPast.slice();
  window.chatSessions[idx].creativeHistoryFuture = creativeHistoryFuture.slice();
  window.chatSessions[idx].creativeHtmlMotionClip = creativeHtmlMotionClip || null;
  window.chatSessions[idx].browserCanvasState = snapshotBrowserCanvasSessionState();
  // Save canvas files for this session (diskPath + name only, content re-fetched from disk)
  window.chatSessions[idx].canvasFiles = canvasTabs
    .filter(t => t.diskPath)
    .map(t => ({ diskPath: t.diskPath, name: t.name }));
  saveChatSessions();
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
  if (typeof window.updateStats === 'function') window.updateStats([]);
}

// Load terminal sessions from the server
async function loadTerminalSessions() {
  try {
    const res = await fetch('/api/sessions?channel=terminal');
    const data = await res.json();
    window.terminalSessions = Array.isArray(data.sessions) ? data.sessions : [];
  } catch {
    window.terminalSessions = [];
  }
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
}

// Open a terminal session by loading it from the server and adding to chat sessions
async function openTerminalSession(id) {
  try {
    const res = await fetch(`/api/sessions/${id}`);
    const data = await res.json();
    if (!data.session) return;
    const s = data.session;

    // Check if already in chatSessions
    let existing = window.chatSessions.find(c => c.id === id);
    if (!existing) {
      existing = {
        id: s.id,
        title: s.title || s.id,
        history: (s.history || []).map(m => ({
          role: m.role === 'user' ? 'user' : 'assistant',
          content: m.content,
          timestamp: m.timestamp,
          channel: 'terminal',
          channelLabel: 'terminal',
        })),
        processLog: [],
        creativeMode: normalizeCreativeMode(s.creativeMode),
        canvasProjectRoot: normalizeCanvasPath(s.canvasProjectRoot) || null,
        canvasProjectLabel: s.canvasProjectLabel || null,
        canvasProjectLink: normalizeCanvasProjectLink(s.canvasProjectLink),
        creativeSceneDoc: s.creativeSceneDoc || null,
        creativeSelectedId: s.creativeSelectedId || null,
        creativeTimelineMs: Number.isFinite(Number(s.creativeTimelineMs)) ? Number(s.creativeTimelineMs) : 0,
        creativeHistoryPast: Array.isArray(s.creativeHistoryPast) ? s.creativeHistoryPast : [],
        creativeHistoryFuture: Array.isArray(s.creativeHistoryFuture) ? s.creativeHistoryFuture : [],
        creativeHtmlMotionClip: s.creativeHtmlMotionClip || null,
        createdAt: s.createdAt,
        updatedAt: s.lastActiveAt,
        automated: false,
        source: 'terminal',
      };
      window.chatSessions.unshift(existing);
      saveChatSessions();
    }

    if (window.currentMode !== 'chat') {
      if (typeof window.setMode === 'function') window.setMode('chat');
      else setMode('chat');
    }

    window.activeChatSessionId = id;
    setAgentSessionId(id);
    syncActiveChat();
    refreshVisibleChannelsList();
  } catch (e) {
    addProcessEntry('error', `Could not load terminal session: ${e.message}`);
  }
}

function newChatSession() {
  const id = generateSessionId();
  if (window.currentMode !== 'chat') {
    if (typeof window.setMode === 'function') window.setMode('chat');
    else setMode('chat');
  }
  if (typeof window.setSidebarSegTab === 'function') window.setSidebarSegTab('chats');
  window.activeChatSessionId = id;
  setAgentSessionId(id);
  syncActiveChat();
  // New regular chat always exits project mode
  if (typeof window._maybeClearProjectState === 'function') {
    window._maybeClearProjectState(id);
  }
}

function toggleSessionsEditMode() {
  window.sessionsEditMode = !window.sessionsEditMode;
  const btn = document.getElementById('sessions-edit-btn');
  if (btn) btn.textContent = window.sessionsEditMode ? 'Done' : 'Edit';
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
}

async function deleteChatSession(id, ev) {
  if (ev) ev.stopPropagation();
  const idx = window.chatSessions.findIndex(s => s.id === id);
  try {
    await deleteSessionFromServer(id);
  } catch (err) {
    showToast(`Delete failed: ${err.message}`, 'error');
    return;
  }

  if (idx !== -1) window.chatSessions.splice(idx, 1);
  if (Array.isArray(window.terminalSessions)) {
    window.terminalSessions = window.terminalSessions.filter(s => s.id !== id);
  }
  if (window.chatSessions.length === 0) {
    const newId = generateSessionId();
    window.activeChatSessionId = newId;
    setAgentSessionId(newId);
  } else if (window.activeChatSessionId === id) {
    window.activeChatSessionId = window.chatSessions[0].id;
    setAgentSessionId(window.activeChatSessionId);
  }

  saveChatSessions();
  syncActiveChat();
  if (typeof window.loadProjects === 'function') window.loadProjects();
  if (typeof window.renderChannelsList === 'function') window.renderChannelsList();
}

async function openSession(id) {
  if (window.currentMode !== 'chat') {
    if (typeof window.setMode === 'function') window.setMode('chat');
    else setMode('chat');
  }
  window.activeChatSessionId = id;
  setAgentSessionId(id);
  const sess = window.chatSessions.find(s => s.id === id);
  if (sess && sess._needsServerLoad) {
    await _loadSessionFromServer(id);
  }
  syncActiveChat();
  refreshVisibleChannelsList();
  // Clear project state if switching to a non-project session
  if (typeof window._maybeClearProjectState === 'function') {
    window._maybeClearProjectState(id);
  }
}

function markSessionUnread(sessionId) {
  const sess = window.chatSessions.find(s => s.id === sessionId);
  if (sess && sessionId !== window.activeChatSessionId) {
    sess.unread = true;
    if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
  }
}

function upsertAutomatedSession(as, opts = {}) {
  if (!as || !as.id) return false;
  if (isInternalChatSession(as) || /^brain_/i.test(String(as.jobId || ''))) return false;
  const markUnread = opts.markUnread !== false;
  const mappedHistory = Array.isArray(as.history)
    ? as.history.map((m) => ({
        role: m.role === 'ai' ? 'assistant' : (m.role === 'assistant' ? 'assistant' : 'user'),
        content: String(m.content || ''),
        timestamp: Number(m.timestamp) || Date.now(),
        channel: String(m.channel || ''),
        channelLabel: String(m.channelLabel || ''),
      }))
    : [];
  const nextSession = {
    id: as.id,
    title: as.title || 'Automated Session',
    history: mappedHistory,
    processLog: [],
    creativeMode: normalizeCreativeMode(as.creativeMode),
    canvasProjectRoot: normalizeCanvasPath(as.canvasProjectRoot) || null,
    canvasProjectLabel: as.canvasProjectLabel || null,
    canvasProjectLink: normalizeCanvasProjectLink(as.canvasProjectLink),
    creativeSceneDoc: as.creativeSceneDoc || null,
    creativeSelectedId: as.creativeSelectedId || null,
    creativeTimelineMs: Number.isFinite(Number(as.creativeTimelineMs)) ? Number(as.creativeTimelineMs) : 0,
    creativeHistoryPast: Array.isArray(as.creativeHistoryPast) ? as.creativeHistoryPast : [],
    creativeHistoryFuture: Array.isArray(as.creativeHistoryFuture) ? as.creativeHistoryFuture : [],
    creativeHtmlMotionClip: as.creativeHtmlMotionClip || null,
    createdAt: Number(as.createdAt) || Date.now(),
    updatedAt: Date.now(),
    automated: true,
    jobName: as.jobName || '',
    source: String(as.source || ''),
    unread: markUnread,
  };
  const existingIdx = window.chatSessions.findIndex(s => s.id === as.id);
  if (existingIdx === -1) window.chatSessions.push(nextSession);
	  else window.chatSessions[existingIdx] = { ...window.chatSessions[existingIdx], ...nextSession };
  saveChatSessions();
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
  if (window.activeChatSessionId === as.id) renderChatMessages();
  return true;
}

// ---- Mode switching ----
function setMode(mode) {
  const validModes = ['chat', 'bgtasks', 'schedule', 'teams', 'proposals', 'audit', 'memory'];
  if (!validModes.includes(mode)) mode = 'chat';
  window.currentMode = mode;

  // Activate v2 sidebar nav items
  validModes.forEach((m) => {
    const el = document.getElementById(`nav-${m}`);
    if (el) el.classList.toggle('active', m === mode);
  });
  // More popover items
  ['audit', 'memory'].forEach(m => {
    const el = document.getElementById(`nav-${m}`);
    if (el) el.classList.toggle('active', m === mode);
  });
  const moreBtn = document.getElementById('moreNavBtn');
  if (moreBtn) moreBtn.classList.toggle('active', mode === 'audit' || mode === 'memory');
  if (typeof window.closeMorePopover === 'function') window.closeMorePopover();

  // Update page title in topbar
  const pageTitles = {
    chat: ['Chat', 'Prometheus operator workspace'],
    bgtasks: ['Tasks', 'Background task queue'],
    schedule: ['Schedule', 'Recurring + one-off jobs'],
    teams: ['Teams', 'Managed agent teams'],
    proposals: ['Proposals', 'Awaiting approval'],
    audit: ['Audit Log', 'Non-main agent runs'],
    memory: ['Memory Graph', 'Knowledge web'],
  };
  const parts = pageTitles[mode] || ['Chat', ''];
  const titleEl = document.getElementById('page-title-text');
  const subEl = document.getElementById('page-title-sub');
  if (titleEl) titleEl.textContent = parts[0];
  if (subEl) subEl.textContent = parts[1];

  // Toggle view panels
  const viewMap = {
    chat: 'chat-view',
    bgtasks: 'bgtasks-view',
    schedule: 'schedule-view',
    teams: 'teams-view',
    proposals: 'proposals-view',
    audit: 'audit-view',
    memory: 'memory-view',
  };
  Object.entries(viewMap).forEach(([m, viewId]) => {
    const el = document.getElementById(viewId);
    if (el) el.style.display = m === mode ? 'flex' : 'none';
  });

  // In v2 layout: sidebar is always visible; main-shell hidden for non-chat modes
  const mainEl = document.querySelector('main.main-shell');
  if (mainEl) mainEl.style.display = mode === 'chat' ? '' : 'none';
  // Right panel: close when switching away from chat; hide toggle on non-chat pages
  const rightPanel = document.getElementById('right-panel');
  const toggleBtn = document.getElementById('drawerToggle');
  if (mode !== 'chat') {
    if (rightPanel) {
      rightPanel.classList.remove('open');
      rightPanel.style.removeProperty('width');
      rightPanel.style.removeProperty('min-width');
      rightPanel.style.removeProperty('max-width');
    }
    document.body.classList.add('right-collapsed');
    if (toggleBtn) { toggleBtn.classList.remove('active'); toggleBtn.style.display = 'none'; }
  } else {
    document.body.classList.toggle('right-collapsed', !(rightPanel?.classList.contains('open')));
    if (toggleBtn) toggleBtn.style.display = '';
  }
  if (typeof window._syncPageViewPositions === 'function') window._syncPageViewPositions();

  // Load data for selected page
  if (mode === 'bgtasks' && typeof window.refreshBgTasks === 'function') window.refreshBgTasks();
  if (mode === 'schedule' && typeof window.refreshSchedules === 'function') window.refreshSchedules();
  if (mode === 'teams') {
    const badge = document.getElementById('teams-badge');
    if (badge) badge.style.display = 'none';
    if (typeof window.teamsPageActivate === 'function') window.teamsPageActivate();
    else if (typeof window.refreshTeams === 'function') window.refreshTeams();
  }
  if (mode === 'proposals') {
    if (typeof window.loadProposals === 'function') window.loadProposals();
    const badge = document.getElementById('proposals-badge');
    if (badge) badge.style.display = 'none';
  }
  if (mode === 'audit' && typeof window.loadAuditLog === 'function') window.loadAuditLog();
  if (mode === 'memory' && typeof window.memoryPageActivate === 'function') window.memoryPageActivate();
}

// ---- Proposals — EXTRACTED to src/pages/ProposalsPage.js (F3b) ----
// Functions: loadProposals, renderProposals, updateProposalBadge,
//            jumpToProposalSession, approveProposal, denyProposal

// ---- Sidebar tabs ----
function setSidebarTab(tab) {
  // Map old tab names to new seg tab names
  const tabMap = { jobs: 'chats', skills: 'skills', projects: 'projects' };
  const newTab = tabMap[tab] || tab;
  if (typeof window.setSidebarSegTab === 'function') {
    window.setSidebarSegTab(newTab);
  }
  if (tab === 'skills' || newTab === 'skills') window.loadInstalledSkills?.();
}

// ---- Agent mode toggle ----
function updateAgentMode() {
  window.useAgentMode = document.getElementById('agent-mode-toggle').checked;
  document.getElementById('agent-mode-label').textContent = window.useAgentMode ? 'Agent' : 'Chat';
  document.getElementById('agent-mode-badge').classList.toggle('visible', window.useAgentMode);
  refreshActiveSlashCommandChrome();
}

// ---- Chat ----
function renderThinkBlock(thinking) {
  if (!thinking || !thinking.trim()) return '';
  const id = 'think_' + Math.random().toString(36).slice(2);
  const wordCount = thinking.trim().split(/\s+/).length;
  return `
    <div class="think-block">
      <button class="think-toggle" id="${id}_btn" onclick="toggleThink('${id}')">
        <span class="think-icon">...</span>
        <span>Thought process</span>
        <span style="margin-left:auto;opacity:0.5">${wordCount} words</span>
      </button>
      <div class="think-content" id="${id}_body">${escHtml(thinking)}</div>
    </div>
  `;
}

function toggleThink(id) {
  const btn = document.getElementById(id + '_btn');
  const body = document.getElementById(id + '_body');
  if (!btn || !body) return;
  const open = body.style.display !== 'none' && body.style.display !== '';
  body.style.display = open ? 'none' : 'block';
  btn.classList.toggle('open', !open);
}

function renderReactSteps(steps) {
  if (!steps || steps.length === 0) return '';
  const toolSteps = steps.filter(s => s.action);
  if (toolSteps.length === 0) return '';

  const getSearchDiagnostics = (s) => s?.toolData?.search_diagnostics || s?.diagnostics || null;
  const extractUrls = (s, resultText) => {
    const fromToolData = Array.isArray(s?.toolData?.results)
      ? s.toolData.results.map(r => String(r?.url || '').trim()).filter(u => /^https?:\/\//i.test(u))
      : [];
    const fromText = String(resultText || '').match(/https?:\/\/[^\s)]+/g) || [];
    const merged = [...fromToolData, ...fromText.map(u => String(u).trim())];
    const out = [];
    const seen = new Set();
    for (const u of merged) {
      if (!u || seen.has(u)) continue;
      seen.add(u);
      out.push(u);
      if (out.length >= 5) break;
    }
    return out;
  };
  const providerSummary = (diag) => {
    if (!diag || !Array.isArray(diag.attempted) || !diag.attempted.length) return '';
    return diag.attempted.map(a => {
      const p = String(a.provider || '').toLowerCase();
      const status = String(a.status || '').toLowerCase();
      if (status === 'success') {
        const count = Number.isFinite(a.result_count) ? `, ${a.result_count} result${a.result_count === 1 ? '' : 's'}` : '';
        return `${p}=success${count}`;
      }
      if (status === 'skipped') return `${p}=skipped${a.reason ? ` (${a.reason})` : ''}`;
      return `${p}=failed${a.reason ? ` (${a.reason})` : ''}`;
    }).join(' | ');
  };

  const id = 'steps_' + Math.random().toString(36).slice(2);
  const items = toolSteps.map(s => {
    const resultText = typeof s.toolResult === 'string' ? s.toolResult : JSON.stringify(s.toolResult || '');
    const diag = String(s.action || '') === 'web_search' ? getSearchDiagnostics(s) : null;
    const query = String(diag?.query || s?.params?.query || '').trim();
    const selectedProvider = String(diag?.selected_provider || s?.toolData?.provider || '').toLowerCase();
    const providers = diag ? providerSummary(diag) : '';
    const urls = String(s.action || '') === 'web_search' ? extractUrls(s, resultText) : [];
    return `
      <div class="react-step">
        ${s.thought ? `<div class="react-step-thought">${escHtml(s.thought.slice(0, 120))}</div>` : ''}
        <div class="react-step-action">${escHtml(s.action)}</div>
        ${resultText ? `<div class="react-step-result${resultText.startsWith('ERROR') ? ' error' : ''}">${escHtml(resultText.slice(0, 160))}${resultText.length > 160 ? '…' : ''}</div>` : ''}
        ${diag ? `
          <div style="margin-top:6px;font-size:10px;color:var(--muted);line-height:1.5">
            ${query ? `<div><b>query</b>: ${escHtml(query)}</div>` : ''}
            ${selectedProvider ? `<div><b>provider hit</b>: ${escHtml(selectedProvider)}</div>` : ''}
            ${providers ? `<div><b>providers</b>: ${escHtml(providers)}</div>` : ''}
          </div>
        ` : ''}
        ${String(s.action || '') === 'web_search' && !diag ? `
          <div style="margin-top:6px;font-size:10px;color:var(--muted);line-height:1.5">
            ${selectedProvider ? `<div><b>provider hit</b>: ${escHtml(selectedProvider)}</div>` : ''}
          </div>
        ` : ''}
        ${urls.length ? `
          <div style="margin-top:6px;font-size:10px;line-height:1.6">
            <div style="color:var(--muted);margin-bottom:2px"><b>sources</b>:</div>
            ${urls.slice(0, 3).map((u, i) => `<div>${i + 1}. <a href="${escHtml(u)}" target="_blank" rel="noopener noreferrer">${escHtml(u)}</a></div>`).join('')}
          </div>
        ` : ''}
      </div>
    `;
  }).join('');

  return `
    <div class="react-steps-toggle" onclick="toggleSteps('${id}')">
      ? ${toolSteps.length} tool step${toolSteps.length !== 1 ? 's' : ''} used
    </div>
    <div class="react-steps" id="${id}" style="display:none">${items}</div>
  `;
}

function toggleSteps(id) {
  const el = document.getElementById(id);
  if (!el) return;
  const visible = el.style.display !== 'none';
  el.style.display = visible ? 'none' : 'block';
  el.previousElementSibling.textContent = `${visible ? '?' : '?'} ${el.querySelectorAll('.react-step').length} tool step${el.querySelectorAll('.react-step').length !== 1 ? 's' : ''} used`;
}

function renderAssistantContent(content) {
  const text = String(content || '');
  const bgHeaderMatch = text.match(/\nBackground agent response:\s*\n?/i) || text.match(/^Background agent response:\s*\n?/i);
  if (bgHeaderMatch && typeof bgHeaderMatch.index === 'number') {
    const splitAt = bgHeaderMatch.index;
    const head = text.slice(0, splitAt).trim();
    const bgBody = text.slice(splitAt + bgHeaderMatch[0].length).trim();
    return `
      <div class="msg-staged">
        ${head ? `<div class="msg-content markdown-body">${renderMd(head)}</div>` : ''}
        <div class="msg-stage">
          <div class="msg-stage-title">Background agent response</div>
          <div class="msg-content markdown-body">${renderMd(bgBody || 'No background details provided.')}</div>
        </div>
      </div>
    `;
  }
  const hasStaged = /(^|\n)(Initial chat|Execution result|Final chat):\s*/i.test(text);
  if (!hasStaged) return `<div class="msg-content markdown-body">${renderMd(text)}</div>`;
  const chunks = text
    .split(/\n\s*---\s*\n/g)
    .map(s => String(s || '').trim())
    .filter(Boolean);
  const html = chunks.map((chunk, idx) => {
    const m = chunk.match(/^(Initial chat|Execution result|Final chat):\s*\n?/i);
    const title = m ? m[1] : `Section ${idx + 1}`;
    const body = m ? chunk.slice(m[0].length).trim() : chunk;
    return `
      <div class="msg-stage">
        <div class="msg-stage-title">${escHtml(title)}</div>
        <div class="msg-content markdown-body">${renderMd(body)}</div>
      </div>
    `;
  }).join('');
  return `<div class="msg-staged">${html}</div>`;
}

// File extension → icon SVG path data and color
