  return icons[ext] || { color:'#5f6f85', label: ext.toUpperCase().slice(0,4) || 'FILE', path:'M14 2H6c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h12c1.1 0 2-.9 2-2V8l-6-6zm-1 7V3.5L18.5 9H13z' };
