function renderFilePills(canvasFiles) {
  if (!Array.isArray(canvasFiles) || !canvasFiles.length) return '';
  const pills = canvasFiles.map(filePath => {
    const path = String(filePath || '');
    const name = path.split('/').pop().split('\\').pop() || path;
    const ext = name.split('.').pop().toLowerCase();
    const icon = getFileIcon(name);
    const pathArg = encodeInlineJsString(path);
    const nameArg = encodeInlineJsString(name);
    return `
      <div class="file-pill">
        <div class="file-pill-icon">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="${escHtml(icon.color)}">
            <path d="${escHtml(icon.path)}"/>
          </svg>
        </div>
        <div class="file-pill-info">
          <div class="file-pill-name">${escHtml(name)}</div>
          <div class="file-pill-meta">${escHtml(ext.toUpperCase())} file &middot; workspace</div>
        </div>
        <div class="file-pill-actions">
          <button class="file-pill-btn" title="Open in Canvas" onclick="canvasPresentFile(${pathArg}, ${nameArg})">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="3" width="20" height="18" rx="2"/><path d="M8 9l-4 3 4 3"/><path d="M16 9l4 3-4 3"/><path d="M12 6v12"/></svg>
          </button>
          <button class="file-pill-btn" title="Download" onclick="canvasDownloadFile(${pathArg}, ${nameArg})">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
          </button>
        </div>
      </div>`;
  }).join('');
  return `<div class="file-pills">${pills}</div>`;
}

function canvasDownloadFile(diskPath, filename) {
  const targetPath = String(diskPath || '').trim();
  if (!targetPath) return;
  const anchor = document.createElement('a');
  anchor.href = `/api/canvas/download?path=${encodeURIComponent(targetPath)}`;
  anchor.download = filename || targetPath.split('/').pop() || 'file';
  anchor.style.display = 'none';
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
}

function formatGeneratedImageSize(bytes) {
  const value = Number(bytes || 0);
  if (!Number.isFinite(value) || value <= 0) return '';
  if (value >= 1024 * 1024) return `${(value / (1024 * 1024)).toFixed(1)} MB`;
  if (value >= 1024) return `${Math.max(1, Math.round(value / 1024))} KB`;
  return `${Math.max(1, Math.round(value))} B`;
}

function normalizeGeneratedImageEntry(raw) {
  if (!raw || typeof raw !== 'object') return null;
  const relPath = normalizeCanvasPath(raw.rel_path || raw.relPath || '');
  const absPath = normalizeCanvasPath(raw.path || raw.absPath || '');
  const cachePath = normalizeCanvasPath(raw.cache_path || raw.cachePath || '');
  const previewPath = absPath || relPath || cachePath;
  if (!previewPath) return null;
  const fileName = String(raw.file_name || raw.fileName || previewPath.split('/').pop() || 'generated-image.png').trim();
  return {
    previewPath,
    relPath,
    absPath,
    cachePath,
    fileName,
    mimeType: String(raw.mime_type || raw.mimeType || '').trim(),
    provider: String(raw.provider || '').trim(),
    model: String(raw.model || '').trim(),
    prompt: String(raw.prompt || '').trim(),
    revisedPrompt: String(raw.revised_prompt || raw.revisedPrompt || '').trim(),
    aspectRatio: String(raw.aspect_ratio || raw.aspectRatio || '').trim(),
    bytes: Number(raw.bytes || 0) || 0,
  };
}

function getGeneratedImagePreviewPath(image) {
  const normalized = normalizeGeneratedImageEntry(image);
  return normalized ? normalized.previewPath : '';
}

function getGeneratedImageCopyPath(image) {
  const normalized = normalizeGeneratedImageEntry(image);
  return normalized ? (normalized.absPath || normalized.relPath || normalized.previewPath) : '';
}

function getGeneratedImageInlineSrc(image) {
  const previewPath = getGeneratedImagePreviewPath(image);
  return previewPath ? `/api/canvas/inline?path=${encodeURIComponent(previewPath)}` : '';
}

async function copyTextToClipboard(text, successTitle, successBody = '') {
  const value = String(text || '').trim();
  if (!value) return;
  try {
    if (!navigator.clipboard?.writeText) throw new Error('Clipboard access is not available.');
    await navigator.clipboard.writeText(value);
    showToast(successTitle, successBody, 'success');
  } catch (err) {
    showToast('Clipboard copy failed', String(err?.message || err || 'Unknown clipboard error.'), 'error');
  }
}

async function copyGeneratedImagePath(pathValue) {
  const normalizedPath = normalizeCanvasPath(pathValue || '');
  if (!normalizedPath) return;
  const filename = normalizedPath.split('/').pop() || normalizedPath;
  await copyTextToClipboard(normalizedPath, 'Image path copied', filename);
}

async function copyGeneratedImageToClipboard(diskPath, filename = 'generated-image.png') {
  const previewPath = normalizeCanvasPath(diskPath || '');
  if (!previewPath) return;
  try {
    if (!navigator.clipboard?.write || typeof window.ClipboardItem === 'undefined') {
      throw new Error('Image clipboard copy is not supported in this browser.');
    }
    const response = await fetch(`/api/canvas/inline?path=${encodeURIComponent(previewPath)}`);
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const blob = await response.blob();
    const mimeType = blob.type || 'image/png';
    await navigator.clipboard.write([
      new window.ClipboardItem({ [mimeType]: blob }),
    ]);
    showToast('Image copied', filename, 'success');
  } catch (err) {
    showToast('Image copy failed', String(err?.message || err || 'Unknown clipboard error.'), 'error');
  }
}

function loadCreativeImageElement(source) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error('Could not load image pixels.'));
    img.decoding = 'async';
    img.crossOrigin = 'anonymous';
    img.src = creativeMediaSourceUrl(source);
  });
}

function cssRgbaFromPixel(data, offset) {
  const r = data[offset];
  const g = data[offset + 1];
  const b = data[offset + 2];
  const a = data[offset + 3];
  if (a >= 255) return `rgb(${r}, ${g}, ${b})`;
  return `rgba(${r}, ${g}, ${b}, ${Math.max(0, Math.min(1, a / 255)).toFixed(3)})`;
}

function pixelsHaveSameColor(data, leftOffset, rightOffset) {
  return data[leftOffset] === data[rightOffset]
    && data[leftOffset + 1] === data[rightOffset + 1]
    && data[leftOffset + 2] === data[rightOffset + 2]
    && data[leftOffset + 3] === data[rightOffset + 3];
}

function isLikelySpriteSheetForegroundPixel(data, offset) {
  const alpha = data[offset + 3];
  if (alpha <= 10) return false;
  if (alpha < 220) return true;
  const r = data[offset];
  const g = data[offset + 1];
  const b = data[offset + 2];
  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  if (max >= 34) return true;
  return max >= 24 && max - min >= 10;
}

function dilateBinaryMask(mask, width, height, radius) {
  const dilated = new Uint8Array(mask.length);
  const r = Math.max(1, Math.round(radius) || 1);
  for (let y = 0; y < height; y += 1) {
    for (let x = 0; x < width; x += 1) {
      if (!mask[(y * width) + x]) continue;
      const x0 = Math.max(0, x - r);
      const x1 = Math.min(width - 1, x + r);
      const y0 = Math.max(0, y - r);
      const y1 = Math.min(height - 1, y + r);
      for (let yy = y0; yy <= y1; yy += 1) {
        const row = yy * width;
        for (let xx = x0; xx <= x1; xx += 1) {
          dilated[row + xx] = 1;
        }
      }
    }
  }
  return dilated;
}

function getConnectedMaskBoxes(mask, width, height) {
  const visited = new Uint8Array(mask.length);
  const boxes = [];
  const queue = [];
  for (let y = 0; y < height; y += 1) {
    for (let x = 0; x < width; x += 1) {
      const start = (y * width) + x;
      if (!mask[start] || visited[start]) continue;
      let qIndex = 0;
      let count = 0;
      let minX = x;
      let maxX = x;
      let minY = y;
      let maxY = y;
      visited[start] = 1;
      queue.length = 0;
      queue.push(start);
      while (qIndex < queue.length) {
        const idx = queue[qIndex++];
        const px = idx % width;
        const py = Math.floor(idx / width);
        count += 1;
        if (px < minX) minX = px;
        if (px > maxX) maxX = px;
        if (py < minY) minY = py;
        if (py > maxY) maxY = py;
        const neighbors = [
          px > 0 ? idx - 1 : -1,
          px < width - 1 ? idx + 1 : -1,
          py > 0 ? idx - width : -1,
          py < height - 1 ? idx + width : -1,
        ];
        for (const next of neighbors) {
          if (next < 0 || !mask[next] || visited[next]) continue;
          visited[next] = 1;
          queue.push(next);
        }
      }
      boxes.push({ x: minX, y: minY, width: maxX - minX + 1, height: maxY - minY + 1, count });
    }
  }
  return boxes;
}

function boxesTouchOrOverlap(a, b, margin) {
  return a.x <= b.x + b.width + margin
    && b.x <= a.x + a.width + margin
    && a.y <= b.y + b.height + margin
    && b.y <= a.y + a.height + margin;
}

function boxOverlapRatio(a, b) {
  const left = Math.max(Number(a.x) || 0, Number(b.x) || 0);
  const top = Math.max(Number(a.y) || 0, Number(b.y) || 0);
  const right = Math.min((Number(a.x) || 0) + (Number(a.width) || 0), (Number(b.x) || 0) + (Number(b.width) || 0));
  const bottom = Math.min((Number(a.y) || 0) + (Number(a.height) || 0), (Number(b.y) || 0) + (Number(b.height) || 0));
  const area = Math.max(0, right - left) * Math.max(0, bottom - top);
  const minArea = Math.max(1, Math.min((Number(a.width) || 0) * (Number(a.height) || 0), (Number(b.width) || 0) * (Number(b.height) || 0)));
  return area / minArea;
}

function mergeNearbyBoxes(boxes, margin) {
  const merged = boxes.map((box) => ({ ...box }));
  let changed = true;
  while (changed) {
    changed = false;
    for (let i = 0; i < merged.length; i += 1) {
      for (let j = i + 1; j < merged.length; j += 1) {
        if (!boxesTouchOrOverlap(merged[i], merged[j], margin)) continue;
        const left = Math.min(merged[i].x, merged[j].x);
        const top = Math.min(merged[i].y, merged[j].y);
        const right = Math.max(merged[i].x + merged[i].width, merged[j].x + merged[j].width);
        const bottom = Math.max(merged[i].y + merged[i].height, merged[j].y + merged[j].height);
        merged[i] = {
          x: left,
          y: top,
          width: right - left,
          height: bottom - top,
          count: (merged[i].count || 0) + (merged[j].count || 0),
        };
        merged.splice(j, 1);
        changed = true;
        break;
      }
      if (changed) break;
    }
  }
  return merged;
}

function padAndClampBox(box, pad, width, height) {
  const x = Math.max(0, Math.floor(box.x - pad));
  const y = Math.max(0, Math.floor(box.y - pad));
  const right = Math.min(width, Math.ceil(box.x + box.width + pad));
  const bottom = Math.min(height, Math.ceil(box.y + box.height + pad));
  return {
    x,
    y,
    width: Math.max(1, right - x),
    height: Math.max(1, bottom - y),
    count: box.count || 0,
  };
}

function findMaskProjectionSegments(mask, width, height, box, axis, options = {}) {
  const minGap = Math.max(2, Math.round(Number(options.minGap) || 2));
  const minSegment = Math.max(4, Math.round(Number(options.minSegment) || 4));
  const segments = [];
  const start = axis === 'x' ? box.x : box.y;
  const length = axis === 'x' ? box.width : box.height;
  const crossStart = axis === 'x' ? box.y : box.x;
  const crossLength = axis === 'x' ? box.height : box.width;
  const threshold = Math.max(0, Math.round(crossLength * (Number(options.thresholdRatio) || 0.04)));
  const projection = new Array(length).fill(0);
  for (let i = 0; i < length; i += 1) {
    const coord = start + i;
    let count = 0;
    for (let j = 0; j < crossLength; j += 1) {
      const cross = crossStart + j;
      const x = axis === 'x' ? coord : cross;
      const y = axis === 'x' ? cross : coord;
      if (x < 0 || x >= width || y < 0 || y >= height) continue;
      if (mask[(y * width) + x]) count += 1;
    }
    projection[i] = count;
  }

  let segmentStart = 0;
  let gapStart = -1;
  for (let i = 0; i <= length; i += 1) {
    const isGap = i >= length || projection[i] <= threshold;
    if (isGap && gapStart < 0) {
      gapStart = i;
    } else if (!isGap && gapStart >= 0) {
      if (gapStart - segmentStart >= minSegment && i - gapStart >= minGap) {
        segments.push({ start: start + segmentStart, end: start + gapStart });
        segmentStart = i;
      }
      gapStart = -1;
    }
    if (i >= length && segmentStart < length && length - segmentStart >= minSegment) {
      segments.push({ start: start + segmentStart, end: start + length });
    }
  }
  return segments.length ? segments : [{ start, end: start + length }];
}

function trimMaskBox(mask, width, height, box) {
  let minX = Infinity;
  let minY = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;
  let count = 0;
  const left = Math.max(0, Math.floor(box.x));
  const top = Math.max(0, Math.floor(box.y));
  const right = Math.min(width, Math.ceil(box.x + box.width));
  const bottom = Math.min(height, Math.ceil(box.y + box.height));
  for (let y = top; y < bottom; y += 1) {
    const row = y * width;
    for (let x = left; x < right; x += 1) {
      if (!mask[row + x]) continue;
      count += 1;
      if (x < minX) minX = x;
      if (x > maxX) maxX = x;
      if (y < minY) minY = y;
      if (y > maxY) maxY = y;
    }
  }
  if (!count) return null;
  return { x: minX, y: minY, width: maxX - minX + 1, height: maxY - minY + 1, count };
}

function splitMergedSpriteSheetBoxes(boxes, mask, width, height, options = {}) {
  const maxSide = Math.max(width, height);
  const minBoxSize = Math.max(10, Math.round(Number(options.minBoxSize) || maxSide * 0.035));
  const minArea = Math.max(60, Math.round(Number(options.minArea) || width * height * 0.00055));
  const maxArea = Math.max(minArea, Number(options.maxArea) || width * height * 0.38);
  const minGap = Math.max(3, Math.round(maxSide * 0.008));
  const splitBoxes = [];

  for (const box of boxes) {
    const xSegments = findMaskProjectionSegments(mask, width, height, box, 'x', {
      minGap,
      minSegment: minBoxSize,
      thresholdRatio: 0.035,
    });
    const ySegments = findMaskProjectionSegments(mask, width, height, box, 'y', {
      minGap,
      minSegment: minBoxSize,
      thresholdRatio: 0.035,
    });
    const shouldSplit = xSegments.length > 1 || ySegments.length > 1;
    if (!shouldSplit) {
      splitBoxes.push(box);
      continue;
    }
    for (const ySeg of ySegments) {
      for (const xSeg of xSegments) {
        const candidate = trimMaskBox(mask, width, height, {
          x: xSeg.start,
          y: ySeg.start,
          width: xSeg.end - xSeg.start,
          height: ySeg.end - ySeg.start,
        });
        if (!candidate) continue;
        if (candidate.count < minArea) continue;
        if (candidate.width < minBoxSize || candidate.height < minBoxSize) continue;
        if (candidate.width * candidate.height > maxArea) continue;
        splitBoxes.push(candidate);
      }
    }
  }

  const deduped = [];
  for (const box of splitBoxes.sort((a, b) => (a.y - b.y) || (a.x - b.x))) {
    const duplicate = deduped.some((candidate) => boxOverlapRatio(candidate, box) > 0.82);
    if (!duplicate) deduped.push(box);
  }
  return deduped;
}

function medianNumber(values) {
  const nums = values.map((value) => Number(value)).filter((value) => Number.isFinite(value)).sort((a, b) => a - b);
  if (!nums.length) return 0;
  const mid = Math.floor(nums.length / 2);
  return nums.length % 2 ? nums[mid] : (nums[mid - 1] + nums[mid]) / 2;
}

function clusterBoxCenters(boxes, axis, tolerance) {
  const centerKey = axis === 'x' ? 'cx' : 'cy';
  const clusters = [];
  boxes
    .map((box) => ({ ...box, cx: box.x + box.width / 2, cy: box.y + box.height / 2 }))
    .sort((a, b) => a[centerKey] - b[centerKey])
    .forEach((box) => {
      const center = box[centerKey];
      const existing = clusters.find((cluster) => Math.abs(cluster.center - center) <= tolerance);
      if (existing) {
        existing.items.push(box);
        existing.center = medianNumber(existing.items.map((item) => item[centerKey]));
      } else {
        clusters.push({ center, items: [box] });
      }
    });
  return clusters;
}

function isLikelySpriteSheetArrangement(boxes, canvasWidth, canvasHeight) {
  if (!Array.isArray(boxes) || boxes.length < 6) return false;
  const medianW = medianNumber(boxes.map((box) => box.width));
  const medianH = medianNumber(boxes.map((box) => box.height));
  if (medianW <= 0 || medianH <= 0) return false;
  const sizeConsistent = boxes.filter((box) => (
    box.width >= medianW * 0.55
    && box.width <= medianW * 1.75
    && box.height >= medianH * 0.55
    && box.height <= medianH * 1.75
  ));
  if (sizeConsistent.length / boxes.length < 0.68) return false;

  const rows = clusterBoxCenters(sizeConsistent, 'y', Math.max(10, medianH * 0.42));
  const cols = clusterBoxCenters(sizeConsistent, 'x', Math.max(10, medianW * 0.42));
  if (rows.length < 2 || cols.length < 2) return false;
  if (rows.some((row) => row.items.length < 2) && rows.length > 2) return false;

  const gridSlots = rows.length * cols.length;
  const occupancy = sizeConsistent.length / Math.max(1, gridSlots);
  if (occupancy < 0.42 || occupancy > 1.25) return false;

  const medianArea = Math.max(1, medianW * medianH);
  const totalBoxArea = sizeConsistent.reduce((sum, box) => sum + (box.width * box.height), 0);
  const canvasArea = Math.max(1, canvasWidth * canvasHeight);
  const areaRatio = totalBoxArea / canvasArea;
  if (medianArea / canvasArea > 0.32) return false;
  if (areaRatio < 0.08 || areaRatio > 0.82) return false;

  const rowCenters = rows.map((row) => row.center).sort((a, b) => a - b);
  const colCenters = cols.map((col) => col.center).sort((a, b) => a - b);
  const rowGaps = rowCenters.slice(1).map((center, index) => center - rowCenters[index]);
  const colGaps = colCenters.slice(1).map((center, index) => center - colCenters[index]);
  const medianRowGap = medianNumber(rowGaps);
  const medianColGap = medianNumber(colGaps);
  const rowGapRegular = rowGaps.length <= 1 || rowGaps.filter((gap) => gap >= medianRowGap * 0.55 && gap <= medianRowGap * 1.65).length / rowGaps.length >= 0.65;
  const colGapRegular = colGaps.length <= 1 || colGaps.filter((gap) => gap >= medianColGap * 0.55 && gap <= medianColGap * 1.65).length / colGaps.length >= 0.65;
  return rowGapRegular && colGapRegular;
}

function detectSpriteSheetTileBoxes(imageData) {
  const width = Math.max(1, Number(imageData?.width) || 1);
  const height = Math.max(1, Number(imageData?.height) || 1);
  const data = imageData?.data;
  if (!data || width < 64 || height < 64) return [];
  const maxSide = Math.max(width, height);
  const mask = new Uint8Array(width * height);
  let foregroundCount = 0;
  for (let i = 0, p = 0; i < data.length; i += 4, p += 1) {
    if (isLikelySpriteSheetForegroundPixel(data, i)) {
      mask[p] = 1;
      foregroundCount += 1;
    }
  }
  const foregroundRatio = foregroundCount / Math.max(1, width * height);
  if (foregroundRatio < 0.01 || foregroundRatio > 0.72) return [];
  const dilated = dilateBinaryMask(mask, width, height, Math.max(2, Math.round(maxSide / 160)));
  const minBoxSize = Math.max(12, Math.round(maxSide * 0.035));
  const minArea = Math.max(80, Math.round(width * height * 0.00055));
  const maxArea = width * height * 0.38;
  const rawBoxes = getConnectedMaskBoxes(dilated, width, height)
    .filter((box) => box.count >= minArea)
    .filter((box) => box.width >= minBoxSize && box.height >= minBoxSize)
    .filter((box) => box.width * box.height <= maxArea);
  if (rawBoxes.length < 2) return [];
  const merged = mergeNearbyBoxes(rawBoxes, Math.max(1, Math.round(maxSide * 0.004)));
  const split = splitMergedSpriteSheetBoxes(merged, mask, width, height, { minBoxSize, minArea, maxArea });
  const pad = Math.max(2, Math.round(maxSide * 0.007));
  const boxes = split
    .map((box) => padAndClampBox(box, pad, width, height))
    .filter((box) => box.width >= minBoxSize && box.height >= minBoxSize)
    .filter((box) => box.width * box.height <= maxArea)
    .sort((a, b) => (a.y - b.y) || (a.x - b.x));
  if (boxes.length < 2 || boxes.length > 120) return [];
  if (!isLikelySpriteSheetArrangement(boxes, width, height)) return [];
  return boxes;
}

async function canvasTryExtractSpriteSheetTilesFromSource(source) {
  let img = null;
  try {
    img = await loadCreativeImageElement(source);
  } catch {
    return false;
  }
  const naturalW = Math.max(1, Math.round(Number(img.naturalWidth) || img.width || 1));
  const naturalH = Math.max(1, Math.round(Number(img.naturalHeight) || img.height || 1));
  const maxSide = Math.max(naturalW, naturalH);
  if (maxSide <= 96 || maxSide > 2400) return false;

  let sourceCanvas = null;
  let imageData = null;
  try {
    sourceCanvas = document.createElement('canvas');
    sourceCanvas.width = naturalW;
    sourceCanvas.height = naturalH;
    const ctx = sourceCanvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return false;
    ctx.clearRect(0, 0, naturalW, naturalH);
    ctx.drawImage(img, 0, 0, naturalW, naturalH);
    imageData = ctx.getImageData(0, 0, naturalW, naturalH);
  } catch {
    return false;
  }

  const boxes = detectSpriteSheetTileBoxes(imageData);
  if (boxes.length < 2) return false;

  const selected = getSelectedCreativeElement();
  const selectedSource = selected?.type === 'image' ? normalizeCanvasPath(selected.meta?.source || '') : '';
  const targetSource = normalizeCanvasPath(source || '');
  const replaceSelected = !!selectedSource && selectedSource === targetSource;
  const canvasW = Math.max(1, Number(creativeSceneDoc.width) || naturalW);
  const canvasH = Math.max(1, Number(creativeSceneDoc.height) || naturalH);
  const scale = replaceSelected
    ? {
        x: Math.max(0.01, Number(selected.width) / naturalW || 1),
        y: Math.max(0.01, Number(selected.height) / naturalH || 1),
      }
    : {
        x: Math.min(canvasW * 0.9 / naturalW, canvasH * 0.9 / naturalH, 1),
        y: Math.min(canvasW * 0.9 / naturalW, canvasH * 0.9 / naturalH, 1),
      };
  const baseX = replaceSelected ? Number(selected.x) || 0 : Math.round((canvasW - (naturalW * scale.x)) / 2);
  const baseY = replaceSelected ? Number(selected.y) || 0 : Math.round((canvasH - (naturalH * scale.y)) / 2);
  const baseZ = replaceSelected
    ? Math.max(0, Number(selected.zIndex) || 0)
    : Math.max(0, ...(creativeSceneDoc.elements || []).map((element) => Number(element.zIndex) || 0)) + 1;
  const ops = replaceSelected ? [{ op: 'delete', id: selected.id }] : [];
  const tileIds = [];
  const stamp = Date.now().toString(36);
  boxes.forEach((box, index) => {
    const cropCanvas = document.createElement('canvas');
    cropCanvas.width = box.width;
    cropCanvas.height = box.height;
    const cropCtx = cropCanvas.getContext('2d');
    if (!cropCtx) return;
    cropCtx.imageSmoothingEnabled = false;
    cropCtx.drawImage(sourceCanvas, box.x, box.y, box.width, box.height, 0, 0, box.width, box.height);
    const id = `sprite_tile_${stamp}_${index.toString(36)}`;
    tileIds.push(id);
    ops.push({
      op: 'add',
      id,
      type: 'image',
      x: Math.round(baseX + (box.x * scale.x)),
      y: Math.round(baseY + (box.y * scale.y)),
      width: Math.max(8, Math.round(box.width * scale.x)),
      height: Math.max(8, Math.round(box.height * scale.y)),
      zIndex: baseZ + index,
      meta: {
        source: cropCanvas.toDataURL('image/png'),
        fit: 'cover',
        radius: 0,
        role: 'sprite_sheet_tile',
        sourceSheet: targetSource,
        crop: {
          x: box.x,
          y: box.y,
          width: box.width,
          height: box.height,
          naturalWidth: naturalW,
          naturalHeight: naturalH,
        },
      },
    });
  });
  if (!tileIds.length) return false;

  const nextDoc = executeSceneGraphOps(creativeSceneDoc, ops);
  creativeHtmlMotionClip = null;
  setCreativeSceneDoc(nextDoc, { recordHistory: true, render: false, persist: false });
  setCreativeSelection(tileIds[0] || null, { render: false, persist: false });
  creativeInspectorTab = 'layers';
  renderCreativeWorkspace();
  persistActiveChat();
  addProcessEntry('info', `Extracted sprite sheet into ${tileIds.length} movable image tile layer${tileIds.length === 1 ? '' : 's'}.`);
  showToast('Sprite sheet extracted', `${tileIds.length} movable image tile layer${tileIds.length === 1 ? '' : 's'} created.`, 'success');
  return true;
}

async function canvasTryExtractSpriteLayersFromSource(source) {
  let img = null;
  try {
    img = await loadCreativeImageElement(source);
  } catch {
    return false;
  }
  const spriteW = Math.max(1, Math.round(Number(img.naturalWidth) || img.width || 1));
  const spriteH = Math.max(1, Math.round(Number(img.naturalHeight) || img.height || 1));
  const spriteMax = Math.max(spriteW, spriteH);
  if (spriteMax > 96) return false;

  let imageData = null;
  try {
    const canvas = document.createElement('canvas');
    canvas.width = spriteW;
    canvas.height = spriteH;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return false;
    ctx.clearRect(0, 0, spriteW, spriteH);
    ctx.drawImage(img, 0, 0, spriteW, spriteH);
    imageData = ctx.getImageData(0, 0, spriteW, spriteH);
  } catch {
    return false;
  }

  const data = imageData.data;
  let coloredPixelCount = 0;
  for (let i = 3; i < data.length; i += 4) {
    if (data[i] > 8) coloredPixelCount += 1;
  }
  if (!coloredPixelCount) {
    showToast('No visible pixels found', 'The sprite appears to be fully transparent.', 'error');
    return true;
  }

  const selected = getSelectedCreativeElement();
  const selectedSource = selected?.type === 'image' ? normalizeCanvasPath(selected.meta?.source || '') : '';
  const targetSource = normalizeCanvasPath(source || '');
  const replaceSelected = !!selectedSource && selectedSource === targetSource;
  const canvasW = Math.max(1, Number(creativeSceneDoc.width) || 1080);
  const canvasH = Math.max(1, Number(creativeSceneDoc.height) || 1080);
  let cellW = 10;
  let cellH = 10;
  let baseX = 0;
  let baseY = 0;
  if (replaceSelected) {
    cellW = Math.max(8, Number(selected.width) / spriteW || 8);
    cellH = Math.max(8, Number(selected.height) / spriteH || 8);
    baseX = Number(selected.x) || 0;
    baseY = Number(selected.y) || 0;
  } else {
    const preferredCell = spriteMax <= 8 ? 40 : spriteMax <= 16 ? 28 : spriteMax <= 32 ? 18 : 10;
    const maxW = Math.max(64, canvasW * 0.72);
    const maxH = Math.max(64, canvasH * 0.72);
    const fit = Math.min(maxW / (spriteW * preferredCell), maxH / (spriteH * preferredCell), 1);
    const fittedCell = Math.max(8, preferredCell * fit);
    cellW = fittedCell;
    cellH = fittedCell;
    baseX = Math.round((canvasW - (spriteW * cellW)) / 2);
    baseY = Math.round((canvasH - (spriteH * cellH)) / 2);
  }

  const baseZ = replaceSelected
    ? Math.max(0, Number(selected.zIndex) || 0)
    : Math.max(0, ...(creativeSceneDoc.elements || []).map((element) => Number(element.zIndex) || 0)) + 1;
  const ops = replaceSelected ? [{ op: 'delete', id: selected.id }] : [];
  const pixelIds = [];
  const stamp = Date.now().toString(36);
  const useIndividualPixels = coloredPixelCount <= 512;
  let layerIndex = 0;
  const pushPixelLayer = (x, y, w, h, color, alpha, pixelMeta) => {
    const id = `sprite_pixel_${stamp}_${layerIndex.toString(36)}`;
    pixelIds.push(id);
    ops.push({
      op: 'add',
      id,
      type: 'shape',
      x: Math.round(baseX + (x * cellW)),
      y: Math.round(baseY + (y * cellH)),
      width: Math.max(8, Math.round(w * cellW)),
      height: Math.max(8, Math.round(h * cellH)),
      zIndex: baseZ + layerIndex,
      meta: {
        shape: 'rect',
        fill: color,
        stroke: 'transparent',
        strokeWidth: 0,
        radius: 0,
        role: useIndividualPixels ? 'sprite_pixel' : 'sprite_pixel_run',
        sprite: {
          source: targetSource,
          width: spriteW,
          height: spriteH,
          alpha,
          ...pixelMeta,
        },
      },
    });
    layerIndex += 1;
  };

  if (useIndividualPixels) {
    for (let y = 0; y < spriteH; y += 1) {
      for (let x = 0; x < spriteW; x += 1) {
        const offset = ((y * spriteW) + x) * 4;
        const alpha = data[offset + 3];
        if (alpha <= 8) continue;
        pushPixelLayer(x, y, 1, 1, cssRgbaFromPixel(data, offset), alpha, { x, y });
      }
    }
  } else {
    for (let y = 0; y < spriteH; y += 1) {
      let x = 0;
      while (x < spriteW) {
        const offset = ((y * spriteW) + x) * 4;
        const alpha = data[offset + 3];
        if (alpha <= 8) {
          x += 1;
          continue;
        }
        let runW = 1;
        while (x + runW < spriteW) {
          const nextOffset = ((y * spriteW) + x + runW) * 4;
          if (data[nextOffset + 3] <= 8 || !pixelsHaveSameColor(data, offset, nextOffset)) break;
          runW += 1;
        }
        pushPixelLayer(x, y, runW, 1, cssRgbaFromPixel(data, offset), alpha, { x, y, runWidth: runW });
        x += runW;
      }
    }
  }

  const nextDoc = executeSceneGraphOps(creativeSceneDoc, ops);
  creativeHtmlMotionClip = null;
  setCreativeSceneDoc(nextDoc, { recordHistory: true, render: false, persist: false });
  setCreativeSelection(pixelIds[0] || null, { render: false, persist: false });
  creativeInspectorTab = 'layers';
  renderCreativeWorkspace();
  persistActiveChat();
  addProcessEntry('info', `Extracted sprite into ${pixelIds.length} editable pixel layer${pixelIds.length === 1 ? '' : 's'} (${spriteW}x${spriteH}).`);
  showToast('Sprite layers extracted', `${pixelIds.length} editable layer${pixelIds.length === 1 ? '' : 's'} created from ${spriteW}x${spriteH} pixels.`, 'success');
  return true;
}

function isCreativeCropCandidateElement(element) {
  const meta = element?.meta || {};
  const extraction = meta.extraction || {};
  if (extraction.cropCandidate === true) return true;
  if (element?.type === 'image' && extraction.source === 'image-to-layers' && !String(meta.source || '').trim()) return true;
  if (element?.type === 'shape' && extraction.source === 'image-to-layers') {
    const role = String(meta.role || '').toLowerCase();
    const fill = String(meta.fill || '').toLowerCase().replace(/\s+/g, '');
    return role === 'object_candidate' || fill === 'rgba(255,255,255,0.01)' || fill === 'transparent';
  }
  return false;
}

async function materializeCreativeCropCandidateLayers(scene, source) {
  const candidateIndexes = (scene?.elements || [])
    .map((element, index) => ({ element, index }))
    .filter(({ element }) => isCreativeCropCandidateElement(element));
  if (!candidateIndexes.length) return scene;

  let img = null;
  try {
    img = await loadCreativeImageElement(source);
  } catch {
    return scene;
  }
  const naturalW = Math.max(1, Math.round(Number(img.naturalWidth) || img.width || 1));
  const naturalH = Math.max(1, Math.round(Number(img.naturalHeight) || img.height || 1));
  const sceneW = Math.max(1, Number(scene?.width) || naturalW);
  const sceneH = Math.max(1, Number(scene?.height) || naturalH);
  const scaleX = naturalW / sceneW;
  const scaleY = naturalH / sceneH;
  const sourceCanvas = document.createElement('canvas');
  sourceCanvas.width = naturalW;
  sourceCanvas.height = naturalH;
  const sourceCtx = sourceCanvas.getContext('2d');
  if (!sourceCtx) return scene;
  sourceCtx.clearRect(0, 0, naturalW, naturalH);
  sourceCtx.drawImage(img, 0, 0, naturalW, naturalH);

  const nextScene = createSceneDocument(scene);
  const targetSource = normalizeCanvasPath(source || '');
  candidateIndexes.forEach(({ element, index }, candidateIndex) => {
    const rawX = Math.max(0, Math.floor((Number(element.x) || 0) * scaleX));
    const rawY = Math.max(0, Math.floor((Number(element.y) || 0) * scaleY));
    const rawW = Math.max(1, Math.ceil((Number(element.width) || 1) * scaleX));
    const rawH = Math.max(1, Math.ceil((Number(element.height) || 1) * scaleY));
    const sx = Math.max(0, Math.min(naturalW - 1, rawX));
    const sy = Math.max(0, Math.min(naturalH - 1, rawY));
    const sw = Math.max(1, Math.min(naturalW - sx, rawW));
    const sh = Math.max(1, Math.min(naturalH - sy, rawH));
    const cropCanvas = document.createElement('canvas');
    cropCanvas.width = sw;
    cropCanvas.height = sh;
      const cropCtx = cropCanvas.getContext('2d');
      if (!cropCtx) return;
      cropCtx.imageSmoothingEnabled = false;
      cropCtx.drawImage(sourceCanvas, sx, sy, sw, sh, 0, 0, sw, sh);
      const alphaBounds = applyApproximateObjectAlphaToCanvas(cropCanvas);
      let layerCanvas = cropCanvas;
      let nextX = element.x;
      let nextY = element.y;
      let nextW = element.width;
      let nextH = element.height;
      if (alphaBounds && alphaBounds.width > 0 && alphaBounds.height > 0) {
        const pad = Math.min(8, Math.max(2, Math.round(Math.min(alphaBounds.width, alphaBounds.height) * 0.03)));
        const trimX = Math.max(0, alphaBounds.x - pad);
        const trimY = Math.max(0, alphaBounds.y - pad);
        const trimW = Math.min(sw - trimX, alphaBounds.width + pad * 2);
        const trimH = Math.min(sh - trimY, alphaBounds.height + pad * 2);
        const trimmed = document.createElement('canvas');
        trimmed.width = Math.max(1, trimW);
        trimmed.height = Math.max(1, trimH);
        const trimmedCtx = trimmed.getContext('2d');
        if (trimmedCtx) {
          trimmedCtx.drawImage(cropCanvas, trimX, trimY, trimW, trimH, 0, 0, trimW, trimH);
          layerCanvas = trimmed;
          nextX = (sx + trimX) / scaleX;
          nextY = (sy + trimY) / scaleY;
          nextW = trimW / scaleX;
          nextH = trimH / scaleY;
        }
      }
      const existingMeta = element.meta || {};
      nextScene.elements[index] = {
        ...element,
        id: element.id || `materialized_crop_${Date.now().toString(36)}_${candidateIndex.toString(36)}`,
        type: 'image',
        x: Math.round(nextX),
        y: Math.round(nextY),
        width: Math.max(1, Math.round(nextW)),
        height: Math.max(1, Math.round(nextH)),
        locked: false,
        visible: element.visible !== false,
        meta: {
          ...existingMeta,
          source: layerCanvas.toDataURL('image/png'),
          fit: 'contain',
          radius: 0,
          role: existingMeta.role || 'object_crop',
          sourceImage: targetSource,
          extraction: {
            ...(existingMeta.extraction || {}),
            source: 'image-to-layers',
            cropCandidate: false,
            materializedCrop: true,
            alphaCutoutFallback: !!alphaBounds,
          },
          crop: {
            x: sx,
            y: sy,
            width: sw,
            height: sh,
            trim: alphaBounds || null,
            naturalWidth: naturalW,
            naturalHeight: naturalH,
          },
      },
    };
  });
  return createSceneDocument(nextScene);
}

function applyApproximateObjectAlphaToCanvas(canvas) {
  const w = Math.max(1, Number(canvas?.width) || 0);
  const h = Math.max(1, Number(canvas?.height) || 0);
  if (!w || !h) return false;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });
  if (!ctx) return false;
  const image = ctx.getImageData(0, 0, w, h);
  const data = image.data;
  const samples = [];
  const pushSample = (x, y) => {
    const idx = (y * w + x) * 4;
    if (data[idx + 3] < 8) return;
    samples.push([data[idx], data[idx + 1], data[idx + 2]]);
  };
  const cornerSamples = [];
  const pushCornerSample = (x, y) => {
    const idx = (y * w + x) * 4;
    if (data[idx + 3] < 8) return;
    cornerSamples.push([data[idx], data[idx + 1], data[idx + 2]]);
  };
  const cornerW = Math.max(3, Math.round(w * 0.12));
  const cornerH = Math.max(3, Math.round(h * 0.12));
  for (let y = 0; y < cornerH; y++) {
    for (let x = 0; x < cornerW; x++) {
      pushCornerSample(x, y);
      pushCornerSample(w - 1 - x, y);
      pushCornerSample(x, h - 1 - y);
      pushCornerSample(w - 1 - x, h - 1 - y);
    }
  }
  for (let x = 0; x < w; x++) {
    pushSample(x, 0);
    pushSample(x, h - 1);
  }
  for (let y = 1; y < h - 1; y++) {
    pushSample(0, y);
    pushSample(w - 1, y);
  }
  if (!samples.length) return false;
  const median = (channel) => {
    const sourceSamples = cornerSamples.length >= 16 ? cornerSamples : samples;
    const values = sourceSamples.map((sample) => sample[channel]).sort((a, b) => a - b);
    return values[Math.floor(values.length / 2)] || 0;
  };
  const bg = { r: median(0), g: median(1), b: median(2) };
  const bgSat = Math.max(bg.r, bg.g, bg.b) - Math.min(bg.r, bg.g, bg.b);
  const colorDistance = (idx) => {
    const dr = data[idx] - bg.r;
    const dg = data[idx + 1] - bg.g;
    const db = data[idx + 2] - bg.b;
    return Math.sqrt(dr * dr + dg * dg + db * db);
  };
  const saturation = (idx) => {
    const max = Math.max(data[idx], data[idx + 1], data[idx + 2]);
    const min = Math.min(data[idx], data[idx + 1], data[idx + 2]);
    return max - min;
  };
  const luminance = (idx) => 0.2126 * data[idx] + 0.7152 * data[idx + 1] + 0.0722 * data[idx + 2];
  const bgLum = 0.2126 * bg.r + 0.7152 * bg.g + 0.0722 * bg.b;
  const similarToBackground = (pixel) => {
    const idx = pixel * 4;
    if (data[idx + 3] < 8) return true;
    const dist = colorDistance(idx);
    const sat = saturation(idx);
    const lum = luminance(idx);
    const brightAccent = sat > 70 && lum > bgLum + 18;
    const coloredSubject = lum > bgLum + 28 || sat > Math.max(52, bgSat + 38);
    const darkMatteLike = lum <= bgLum + 18 && sat <= bgSat + 32;
    return !brightAccent && !coloredSubject && (dist < 74 || (darkMatteLike && Math.abs(lum - bgLum) < 58));
  };
  const total = w * h;
  const bgMask = new Uint8Array(total);
  const queue = new Int32Array(total);
  let head = 0;
  let tail = 0;
  const enqueue = (pixel) => {
    if (pixel < 0 || pixel >= total || bgMask[pixel]) return;
    if (!similarToBackground(pixel)) return;
    bgMask[pixel] = 1;
    queue[tail++] = pixel;
  };
  for (let x = 0; x < w; x++) {
    enqueue(x);
    enqueue((h - 1) * w + x);
  }
  for (let y = 1; y < h - 1; y++) {
    enqueue(y * w);
    enqueue(y * w + w - 1);
  }
  while (head < tail) {
    const pixel = queue[head++];
    const x = pixel % w;
    const y = Math.floor(pixel / w);
    if (x > 0) enqueue(pixel - 1);
    if (x < w - 1) enqueue(pixel + 1);
    if (y > 0) enqueue(pixel - w);
    if (y < h - 1) enqueue(pixel + w);
  }
  closeMaskGaps(bgMask, w, h, 1);
  let foreground = 0;
  let minX = w;
  let minY = h;
  let maxX = 0;
  let maxY = 0;
  for (let pixel = 0; pixel < total; pixel++) {
    const idx = pixel * 4;
    const isBackground = !!bgMask[pixel];
    if (isBackground) {
      data[idx + 3] = 0;
      continue;
    }
    if (data[idx + 3] > 8) {
      foreground++;
      const x = pixel % w;
      const y = Math.floor(pixel / w);
      minX = Math.min(minX, x);
      minY = Math.min(minY, y);
      maxX = Math.max(maxX, x);
      maxY = Math.max(maxY, y);
    }
  }
  if (foreground < Math.max(32, total * 0.015) || foreground > total * 0.96) return null;
  featherAlphaEdges(data, bgMask, w, h);
  ctx.putImageData(image, 0, 0);
  return {
    x: minX,
    y: minY,
    width: Math.max(1, maxX - minX + 1),
    height: Math.max(1, maxY - minY + 1),
  };
}

function closeMaskGaps(mask, w, h, iterations = 1) {
  for (let it = 0; it < iterations; it++) {
    const next = new Uint8Array(mask);
    for (let y = 1; y < h - 1; y++) {
      for (let x = 1; x < w - 1; x++) {
        const pixel = y * w + x;
        if (mask[pixel]) continue;
        const horizontal = mask[pixel - 1] && mask[pixel + 1];
        const vertical = mask[pixel - w] && mask[pixel + w];
        if (horizontal || vertical) next[pixel] = 1;
      }
    }
    mask.set(next);
  }
}

function featherAlphaEdges(data, bgMask, w, h) {
  const alpha = new Uint8ClampedArray(w * h);
  for (let pixel = 0; pixel < alpha.length; pixel++) alpha[pixel] = data[pixel * 4 + 3];
  for (let y = 1; y < h - 1; y++) {
    for (let x = 1; x < w - 1; x++) {
      const pixel = y * w + x;
      if (bgMask[pixel] || alpha[pixel] < 8) continue;
      const touchesBg = bgMask[pixel - 1] || bgMask[pixel + 1] || bgMask[pixel - w] || bgMask[pixel + w];
      if (touchesBg) data[pixel * 4 + 3] = Math.min(alpha[pixel], 180);
    }
  }
}

async function saveGeneratedImageFile(diskPath, filename = 'generated-image.png') {
  const previewPath = normalizeCanvasPath(diskPath || '');
  if (!previewPath) return;
  try {
    if (typeof window.showSaveFilePicker !== 'function') {
      canvasDownloadFile(previewPath, filename);
      return;
    }
    const response = await fetch(`/api/canvas/inline?path=${encodeURIComponent(previewPath)}`);
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const blob = await response.blob();
    const extMatch = String(filename || '').match(/(\.[a-z0-9]+)$/i);
    const types = blob.type
      ? [{
          description: 'Image file',
          accept: { [blob.type]: [extMatch ? extMatch[1] : '.png'] },
        }]
      : undefined;
    const handle = await window.showSaveFilePicker({
      suggestedName: filename,
      types,
    });
    const writable = await handle.createWritable();
    await writable.write(blob);
    await writable.close();
    showToast('Image saved', filename, 'success');
  } catch (err) {
    if (err?.name === 'AbortError') return;
    showToast('Save failed', String(err?.message || err || 'Unknown save error.'), 'error');
  }
}

async function openGeneratedImageInCanvas(diskPath, label) {
  const targetPath = normalizeCanvasPath(diskPath || '');
  if (!targetPath) return;
  const targetLabel = String(label || targetPath.split('/').pop() || targetPath).trim();
  try {
    if (isBrowserCanvasSurfaceActive()) {
      showCanvasFilesSurface();
    }
    if (isCreativeModeLocked()) {
      try {
        await exitCreativeModeForBrowserSwitch({
          sessionId: getCurrentChatModeSessionId(),
          mode: window.currentCreativeMode,
        });
      } catch (err) {
        const sid = getCurrentChatModeSessionId();
        if (sid) applySessionCreativeMode(sid, null);
        else {
          window.currentCreativeMode = null;
          applyCreativeModeUI();
        }
      }
    }
    await canvasPresentFile(targetPath, targetLabel);
  } catch (err) {
    showToast('Could not open image in Canvas', String(err?.message || err || 'Unknown canvas error.'), 'error');
  }
}

async function canvasExtractLayersFromSource(source, promptText = '', overrides = {}) {
  if (creativeLayerExtractionBusy) return;
  let targetSource = normalizeCanvasPath(source || '');
  if (!targetSource) {
    const selected = getSelectedCreativeElement();
    if (selected?.type === 'image' && selected.meta?.source) {
      targetSource = normalizeCanvasPath(selected.meta.source);
    }
  }
  if (!targetSource) {
    showToast('Choose an image first', 'Select an image layer or use Extract Layers from a generated image card.', 'error');
    return;
  }
  const sid = getCurrentChatModeSessionId() || window.activeChatSessionId || window.agentSessionId || 'default';
  const requestId = canvasCreateExtractRequestId();
  creativeLayerExtractionRequestId = requestId;
  creativeLayerExtractionProgress = null;
  creativeLayerExtractionBusy = true;
  renderChatMessages();
  renderCreativeWorkspace();
  canvasShowExtractScanOverlay({ requestId, label: 'Preparing extraction', detail: 'Reading source image' });
  addProcessEntry('info', `Extracting editable layers from ${targetSource.split('/').pop() || targetSource}...`);
  try {
    if (normalizeCreativeMode(window.currentCreativeMode) !== 'image') {
      const savedMode = await persistCreativeMode(sid, 'image');
      applySessionCreativeMode(sid, savedMode);
    }
    ensureCreativeSceneForMode(window.currentCreativeMode);
    const spriteSheetHandled = await canvasTryExtractSpriteSheetTilesFromSource(targetSource);
    if (spriteSheetHandled) return;
    const spriteHandled = await canvasTryExtractSpriteLayersFromSource(targetSource);
    if (spriteHandled) return;
    const opts = Object.assign({
      mode: 'deep',
      textEditable: true,
      useOcr: true,
      extractObjects: true,
      preserveOriginal: true,
      useSam: true,
      inpaintBackground: true,
      vectorTraceShapes: true,
      maxTextLayers: 24,
      maxShapeLayers: 16,
    }, overrides || {});
    const res = await fetch('/api/canvas/creative-extract-layers', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId: sid,
        root: canvasProjectRoot || '',
        requestId,
        source: targetSource,
        prompt: String(promptText || ''),
        copySource: true,
        ...opts,
      }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.success === false) {
      throw new Error(String(data?.error || `HTTP ${res.status}`));
    }
    const nextScene = await materializeCreativeCropCandidateLayers(createSceneDocument(data.scene || {}), targetSource);
    creativeHtmlMotionClip = null;
    setCreativeSceneDoc(nextScene, { recordHistory: true, render: false, persist: false });
    const selectedId = nextScene.selectedId || nextScene.elements.find((element) => element.type === 'text')?.id || nextScene.elements[nextScene.elements.length - 1]?.id || null;
    setCreativeSelection(selectedId, { render: false, persist: false });
    creativeInspectorTab = 'layers';
    renderCreativeWorkspace();
    persistActiveChat();
    loadCreativeAssets({ force: true }).catch(() => {});
    const summary = data.sceneSummary || {};
    const textCount = Number(summary.textCount || 0);
    const elementCount = Number(summary.elementCount || nextScene.elements.length || 0);
    const warnings = Array.isArray(data.diagnostics?.warnings) ? data.diagnostics.warnings : [];
    canvasApplyExtractProgressEvent({
      requestId,
      stage: 'done',
      label: 'Editable layers ready',
      detail: `${elementCount} layer${elementCount === 1 ? '' : 's'} assembled`,
      width: nextScene.width,
      height: nextScene.height,
      boxes: (nextScene.elements || [])
        .filter((element) => element?.id !== 'extracted_background_plate' && element?.id !== 'extracted_original_reference')
        .slice(0, 18)
        .map((element) => ({
          id: element.id,
          type: element.type,
          role: element.meta?.role,
          label: element.meta?.content || element.meta?.label || element.meta?.role || element.type,
          x: element.x,
          y: element.y,
          width: element.width,
          height: element.height,
          cutoutPath: element.type === 'image' ? element.meta?.source : '',
        })),
    });
    addProcessEntry('info', `Extracted ${elementCount} layer${elementCount === 1 ? '' : 's'}${textCount ? ` with ${textCount} editable text layer${textCount === 1 ? '' : 's'}` : ''}.`);
    showToast('Layers extracted', warnings.length ? warnings[0] : `${elementCount} editable layers created.`, warnings.length ? 'info' : 'success');
  } catch (err) {
    const message = String(err?.message || err || 'Layer extraction failed.');
    addProcessEntry('error', `Extract layers failed: ${message}`);
    showToast('Extract layers failed', message, 'error');
  } finally {
    creativeLayerExtractionBusy = false;
    canvasHideExtractScanOverlay();
    creativeLayerExtractionRequestId = '';
    renderChatMessages();
    renderCreativeWorkspace();
  }
}

