function getCanvasProjectDisplayName(projectRoot, fallbackLabel = '') {
  const normalized = normalizeCanvasPath(projectRoot);
  if (fallbackLabel) return String(fallbackLabel);
  if (!normalized) return '';
  const parts = normalized.split('/').filter(Boolean);
  return parts.length ? parts[parts.length - 1] : normalized;
}

function getCanvasDirectoryPath(filePath) {
  const normalized = normalizeCanvasPath(filePath);
  if (!normalized) return '';
  const parts = normalized.split('/').filter(Boolean);
  if (parts.length <= 1) return normalized;
  return normalized.startsWith('/')
    ? `/${parts.slice(0, -1).join('/')}`
    : normalized.slice(0, normalized.lastIndexOf('/'));
}

function isCanvasPathWithin(basePath, targetPath) {
  const base = normalizeCanvasPath(basePath);
  const target = normalizeCanvasPath(targetPath);
  if (!base || !target) return false;
  return target === base || target.startsWith(`${base}/`);
}

function getCanvasWorkspaceDisplayRoot() {
  return canvasWorkspaceRootPath || canvasProjectRoot || '';
}

function updateDesignSelectionChip() {
  const chip = document.getElementById('chat-design-selection-chip');
  if (!chip) return;
  const browserState = getBrowserCanvasState();
  if (isBrowserCanvasSurfaceActive() && browserState.selectedElement) {
    const label = browserState.selectedElement.selector
      || (browserState.selectedElement.id ? `#${browserState.selectedElement.id}` : '')
      || browserState.selectedElement.tagName
      || 'element';
    chip.textContent = `Browser: ${label}`;
    chip.style.display = 'block';
    return;
  }
  if (normalizeCreativeMode(window.currentCreativeMode) === 'video' && creativeHtmlMotionSelectedElementContext) {
    const ctx = creativeHtmlMotionSelectedElementContext;
    const label = ctx.selector
      || (ctx.id ? `#${ctx.id}` : '')
      || ctx.role
      || ctx.tagName
      || 'element';
    const text = String(ctx.text || '').trim().replace(/\s+/g, ' ');
    const timing = ctx.timing
      ? [ctx.timing.startMs != null ? `${ctx.timing.startMs}ms` : '', ctx.timing.durationMs != null ? `${ctx.timing.durationMs}ms` : ''].filter(Boolean).join(' / ')
      : '';
    chip.textContent = `HTML Motion: ${String(label).slice(0, 90)}${text ? ` :: ${text.slice(0, 70)}` : ''}`;
    chip.title = [
      `Selected HTML motion element: ${label}`,
      text ? `Text: ${text}` : '',
      timing ? `Timing: ${timing}` : '',
      ctx.pretext ? `PreText: ${ctx.pretext.lineCount || '?'} line(s), ${ctx.pretext.measuredHeight || '?'}px measured / ${ctx.pretext.availableHeight || '?'}px box` : '',
      ctx.snippet ? `Snippet:\n${ctx.snippet}` : '',
    ].filter(Boolean).join('\n\n');
    chip.style.display = 'block';
    return;
  }
  if (normalizeCreativeMode(window.currentCreativeMode) !== 'design' || !designSelectedElementContext) {
    chip.style.display = 'none';
    chip.textContent = '';
    chip.title = '';
    return;
  }
  const label = designSelectedElementContext.selector
    || (designSelectedElementContext.id ? `#${designSelectedElementContext.id}` : '')
    || designSelectedElementContext.tagName
    || 'element';
  chip.textContent = `Element: ${label}`;
  chip.title = `Selected design element: ${label}`;
  chip.style.display = 'block';
}

async function promptAllowCanvasDirectory(filePath) {
  const directoryPath = getCanvasDirectoryPath(filePath);
  if (!directoryPath) return false;
  return await addCanvasAllowedDirectory(directoryPath, `Prometheus can't edit this path yet because it is outside the workspace.\n\nAllow directory:\n${directoryPath}\n\nThis will add it to Settings > Security > Allowed Paths.`);
}

async function addCanvasAllowedDirectory(directoryPath, message = '') {
  const normalizedDirectoryPath = normalizeCanvasPath(directoryPath);
  if (!normalizedDirectoryPath) return false;
  const approved = await showConfirm(
    'Add this to allowed directories?',
    message || `Allow directory:\n${normalizedDirectoryPath}\n\nThis will add it to Settings > Security > Allowed Paths.`
  );
  if (!approved) return false;
  const current = await fetch('/api/settings/paths').then((res) => res.json());
  const allowed = Array.isArray(current?.allowed_paths) ? current.allowed_paths.slice() : [];
  if (!allowed.includes(normalizedDirectoryPath)) allowed.push(normalizedDirectoryPath);
  const response = await fetch('/api/settings/paths', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      workspace_path: current?.workspace_path || '',
      allowed_paths: allowed,
      blocked_paths: Array.isArray(current?.blocked_paths) ? current.blocked_paths : [],
    }),
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.success === false) {
    throw new Error(data.error || 'Could not update allowed directories.');
  }
  const allowedPathsField = document.getElementById('settings-allowed-paths');
  if (allowedPathsField) allowedPathsField.value = allowed.join('\n');
  addProcessEntry('info', `Canvas: added allowed directory ${normalizedDirectoryPath}`);
  return true;
}

async function ensureCanvasTreeFocusedForFile(diskPath) {
  const directoryPath = getCanvasDirectoryPath(diskPath);
  if (!directoryPath) return;
  const normalizedDirectoryPath = normalizeCanvasPath(directoryPath);
  const normalizedWorkspaceRoot = normalizeCanvasPath(canvasWorkspaceRootPath || '');
  if (normalizedWorkspaceRoot === normalizedDirectoryPath) return;
  await canvasLoadWorkspaceFiles(directoryPath);
}

function ensureCanvasProjectWidth() {
  if (isCreativeModeLocked()) return;
  if (!canvasProjectRoot) return;
  const rightPanel = document.getElementById('right-panel');
  if (!rightPanel) return;
  const currentWidth = rightPanel.offsetWidth || 0;
  const nextWidth = Math.max(currentWidth, CANVAS_PANEL_MIN_WIDTH);
  setRightPanelWidth(nextWidth, { minimumWidth: 860 });
  if (typeof window._syncPageViewPositions === 'function') window._syncPageViewPositions();
}

function updateCanvasWorkspaceChrome() {
  const sidebar = document.getElementById('canvas-workspace-sidebar');
  const tree = document.getElementById('canvas-project-tree');
  const emptyHint = document.getElementById('canvas-tree-empty');
  const header = document.getElementById('canvas-workspace-header');
  const headerInfo = document.getElementById('canvas-workspace-header-info');
  const actions = document.getElementById('canvas-workspace-actions');
  const rootLabel = document.getElementById('canvas-project-root-label');
  const rootPath = document.getElementById('canvas-project-root-path');
  const clearBtn = document.getElementById('canvas-project-clear-btn');
  const toggleBtn = document.getElementById('canvas-workspace-toggle');
  const browserBtn = document.getElementById('canvas-workspace-browser-btn');
  const hasTree = Array.isArray(canvasWorkspaceTree) && canvasWorkspaceTree.length > 0;
  const browserSurfaceActive = isBrowserCanvasSurfaceActive();
  const displayRoot = getCanvasWorkspaceDisplayRoot();
  const displayLabel = displayRoot
    ? getCanvasProjectDisplayName(
        displayRoot,
        canvasProjectRoot && normalizeCanvasPath(displayRoot) === normalizeCanvasPath(canvasProjectRoot)
          ? (canvasProjectLabel || '')
          : ''
      )
    : 'Workspace Files';
  if (sidebar) sidebar.style.display = browserSurfaceActive ? 'none' : ((hasTree || canvasProjectRoot) ? 'flex' : 'none');
  if (sidebar) {
    sidebar.style.width = canvasBrowserCollapsed ? '48px' : '280px';
    sidebar.style.minWidth = canvasBrowserCollapsed ? '48px' : '280px';
  }
  if (header) {
    header.style.alignItems = canvasBrowserCollapsed ? 'center' : 'flex-start';
    header.style.justifyContent = canvasBrowserCollapsed ? 'center' : 'space-between';
    header.style.padding = canvasBrowserCollapsed ? '10px 6px' : '10px 12px';
  }
  if (headerInfo) headerInfo.style.display = canvasBrowserCollapsed ? 'none' : 'block';
  if (actions) actions.style.display = canvasBrowserCollapsed ? 'none' : 'flex';
  if (tree) tree.style.display = canvasBrowserCollapsed ? 'none' : 'block';
  if (emptyHint) emptyHint.style.display = (!canvasBrowserCollapsed && !hasTree) ? 'block' : 'none';
  if (rootLabel) rootLabel.textContent = displayLabel;
  if (rootPath) rootPath.textContent = displayRoot ? normalizeCanvasPath(displayRoot) : 'Browsing the full workspace';
  if (clearBtn) clearBtn.style.display = canvasProjectRoot && !canvasBrowserCollapsed ? 'inline-flex' : 'none';
  if (toggleBtn) {
    toggleBtn.textContent = canvasBrowserCollapsed ? '<' : '< Back';
    toggleBtn.title = canvasBrowserCollapsed ? 'Expand workspace tree' : 'Collapse workspace tree';
  }
  if (browserBtn) browserBtn.textContent = canvasProjectRoot ? 'Refresh Project' : 'Browse Workspace';
}

function setCanvasProjectState(projectRoot, projectLabel, options = {}) {
  const hadWorkspaceBrowser = Boolean(canvasProjectRoot || (Array.isArray(canvasWorkspaceTree) && canvasWorkspaceTree.length));
  canvasProjectRoot = normalizeCanvasPath(projectRoot) || null;
  canvasProjectLabel = canvasProjectRoot ? (String(projectLabel || getCanvasProjectDisplayName(canvasProjectRoot)).trim() || null) : null;
  if (!canvasProjectRoot) {
    canvasProjectLink = null;
    canvasPublishState = null;
  }
  if (canvasProjectRoot && options.expandBrowser !== false) {
    canvasBrowserCollapsed = false;
  } else if (canvasProjectRoot && !hadWorkspaceBrowser) {
    canvasBrowserCollapsed = true;
  }
  const session = getActiveChatSessionRecord();
  if (session) {
    session.canvasProjectRoot = canvasProjectRoot;
    session.canvasProjectLabel = canvasProjectLabel;
    if (!canvasProjectRoot) session.canvasProjectLink = null;
  }
  if (canvasProjectRoot) ensureCanvasProjectWidth();
  updateCanvasWorkspaceChrome();
  renderCanvasPublishControls();
  if (canvasProjectRoot && options.refreshPublish !== false) {
    loadCanvasPublishState().catch(() => {});
  }
  if (options.persist !== false) persistActiveChat();
}

function clearDesignSelectionContext() {
  designSelectedElementContext = null;
  updateDesignSelectionChip();
  if (typeof hideAllDesignPopovers === 'function') hideAllDesignPopovers();
  designLastClickedElement = null;
  designLastClickedFrame = null;
}

function getCreativeHtmlMotionTimelineTracks(durationMs) {
  const composition = creativeHtmlMotionLintState?.composition || creativeHtmlMotionClip?.composition || null;
  const nodes = Array.isArray(composition?.timedNodes) ? composition.timedNodes : [];
  if (!nodes.length) return [];
  const total = Math.max(1, Number(durationMs) || 0);
  const selectedSelector = String(creativeHtmlMotionSelectedElementContext?.selector || '').trim();
  return nodes.map((node) => {
    const startMs = Math.max(0, Math.min(total, Number(node.startMs) || 0));
    const explicitEnd = Number.isFinite(Number(node.endMs)) ? Number(node.endMs) : null;
    const explicitDur = Number.isFinite(Number(node.durationMs)) ? Number(node.durationMs) : null;
    let endMs = explicitEnd != null ? explicitEnd : (explicitDur != null ? startMs + explicitDur : total);
    endMs = Math.max(startMs + 50, Math.min(total, endMs));
    const role = String(node.role || '').trim();
    const id = String(node.id || '').trim();
    const selector = String(node.selector || '').trim();
    const label = role || id || selector || node.tag || 'Layer';
    const captionPart = node.caption ? ` | ${String(node.caption).slice(0, 40)}` : '';
    const animatePart = node.animate ? ` | anim ${String(node.animate).slice(0, 24)}` : '';
    const metaLine = `${formatCreativeTimelineTime(startMs)} - ${formatCreativeTimelineTime(endMs)}${animatePart}${captionPart}`;
    const tag = String(node.tag || '').toLowerCase();
    let icon = 'solar:layers-bold-duotone';
    if (tag === 'img') icon = 'solar:gallery-bold-duotone';
    else if (tag === 'video') icon = 'solar:videocamera-record-bold-duotone';
    else if (/^h[1-6]$/.test(tag) || tag === 'p' || tag === 'span') icon = 'solar:text-bold-duotone';
    else if (node.animate) icon = 'solar:play-circle-bold-duotone';
    return {
      selector,
      label,
      metaLine,
      icon,
      startMs,
      endMs,
      isSelected: selector && selectedSelector && selector === selectedSelector,
    };
  });
}

function canvasSelectCreativeHtmlMotionBySelector(encodedSelector) {
  const selector = (() => {
    try { return decodeURIComponent(String(encodedSelector || '')); } catch { return String(encodedSelector || ''); }
  })().trim();
  if (!selector) return;
  const frame = document.getElementById('creative-html-motion-frame');
  const doc = frame?.contentDocument;
  if (!frame || !doc) return;
  let element = null;
  try { element = doc.querySelector(selector); } catch { element = null; }
  if (!element) {
    addProcessEntry('warning', `HTML Motion: timeline selector "${selector}" not found in preview.`);
    return;
  }
  applyCreativeHtmlMotionPreviewSelection(element, frame);
  try { element.scrollIntoView({ block: 'nearest', inline: 'nearest', behavior: 'smooth' }); } catch {}
  renderCreativeWorkspace();
}

function canvasHandleCreativeHtmlMotionLanePointer(event, encodedSelector, laneNode) {
  if (!event || event.button !== 0) return;
  const lane = laneNode instanceof Element ? laneNode : (event.target instanceof Element ? event.target.closest('.creative-timeline-track-lane') : null);
  if (!lane) return;
  event.preventDefault();
  const rect = lane.getBoundingClientRect();
  if (rect.width > 0) {
    const ratio = Math.max(0, Math.min(1, (event.clientX - rect.left) / rect.width));
    const durationMs = getCreativeTimelineDurationMs();
    setCreativeTimelinePosition(Math.round(ratio * durationMs), { persist: true, forceSeek: true });
  }
  canvasSelectCreativeHtmlMotionBySelector(encodedSelector);
}

function clearCreativeHtmlMotionSelectionContext(options = {}) {
  const frame = creativeHtmlMotionLastClickedFrame;
  try {
    frame?.contentDocument?.querySelectorAll?.('[data-prometheus-html-motion-selected="true"],[data-prometheus-html-motion-hover="true"]').forEach((node) => {
      node.removeAttribute('data-prometheus-html-motion-selected');
      node.removeAttribute('data-prometheus-html-motion-hover');
    });
  } catch {}
  creativeHtmlMotionSelectedElementContext = null;
  creativeHtmlMotionLastClickedElement = null;
  creativeHtmlMotionLastClickedFrame = null;
  hideCreativeHtmlMotionTransformOverlay(frame);
  updateDesignSelectionChip();
  if (options.popovers !== false) hideCreativeHtmlMotionPopovers();
}

function getCanvasPublishButtonStyle(kind = 'default') {
  if (kind === 'primary') return 'display:inline-flex;align-items:center;gap:6px;border:1px solid rgba(56,189,248,0.35);background:rgba(56,189,248,0.15);color:#7dd3fc;border-radius:8px;padding:4px 10px;font-size:11px;font-weight:700;cursor:pointer;font-family:\'Manrope\',sans-serif';
  if (kind === 'success') return 'display:inline-flex;align-items:center;gap:6px;border:1px solid rgba(16,185,129,0.35);background:rgba(16,185,129,0.14);color:#6ee7b7;border-radius:8px;padding:4px 10px;font-size:11px;font-weight:700;cursor:pointer;font-family:\'Manrope\',sans-serif';
  if (kind === 'muted') return 'display:inline-flex;align-items:center;gap:6px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.06);color:#9a9890;border-radius:8px;padding:4px 10px;font-size:11px;font-weight:700;cursor:pointer;font-family:\'Manrope\',sans-serif';
  return 'display:inline-flex;align-items:center;gap:6px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.06);color:#e8e6e1;border-radius:8px;padding:4px 10px;font-size:11px;font-weight:700;cursor:pointer;font-family:\'Manrope\',sans-serif';
}

async function downloadCanvasProjectExport(format = 'zip') {
  const sid = String(window.activeChatSessionId || window.agentSessionId || '').trim();
  if (!sid || !canvasProjectRoot) return;
  const activeTab = getActiveCanvasTab();
  const params = new URLSearchParams({
    sessionId: sid,
    format: String(format || 'zip').toLowerCase(),
  });
  if (String(format || '').toLowerCase() === 'html') {
    const previewPath = getDesignPreviewEntryPath(activeTab);
    if (previewPath) params.set('entry', previewPath);
  }
  try {
    await syncDirtyDesignTabsToDisk();
    const response = await fetch(`/api/canvas/project-export?${params.toString()}`);
    if (!response.ok) {
      let message = `HTTP ${response.status}`;
      try {
        const data = await response.json();
        if (data?.error) message = data.error;
      } catch {}
      throw new Error(message);
    }
    const blob = await response.blob();
    const objectUrl = URL.createObjectURL(blob);
    const link = document.createElement('a');
    const projectName = sanitizePublishName(canvasProjectLabel || getCanvasProjectDisplayName(canvasProjectRoot));
    link.href = objectUrl;
    link.download = String(format || '').toLowerCase() === 'html'
      ? `${projectName || 'prometheus-design'}-standalone.html`
      : `${projectName || 'prometheus-design'}.zip`;
    document.body.appendChild(link);
    link.click();
    link.remove();
    setTimeout(() => URL.revokeObjectURL(objectUrl), 1000);
    addProcessEntry('info', `Design: exported ${String(format || 'zip').toUpperCase()}.`);
  } catch (err) {
    showToast(`Design export failed: ${err.message}`, 'error');
    addProcessEntry('error', `Design export failed: ${String(err?.message || err)}`);
  }
}

function renderCanvasPublishControls() {
  const wrap = document.getElementById('canvas-publish-controls');
  if (!wrap) return;
  const isDesign = normalizeCreativeMode(window.currentCreativeMode) === 'design';
  if (!isDesign || !canvasProjectRoot) {
    wrap.style.display = 'none';
    wrap.innerHTML = '';
    return;
  }
  const state = canvasPublishState || {};
  const git = state.git || {};
  const vercel = state.vercel || {};
  const publish = state.publish || {};
  const parts = [];
  parts.push(`<div style="display:flex;align-items:center;gap:6px;margin-right:4px;font-size:10px;font-weight:800;letter-spacing:0.04em;text-transform:uppercase;color:#b7b4ac">`);
  parts.push(`<span style="display:inline-flex;align-items:center;gap:4px"><iconify-icon icon="mdi:github" width="13" height="13"></iconify-icon>${git.repoFullName ? escHtml(git.repoFullName) : 'GitHub unlinked'}</span>`);
  parts.push(`<span style="display:inline-flex;align-items:center;gap:4px"><iconify-icon icon="simple-icons:vercel" width="11" height="11"></iconify-icon>${vercel.projectName || vercel.projectId || 'Vercel unlinked'}</span>`);
  parts.push(`</div>`);
  parts.push(`<button onclick="downloadCanvasProjectExport('html')" title="Download a best-effort standalone HTML export of the active preview entry" style="${getCanvasPublishButtonStyle('muted')}"><iconify-icon icon="solar:file-download-bold-duotone" width="14" height="14"></iconify-icon>Export HTML</button>`);
  parts.push(`<button onclick="downloadCanvasProjectExport('zip')" title="Download the full project root as a ZIP archive" style="${getCanvasPublishButtonStyle('muted')}"><iconify-icon icon="solar:archive-down-bold-duotone" width="14" height="14"></iconify-icon>Export ZIP</button>`);
  if (publish.canCreateRepo) {
    parts.push(`<button onclick="canvasPreparePublishAction('github_create_repo')" title="Create and link a GitHub repository" style="${getCanvasPublishButtonStyle('primary')}"><iconify-icon icon="mdi:github" width="14" height="14"></iconify-icon>Create Repo</button>`);
  } else if (publish.canCommitPush) {
    parts.push(`<button onclick="canvasPreparePublishAction('git_commit_push')" title="Commit and push project changes" style="${getCanvasPublishButtonStyle()}"><iconify-icon icon="solar:upload-bold-duotone" width="14" height="14"></iconify-icon>Commit & Push</button>`);
  }
  if (publish.canCreateVercelProject) {
    parts.push(`<button onclick="canvasPreparePublishAction('vercel_create_project')" title="Create a linked Vercel project" style="${getCanvasPublishButtonStyle('muted')}"><iconify-icon icon="simple-icons:vercel" width="12" height="12"></iconify-icon>Link Vercel</button>`);
  }
  if (publish.canDeploy) {
    parts.push(`<button onclick="canvasPreparePublishAction('vercel_deploy')" title="Deploy this project to Vercel" style="${getCanvasPublishButtonStyle('success')}"><iconify-icon icon="solar:rocket-bold-duotone" width="14" height="14"></iconify-icon>Deploy</button>`);
  }
  if (vercel.deploymentUrl) {
    parts.push(`<button onclick="window.open('${escHtml(vercel.deploymentUrl).replace(/'/g, '&#39;')}', '_blank')" title="Open live deployment" style="${getCanvasPublishButtonStyle('muted')}"><iconify-icon icon="solar:square-arrow-right-up-bold-duotone" width="14" height="14"></iconify-icon>Live</button>`);
  } else if (vercel.dashboardUrl) {
    parts.push(`<button onclick="window.open('${escHtml(vercel.dashboardUrl).replace(/'/g, '&#39;')}', '_blank')" title="Open Vercel dashboard" style="${getCanvasPublishButtonStyle('muted')}"><iconify-icon icon="solar:window-frame-bold-duotone" width="14" height="14"></iconify-icon>Dashboard</button>`);
  }
  wrap.innerHTML = parts.join('');
  wrap.style.display = 'flex';
}

async function loadCanvasPublishState(force = false) {
  if (!canvasProjectRoot && !force) {
    canvasPublishState = null;
    renderCanvasPublishControls();
    return null;
  }
  const sid = String(window.activeChatSessionId || window.agentSessionId || '').trim();
  if (!sid) return null;
  try {
    const res = await fetch(`/api/canvas/project-link?sessionId=${encodeURIComponent(sid)}`);
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.success === false) throw new Error(data.error || `HTTP ${res.status}`);
    canvasPublishState = data.state || null;
    canvasProjectLink = normalizeCanvasProjectLink(data.state?.explicitLink);
    const session = getActiveChatSessionRecord();
    if (session) session.canvasProjectLink = normalizeCanvasProjectLink(canvasProjectLink);
    renderCanvasPublishControls();
    persistActiveChat();
    return canvasPublishState;
  } catch (err) {
    canvasPublishState = null;
    renderCanvasPublishControls();
    if (force) showToast(`Could not load publish status`, err.message, 'error');
    return null;
  }
}

async function canvasPreparePublishAction(action) {
  const sid = String(window.activeChatSessionId || window.agentSessionId || '').trim();
  if (!sid || !canvasProjectRoot) return;
  const body = { sessionId: sid, action };
  if (action === 'git_commit_push') {
    const message = prompt('Commit message:', `Publish ${canvasProjectLabel || getCanvasProjectDisplayName(canvasProjectRoot)}`);
    if (!message || !message.trim()) return;
    body.commitMessage = message.trim();
  }
  if (action === 'github_create_repo') {
    const repoName = prompt('GitHub repository name:', sanitizePublishName(canvasProjectLabel || getCanvasProjectDisplayName(canvasProjectRoot)));
    if (!repoName || !repoName.trim()) return;
    body.repoName = repoName.trim();
  }
  if (action === 'vercel_create_project') {
    const projectName = prompt('Vercel project name:', sanitizePublishName(canvasProjectLabel || getCanvasProjectDisplayName(canvasProjectRoot)));
    if (!projectName || !projectName.trim()) return;
    body.projectName = projectName.trim();
  }
  try {
    const res = await fetch('/api/canvas/publish/prepare', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.success === false) throw new Error(data.error || `HTTP ${res.status}`);
    const approval = data.approval || {};
    showConfirm(
      approval.summary || 'Approve this action?',
      async () => {
        const execRes = await fetch(`/api/canvas/publish/execute/${encodeURIComponent(approval.id)}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ approved: true }),
        });
        const execData = await execRes.json().catch(() => ({}));
        if (!execRes.ok || execData.success === false) throw new Error(execData.error || `HTTP ${execRes.status}`);
        if (execData.state?.explicitLink) {
          canvasProjectLink = normalizeCanvasProjectLink(execData.state.explicitLink);
          const session = getActiveChatSessionRecord();
          if (session) session.canvasProjectLink = normalizeCanvasProjectLink(canvasProjectLink);
        }
        canvasPublishState = execData.state || null;
        renderCanvasPublishControls();
        persistActiveChat();
        showToast(execData.result?.summary || `${approval.title || 'Action'} complete`, '', 'success');
      },
      async () => {
        await fetch(`/api/canvas/publish/execute/${encodeURIComponent(approval.id)}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ approved: false }),
        }).catch(() => {});
      },
      {
        title: approval.title || 'Publish Approval',
        confirmText: 'Approve & Run',
        cancelText: 'Cancel',
        details: approval.details || '',
      }
    );
  } catch (err) {
    showToast('Could not prepare publish action', err.message, 'error');
  }
}

function sanitizePublishName(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, '-')
    .replace(/^-+|-+$/g, '') || 'prometheus-project';
}

async function persistCanvasProjectRoot(projectRoot, projectLabel = '') {
  const sid = String(window.activeChatSessionId || window.agentSessionId || '').trim();
  if (!sid) return null;
  const res = await fetch('/api/canvas/project-root', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sessionId: sid, rootPath: projectRoot || '', label: projectLabel || '' }),
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok || data.success === false) {
    throw new Error(data.error || `HTTP ${res.status}`);
  }
  return {
    projectRoot: normalizeCanvasPath(data.projectRoot) || null,
    projectLabel: data.projectLabel || null,
  };
}

