async function renderCreativeHtmlMotionSnapshot(payload = {}) {
  const clip = normalizeCreativeHtmlMotionClip(payload.clip || creativeHtmlMotionClip);
  if (!clip) throw new Error('No active HTML motion clip. Create one first with creative_create_html_motion_clip.');
  const durationMs = Math.max(1000, Number(clip.durationMs) || 8000);
  const sampleTimesMs = Array.isArray(payload.sampleTimesMs) && payload.sampleTimesMs.length
    ? payload.sampleTimesMs
    : [
        Number.isFinite(Number(payload.atMs)) ? Number(payload.atMs) : 500,
        Math.round(durationMs / 2),
        Math.max(0, durationMs - 500),
      ];
  const response = await fetch('/api/canvas/html-motion-clip/snapshot', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      sessionId: getActiveCreativeSessionId() || 'default',
      root: canvasProjectRoot || '',
      path: clip.path,
      width: clip.width,
      height: clip.height,
      durationMs,
      sampleTimesMs,
      includeDataUrl: payload.includeDataUrl !== false,
    }),
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data?.success === false) throw new Error(data?.error || `HTTP ${response.status}`);
  updateCreativeHtmlMotionLintFromPayload(data);
  return data;
}

async function exportCreativeHtmlMotionClip(payload = {}) {
  const clip = normalizeCreativeHtmlMotionClip(payload.clip || creativeHtmlMotionClip);
  if (!clip) throw new Error('No active HTML motion clip. Create one first with creative_create_html_motion_clip.');
  const format = String(payload.format || 'mp4').trim().toLowerCase();
  if (format !== 'mp4') throw new Error('HTML motion clip export currently supports mp4.');
  const startedAt = Date.now();
  const durationMs = Math.max(1000, Number(clip.durationMs) || 8000);
  const frameRate = Math.max(1, Number(clip.frameRate) || 60);
  creativeExportUiStamp = 0;
  creativeActiveExport = {
    format: 'mp4',
    renderer: 'html-motion',
    serverJobId: '',
    startedAt,
    frameRate,
    progress: 0,
    elapsedMs: 0,
    cancelRequested: false,
    status: 'capturing',
    progressLabel: 'Preparing HTML motion render',
    audioRequested: false,
    audioEnabled: false,
    htmlMotionPath: clip.path,
  };
  renderCreativeWorkspace({ skipStageRender: true });
  addProcessEntry('info', `Prometheus Video: started HTML motion MP4 export (${Math.round(durationMs / 1000)}s at ${frameRate} fps).`);
  try {
    const response = await fetch('/api/canvas/html-motion-clip/export', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId: getActiveCreativeSessionId() || 'default',
        root: canvasProjectRoot || '',
        path: clip.path,
        filename: payload.filename || '',
        width: clip.width,
        height: clip.height,
        durationMs,
        frameRate,
        force: payload.force === true,
      }),
    });
    const data = await response.json().catch(() => ({}));
    updateCreativeHtmlMotionLintFromPayload(data);
    if (!response.ok || data?.success === false) throw new Error(data?.error || `HTTP ${response.status}`);
    refreshCreativeExportChrome({
      progress: 1,
      elapsedMs: durationMs,
      status: 'completed',
      progressLabel: 'HTML motion export complete',
    }, { force: true });
    await refreshCreativeStorageRootQuiet(data, 'video');
    await loadCreativeAssets({ mode: 'video', force: true, silent: true }).catch(() => {});
    if (data.export?.path) addProcessEntry('info', `Prometheus Video: exported HTML motion MP4 ${data.export.path}.`);
    return data;
  } catch (err) {
    refreshCreativeExportChrome({
      status: 'failed',
      progressLabel: String(err?.message || err || 'HTML motion export failed'),
    }, { force: true });
    throw err;
  } finally {
    creativeActiveExport = null;
    renderCreativeWorkspace({ skipStageRender: true });
  }
}

async function loadCreativeHtmlMotionBlocks(options = {}) {
  const query = options.query !== undefined ? String(options.query || '').trim() : creativeHtmlMotionBlocksState.query;
  creativeHtmlMotionBlocksState = {
    ...creativeHtmlMotionBlocksState,
    query,
    loading: true,
    error: '',
  };
  if (options.render !== false) renderCreativeWorkspace({ skipStageRender: true });
  try {
    const params = new URLSearchParams();
    if (query) params.set('query', query);
    if (options.category) params.set('category', String(options.category));
    if (options.packId) params.set('packId', String(options.packId));
    const response = await fetch(`/api/canvas/html-motion-blocks${params.toString() ? `?${params.toString()}` : ''}`);
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) throw new Error(data?.error || `HTTP ${response.status}`);
    creativeHtmlMotionBlocksState = {
      ...creativeHtmlMotionBlocksState,
      loading: false,
      loaded: true,
      error: '',
      blocks: Array.isArray(data.blocks) ? data.blocks : [],
      query,
    };
  } catch (err) {
    creativeHtmlMotionBlocksState = {
      ...creativeHtmlMotionBlocksState,
      loading: false,
      loaded: true,
      error: String(err?.message || err || 'Could not load HTML motion blocks.'),
      query,
    };
  }
  if (options.render !== false) renderCreativeWorkspace({ skipStageRender: true });
  return creativeHtmlMotionBlocksState.blocks;
}

function ensureCreativeHtmlMotionBlocksHydrated() {
  if (creativeHtmlMotionBlocksState.loaded || creativeHtmlMotionBlocksState.loading) return;
  loadCreativeHtmlMotionBlocks({ render: true }).catch(() => {});
}

let _htmlMotionBlocksDebounceTimer = null;
async function canvasSearchHtmlMotionBlocks(query) {
  const q = String(query || '');
  creativeHtmlMotionBlocksState = {
    ...creativeHtmlMotionBlocksState,
    query: q,
  };
  if (_htmlMotionBlocksDebounceTimer) {
    clearTimeout(_htmlMotionBlocksDebounceTimer);
    _htmlMotionBlocksDebounceTimer = null;
  }
  _htmlMotionBlocksDebounceTimer = setTimeout(() => {
    loadCreativeHtmlMotionBlocks({ query: q, render: true }).catch(() => {});
  }, 180);
}

async function canvasRefreshHtmlMotionLint(options = {}) {
  const clip = normalizeCreativeHtmlMotionClip(options.clip || creativeHtmlMotionClip);
  if (!clip) {
    showToast('Create or open an HTML motion clip first.', 'info');
    return null;
  }
  creativeHtmlMotionLintState = { ...creativeHtmlMotionLintState, loading: true, error: '' };
  if (options.render !== false) renderCreativeWorkspace({ skipStageRender: true });
  try {
    const response = await fetch('/api/canvas/html-motion-clip/lint', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId: getActiveCreativeSessionId() || 'default',
        root: canvasProjectRoot || '',
        path: clip.path,
      }),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) throw new Error(data?.error || `HTTP ${response.status}`);
    updateCreativeHtmlMotionLintFromPayload(data);
    if (options.silent !== true) {
      const errors = creativeHtmlMotionLintState.lint?.errors?.length || 0;
      const warnings = creativeHtmlMotionLintState.lint?.warnings?.length || 0;
      showToast(errors ? `${errors} lint issue${errors === 1 ? '' : 's'} found.` : `HTML motion lint clean${warnings ? ` with ${warnings} warning${warnings === 1 ? '' : 's'}` : ''}.`, errors ? 'error' : 'success');
    }
    return data;
  } catch (err) {
    creativeHtmlMotionLintState = {
      ...creativeHtmlMotionLintState,
      loading: false,
      error: String(err?.message || err || 'Could not lint HTML motion clip.'),
    };
    if (options.silent !== true) showToast(creativeHtmlMotionLintState.error, 'error');
    return null;
  } finally {
    if (options.render !== false) renderCreativeWorkspace({ skipStageRender: true });
  }
}

function normalizeHtmlMotionParameterValue(parameter, rawValue) {
  const type = String(parameter?.type || 'text').toLowerCase();
  if (type === 'range' || type === 'number') {
    let value = Number(rawValue);
    if (!Number.isFinite(value)) value = Number(parameter?.defaultValue) || 0;
    if (Number.isFinite(Number(parameter?.min))) value = Math.max(Number(parameter.min), value);
    if (Number.isFinite(Number(parameter?.max))) value = Math.min(Number(parameter.max), value);
    return String(value);
  }
  if (type === 'boolean') return rawValue === true || rawValue === 'true' || rawValue === '1' ? 'true' : 'false';
  return String(rawValue ?? parameter?.defaultValue ?? '').trim();
}

function getHtmlMotionParameterCurrentValue(parameter, clip = creativeHtmlMotionClip) {
  const values = clip?.parameterValues && typeof clip.parameterValues === 'object' ? clip.parameterValues : {};
  const id = String(parameter?.id || '').trim();
  const value = values[id];
  if (value !== undefined && value !== null && value !== '') return value;
  return parameter?.defaultValue ?? '';
}

async function canvasUpdateHtmlMotionParameter(parameterId, rawValue) {
  const clip = normalizeCreativeHtmlMotionClip(creativeHtmlMotionClip);
  if (!clip) {
    showToast('Create or open an HTML motion clip first.', 'info');
    return null;
  }
  const parameters = Array.isArray(clip.parameters) ? clip.parameters : [];
  const parameter = parameters.find((candidate) => String(candidate?.id || '') === String(parameterId || ''));
  if (!parameter) {
    showToast(`Unknown HTML motion knob: ${parameterId}`, 'error');
    return null;
  }
  const value = normalizeHtmlMotionParameterValue(parameter, rawValue);
  const path = String(parameter?.target?.path || '').trim();
  const ops = [];
  if (path.startsWith('--')) {
    ops.push({ op: 'set_css_var', name: path, value, required: false });
  }
  const nextValues = {
    ...(clip.parameterValues && typeof clip.parameterValues === 'object' ? clip.parameterValues : {}),
    [parameter.id]: value,
  };
  ops.push({ op: 'set_manifest', key: 'parameterValues', value: nextValues });
  try {
    const patched = await patchCreativeHtmlMotionClip({
      clip,
      ops,
      reason: `update HTML motion knob ${parameter.id}`,
      includeHtml: false,
    });
    const nextClip = {
      ...(patched.clip || clip),
      parameters,
      parameterValues: nextValues,
    };
    setCreativeHtmlMotionClip(nextClip, { updateScene: true, render: true, persist: true });
    showToast(`${parameter.label || parameter.id} updated.`, 'success');
    return patched;
  } catch (err) {
    showToast(String(err?.message || err || 'Could not update HTML motion knob.'), 'error');
    return null;
  }
}

async function canvasRunHtmlMotionFrameQA() {
  const clip = normalizeCreativeHtmlMotionClip(creativeHtmlMotionClip);
  if (!clip) {
    showToast('Create or open an HTML motion clip first.', 'info');
    return null;
  }
  try {
    const durationMs = Math.max(1000, Number(clip.durationMs) || 8000);
    const data = await renderCreativeHtmlMotionSnapshot({
      includeDataUrl: false,
      sampleTimesMs: [500, Math.round(durationMs / 2), Math.max(0, durationMs - 500)],
    });
    addProcessEntry('info', `Prometheus Video: sampled ${Array.isArray(data.frames) ? data.frames.length : 0} HTML motion QA frames.`);
    showToast('HTML motion frame QA complete.', 'success');
    renderCreativeWorkspace({ skipStageRender: true });
    return data;
  } catch (err) {
    showToast(String(err?.message || err || 'Could not sample HTML motion frames.'), 'error');
    return null;
  }
}

async function canvasExportHtmlMotionClip(force = false) {
  try {
    const data = await exportCreativeHtmlMotionClip({ format: 'mp4', force: force === true });
    showToast(data?.export?.path ? 'HTML motion MP4 exported in-house.' : 'HTML motion export complete.', 'success');
    renderCreativeWorkspace({ skipStageRender: true });
    return data;
  } catch (err) {
    showToast(String(err?.message || err || 'Could not export HTML motion MP4.'), 'error');
    renderCreativeWorkspace({ skipStageRender: true });
    return null;
  }
}

async function canvasInsertHtmlMotionBlock(blockId) {
  const id = String(blockId || '').trim();
  if (!id) return null;
  try {
    let clip = normalizeCreativeHtmlMotionClip(creativeHtmlMotionClip);
    if (!clip) {
      const created = await canvasCreateBlankHtmlMotionComposition({ title: 'HTML Motion Composition' });
      clip = normalizeCreativeHtmlMotionClip(created?.clip || creativeHtmlMotionClip);
    }
    const response = await fetch('/api/canvas/html-motion-blocks/render', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ blockId: id, inputs: {} }),
    });
    const rendered = await response.json().catch(() => ({}));
    if (!response.ok || rendered?.success === false) throw new Error(rendered?.error || `HTTP ${response.status}`);
    const blockName = rendered?.block?.name || id;
    const ops = [];
    if (rendered.css) {
      ops.push({
        op: 'insert_before',
        marker: '/* @prometheus-region styles */',
        content: `\n    /* ${blockName} */\n    ${rendered.css}\n`,
      });
    }
    if (rendered.html) {
      ops.push({
        op: 'insert_after',
        marker: '<!-- @prometheus-region blocks -->',
        content: `\n    ${rendered.html}`,
      });
    }
    if (rendered.js) {
      ops.push({
        op: 'insert_before',
        marker: '<!-- @prometheus-region scripts -->',
        content: `\n  ${rendered.js}\n`,
      });
    }
    if (!ops.length) throw new Error(`Block ${id} did not return insertable content.`);
    const patched = await patchCreativeHtmlMotionClip({
      clip,
      ops,
      reason: `insert HTML motion block ${id}`,
      includeHtml: false,
    });
    updateCreativeHtmlMotionLintFromPayload(patched);
    await canvasRefreshHtmlMotionLint({ render: false, silent: true });
    showToast(`Inserted ${blockName}.`, 'success');
    renderCreativeWorkspace({ skipStageRender: false });
    return patched;
  } catch (err) {
    showToast(String(err?.message || err || 'Could not insert HTML motion block.'), 'error');
    renderCreativeWorkspace({ skipStageRender: true });
    return null;
  }
}

