function formatCreativeAssetBytes(size) {
  const fileSize = Math.max(0, Number(size) || 0);
  if (fileSize >= 1024 * 1024) return `${(fileSize / (1024 * 1024)).toFixed(2)} MB`;
  if (fileSize >= 1024) return `${(fileSize / 1024).toFixed(1)} KB`;
  return `${fileSize} bytes`;
}

function formatCreativeAssetTimestamp(value) {
  const date = new Date(value || '');
  if (Number.isNaN(date.getTime())) return 'Unknown time';
  return date.toLocaleString([], {
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });
}

function describeCreativeSceneAssetSummary(entry) {
  const summary = entry?.summary && typeof entry.summary === 'object' ? entry.summary : null;
  const parts = [];
  if (Number.isFinite(Number(summary?.width)) && Number.isFinite(Number(summary?.height))) {
    parts.push(`${Number(summary.width)} x ${Number(summary.height)}`);
  }
  if (Number.isFinite(Number(summary?.elementCount))) {
    parts.push(`${Number(summary.elementCount)} elements`);
  }
  if (Number(summary?.animatedCount) > 0) {
    parts.push(`${Number(summary.animatedCount)} animated`);
  }
  return parts.join(' | ') || 'Scene snapshot';
}

function getCreativeAssetsRequestKey(mode = window.currentCreativeMode) {
  const sessionId = getActiveCreativeSessionId();
  const normalizedMode = normalizeCreativeMode(mode);
  const root = normalizeCanvasPath(canvasProjectRoot || '');
  return `${sessionId}::${normalizedMode}::${root}`;
}

function syncCreativeLibrariesFromPayload(payload, options = {}) {
  const sessionId = String(options.sessionId || getActiveCreativeSessionId() || '').trim();
  const normalizedMode = normalizeCreativeMode(options.mode || window.currentCreativeMode);
  const requestKey = String(options.key || `${sessionId}::${normalizedMode}::${normalizeCanvasPath(options.root || canvasProjectRoot || '')}`);
  const customPacks = Array.isArray(payload?.customPacks) ? payload.customPacks : [];
  setCreativeLibraryRuntimePacks(customPacks);
  const libraryCatalog = Array.isArray(payload?.libraries) && payload.libraries.length
    ? payload.libraries
    : getCreativeLibraryPackCatalog(customPacks).map((pack) => ({ ...pack, enabled: !!pack.defaultEnabled, source: pack.source || 'builtin' }));
  creativeLibrariesState = {
    key: requestKey,
    sessionId,
    mode: normalizedMode,
    storageRoot: normalizeCanvasPath(payload?.storageRoot || creativeLibrariesState.storageRoot || ''),
    storageRootRelative: normalizeCanvasPath(payload?.storageRootRelative || creativeLibrariesState.storageRootRelative || ''),
    usesProjectRoot: payload?.usesProjectRoot === true,
    librariesDir: normalizeCanvasPath(payload?.librariesDir || creativeLibrariesState.librariesDir || ''),
    librariesDirRelative: normalizeCanvasPath(payload?.librariesDirRelative || creativeLibrariesState.librariesDirRelative || ''),
    libraries: libraryCatalog,
    customPacks: customPacks.slice(),
    enabledLibraryIds: Array.isArray(payload?.enabledLibraryIds) ? payload.enabledLibraryIds.map((id) => String(id || '').trim().toLowerCase()).filter(Boolean) : getEnabledCreativeLibraryIds([]),
    loadedAt: Date.now(),
    loading: false,
    error: '',
  };
  if (window.prometheusCreativeCore && typeof window.prometheusCreativeCore === 'object') {
    window.prometheusCreativeCore.libraryPacks = getCreativeLibraryPackCatalog(customPacks);
    window.prometheusCreativeCore.elementLibrary = getCreativeElementLibrary(creativeLibrariesState.enabledLibraryIds);
    window.prometheusCreativeCore.enabledLibraryIds = getActiveCreativeLibraryIds();
  }
}

function getCreativeLibrariesRequestKey(mode = window.currentCreativeMode) {
  return getCreativeAssetsRequestKey(mode);
}

function getActiveCreativeLibraryIds() {
  return getEnabledCreativeLibraryIds(Array.isArray(creativeLibrariesState.enabledLibraryIds) ? creativeLibrariesState.enabledLibraryIds : []);
}

function getActiveCreativeElementLibrary() {
  return getCreativeElementLibrary(getActiveCreativeLibraryIds());
}

function getActiveCreativeAnimationPresetCatalog(elementType = '') {
  return getCreativeAnimationPresetCatalog(getActiveCreativeLibraryIds(), elementType);
}

function getCreativeLibraryPackCatalogState() {
  return Array.isArray(creativeLibrariesState.libraries) && creativeLibrariesState.libraries.length
    ? creativeLibrariesState.libraries
    : getCreativeLibraryPackCatalog(Array.isArray(creativeLibrariesState.customPacks) ? creativeLibrariesState.customPacks : []);
}

function getCreativeLibraryPackMap() {
  const map = new Map();
  getCreativeLibraryPackCatalogState().forEach((pack) => {
    if (pack?.id) map.set(String(pack.id).trim().toLowerCase(), pack);
  });
  return map;
}

function normalizeCreativeBrowserQuery(value) {
  return String(value || '').trim().toLowerCase();
}

function getFilteredCreativeLibrarySections() {
  const packMap = getCreativeLibraryPackMap();
  const activeLibrary = getActiveCreativeElementLibrary();
  const query = normalizeCreativeBrowserQuery(creativeLibraryBrowserState.query);
  const selectedLibrary = String(creativeLibraryBrowserState.libraryId || '__all__').trim().toLowerCase() || '__all__';
  const sections = Object.entries(activeLibrary).map(([section, items]) => {
    const filteredItems = (Array.isArray(items) ? items : []).filter((item) => {
      const itemLibraryId = String(item?.libraryId || '').trim().toLowerCase();
      const pack = itemLibraryId ? packMap.get(itemLibraryId) : null;
      const packLabel = String(pack?.label || item?.libraryId || '').trim();
      if (selectedLibrary === '__builtin__' && String(pack?.source || 'builtin') === 'custom') return false;
      if (selectedLibrary === '__custom__' && String(pack?.source || 'builtin') !== 'custom') return false;
      if (!selectedLibrary.startsWith('__') && itemLibraryId !== selectedLibrary) return false;
      if (!query) return true;
      const haystack = [
        section,
        item?.label,
        item?.kind,
        item?.type,
        item?.libraryId,
        packLabel,
        item?.meta?.iconName,
        item?.meta?.shape,
        item?.meta?.component,
        item?.meta?.content,
      ].map((value) => String(value || '').toLowerCase()).join(' ');
      return haystack.includes(query);
    }).map((item) => {
      const itemLibraryId = String(item?.libraryId || '').trim().toLowerCase();
      return {
        ...item,
        pack: itemLibraryId ? packMap.get(itemLibraryId) || null : null,
      };
    });
    return {
      section,
      items: filteredItems,
    };
  }).filter((entry) => entry.items.length);
  const totalItems = sections.reduce((sum, entry) => sum + entry.items.length, 0);
  const matchedLibraryIds = [...new Set(sections.flatMap((entry) => entry.items.map((item) => String(item?.libraryId || '').trim().toLowerCase()).filter(Boolean)))];
  return {
    sections,
    totalItems,
    matchedLibraryIds,
  };
}

function getFilteredCreativePresetCatalog(elementType = '') {
  const packMap = getCreativeLibraryPackMap();
  const presetCatalog = getActiveCreativeAnimationPresetCatalog(elementType);
  const query = normalizeCreativeBrowserQuery(creativePresetBrowserState.query);
  const selectedLibrary = String(creativePresetBrowserState.libraryId || '__all__').trim().toLowerCase() || '__all__';
  const filtered = presetCatalog.filter((preset) => {
    const libraryId = String(preset?.libraryId || '').trim().toLowerCase();
    const pack = libraryId ? packMap.get(libraryId) : null;
    const packLabel = String(pack?.label || libraryId || '').trim();
    if (selectedLibrary === '__builtin__' && String(pack?.source || 'builtin') === 'custom') return false;
    if (selectedLibrary === '__custom__' && String(pack?.source || 'builtin') !== 'custom') return false;
    if (!selectedLibrary.startsWith('__') && libraryId !== selectedLibrary) return false;
    if (!query) return true;
    const haystack = [
      preset?.id,
      preset?.label,
      preset?.libraryId,
      packLabel,
      ...(Array.isArray(preset?.targets) ? preset.targets : []),
    ].map((value) => String(value || '').toLowerCase()).join(' ');
    return haystack.includes(query);
  }).map((preset) => {
    const libraryId = String(preset?.libraryId || '').trim().toLowerCase();
    return {
      ...preset,
      pack: libraryId ? packMap.get(libraryId) || null : null,
    };
  });
  const grouped = filtered.reduce((acc, preset) => {
    const libraryId = String(preset?.libraryId || 'unassigned').trim().toLowerCase() || 'unassigned';
    if (!acc[libraryId]) acc[libraryId] = [];
    acc[libraryId].push(preset);
    return acc;
  }, {});
  const groups = Object.entries(grouped).map(([libraryId, presets]) => ({
    libraryId,
    pack: presets[0]?.pack || packMap.get(libraryId) || null,
    presets,
  }));
  return {
    presets: filtered,
    groups,
  };
}

function canvasSetCreativeLibraryNavTab(tab) {
  const next = String(tab || '').trim().toLowerCase() || null;
  creativeLibraryNavTab = (creativeLibraryNavTab === next) ? null : next;
  renderCreativeWorkspace({ skipStageRender: true });
}

function canvasSetCreativeLibraryCategory(cat) {
  creativeLibraryActiveCategory = cat ? String(cat).trim().toLowerCase() : null;
  renderCreativeWorkspace({ skipStageRender: true });
}

let _iconifyDebounceTimer = null;
async function canvasSearchIconify(query) {
  const q = String(query || '').trim();
  // Update query state immediately but don't re-render — that would blow away the input/focus.
  creativeIconifySearch.query = q;
  if (_iconifyDebounceTimer) { clearTimeout(_iconifyDebounceTimer); _iconifyDebounceTimer = null; }
  if (!q) {
    creativeIconifySearch = { query: '', results: [], loading: false, error: '' };
    renderCreativeWorkspace({ skipStageRender: true });
    refocusIconifySearchInput();
    return;
  }
  _iconifyDebounceTimer = setTimeout(async () => {
    creativeIconifySearch = { query: q, results: creativeIconifySearch.results, loading: true, error: '' };
    renderCreativeWorkspace({ skipStageRender: true });
    refocusIconifySearchInput();
    try {
      const res = await fetch(`https://api.iconify.design/search?query=${encodeURIComponent(q)}&limit=64`);
      const data = await res.json();
      creativeIconifySearch = { query: q, results: Array.isArray(data.icons) ? data.icons : [], loading: false, error: '' };
    } catch (err) {
      creativeIconifySearch = { ...creativeIconifySearch, loading: false, error: 'Search failed. Check connection.' };
    }
    renderCreativeWorkspace({ skipStageRender: true });
    refocusIconifySearchInput();
  }, 280);
}

function refocusIconifySearchInput() {
  setTimeout(() => {
    const input = document.querySelector('#canvas-creative-library input[type="search"]');
    if (input && document.activeElement !== input) {
      input.focus();
      const len = input.value.length;
      try { input.setSelectionRange(len, len); } catch {}
    }
  }, 0);
}

function canvasAddIconifyIcon(iconName) {
  const name = String(iconName || '').trim();
  if (!name) return;
  ensureCreativeSceneForMode(window.currentCreativeMode);
  const nextZ = creativeSceneDoc.elements.length;
  const baseX = 96 + (creativeSceneDoc.elements.length % 4) * 56;
  const baseY = 120 + (creativeSceneDoc.elements.length % 5) * 44;
  const patch = { op: 'add', type: 'icon', x: baseX, y: baseY, width: 84, height: 84, zIndex: nextZ, meta: { iconName: name, color: '#111827' } };
  const nextDoc = executeSceneGraphOps(creativeSceneDoc, [patch]);
  const added = nextDoc.elements[nextDoc.elements.length - 1];
  setCreativeSceneDoc(nextDoc, { render: false, recordHistory: true });
  setCreativeSelection(added?.id || null, { render: false });
  renderCreativeWorkspace();
}

