function ensureCreativeLibrariesHydrated(mode = window.currentCreativeMode) {
  const normalizedMode = normalizeCreativeMode(mode);
  const sessionId = getActiveCreativeSessionId();
  if (!sessionId || !isStructuredCreativeMode(normalizedMode)) return;
  const requestKey = getCreativeLibrariesRequestKey(normalizedMode);
  if (creativeLibrariesState.loading && creativeLibrariesState.key === requestKey) return;
  if (creativeLibrariesState.key === requestKey && creativeLibrariesState.loadedAt && !creativeLibrariesState.error) return;
  loadCreativeLibraries({ mode: normalizedMode, silent: true, renderStart: false }).catch(() => {});
}

async function loadCreativeLibraries(options = {}) {
  const sessionId = getActiveCreativeSessionId();
  const normalizedMode = normalizeCreativeMode(options.mode || window.currentCreativeMode);
  if (!sessionId || !isStructuredCreativeMode(normalizedMode)) {
    creativeLibrariesState = {
      key: '',
      sessionId: '',
      mode: null,
      storageRoot: '',
      storageRootRelative: '',
      usesProjectRoot: false,
      librariesDir: '',
      librariesDirRelative: '',
      libraries: [],
      customPacks: [],
      enabledLibraryIds: [],
      loadedAt: 0,
      loading: false,
      error: '',
    };
    setCreativeLibraryRuntimePacks([]);
    if (window.prometheusCreativeCore && typeof window.prometheusCreativeCore === 'object') {
      window.prometheusCreativeCore.libraryPacks = getCreativeLibraryPackCatalog([]);
      window.prometheusCreativeCore.elementLibrary = getCreativeElementLibrary([]);
      window.prometheusCreativeCore.enabledLibraryIds = getEnabledCreativeLibraryIds([]);
    }
    return null;
  }
  const rootHint = normalizeCanvasPath(options.root || canvasProjectRoot || '');
  const requestKey = `${sessionId}::${normalizedMode}::${rootHint}`;
  if (!options.force) {
    if (creativeLibrariesState.loading && creativeLibrariesState.key === requestKey) return creativeLibrariesState;
    if (creativeLibrariesState.key === requestKey && creativeLibrariesState.loadedAt && !creativeLibrariesState.error) return creativeLibrariesState;
  }
  creativeLibrariesState = {
    ...creativeLibrariesState,
    key: requestKey,
    sessionId,
    mode: normalizedMode,
    loading: true,
    error: '',
  };
  if (options.renderStart !== false) renderCreativeWorkspace();
  const requestToken = ++creativeLibrariesRequestToken;
  try {
    const params = new URLSearchParams({ sessionId });
    if (rootHint) params.set('root', rootHint);
    const response = await fetch(`/api/canvas/creative-libraries?${params.toString()}`);
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) {
      throw new Error(data?.error || `HTTP ${response.status}`);
    }
    if (requestToken !== creativeLibrariesRequestToken) return creativeLibrariesState;
    syncCreativeLibrariesFromPayload(data, { sessionId, mode: normalizedMode, key: requestKey, root: rootHint });
    return creativeLibrariesState;
  } catch (err) {
    if (requestToken !== creativeLibrariesRequestToken) return null;
    creativeLibrariesState = {
      ...creativeLibrariesState,
      key: requestKey,
      sessionId,
      mode: normalizedMode,
      loading: false,
      error: String(err?.message || err || 'Could not load creative libraries.'),
    };
    if (!options.silent) {
      showToast('Could not load creative libraries', creativeLibrariesState.error, 'error');
    }
    return null;
  } finally {
    if (requestToken === creativeLibrariesRequestToken && options.renderEnd !== false) {
      renderCreativeWorkspace();
    }
  }
}

async function canvasToggleCreativeLibraryPack(libraryId, enabled) {
  const sessionId = getActiveCreativeSessionId();
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  const normalizedId = String(libraryId || '').trim().toLowerCase();
  if (!sessionId || !normalizedId || !isStructuredCreativeMode(mode)) return null;
  creativeLibrariesState = {
    ...creativeLibrariesState,
    loading: true,
    error: '',
  };
  renderCreativeWorkspace();
  try {
    const response = await fetch('/api/canvas/creative-libraries', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId,
        mode,
        root: canvasProjectRoot || '',
        libraryId: normalizedId,
        enabled: enabled !== false,
      }),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) {
      throw new Error(data?.error || `HTTP ${response.status}`);
    }
    syncCreativeLibrariesFromPayload(data, {
      sessionId,
      mode,
      key: getCreativeLibrariesRequestKey(mode),
      root: canvasProjectRoot || '',
    });
    showToast(
      enabled !== false ? 'Library installed' : 'Library disabled',
      `${data?.libraries?.find?.((entry) => entry.id === normalizedId)?.label || normalizedId} ${enabled !== false ? 'is now available in the studio.' : 'has been hidden from the studio rail.'}`,
      'success'
    );
    renderCreativeWorkspace();
    persistActiveChat();
    return data;
  } catch (err) {
    creativeLibrariesState = {
      ...creativeLibrariesState,
      loading: false,
      error: String(err?.message || err || 'Could not update creative library.'),
    };
    showToast('Could not update creative library', creativeLibrariesState.error, 'error');
    renderCreativeWorkspace();
    return null;
  }
}

