  if (kind === 'video' || kind === 'movie') return 'solar:videocamera-bold-duotone';
  if (kind === 'audio' || kind === 'sound') return 'solar:music-note-bold-duotone';
  if (kind === 'file' || kind === 'document') return 'solar:document-bold-duotone';
  if (kind === 'link' || kind === 'url') return 'solar:link-bold-duotone';
  if (kind === 'tag' || kind === 'label') return 'solar:tag-bold-duotone';
