async function handleCreativeHtmlMotionAutoHeight() {
  if (creativeHtmlMotionActionPopoverEl) creativeHtmlMotionActionPopoverEl.style.display = 'none';
  const el = creativeHtmlMotionLastClickedElement;
  const frame = creativeHtmlMotionLastClickedFrame;
  if (!el || !frame || !isCreativeHtmlMotionElementTextEditable(el)) return;
  try {
    const measurement = measureCreativeHtmlMotionTextElement(el, frame, String(el.textContent || ''));
    if (!measurement) throw new Error('Could not measure selected text.');
    const nextHeight = Math.max(24, Math.ceil(measurement.measuredHeight + 8));
    await patchSelectedCreativeHtmlMotionTextStyle({
      height: `${nextHeight}px`,
      minHeight: `${nextHeight}px`,
      boxSizing: 'border-box',
    }, 'Auto-fit selected HTML motion text height with PreText.', 'HTML Motion: text height fit.');
  } catch (err) {
    showToast(`HTML motion auto-height failed: ${err.message || err}`, 'error');
  }
}

async function handleCreativeHtmlMotionShrinkToFit() {
  if (creativeHtmlMotionActionPopoverEl) creativeHtmlMotionActionPopoverEl.style.display = 'none';
  const el = creativeHtmlMotionLastClickedElement;
  const frame = creativeHtmlMotionLastClickedFrame;
  if (!el || !frame || !isCreativeHtmlMotionElementTextEditable(el)) return;
  try {
    const computed = frame.contentWindow?.getComputedStyle?.(el);
    const rect = el.getBoundingClientRect();
    if (!computed || !rect.width || !rect.height) throw new Error('Could not inspect selected text bounds.');
    const startSize = Math.max(8, parseCreativeHtmlMotionPx(computed.fontSize, 16));
    const minSize = Math.max(10, Math.floor(startSize * 0.55));
    let chosen = measureCreativeHtmlMotionTextForSize(el, frame, startSize, rect.width, rect.height);
    for (let size = Math.floor(startSize); size >= minSize; size -= 1) {
      const measured = measureCreativeHtmlMotionTextForSize(el, frame, size, rect.width, rect.height);
      if (!measured) continue;
      chosen = measured;
      if (!measured.overflowY) break;
    }
    if (!chosen) throw new Error('Could not calculate a fitting font size.');
    await patchSelectedCreativeHtmlMotionTextStyle({
      fontSize: `${Math.round(chosen.fontSize)}px`,
      lineHeight: Number(chosen.lineHeightRatio || 1.15).toFixed(2),
      boxSizing: 'border-box',
    }, 'Shrink selected HTML motion text to fit with PreText.', 'HTML Motion: text shrunk to fit.');
  } catch (err) {
    showToast(`HTML motion shrink-to-fit failed: ${err.message || err}`, 'error');
  }
}

async function handleCreativeHtmlMotionBalanceText() {
  if (creativeHtmlMotionActionPopoverEl) creativeHtmlMotionActionPopoverEl.style.display = 'none';
  const el = creativeHtmlMotionLastClickedElement;
  const frame = creativeHtmlMotionLastClickedFrame;
  if (!el || !frame || !isCreativeHtmlMotionElementTextEditable(el)) return;
  try {
    const rect = el.getBoundingClientRect();
    if (!rect.width || !rect.height) throw new Error('Could not inspect selected text bounds.');
    const currentWidth = Math.max(24, Math.round(rect.width));
    const minWidth = Math.max(80, Math.round(currentWidth * 0.72));
    const maxWidth = Math.round(currentWidth * 1.28);
    let best = null;
    for (let width = minWidth; width <= maxWidth; width += 8) {
      const measured = measureCreativeHtmlMotionTextForSize(
        el,
        frame,
        Math.max(8, parseCreativeHtmlMotionPx(frame.contentWindow?.getComputedStyle?.(el)?.fontSize, 16)),
        width,
        rect.height
      );
      if (!measured) continue;
      const linePenalty = Math.abs(measured.lineCount - 2.5) * 28;
      const overflowPenalty = measured.overflowY ? 10000 + Math.max(0, measured.measuredHeight - rect.height) * 20 : 0;
      const driftPenalty = Math.abs(width - currentWidth) * 0.18;
      const ragPenalty = Math.abs((measured.measuredHeight / Math.max(1, measured.lineHeightPx)) - measured.lineCount) * 6;
      const score = linePenalty + overflowPenalty + driftPenalty + ragPenalty;
      if (!best || score < best.score) best = { score, width, measured };
    }
    if (!best) throw new Error('Could not calculate a balanced text width.');
    await patchSelectedCreativeHtmlMotionTextStyle({
      width: `${Math.round(best.width)}px`,
      boxSizing: 'border-box',
    }, 'Balance selected HTML motion text width with PreText.', 'HTML Motion: text balanced.');
  } catch (err) {
    showToast(`HTML motion text balance failed: ${err.message || err}`, 'error');
  }
}

function isCreativeHtmlMotionElementTextEditable(element) {
  if (!element || element.nodeType !== 1) return false;
  const tag = String(element.tagName || '').toLowerCase();
  if (['input','textarea','select','script','style','img','svg','video','audio','iframe','canvas','picture','source','hr','br','meta','link'].includes(tag)) return false;
  const text = String(element.innerText || element.textContent || '').trim();
  if (!text) return false;
  const children = Array.from(element.children || []);
  if (!children.length) return true;
  const inlineTags = new Set(['b','i','em','strong','span','br','u','small','sup','sub','mark']);
  return children.every((child) => inlineTags.has(String(child.tagName || '').toLowerCase()) && !child.children.length);
}

function showCreativeHtmlMotionInlineEditor(element, frame) {
  if (!element || !frame) return;
  if (element.dataset.prometheusHtmlMotionInlineEditing === '1') return;
  const originalText = String(element.textContent || '');
  element.dataset.prometheusHtmlMotionInlineEditing = '1';
  element.dataset.prometheusHtmlMotionOriginalText = originalText;
  element.setAttribute('contenteditable', 'true');
  element.spellcheck = false;
  try { element.focus({ preventScroll: false }); } catch { element.focus(); }
  applyCreativeHtmlMotionPretextInlineFeedback(element, frame, originalText);
  try {
    const doc = frame.contentDocument;
    const range = doc.createRange();
    range.selectNodeContents(element);
    const sel = frame.contentWindow.getSelection();
    sel.removeAllRanges();
    sel.addRange(range);
  } catch {}
  let canceled = false;
  const cleanup = () => {
    element.removeEventListener('blur', onBlur);
    element.removeEventListener('keydown', onKey);
    element.removeEventListener('input', onInput);
    element.removeAttribute('contenteditable');
    element.style.outline = '';
    element.style.boxShadow = '';
    element.removeAttribute('title');
    delete element.dataset.prometheusHtmlMotionPretext;
    delete element.dataset.prometheusHtmlMotionInlineEditing;
  };
  const onKey = (e) => {
    if (e.key === 'Escape') { e.preventDefault(); canceled = true; element.blur(); }
    else if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); element.blur(); }
  };
  const onInput = () => {
    applyCreativeHtmlMotionPretextInlineFeedback(element, frame, String(element.textContent || ''));
  };
  const onBlur = () => {
    cleanup();
    if (canceled) {
      element.textContent = originalText;
      delete element.dataset.prometheusHtmlMotionOriginalText;
      return;
    }
    commitCreativeHtmlMotionInlineEdit(element, originalText);
  };
  element.addEventListener('blur', onBlur);
  element.addEventListener('keydown', onKey);
  element.addEventListener('input', onInput);
}

async function commitCreativeHtmlMotionInlineEdit(element, originalText) {
  const newText = String(element.textContent || '');
  delete element.dataset.prometheusHtmlMotionOriginalText;
  if (newText === originalText) return;
  if (!creativeHtmlMotionClip) {
    element.textContent = originalText;
    showToast('No active HTML motion clip to patch.', 'error');
    return;
  }
  const measurement = measureCreativeHtmlMotionTextElement(element, creativeHtmlMotionLastClickedFrame, newText);
  try {
    const result = await patchCreativeHtmlMotionInlineTextBySelection(element, originalText, newText);
    const appliedCount = (Array.isArray(result?.appliedOps) ? result.appliedOps : Array.isArray(result?.applied) ? result.applied : [])
      .reduce((sum, op) => sum + Math.max(0, Number(op?.count) || 0), 0);
    if (!appliedCount) throw new Error('Could not uniquely locate that text in the clip HTML.');
    showToast(
      measurement?.overflowY ? 'HTML Motion: text updated, but may overflow.' : 'HTML Motion: text updated.',
      measurement?.overflowY ? 'PreText measured the edited copy taller than its selected box.' : 'PreText fit check passed.',
      measurement?.overflowY ? 'warn' : 'success'
    );
    if (creativeHtmlMotionLastClickedElement && creativeHtmlMotionLastClickedFrame) {
      creativeHtmlMotionSelectedElementContext = extractCreativeHtmlMotionElementContext(creativeHtmlMotionLastClickedElement, creativeHtmlMotionLastClickedFrame);
      updateDesignSelectionChip();
    }
  } catch (err) {
    element.textContent = originalText;
    showToast(`HTML motion edit failed: ${err.message || err}`, 'error');
  }
}

async function patchCreativeHtmlMotionInlineTextBySelection(element, originalText, newText) {
  const selector = String(creativeHtmlMotionSelectedElementContext?.selector || '').trim();
  if (selector) {
    try {
      const read = await readCreativeHtmlMotionClip({ includeHtml: true });
      const html = String(read?.clip?.html || read?.html || '');
      if (html) {
        const parser = new DOMParser();
        const doc = parser.parseFromString(html, 'text/html');
        const target = doc.querySelector(selector);
        if (target) {
          const beforeOuter = String(target.outerHTML || '');
          target.textContent = String(newText || '');
          const afterOuter = String(target.outerHTML || '');
          if (beforeOuter && afterOuter && beforeOuter !== afterOuter) {
            return patchCreativeHtmlMotionClip({
              reason: `Direct inline text edit for selected HTML motion element ${selector}.`,
              ops: [{ op: 'replace_text', find: beforeOuter, replace: afterOuter, occurrence: 1 }],
            });
          }
        }
      }
    } catch {}
  }
  const originalEscaped = _designHtmlEscape(originalText);
  const newEscaped = _designHtmlEscape(newText);
  return patchCreativeHtmlMotionClip({
    reason: 'Direct inline text edit from the HTML motion preview.',
    ops: [
      { op: 'replace_text', find: originalText, replace: newText, occurrence: 1, required: false },
      originalEscaped !== originalText
        ? { op: 'replace_text', find: originalEscaped, replace: newEscaped, occurrence: 1, required: false }
        : null,
    ].filter(Boolean),
  });
}

function showCreativeHtmlMotionChatPopover(element, frame) {
  if (!creativeHtmlMotionChatPopoverEl) {
    creativeHtmlMotionChatPopoverEl = document.createElement('div');
    creativeHtmlMotionChatPopoverEl.id = 'creative-html-motion-chat-popover';
    creativeHtmlMotionChatPopoverEl.style.cssText = 'position:fixed;z-index:10000;display:none;width:320px;padding:10px;border-radius:12px;border:1px solid rgba(255,255,255,0.14);background:rgba(12,16,24,0.98);box-shadow:0 14px 36px rgba(0,0,0,0.5);backdrop-filter:blur(14px);font-family:Manrope,sans-serif;flex-direction:column;gap:8px';
    creativeHtmlMotionChatPopoverEl.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:space-between;gap:8px">
        <div style="font-size:10px;font-weight:800;letter-spacing:0.08em;text-transform:uppercase;color:#a8a29e">Chat about selected clip element</div>
        <button type="button" onclick="hideCreativeHtmlMotionChatPopover()" style="border:none;background:transparent;color:#a8a29e;font-size:16px;cursor:pointer;padding:0;line-height:1;font-family:inherit">x</button>
      </div>
      <textarea id="creative-html-motion-chat-input" rows="3" placeholder="Ask to move, restyle, replace, retime, or explain this element..." style="width:100%;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:8px;padding:8px 10px;font-size:12px;font-family:inherit;resize:vertical;outline:none"></textarea>
      <div style="display:flex;align-items:center;gap:6px">
        <div style="flex:1"></div>
        <button type="button" onclick="submitCreativeHtmlMotionChatPopover()" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(56,189,248,0.28);background:rgba(56,189,248,0.16);color:#bae6fd;border-radius:8px;padding:6px 12px;font-size:11px;font-weight:800;cursor:pointer;font-family:inherit"><iconify-icon icon="solar:plain-bold-duotone" width="14" height="14"></iconify-icon>Send</button>
      </div>
    `;
    document.body.appendChild(creativeHtmlMotionChatPopoverEl);
    const ta = creativeHtmlMotionChatPopoverEl.querySelector('#creative-html-motion-chat-input');
    ta?.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); submitCreativeHtmlMotionChatPopover(); }
      if (e.key === 'Escape') { e.preventDefault(); hideCreativeHtmlMotionChatPopover(); }
    });
  }
  const ta = document.getElementById('creative-html-motion-chat-input');
  if (ta) ta.value = '';
  creativeHtmlMotionChatPopoverEl.style.display = 'flex';
  positionCreativeHtmlMotionPopover(creativeHtmlMotionChatPopoverEl, element, frame);
  setTimeout(() => document.getElementById('creative-html-motion-chat-input')?.focus(), 30);
}

async function submitCreativeHtmlMotionChatPopover() {
  const textarea = document.getElementById('creative-html-motion-chat-input');
  const text = String(textarea?.value || '').trim();
  if (!text) return;
  const mainInput = document.getElementById('chat-input');
  if (!mainInput) { showToast('Main chat input not found.', 'error'); return; }
  mainInput.value = text;
  hideCreativeHtmlMotionChatPopover();
  try { await sendChat(); } catch (err) { showToast(`Send failed: ${err.message}`, 'error'); }
}

// === Design-mode click-to-edit popover system ===
let designActionPopoverEl = null;
let designChatPopoverEl = null;
let designFilesPopoverEl = null;
let designLastClickedFrame = null;
let designLastClickedElement = null;
let designSelectMode = false;
let designMultiSelectedElements = [];
let designSelectModeOutsideHandler = null;

function getDesignPreviewTabPath() {
  const tab = canvasTabs.find((t) => t.id === activeCanvasTabId);
  return tab?.diskPath || '';
}

function repositionDesignPopovers() {
  if (designActionPopoverEl && designActionPopoverEl.style.display !== 'none' && designLastClickedElement && designLastClickedFrame) {
    showDesignActionPopover(designLastClickedElement, designLastClickedFrame);
  }
  if (designChatPopoverEl && designChatPopoverEl.style.display !== 'none' && designLastClickedElement && designLastClickedFrame) {
    positionDesignChatPopover(designLastClickedElement, designLastClickedFrame);
  }
}

function hideAllDesignPopovers() {
  if (designActionPopoverEl) designActionPopoverEl.style.display = 'none';
  if (designChatPopoverEl) designChatPopoverEl.style.display = 'none';
  if (designFilesPopoverEl) designFilesPopoverEl.style.display = 'none';
}

function getDesignFrameScale(frame) {
  const rect = frame?.getBoundingClientRect?.();
  const width = Number(frame?.offsetWidth || 0);
  return rect?.width && width ? rect.width / width : 1;
}

function showDesignActionPopover(element, frame) {
  if (!designActionPopoverEl) {
    designActionPopoverEl = document.createElement('div');
    designActionPopoverEl.id = 'design-action-popover';
    designActionPopoverEl.style.cssText = 'position:fixed;z-index:10000;display:none;gap:4px;padding:4px;border-radius:10px;border:1px solid rgba(255,255,255,0.14);background:rgba(17,15,14,0.96);box-shadow:0 8px 24px rgba(0,0,0,0.45);backdrop-filter:blur(12px);font-family:Manrope,sans-serif';
    designActionPopoverEl.innerHTML = `
      <button type="button" onclick="handleDesignEdit()" style="display:inline-flex;align-items:center;gap:6px;border:none;background:rgba(249,115,22,0.16);color:#fdba74;border-radius:6px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer;font-family:inherit"><iconify-icon icon="solar:pen-2-bold-duotone" width="14" height="14"></iconify-icon>Edit</button>
      <button type="button" onclick="handleDesignChat()" style="display:inline-flex;align-items:center;gap:6px;border:none;background:rgba(56,189,248,0.16);color:#bae6fd;border-radius:6px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer;font-family:inherit"><iconify-icon icon="solar:chat-round-line-bold-duotone" width="14" height="14"></iconify-icon>Chat</button>
      <button type="button" onclick="handleDesignSelect()" style="display:inline-flex;align-items:center;gap:6px;border:none;background:rgba(168,85,247,0.18);color:#d8b4fe;border-radius:6px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer;font-family:inherit"><iconify-icon icon="solar:cursor-square-bold-duotone" width="14" height="14"></iconify-icon>Select</button>
    `;
    document.body.appendChild(designActionPopoverEl);
  }
  designActionPopoverEl.style.display = 'flex';
  const frameRect = frame.getBoundingClientRect();
  const rect = element.getBoundingClientRect();
  const scale = getDesignFrameScale(frame);
  const pw = designActionPopoverEl.offsetWidth || 160;
  const ph = designActionPopoverEl.offsetHeight || 34;
  const absLeft = frameRect.left + (rect.left * scale);
  const absTop = frameRect.top + (rect.top * scale);
  const scaledHeight = rect.height * scale;
  let top = absTop - ph - 8;
  if (top < 12) top = absTop + scaledHeight + 8;
  let left = absLeft;
  if (left + pw > window.innerWidth - 8) left = window.innerWidth - pw - 8;
  if (left < 8) left = 8;
  designActionPopoverEl.style.left = `${left}px`;
  designActionPopoverEl.style.top = `${top}px`;
}

function isDesignElementTextEditable(element) {
  if (!element || element.nodeType !== 1) return false;
  const tag = String(element.tagName || '').toLowerCase();
  if (['input','textarea','select','script','style','img','svg','video','audio','iframe','canvas','picture','source','hr','br','meta','link'].includes(tag)) return false;
  if (!element.childNodes.length) return false;
  const inlineTags = new Set(['b','i','em','strong','span','br','u','small','sup','sub']);
  for (const child of element.childNodes) {
    if (child.nodeType === 3) continue;
    if (child.nodeType === 1 && inlineTags.has(String(child.tagName || '').toLowerCase()) && !child.children.length) continue;
    return false;
  }
  return String(element.textContent || '').trim().length > 0;
}

async function handleDesignEdit() {
  const el = designLastClickedElement;
  const frame = designLastClickedFrame;
  if (designActionPopoverEl) designActionPopoverEl.style.display = 'none';
  if (!el || !frame) return;
  if (isDesignElementTextEditable(el)) {
    showDesignInlineEditor(el, frame);
    return;
  }
  const matches = await findDesignElementInSources(el).catch(() => []);
  if (!matches.length) {
    showToast('No matching source files found for that element.', 'warn');
    return;
  }
  if (matches.length === 1) {
    await openDesignCodeHighlight(matches[0].diskPath, matches[0].matches);
    return;
  }
  showDesignFilesPopover(el, frame, matches);
}

function handleDesignChat() {
  if (designActionPopoverEl) designActionPopoverEl.style.display = 'none';
  if (!designLastClickedElement || !designLastClickedFrame) return;
  showDesignChatPopover(designLastClickedElement, designLastClickedFrame);
}

function showDesignInlineEditor(element, frame) {
  if (!element || !frame) return;
  if (element.dataset.prometheusInlineEditing === '1') return;
  const originalText = String(element.textContent || '');
  element.dataset.prometheusInlineEditing = '1';
  element.dataset.prometheusOriginalText = originalText;
  element.setAttribute('contenteditable', 'true');
  element.spellcheck = false;
  try { element.focus({ preventScroll: false }); } catch { element.focus(); }
  try {
    const doc = frame.contentDocument;
    const range = doc.createRange();
    range.selectNodeContents(element);
    const sel = frame.contentWindow.getSelection();
    sel.removeAllRanges();
    sel.addRange(range);
  } catch {}
  let canceled = false;
  const cleanup = () => {
    element.removeEventListener('blur', onBlur);
    element.removeEventListener('keydown', onKey);
    element.removeAttribute('contenteditable');
    delete element.dataset.prometheusInlineEditing;
  };
  const onKey = (e) => {
    if (e.key === 'Escape') { e.preventDefault(); canceled = true; element.blur(); }
    else if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); element.blur(); }
  };
  const onBlur = () => {
    cleanup();
    if (canceled) {
      element.textContent = originalText;
      delete element.dataset.prometheusOriginalText;
      return;
    }
    commitDesignInlineEdit(element, originalText);
  };
  element.addEventListener('blur', onBlur);
  element.addEventListener('keydown', onKey);
}

function _designHtmlEscape(s) {
  return String(s).replace(/[&<>"']/g, (c) => ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;', "'":'&#39;' })[c]);
}
function _designEscapeRe(s) { return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

async function commitDesignInlineEdit(el, originalText) {
  const newText = String(el.textContent || '');
  delete el.dataset.prometheusOriginalText;
  if (newText === originalText) return;
  const path = getDesignPreviewTabPath();
  if (!path) {
    el.textContent = originalText;
    showToast('No source file is active for this preview.', 'error');
    return;
  }
  try {
    const res = await fetch(`/api/canvas/file?path=${encodeURIComponent(path)}`);
    const data = await res.json();
    if (!data.success) throw new Error(data.error || 'Load failed');
    const source = String(data.content || '');
    const origEscaped = _designHtmlEscape(originalText);
    const newEscaped = _designHtmlEscape(newText);
    let updatedSource = null;
    const currentOuter = String(el.outerHTML || '');
    const originalOuter = currentOuter.replace(newEscaped, origEscaped);
    if (originalOuter && originalOuter !== currentOuter && source.includes(originalOuter)) {
      updatedSource = source.replace(originalOuter, currentOuter);
    }
    if (!updatedSource) {
      const re = new RegExp(_designEscapeRe(origEscaped), 'g');
      const count = (source.match(re) || []).length;
      if (count === 1) updatedSource = source.replace(origEscaped, newEscaped);
    }
    if (!updatedSource) {
      el.textContent = originalText;
      showToast('Could not uniquely locate the text in the source file. Use Chat for this edit.', 'warn');
      return;
    }
    const saveRes = await fetch('/api/canvas/file', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ path, content: updatedSource }),
    });
    const saveData = await saveRes.json();
    if (!saveData.success) throw new Error(saveData.error || 'Save failed');
    const tab = canvasTabs.find((t) => t.diskPath === path);
    if (tab) {
      tab.content = updatedSource;
      tab.savedContent = updatedSource;
      if (canvasEditor && activeCanvasTabId === tab.id) canvasEditor.setValue(updatedSource);
    }
    showToast('Design: text updated and saved.', 'info');
    addProcessEntry('info', `Design: updated text in ${path}`);
  } catch (err) {
    el.textContent = originalText;
    showToast(`Design edit failed: ${err.message}`, 'error');
  }
}

function handleDesignSelect() {
  if (designActionPopoverEl) designActionPopoverEl.style.display = 'none';
  if (!designLastClickedElement || !designLastClickedFrame) return;
  designSelectMode = true;
  addDesignMultiSelection(designLastClickedElement, designLastClickedFrame);
  installDesignSelectModeOutsideClick();
  showToast('Select mode: click elements to attach. Click outside the canvas to finish.', 'info');
}

function addDesignMultiSelection(element, frame) {
  const ctx = extractDesignElementContext(element, frame);
  if (!ctx) return;
  const key = `${ctx.selector}|${(ctx.htmlSnippet || '').slice(0, 96)}`;
  if (designMultiSelectedElements.some((e) => e._key === key)) return;
  try { element.setAttribute('data-prometheus-design-multi-selected', 'true'); } catch {}
  designMultiSelectedElements.push({ _key: key, context: ctx, element, frame });
  renderDesignSelectionPills();
}

function removeDesignSelectionPill(idx) {
  const entry = designMultiSelectedElements[idx];
  if (entry?.element) {
    try { entry.element.removeAttribute('data-prometheus-design-multi-selected'); } catch {}
  }
  designMultiSelectedElements.splice(idx, 1);
  renderDesignSelectionPills();
}

function clearDesignMultiSelectionHighlights() {
  for (const entry of designMultiSelectedElements) {
    if (entry?.element) {
      try { entry.element.removeAttribute('data-prometheus-design-multi-selected'); } catch {}
    }
    if (entry?.frame?.contentDocument) {
      try {
        entry.frame.contentDocument.querySelectorAll('[data-prometheus-design-multi-selected="true"]').forEach((node) => node.removeAttribute('data-prometheus-design-multi-selected'));
      } catch {}
    }
  }
}

function clearDesignMultiSelection() {
  clearDesignMultiSelectionHighlights();
  designMultiSelectedElements = [];
  renderDesignSelectionPills();
}

function renderDesignSelectionPills() {
  const cont = document.getElementById('chat-design-selection-pills');
  if (!cont) return;
  if (!designMultiSelectedElements.length) {
    cont.style.display = 'none';
    cont.innerHTML = '';
    return;
  }
  cont.style.display = 'flex';
  cont.innerHTML = designMultiSelectedElements.map((entry, idx) => {
    const c = entry.context;
    const label = c.selector || (c.id ? `#${c.id}` : '') || c.tagName || 'element';
    const truncated = label.length > 40 ? `${label.slice(0, 38)}…` : label;
    return `<div class="chat-file-pill" title="${escHtml(label)}">
      <span class="pill-icon"><iconify-icon icon="solar:cursor-square-bold-duotone" width="14" height="14"></iconify-icon></span>
      <span class="pill-name">${escHtml(truncated)}</span>
      <span class="pill-ext">${escHtml(c.tagName || 'el')}</span>
      <button class="pill-remove" onclick="removeDesignSelectionPill(${idx})" title="Remove">&times;</button>
    </div>`;
  }).join('');
}

function installDesignSelectModeOutsideClick() {
  if (designSelectModeOutsideHandler) return;
  designSelectModeOutsideHandler = (e) => {
    if (!designSelectMode) return;
    const canvasPanel = document.getElementById('canvas-panel');
    if (canvasPanel && canvasPanel.contains(e.target)) return;
    exitDesignSelectMode();
  };
  document.addEventListener('mousedown', designSelectModeOutsideHandler, true);
}

function exitDesignSelectMode() {
  designSelectMode = false;
  clearDesignMultiSelectionHighlights();
  if (designSelectModeOutsideHandler) {
    document.removeEventListener('mousedown', designSelectModeOutsideHandler, true);
    designSelectModeOutsideHandler = null;
  }
}

function buildDesignSearchNeedles(element) {
  const out = [];
  if (element.id) out.push(`id="${element.id}"`);
  const classes = Array.from(element.classList || []);
  if (classes.length) out.push(`class="${classes.join(' ')}"`);
  const text = String(element.innerText || element.textContent || '').replace(/\s+/g, ' ').trim();
  if (text && text.length >= 8 && text.length <= 160) out.push(text);
  return out;
}

async function findDesignElementInSources(element) {
  const previewPath = getDesignPreviewTabPath();
  if (!previewPath) return [];
  const files = new Set([previewPath]);
  try {
    const res = await fetch(`/api/canvas/file?path=${encodeURIComponent(previewPath)}`);
    const data = await res.json();
    if (data.success) {
      const hrefs = String(data.content || '').matchAll(/<(?:link|script)[^>]*?(?:href|src)=["']([^"']+)["']/g);
      const sep = previewPath.includes('\\') ? '\\' : '/';
      const dir = previewPath.replace(/[\\/][^\\/]+$/, '');
      for (const m of hrefs) {
        const raw = m[1];
        if (/^https?:/i.test(raw) || raw.startsWith('//') || raw.startsWith('data:') || raw.startsWith('#')) continue;
        const absPath = raw.startsWith('/') ? raw : `${dir}${sep}${raw}`;
        files.add(normalizeCanvasPath(absPath));
      }
    }
  } catch {}
  const needles = buildDesignSearchNeedles(element);
  if (!needles.length) return [];
  const results = [];
  for (const path of files) {
    try {
      const res = await fetch(`/api/canvas/file?path=${encodeURIComponent(path)}`);
      const data = await res.json();
      if (!data.success || data.isBinary || data.isImage) continue;
      const content = String(data.content || '');
      const matches = [];
      for (const needle of needles) {
        let idx = 0;
        while ((idx = content.indexOf(needle, idx)) !== -1) {
          matches.push({ index: idx, length: needle.length });
          idx += Math.max(1, needle.length);
        }
      }
      if (matches.length) results.push({ diskPath: path, name: path.split(/[\\/]/).pop(), matches });
    } catch {}
  }
  results.sort((a, b) => b.matches.length - a.matches.length);
  return results;
}

async function openDesignCodeHighlight(diskPath, matches) {
  await canvasPresentFile(diskPath, diskPath.split(/[\\/]/).pop());
  setCanvasMode('code');
  setTimeout(() => {
    if (!canvasEditor) return;
    canvasEditor.getAllMarks().forEach((m) => { if (m.__designHighlight) m.clear(); });
    const doc = canvasEditor.getDoc();
    matches.forEach((m) => {
      const from = doc.posFromIndex(m.index);
      const to = doc.posFromIndex(m.index + m.length);
      const mark = doc.markText(from, to, { className: 'cm-design-highlight' });
      mark.__designHighlight = true;
    });
    if (matches.length) {
      const first = matches[0];
      const fromPos = doc.posFromIndex(first.index);
      canvasEditor.scrollIntoView(fromPos, 80);
      canvasEditor.setCursor(fromPos);
    }
    canvasEditor.refresh();
    canvasEditor.focus();
  }, 150);
}

function showDesignFilesPopover(element, frame, results) {
  if (!designFilesPopoverEl) {
    designFilesPopoverEl = document.createElement('div');
    designFilesPopoverEl.id = 'design-files-popover';
    designFilesPopoverEl.style.cssText = 'position:fixed;z-index:10000;display:none;min-width:240px;max-width:340px;padding:6px;border-radius:10px;border:1px solid rgba(255,255,255,0.14);background:rgba(17,15,14,0.98);box-shadow:0 12px 32px rgba(0,0,0,0.45);backdrop-filter:blur(14px);font-family:Manrope,sans-serif';
    document.body.appendChild(designFilesPopoverEl);
  }
  designFilesPopoverEl.innerHTML = `
    <div style="padding:6px 8px;font-size:10px;font-weight:800;letter-spacing:0.08em;text-transform:uppercase;color:#a8a29e">Open in code</div>
    ${results.map((r) => `
      <button type="button" onclick="openDesignFilePick('${escHtml(r.diskPath).replace(/'/g, '&#39;')}')" style="width:100%;display:flex;align-items:center;justify-content:space-between;gap:10px;padding:7px 10px;border:none;background:transparent;color:#e7e5e4;border-radius:6px;font-size:12px;font-weight:600;cursor:pointer;font-family:inherit;text-align:left" onmouseover="this.style.background='rgba(249,115,22,0.12)';this.style.color='#fdba74'" onmouseout="this.style.background='transparent';this.style.color='#e7e5e4'">
        <span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(r.name)}</span>
        <span style="font-size:10px;color:#78716c;font-weight:700">${r.matches.length} match${r.matches.length === 1 ? '' : 'es'}</span>
      </button>
    `).join('')}
  `;
  designFilesPopoverEl._results = results;
  const frameRect = frame.getBoundingClientRect();
  const rect = element.getBoundingClientRect();
  const scale = getDesignFrameScale(frame);
  designFilesPopoverEl.style.display = 'block';
  const pw = designFilesPopoverEl.offsetWidth || 260;
  const absLeft = frameRect.left + (rect.left * scale);
  const absTop = frameRect.top + ((rect.top + rect.height) * scale) + 8;
  let left = absLeft;
  if (left + pw > window.innerWidth - 8) left = window.innerWidth - pw - 8;
  if (left < 8) left = 8;
  designFilesPopoverEl.style.left = `${left}px`;
  designFilesPopoverEl.style.top = `${absTop}px`;
}

async function openDesignFilePick(diskPath) {
  const results = designFilesPopoverEl?._results || [];
  if (designFilesPopoverEl) designFilesPopoverEl.style.display = 'none';
  const hit = results.find((r) => r.diskPath === diskPath);
  if (hit) await openDesignCodeHighlight(diskPath, hit.matches);
  else { await canvasPresentFile(diskPath, diskPath.split(/[\\/]/).pop()); setCanvasMode('code'); }
}

function positionDesignChatPopover(element, frame) {
  if (!designChatPopoverEl) return;
  const frameRect = frame.getBoundingClientRect();
  const rect = element.getBoundingClientRect();
  const scale = getDesignFrameScale(frame);
  const pw = 320;
  const ph = designChatPopoverEl.offsetHeight || 180;
  let left = frameRect.left + (rect.left * scale);
  let top = frameRect.top + ((rect.top + rect.height) * scale) + 8;
  if (left + pw > window.innerWidth - 8) left = window.innerWidth - pw - 8;
  if (left < 8) left = 8;
  if (top + ph > window.innerHeight - 8) top = Math.max(8, frameRect.top + (rect.top * scale) - ph - 8);
  designChatPopoverEl.style.left = `${left}px`;
  designChatPopoverEl.style.top = `${top}px`;
}

function showDesignChatPopover(element, frame) {
  if (!designChatPopoverEl) {
    designChatPopoverEl = document.createElement('div');
    designChatPopoverEl.id = 'design-chat-popover';
    designChatPopoverEl.style.cssText = 'position:fixed;z-index:10000;display:none;width:320px;padding:10px;border-radius:12px;border:1px solid rgba(255,255,255,0.14);background:rgba(17,15,14,0.98);box-shadow:0 14px 36px rgba(0,0,0,0.5);backdrop-filter:blur(14px);font-family:Manrope,sans-serif;flex-direction:column;gap:8px';
    designChatPopoverEl.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:space-between;gap:8px">
        <div style="font-size:10px;font-weight:800;letter-spacing:0.08em;text-transform:uppercase;color:#a8a29e">Chat about this element</div>
        <button type="button" onclick="hideDesignChatPopover()" style="border:none;background:transparent;color:#a8a29e;font-size:16px;cursor:pointer;padding:0;line-height:1;font-family:inherit">×</button>
      </div>
      <textarea id="design-chat-input" rows="3" placeholder="Ask to change, restyle, or explain this element…" style="width:100%;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:8px;padding:8px 10px;font-size:12px;font-family:inherit;resize:vertical;outline:none"></textarea>
      <div id="design-chat-attachments" style="display:none;flex-wrap:wrap;gap:6px"></div>
      <div style="display:flex;align-items:center;gap:6px">
        <button type="button" onclick="document.getElementById('design-chat-file-input').click()" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.05);color:#e7e5e4;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer;font-family:inherit"><iconify-icon icon="solar:paperclip-bold-duotone" width="14" height="14"></iconify-icon>Attach</button>
        <input id="design-chat-file-input" type="file" multiple style="display:none" onchange="onDesignChatFilesChosen(this.files)" />
        <div style="flex:1"></div>
        <button type="button" onclick="submitDesignChatPopover()" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(56,189,248,0.28);background:rgba(56,189,248,0.16);color:#bae6fd;border-radius:8px;padding:6px 12px;font-size:11px;font-weight:800;cursor:pointer;font-family:inherit"><iconify-icon icon="solar:plain-bold-duotone" width="14" height="14"></iconify-icon>Send</button>
      </div>
    `;
    document.body.appendChild(designChatPopoverEl);
    const ta = designChatPopoverEl.querySelector('#design-chat-input');
    ta?.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); submitDesignChatPopover(); }
      if (e.key === 'Escape') { e.preventDefault(); hideDesignChatPopover(); }
    });
  }
  designChatPopoverEl._attachments = [];
  const attachList = document.getElementById('design-chat-attachments');
  if (attachList) { attachList.innerHTML = ''; attachList.style.display = 'none'; }
  const ta = document.getElementById('design-chat-input');
  if (ta) ta.value = '';
  designChatPopoverEl.style.display = 'flex';
  positionDesignChatPopover(element, frame);
  setTimeout(() => document.getElementById('design-chat-input')?.focus(), 30);
  installDesignChatOutsideClick();
}

let designChatOutsideHandler = null;
function installDesignChatOutsideClick() {
  if (designChatOutsideHandler) return;
  designChatOutsideHandler = (e) => {
    if (!designChatPopoverEl || designChatPopoverEl.style.display === 'none') return;
    if (designChatPopoverEl.contains(e.target)) return;
    hideDesignChatPopover();
  };
  document.addEventListener('mousedown', designChatOutsideHandler, true);
}

function hideDesignChatPopover() {
  if (designChatPopoverEl) designChatPopoverEl.style.display = 'none';
  if (designChatOutsideHandler) {
    document.removeEventListener('mousedown', designChatOutsideHandler, true);
    designChatOutsideHandler = null;
  }
}

function onDesignChatFilesChosen(files) {
  if (!designChatPopoverEl) return;
  const arr = Array.from(files || []);
  designChatPopoverEl._attachments = (designChatPopoverEl._attachments || []).concat(arr);
  const list = document.getElementById('design-chat-attachments');
  if (list) {
    list.style.display = designChatPopoverEl._attachments.length ? 'flex' : 'none';
    list.innerHTML = designChatPopoverEl._attachments.map((f, i) => `
      <span style="display:inline-flex;align-items:center;gap:4px;padding:3px 7px;border-radius:999px;background:rgba(255,255,255,0.06);color:#e7e5e4;font-size:10px;font-weight:700">
        <iconify-icon icon="solar:file-bold-duotone" width="12" height="12"></iconify-icon>${escHtml(f.name)}
        <button type="button" onclick="removeDesignChatAttachment(${i})" style="border:none;background:transparent;color:#a8a29e;cursor:pointer;padding:0 2px;font-size:12px;font-family:inherit;line-height:1">×</button>
      </span>
    `).join('');
  }
  const input = document.getElementById('design-chat-file-input');
  if (input) input.value = '';
}

function removeDesignChatAttachment(idx) {
  if (!designChatPopoverEl?._attachments) return;
  designChatPopoverEl._attachments.splice(idx, 1);
  onDesignChatFilesChosen([]);
}

async function submitDesignChatPopover() {
  const textarea = document.getElementById('design-chat-input');
  const text = String(textarea?.value || '').trim();
  if (!text) return;
  const attachments = designChatPopoverEl?._attachments || [];
  const mainInput = document.getElementById('chat-input');
  if (!mainInput) { showToast('Main chat input not found.', 'error'); return; }
  if (attachments.length && typeof window.stageFiles === 'function') {
    try { await window.stageFiles(attachments); } catch {}
  }
  mainInput.value = text;
  hideDesignChatPopover();
  try { await sendChat(); } catch (err) { showToast(`Send failed: ${err.message}`, 'error'); }
}

function applyDesignPreviewSelection(element, frame) {
  const doc = frame?.contentDocument;
  if (!doc) return;
  doc.querySelectorAll('[data-prometheus-design-selected="true"]').forEach((node) => {
    node.removeAttribute('data-prometheus-design-selected');
  });
  if (element && element instanceof frame.contentWindow.HTMLElement) {
    element.setAttribute('data-prometheus-design-selected', 'true');
    designSelectedElementContext = extractDesignElementContext(element, frame);
    updateDesignSelectionChip();
    addProcessEntry('info', `Design: selected ${designSelectedElementContext?.selector || designSelectedElementContext?.tagName || 'element'} in preview.`);
  } else {
    clearDesignSelectionContext();
  }
}

function setupDesignPreviewSelection(frame, tab) {
  const doc = frame?.contentDocument;
  if (!doc || !doc.documentElement) return;
  let styleEl = doc.getElementById('prometheus-design-selection-style');
  if (!styleEl) {
    styleEl = doc.createElement('style');
    styleEl.id = 'prometheus-design-selection-style';
    styleEl.textContent = `
      [data-prometheus-design-selected="true"] {
        outline: 2px solid #f97316 !important;
        outline-offset: 2px !important;
        box-shadow: 0 0 0 4px rgba(249,115,22,0.18), inset 0 0 0 9999px rgba(249,115,22,0.08) !important;
      }
      [data-prometheus-design-multi-selected="true"] {
        outline: 2px solid #a855f7 !important;
        outline-offset: 2px !important;
        box-shadow: 0 0 0 4px rgba(168,85,247,0.22), inset 0 0 0 9999px rgba(168,85,247,0.10) !important;
      }
      [data-prometheus-design-hover="true"] {
        outline: 1px dashed rgba(56,189,248,0.9) !important;
        outline-offset: 2px !important;
        box-shadow: inset 0 0 0 9999px rgba(56,189,248,0.10) !important;
      }
      body[data-prometheus-design-mode="true"] * {
        cursor: crosshair !important;
      }
    `;
    doc.head.appendChild(styleEl);
  }
  if (doc.body) doc.body.dataset.prometheusDesignMode = 'true';
  doc.addEventListener('mouseover', (event) => {
    const target = event.target;
    if (!(target instanceof frame.contentWindow.HTMLElement)) return;
    doc.querySelectorAll('[data-prometheus-design-hover="true"]').forEach((node) => node.removeAttribute('data-prometheus-design-hover'));
    target.setAttribute('data-prometheus-design-hover', 'true');
  }, true);
  doc.addEventListener('mouseout', () => {
    doc.querySelectorAll('[data-prometheus-design-hover="true"]').forEach((node) => node.removeAttribute('data-prometheus-design-hover'));
  }, true);
  doc.addEventListener('mousedown', () => {
    if (designChatPopoverEl && designChatPopoverEl.style.display !== 'none') hideDesignChatPopover();
  }, true);
  let designClickTimeout = null;
  doc.addEventListener('click', (event) => {
    const target = event.target;
    if (!(target instanceof frame.contentWindow.HTMLElement)) return;
    if (target.closest('[data-prometheus-inline-editing="1"]')) return;
    if (frame._designBypassClick) return;
    event.preventDefault();
    event.stopPropagation();
    if (designSelectMode) {
      addDesignMultiSelection(target, frame);
      return;
    }
    if (designClickTimeout) clearTimeout(designClickTimeout);
    designClickTimeout = setTimeout(() => {
      designClickTimeout = null;
      applyDesignPreviewSelection(target, frame);
      designLastClickedElement = target;
      designLastClickedFrame = frame;
      showDesignActionPopover(target, frame);
    }, 240);
  }, true);
  doc.addEventListener('dblclick', (event) => {
    const target = event.target;
    if (!(target instanceof frame.contentWindow.HTMLElement)) return;
    if (designSelectMode) return;
    if (designClickTimeout) { clearTimeout(designClickTimeout); designClickTimeout = null; }
    if (designActionPopoverEl) designActionPopoverEl.style.display = 'none';
    event.preventDefault();
    event.stopPropagation();
    frame._designBypassClick = true;
    try {
      target.dispatchEvent(new frame.contentWindow.MouseEvent('click', {
        bubbles: true,
        cancelable: true,
        view: frame.contentWindow,
        button: 0,
      }));
    } catch {}
    setTimeout(() => { frame._designBypassClick = false; }, 0);
  }, true);
  frame.contentWindow.addEventListener('scroll', () => repositionDesignPopovers(), true);
  if (designSelectedElementContext?.selector) {
    try {
      const existing = doc.querySelector(designSelectedElementContext.selector);
      if (existing) applyDesignPreviewSelection(existing, frame);
    } catch {}
  } else {
    clearDesignSelectionContext();
  }
  if (tab) tab.mode = 'preview';
}

async function applySingleDesignOp(op) {
  const opName = String(op?.op || '').trim();
  if (!opName) throw new Error('Invalid Design op.');
  let diskPath = '';
  let snapshot = null;
  let nextContent = '';
  let summary = '';

  if (opName === 'patch-css-rule') {
    diskPath = resolveDesignFilePath(op.file, ['css', 'scss', 'less']);
    snapshot = await loadCanvasFileSnapshot(diskPath);
    const selector = String(op.selector || designSelectedElementContext?.selector || '').trim();
    if (!selector) throw new Error('patch-css-rule requires a selector.');
    const declarations = op.declarations && typeof op.declarations === 'object'
      ? op.declarations
      : (op.patch && typeof op.patch === 'object' ? op.patch : {});
    nextContent = upsertCssRuleContent(snapshot.content, selector, declarations);
    summary = `patched CSS rule ${selector} in ${snapshot.name}`;
  } else if (opName === 'patch-html-attributes') {
    diskPath = resolveDesignFilePath(op.file, ['html', 'htm']);
    snapshot = await loadCanvasFileSnapshot(diskPath);
    nextContent = patchHtmlAttributesContent(snapshot.content, op.selector, {
      attributes: op.attributes || op.patch || {},
      styles: op.styles || {},
      removeAttributes: op.removeAttributes || [],
    });
    summary = `patched HTML attributes in ${snapshot.name}`;
  } else if (opName === 'replace-inner-text') {
    diskPath = resolveDesignFilePath(op.file, ['html', 'htm']);
    snapshot = await loadCanvasFileSnapshot(diskPath);
    nextContent = replaceInnerTextContent(snapshot.content, op.selector, op.text ?? op.value ?? '');
    summary = `updated inner text in ${snapshot.name}`;
  } else if (opName === 'replace-in-file') {
    diskPath = resolveDesignFilePath(op.file);
    snapshot = await loadCanvasFileSnapshot(diskPath);
    nextContent = replaceInFileContent(snapshot.content, op);
    summary = `replaced source in ${snapshot.name}`;
  } else if (opName === 'insert-in-file') {
    diskPath = resolveDesignFilePath(op.file);
    snapshot = await loadCanvasFileSnapshot(diskPath);
    nextContent = insertInFileContent(snapshot.content, op);
    summary = `inserted source into ${snapshot.name}`;
  } else {
    throw new Error(`Unsupported Design op: ${opName}`);
  }

  if (nextContent === snapshot.content) {
    return { changed: false, summary: `${summary} (no content change)` };
  }
  await writeCanvasFileSnapshot(snapshot.diskPath, nextContent, { name: snapshot.name });
  return { changed: true, summary, diskPath: snapshot.diskPath };
}

async function applyDesignAssistantOps(replyText) {
  if (normalizeCreativeMode(window.currentCreativeMode) !== 'design') {
    return { matched: false, applied: 0, errors: [] };
  }
  const parsed = parseDesignOpsFromText(replyText);
  if (!parsed.matched) return { matched: false, applied: 0, errors: [] };

  const results = [];
  const errors = [];
  for (const op of parsed.ops) {
    try {
      const result = await applySingleDesignOp(op);
      results.push(result);
    } catch (err) {
      errors.push(`${String(op?.op || 'op')}: ${String(err?.message || err || 'Unknown error')}`);
    }
  }

  const applied = results.filter((result) => result?.changed).length;
  if (applied > 0) {
    addProcessEntry('result', `Design: applied ${applied} file op${applied === 1 ? '' : 's'}.`);
    results.filter((result) => result?.summary).forEach((result) => addProcessEntry('info', `Design: ${result.summary}`));
    if (errors.length) addProcessEntry('warn', `Design: ${errors.join(' | ')}`);
    const activeTab = canvasTabs.find((tab) => tab.id === activeCanvasTabId) || null;
    if (activeTab?.mode === 'preview') canvasUpdatePreview();
    showToast(`Design applied ${applied} edit${applied === 1 ? '' : 's'}`);
  } else if (errors.length) {
    addProcessEntry('warn', `Design patch parsing matched, but nothing was applied. ${errors.join(' | ')}`);
  }

  return { matched: true, applied, errors };
}

function toggleLeftPanel() {
  leftPanelCollapsed = !leftPanelCollapsed;
  document.body.classList.toggle('left-collapsed', leftPanelCollapsed);
  const btn = document.getElementById('sidebar-collapse-btn');
  if (btn) btn.title = leftPanelCollapsed ? 'Expand sidebar' : 'Collapse sidebar';
}

function syncHeaderCanvasChrome() {
  const rightPanel = document.getElementById('right-panel');
  const isRightCanvasOpen = Boolean(
    canvasOpen &&
    rightPanel &&
    rightPanel.classList.contains('open') &&
    rightPanel.classList.contains('canvas-open')
  );
  document.body.classList.toggle('right-canvas-open', isRightCanvasOpen);
  document.body.classList.toggle('right-creative-canvas-open', isRightCanvasOpen && isStructuredCreativeMode(window.currentCreativeMode));
}

function toggleRightPanel() {
  const panel = document.getElementById('right-panel');
  const toggleBtn = document.getElementById('drawerToggle');
  if (!panel) return;
  const wasOpen = panel.classList.contains('open');
  if (wasOpen && isCreativeModeLocked()) {
    showToast('Close the Creative workspace to close the canvas.', 'info');
    return;
  }
  const isOpen = panel.classList.toggle('open');
  document.body.classList.toggle('right-collapsed', !isOpen);
  if (toggleBtn) toggleBtn.classList.toggle('active', isOpen);
  // When closing: clear inline resize styles so CSS width:0 takes effect
  if (!isOpen && wasOpen) {
    panel.style.removeProperty('width');
    panel.style.removeProperty('min-width');
    panel.style.removeProperty('max-width');
  } else if (isOpen && !wasOpen) {
    const sidebar = document.getElementById('sidebar');
    if (sidebar && !sidebar.classList.contains('collapsed')) {
      if (typeof window.toggleSidebar === 'function') window.toggleSidebar();
    }
  }
  if (typeof window._syncPageViewPositions === 'function') window._syncPageViewPositions();
  syncHeaderCanvasChrome();
}

function toggleCanvas(nextOpen = null, options = {}) {
  const targetOpen = typeof nextOpen === 'boolean' ? nextOpen : !canvasOpen;
  if (!targetOpen && isCreativeModeLocked() && options.force !== true) {
    const meta = getCreativeModeMeta(window.currentCreativeMode);
    showToast(`Close ${meta?.title || 'the Creative workspace'} to close the canvas.`, 'info');
    return;
  }
  canvasOpen = targetOpen;
  const panel = document.getElementById('canvas-panel');
  const btn = document.getElementById('canvas-toggle-btn');
  const topbar = document.getElementById('right-panel-topbar');
  const dot = document.getElementById('canvas-notify-dot');
  if (!panel) return;
  if (canvasOpen) {
    // Ensure right panel is open
    const rightPanel = document.getElementById('right-panel');
    if (rightPanel && !rightPanel.classList.contains('open')) {
      if (typeof window.toggleRightPanel === 'function') window.toggleRightPanel();
    }
    if (rightPanel) {
      rightPanelCanvasSavedScrollTop = rightPanel.scrollTop || 0;
      rightPanel.classList.add('canvas-open');
      rightPanel.scrollTop = 0;
    }
    document.body.classList.remove('right-collapsed');
    // Auto-collapse sidebar for more canvas space
    const sidebar = document.getElementById('sidebar');
    if (sidebar && !sidebar.classList.contains('collapsed')) {
      if (typeof window.toggleSidebar === 'function') window.toggleSidebar();
    }
    panel.style.display = 'flex';
    if (!isCreativeModeLocked()) {
      const rightPanel = document.getElementById('right-panel');
      const currentWidth = rightPanel?.offsetWidth || 0;
      if (currentWidth < CANVAS_PANEL_MIN_WIDTH) {
        setRightPanelWidth(CANVAS_PANEL_MIN_WIDTH, { minimumWidth: 860 });
      }
    }
    if (topbar) topbar.style.display = 'none';
    if (btn) { btn.style.background='rgba(249,115,22,0.15)'; btn.style.borderColor='rgba(249,115,22,0.45)'; btn.style.color='#f97316'; }
    if (dot) dot.style.display = 'none';
    try {
      if (!canvasEditorInitialized) initCanvasEditor();
    } catch (err) {
      addProcessEntry('error', `Canvas editor init failed: ${String(err?.message || err)}`);
    }
    const activeTab = canvasTabs.find((tab) => tab.id === activeCanvasTabId) || null;
    try {
      applyCanvasViewMode(activeTab?.mode || 'code', activeTab);
      canvasRenderTabs();
    } catch (err) {
      addProcessEntry('error', `Canvas view restore failed: ${String(err?.message || err)}`);
      const creativeShell = document.getElementById('canvas-creative-shell');
      const editorWrap = document.getElementById('canvas-editor-wrap');
      const previewShell = document.getElementById('canvas-preview-shell');
      const previewFrame = document.getElementById('canvas-preview-frame');
      const emptyState = document.getElementById('canvas-empty-state');
      if (creativeShell) creativeShell.style.display = 'none';
      if (editorWrap) editorWrap.style.display = 'none';
      if (previewShell) previewShell.style.display = 'none';
      if (previewFrame) previewFrame.style.display = 'none';
      if (emptyState) emptyState.style.display = 'flex';
    }
	    updateCanvasWorkspaceChrome();
	  } else {
    const rightPanel = document.getElementById('right-panel');
    if (rightPanel) {
      rightPanel.classList.remove('canvas-open');
      rightPanel.scrollTop = rightPanelCanvasSavedScrollTop || 0;
    }
	    // Reset fullscreen if active
	    if (canvasFullscreenMode) {
	      canvasFullscreenMode = false;
      panel.style.position = 'absolute';
      panel.style.inset = '0';
      panel.style.zIndex = '20';
      panel.style.background = '';
      const fsBtn = document.getElementById('canvas-fullscreen-btn');
      if (fsBtn) fsBtn.title = 'Fullscreen';
    }
	    panel.style.display = 'none';
	    if (topbar) topbar.style.display = 'flex';
	    if (btn) { btn.style.background=''; btn.style.borderColor=''; btn.style.color=''; }
	  }
    syncHeaderCanvasChrome();
	  syncCanvasSurfaceWidthLock();
    syncBrowserCanvasStream({ force: true });
	}

function toggleCanvasFullscreen() {
  const panel = document.getElementById('canvas-panel');
  if (!panel || !canvasOpen) return;
  canvasFullscreenMode = !canvasFullscreenMode;
  const btn = document.getElementById('canvas-fullscreen-btn');
  if (canvasFullscreenMode) {
    panel.style.position = 'fixed';
    panel.style.inset = '0';
    panel.style.zIndex = '1000';
    panel.style.background = '#2a2a2a';
    if (btn) btn.title = 'Exit fullscreen';
  } else {
    panel.style.position = 'absolute';
    panel.style.inset = '0';
    panel.style.zIndex = '20';
    panel.style.background = '';
    if (btn) btn.title = 'Fullscreen';
  }
  if (isStructuredCreativeMode(normalizeCreativeMode(window.currentCreativeMode))) {
    scheduleCreativeStageViewportSync({ force: true, center: creativeStageZoomMode !== 'manual' });
  }
}

function initCanvasEditor() {
  canvasEditorInitialized = true;
  const wrap = document.getElementById('canvas-editor-wrap');
  if (!wrap || typeof CodeMirror === 'undefined') return;
  canvasEditor = CodeMirror(wrap, {
    value: '',
    mode: 'htmlmixed',
    lineNumbers: true,
    lineWrapping: true,
    tabSize: 2,
    indentWithTabs: false,
    theme: 'material-darker',
    extraKeys: { 'Ctrl-S': () => canvasSave(), 'Cmd-S': () => canvasSave() },
  });
  canvasEditor.on('change', () => {
    const tab = canvasTabs.find(t => t.id === activeCanvasTabId);
    if (!tab) return;
    const newVal = canvasEditor.getValue();
    if (tab.diskPath && newVal !== tab.savedContent) {
      tab.dirty = true;
    } else if (tab.diskPath) {
      tab.dirty = false;
    }
    tab.content = newVal;
    if (tab.mode === 'preview') canvasUpdatePreview();
    canvasRenderTabs();
  });
}

function canvasNewFile() {
  const name = prompt('File name:', 'untitled.html');
  if (!name || !name.trim()) return;
  const id = 'ctab_' + Math.random().toString(36).slice(2);
  canvasTabs.push({ id, name: name.trim(), content: '', mode: 'code', language: getCanvasLang(name) });
  canvasOpenTab(id);
}

function canvasOpenTab(id) {
  activeCanvasTabId = id;
  const tab = canvasTabs.find(t => t.id === id);
  if (!tab) return;
  // Apply view mode FIRST so the change event fires with the correct mode already set
  applyCanvasViewMode(tab.mode || 'code', tab);
  if (canvasEditor) {
    // Temporarily disconnect change handler to avoid double-render during setValue
    const silentSet = () => {
      canvasEditor.setValue(tab.content || '');
      canvasEditor.setOption('mode', tab.language || 'null');
      setTimeout(() => canvasEditor.refresh(), 10);
    };
    silentSet();
  }
  canvasRenderTabs();
}

function canvasCloseTab(id, ev) {
  if (ev) ev.stopPropagation();
  const idx = canvasTabs.findIndex(t => t.id === id);
  if (idx === -1) return;
  // Tell server this file is no longer on the canvas
  const closingTab = canvasTabs[idx];
  if (closingTab && closingTab.diskPath) canvasNotifyClose(closingTab.diskPath);
  canvasTabs.splice(idx, 1);
  if (activeCanvasTabId === id) {
    if (canvasTabs.length > 0) {
      canvasOpenTab(canvasTabs[Math.min(idx, canvasTabs.length - 1)].id);
    } else {
      activeCanvasTabId = null;
      if (canvasEditor) canvasEditor.setValue('');
      applyCanvasViewMode('code', null);
      canvasRenderTabs();
    }
  } else {
    canvasRenderTabs();
  }
  const tree = document.getElementById('canvas-project-tree');
  if (tree && canvasWorkspaceTree.length) tree.innerHTML = canvasRenderWorkspaceTree(canvasWorkspaceTree, 0);
}

function setCanvasMode(mode) {
  const tab = canvasTabs.find(t => t.id === activeCanvasTabId);
  if (!tab) return;
  // sync editor -> tab before switching
  if (canvasEditor && tab.mode !== 'preview') tab.content = canvasEditor.getValue();
  tab.mode = mode;
  applyCanvasViewMode(mode, tab);
  canvasRenderTabs();
}

function applyCanvasViewMode(mode, tab) {
  const creativeShell = document.getElementById('canvas-creative-shell');
  const browserShell = document.getElementById('canvas-browser-shell');
  const editorWrap = document.getElementById('canvas-editor-wrap');
  const previewShell = document.getElementById('canvas-preview-shell');
  const previewFrame = document.getElementById('canvas-preview-frame');
  const emptyState = document.getElementById('canvas-empty-state');
  const noFilesHint = document.getElementById('canvas-no-files-hint');
  const fileBrowser = document.getElementById('canvas-file-browser');
  const codeModeBtn = document.getElementById('canvas-code-btn');
  const previewModeBtn = document.getElementById('canvas-preview-btn');
  updateCanvasWorkspaceChrome();
  if (isStructuredCreativeMode()) {
    if (creativeShell) creativeShell.style.display = 'flex';
    if (browserShell) browserShell.style.display = 'none';
    if (editorWrap) editorWrap.style.display = 'none';
    if (previewShell) previewShell.style.display = 'none';
    if (previewFrame) previewFrame.style.display = 'none';
    if (emptyState) emptyState.style.display = 'none';
    if (noFilesHint) noFilesHint.style.display = 'none';
    if (fileBrowser) fileBrowser.style.display = 'none';
    if (codeModeBtn) codeModeBtn.style.display = 'none';
    if (previewModeBtn) previewModeBtn.style.display = 'none';
    renderCreativeWorkspace();
    syncCanvasSurfaceWidthLock(tab);
    return;
  }
  if (creativeShell) creativeShell.style.display = 'none';
  if (isBrowserCanvasSurfaceActive()) {
    if (browserShell) browserShell.style.display = 'flex';
    if (editorWrap) editorWrap.style.display = 'none';
    if (previewShell) previewShell.style.display = 'none';
    if (previewFrame) previewFrame.style.display = 'none';
    if (emptyState) emptyState.style.display = 'none';
    if (noFilesHint) noFilesHint.style.display = 'none';
    if (fileBrowser) fileBrowser.style.display = 'none';
    if (codeModeBtn) codeModeBtn.style.display = 'none';
    if (previewModeBtn) previewModeBtn.style.display = 'none';
    renderBrowserCanvasSurface();
    syncCanvasSurfaceWidthLock(tab);
    return;
  }
  if (browserShell) browserShell.style.display = 'none';
  if (!tab) {
    if (normalizeCreativeMode(window.currentCreativeMode) !== 'design') clearDesignSelectionContext();
    if (editorWrap) editorWrap.style.display = 'none';
    if (previewShell) previewShell.style.display = 'none';
    if (previewFrame) previewFrame.style.display = 'none';
    if (emptyState) emptyState.style.display = 'flex';
    if (noFilesHint) noFilesHint.style.display = 'flex';
    if (fileBrowser) fileBrowser.style.display = 'none';
    syncCanvasSurfaceWidthLock(tab);
    return;
  }
  if (emptyState) emptyState.style.display = 'none';
  if (noFilesHint) noFilesHint.style.display = 'none';
  if (fileBrowser) fileBrowser.style.display = 'none';
  if (normalizeCreativeMode(window.currentCreativeMode) !== 'design' || mode !== 'preview') {
    clearDesignSelectionContext();
  }
  // Image tabs always show in preview mode — hide code/preview toggle buttons
  if (tab.isImage || tab.isBinary) {
    if (editorWrap) editorWrap.style.display = 'none';
    if (previewShell) { previewShell.style.display = 'flex'; previewShell.style.flex = '1'; }
    if (previewFrame) { previewFrame.style.display = 'block'; previewFrame.style.flex = 'none'; }
    if (codeModeBtn) codeModeBtn.style.display = 'none';
    if (previewModeBtn) previewModeBtn.style.display = 'none';
    canvasUpdatePreview();
    syncCanvasPreviewDeviceFrame();
    syncCanvasSurfaceWidthLock(tab);
    return;
  }
  // Restore buttons for non-image tabs
  if (codeModeBtn) codeModeBtn.style.display = '';
  if (previewModeBtn) previewModeBtn.style.display = '';
  if (mode === 'preview') {
    if (editorWrap) editorWrap.style.display = 'none';
    if (previewShell) { previewShell.style.display = 'flex'; previewShell.style.flex = '1'; }
    if (previewFrame) { previewFrame.style.display = 'block'; previewFrame.style.flex = 'none'; }
    if (codeModeBtn) codeModeBtn.classList.remove('active');
    if (previewModeBtn) previewModeBtn.classList.add('active');
    canvasUpdatePreview();
    syncCanvasPreviewDeviceFrame();
  } else {
    if (editorWrap) { editorWrap.style.display = 'flex'; editorWrap.style.flex = '1'; }
    if (previewShell) previewShell.style.display = 'none';
    if (previewFrame) previewFrame.style.display = 'none';
    if (codeModeBtn) codeModeBtn.classList.add('active');
    if (previewModeBtn) previewModeBtn.classList.remove('active');
    if (canvasEditor) setTimeout(() => { canvasEditor.refresh(); canvasEditor.focus(); }, 10);
  }
  syncCanvasSurfaceWidthLock(tab);
}

function canvasRenderTabs() {
  const tabsEl = document.getElementById('canvas-tabs');
  if (!tabsEl) return;
  if (isStructuredCreativeMode()) {
    const label = getStructuredCreativeModeLabel(window.currentCreativeMode);
    tabsEl.innerHTML = `<div class="canvas-tab active" style="cursor:default"><span>${escHtml(label)}</span></div>`;
    const codeModeBtn = document.getElementById('canvas-code-btn');
    const previewModeBtn = document.getElementById('canvas-preview-btn');
    const saveBtn = document.getElementById('canvas-save-btn');
    if (codeModeBtn) codeModeBtn.style.display = 'none';
    if (previewModeBtn) previewModeBtn.style.display = 'none';
    if (saveBtn) saveBtn.style.display = 'none';
    renderCreativeWorkspace();
    return;
  }
  if (isBrowserCanvasSurfaceActive()) {
    tabsEl.innerHTML = '<div class="canvas-tab active" style="cursor:default"><span>Live Browser</span></div>';
    const codeModeBtn = document.getElementById('canvas-code-btn');
    const previewModeBtn = document.getElementById('canvas-preview-btn');
    const saveBtn = document.getElementById('canvas-save-btn');
    if (codeModeBtn) codeModeBtn.style.display = 'none';
    if (previewModeBtn) previewModeBtn.style.display = 'none';
    if (saveBtn) saveBtn.style.display = 'none';
    renderBrowserCanvasSurface();
    return;
  }
  tabsEl.innerHTML = canvasTabs.map(t => `
    <div class="canvas-tab ${t.id === activeCanvasTabId ? 'active' : ''} ${t.dirty ? 'canvas-tab-dirty' : ''}" onclick="canvasOpenTab('${t.id}')" title="${escHtml(t.diskPath || t.name)}">
      <span>${escHtml(t.name)}</span>
      <button class="canvas-tab-close" onclick="canvasCloseTab('${t.id}', event)" title="Close">×</button>
    </div>
  `).join('') + `<button class="canvas-new-tab" onclick="canvasNewFile()" title="New file">+</button>`;
  const tab = canvasTabs.find(t => t.id === activeCanvasTabId);
  const codeModeBtn = document.getElementById('canvas-code-btn');
  const previewModeBtn = document.getElementById('canvas-preview-btn');
  const saveBtn = document.getElementById('canvas-save-btn');
  if (codeModeBtn) codeModeBtn.classList.toggle('active', !tab || tab.mode !== 'preview');
  if (previewModeBtn) previewModeBtn.classList.toggle('active', !!(tab && tab.mode === 'preview'));
  // Show save button only for non-image files with a disk path
  if (saveBtn) saveBtn.style.display = (tab && tab.diskPath && !tab.isImage && !tab.isBinary) ? 'flex' : 'none';
  applyCanvasViewMode(tab?.mode || 'code', tab || null);
}

async function canvasUpdatePreview() {
  const frame = document.getElementById('canvas-preview-frame');
  const tab = canvasTabs.find(t => t.id === activeCanvasTabId);
  if (!frame || !tab) return;
  const content = tab.content || '';
  const ext = (tab.name || '').split('.').pop().toLowerCase();
  const isDesignMode = normalizeCreativeMode(window.currentCreativeMode) === 'design';

  frame.onload = null;
  if (tab.isBinary) frame.removeAttribute('sandbox');
  else frame.setAttribute('sandbox', 'allow-scripts allow-same-origin');

  const useProjectPreview = isDesignMode && !!canvasProjectRoot && !tab.isImage && !tab.isBinary;
  if (useProjectPreview) {
    const previewPath = getDesignPreviewEntryPath(tab);
    if (previewPath) {
      try {
        await syncDirtyDesignTabsToDisk();
      } catch (err) {
        addProcessEntry('warn', `Design preview sync failed: ${String(err?.message || err || 'Unknown error')}`);
      }
      frame.removeAttribute('srcdoc');
      frame.onload = () => {
        try {
          const doc = frame.contentDocument;
          if (!doc || !doc.body) return;
          doc.body.contentEditable = 'false';
          doc.body.spellcheck = false;
          setupDesignPreviewSelection(frame, tab);
        } catch {}
      };
      const sessionId = encodeURIComponent(String(window.agentSessionId || 'default'));
      frame.src = `/api/canvas/project-preview/${sessionId}/${encodeCanvasPreviewPath(previewPath)}?v=${Date.now()}`;
      return;
    }
  }

  if (tab.isImage) {
    frame.removeAttribute('src');
    const bg = document.documentElement.getAttribute('data-theme') === 'dark' ? '#1f242d' : '#f4f6fb';
    frame.srcdoc = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>
      * { margin: 0; padding: 0; box-sizing: border-box; }
      body { background: ${bg}; display: flex; align-items: center; justify-content: center;
             min-height: 100vh; padding: 16px; }
      img { max-width: 100%; max-height: 100vh; object-fit: contain;
            border-radius: 6px; box-shadow: 0 4px 24px rgba(0,0,0,0.18); }
      .info { position: fixed; bottom: 10px; right: 12px; font-family: monospace;
              font-size: 10px; color: #888; background: rgba(0,0,0,0.45);
              padding: 3px 8px; border-radius: 4px; }
    </style></head><body>
      <img src="${content}" alt="${tab.name}" onload="document.querySelector('.info').textContent=this.naturalWidth+'×'+this.naturalHeight">
      <div class="info">loading...</div>
    </body></html>`;
    return;
  }

  if (tab.isBinary) {
    if (tab.diskPath) {
      frame.removeAttribute('srcdoc');
      frame.src = `/api/canvas/preview-document?path=${encodeURIComponent(String(tab.diskPath || ''))}&v=${Date.now()}`;
      return;
    }
    frame.removeAttribute('src');
    const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
    const bg = isDark ? '#12161d' : '#f5f7fb';
    const panel = isDark ? '#1b2230' : '#ffffff';
    const border = isDark ? '#2f3b51' : '#d7deeb';
    const textColor = isDark ? '#e6edf7' : '#17243b';
    const muted = isDark ? '#97a6ba' : '#5f6f86';
    const fileSize = Number(tab.size || 0);
    const sizeLabel = fileSize > 1024 * 1024
      ? `${(fileSize / (1024 * 1024)).toFixed(2)} MB`
      : fileSize > 1024
        ? `${(fileSize / 1024).toFixed(1)} KB`
        : `${fileSize} bytes`;
    frame.srcdoc = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>
      *{box-sizing:border-box}
      body{margin:0;min-height:100vh;padding:28px;background:${bg};color:${textColor};font-family:Segoe UI,system-ui,sans-serif;display:flex;align-items:center;justify-content:center}
      .card{width:min(720px,92vw);background:${panel};border:1px solid ${border};border-radius:18px;padding:24px;box-shadow:0 16px 44px rgba(0,0,0,.12)}
      .eyebrow{font-size:12px;letter-spacing:.08em;text-transform:uppercase;color:${muted};margin-bottom:10px}
      h1{margin:0 0 8px;font-size:24px;line-height:1.2}
      p{margin:0 0 14px;color:${muted};line-height:1.6}
      .meta{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px;margin:18px 0}
      .meta div{padding:10px 12px;border:1px solid ${border};border-radius:12px;background:rgba(127,127,127,.04)}
      .label{display:block;font-size:11px;text-transform:uppercase;letter-spacing:.06em;color:${muted};margin-bottom:4px}
      .value{display:block;font-size:13px;word-break:break-word}
      code{font-family:Cascadia Code,Consolas,monospace;font-size:12px}
    </style></head><body><div class="card">
      <div class="eyebrow">Binary File In Canvas</div>
      <h1>${escHtml(tab.name || 'Document')}</h1>
      <p>This upload is now pinned to the canvas and available to the assistant by exact workspace path, without trying to decode the raw binary as plain text.</p>
      <div class="meta">
        <div><span class="label">Type</span><span class="value">${escHtml(String(tab.mimeType || tab.ext || 'binary'))}</span></div>
        <div><span class="label">Size</span><span class="value">${escHtml(sizeLabel)}</span></div>
        <div><span class="label">Workspace Path</span><span class="value"><code>${escHtml(String(tab.diskPath || ''))}</code></span></div>
      </div>
      <p>For Word files, the assistant should use the <code>docx-reader</code> skill. PDFs and spreadsheets can also be processed from this same workspace path.</p>
    </div></body></html>`;
    return;
  }

  if (ext === 'md' && typeof marked !== 'undefined') {
    frame.removeAttribute('src');
    const rendered = marked.parse(content, { breaks: true, gfm: true, mangle: false, headerIds: false });
    frame.srcdoc = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>
      body{font-family:system-ui,sans-serif;line-height:1.7;padding:24px 32px;max-width:800px;margin:0 auto;color:#17243b}
      h1,h2,h3{font-weight:700;margin:16px 0 8px} code{background:#f0f4fb;padding:2px 6px;border-radius:4px;font-size:0.88em}
      pre{background:#f0f4fb;padding:14px;border-radius:8px;overflow-x:auto} pre code{background:none;padding:0}
      blockquote{border-left:3px solid #3b82f6;padding-left:14px;color:#64748b;margin:10px 0}
      table{border-collapse:collapse;width:100%} th,td{border:1px solid #dbe3ee;padding:6px 10px}
      a{color:#1668e3} hr{border:none;border-top:1px solid #dbe3ee;margin:16px 0}
    </style></head><body>${rendered}</body></html>`;
    return;
  }

  if (ext === 'json') {
    frame.removeAttribute('src');
    try {
      const pretty = JSON.stringify(JSON.parse(content), null, 2);
      frame.srcdoc = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{font-family:monospace;font-size:13px;padding:16px;white-space:pre-wrap;word-break:break-word;color:#17243b}</style></head><body>${pretty.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</body></html>`;
    } catch {
      frame.srcdoc = `<pre style="font-family:monospace;padding:16px;white-space:pre-wrap">${content.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</pre>`;
    }
    return;
  }

  if (!isHtmlFile(tab.name) && !content.trim().startsWith('<')) {
    frame.removeAttribute('src');
    frame.srcdoc = `<pre style="font-family:monospace;padding:16px;white-space:pre-wrap;word-break:break-word">${content.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</pre>`;
    return;
  }
  frame.removeAttribute('src');
  frame.srcdoc = content;
  frame.onload = () => {
    try {
      const doc = frame.contentDocument;
      if (!doc || !doc.body) return;
      if (isDesignMode) {
        doc.body.contentEditable = 'false';
        doc.body.spellcheck = false;
        setupDesignPreviewSelection(frame, tab);
      } else {
        doc.body.contentEditable = 'true';
        doc.body.spellcheck = false;
        doc.body.addEventListener('input', () => {
          const html = '<!DOCTYPE html>\n' + doc.documentElement.outerHTML;
          tab.content = html;
          if (canvasEditor && tab.mode !== 'preview') canvasEditor.setValue(html);
        });
      }
    } catch {}
  };
}

async function canvasSave() {
  const tab = canvasTabs.find(t => t.id === activeCanvasTabId);
  if (!tab) { addProcessEntry('warn', 'Canvas: no file open to save.'); return; }
  if (canvasEditor && tab.mode !== 'preview') tab.content = canvasEditor.getValue();

  // If tab has a workspace disk path, save back to disk
  if (tab.diskPath) {
    const btn = document.getElementById('canvas-save-btn');
    if (btn) { btn.textContent = 'Saving…'; btn.disabled = true; }
    try {
      const r = await fetch('/api/canvas/file', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ path: tab.diskPath, content: tab.content }),
      });
      const d = await r.json();
      if (d.success) {
        tab.dirty = false;
        tab.savedContent = tab.content;
        canvasRenderTabs();
        addProcessEntry('info', `Canvas: saved → ${tab.diskPath}`);
      } else {
        addProcessEntry('error', `Canvas: save failed — ${d.error}`);
      }
    } catch (e) {
      addProcessEntry('error', `Canvas: save error — ${e.message}`);
    } finally {
      if (btn) {
        btn.disabled = false;
        btn.innerHTML = '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg> Save';
      }
    }
    return;
  }

  // No disk path — fall back to browser download
  const blob = new Blob([tab.content], { type: 'text/plain;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = tab.name; a.click();
  URL.revokeObjectURL(url);
  addProcessEntry('info', `Canvas: downloaded ${tab.name}`);
}

function canvasAddToContext() {
  const tab = canvasTabs.find(t => t.id === activeCanvasTabId);
  if (!tab) { addProcessEntry('warn', 'Canvas: no file open.'); return; }
  if (canvasEditor && tab.mode !== 'preview') tab.content = canvasEditor.getValue();
  const ext = tab.name.split('.').pop() || 'txt';
  const block = '```' + ext + '\n' + tab.content + '\n```';
  // Send as a message to the LLM so it enters context
  const prompt = `Here is the contents of my file "${tab.name}" for reference:\n\n${block}\n\nI've loaded this file into context. What would you like me to do with it?`;
  const chatInput = document.getElementById('chat-input');
  if (chatInput) {
    chatInput.value = prompt;
    chatInput.style.height = 'auto';
    chatInput.style.height = Math.min(chatInput.scrollHeight, 140) + 'px';
  }
  sendChat();
  addProcessEntry('info', `Canvas: sent ${tab.name} to LLM as context.`);
}

// ──────────────────────────────────────────────────────────────────────────
// CHAT FILE UPLOAD
// Staged files live in pendingChatFiles[] until the user hits Send.
// On send they are uploaded to workspace/uploads/ and loaded into canvas.
// ──────────────────────────────────────────────────────────────────────────

// Each entry: { file: File, name: string, ext: string, text: string|null }
let pendingChatFiles = [];
let pendingChatFileStagingPromises = [];

const TEXT_EXTENSIONS = new Set([
  'txt','md','csv','json','js','ts','jsx','tsx','html','htm','css','scss','less',
  'py','rb','php','java','c','cpp','h','go','rs','sh','bash','yaml','yml',
  'toml','ini','cfg','conf','xml','svg','sql','graphql','vue','svelte','log'
]);

// Images — read as DataURL, uploaded as binary, sent to AI as vision attachment
const IMAGE_EXTENSIONS = new Set(['png','jpg','jpeg','webp','gif','bmp','ico']);
const VIDEO_EXTENSIONS = new Set(['mp4','mov','m4v','webm','avi','mkv','mpeg','mpg','3gp']);
// Other binary types — uploaded as binary, AI reads by path/shell tools
const BINARY_EXTENSIONS = new Set(['pdf','docx','doc','xls','xlsx','pptx','ppt','zip','rar','7z']);

function getCanvasFileIcon(ext) {
  const e = (ext || '').toLowerCase();
  if (['jpg','jpeg','png','gif','webp','bmp','ico','svg'].includes(e)) return '🖼️';
  if (['mp4','mov','avi','mkv','webm'].includes(e)) return '🎥';
  if (['mp3','wav','ogg','flac','m4a'].includes(e)) return '🎵';
  if (['pdf'].includes(e)) return '📄';
  if (['zip','rar','7z','tar','gz'].includes(e)) return '📦';
  if (['doc','docx'].includes(e)) return '📃';
  if (['xls','xlsx','csv'].includes(e)) return '📈';
  if (['ppt','pptx'].includes(e)) return '📊';
  if (['js','ts','jsx','tsx','py','rb','java','c','cpp','go','rs'].includes(e)) return '💻';
  if (['html','htm','css','scss'].includes(e)) return '🌐';
  if (['json','yaml','yml','toml','xml'].includes(e)) return '⚙️';
  if (['md','txt'].includes(e)) return '📝';
  if (['sh','bash'].includes(e)) return '🖥️';
  return '📎';
}

function renderChatFilePills() {
  const staging = document.getElementById('chat-file-staging');
  if (!staging) return;
  if (!pendingChatFiles.length) {
    staging.style.display = 'none';
    staging.innerHTML = '';
    return;
  }
  staging.style.display = 'flex';
  staging.innerHTML = pendingChatFiles.map((f, idx) => {
    const isImg = IMAGE_EXTENSIONS.has(f.ext);
    const preview = isImg && f.dataUrl
      ? `<img src="${f.dataUrl}" style="width:28px;height:28px;object-fit:cover;border-radius:4px;flex-shrink:0" alt="">`
      : `<span class="pill-icon">${getCanvasFileIcon(f.ext)}</span>`;
    return `<div class="chat-file-pill">
      ${preview}
      <span class="pill-name" title="${escHtml(f.name)}">${escHtml(f.name)}</span>
      <span class="pill-ext">${escHtml(f.ext || 'file')}</span>
      <button class="pill-remove" onclick="removeChatFile(${idx})" title="Remove">&times;</button>
    </div>`;
  }).join('');
}

function openImgPreview(src, name) {
  if (document.getElementById('img-preview-overlay')) return;
  const overlay = document.createElement('div');
  overlay.id = 'img-preview-overlay';
  overlay.className = 'img-preview-overlay';
  overlay.innerHTML = `
    <div class="img-preview-box" onclick="event.stopPropagation()">
      <button class="img-preview-close" onclick="closeImgPreview()" title="Close">&times;</button>
      <img src="${src}" alt="${name || ''}">
      ${name ? `<div class="img-preview-name">${name}</div>` : ''}
    </div>`;
  overlay.addEventListener('click', closeImgPreview);
  document.body.appendChild(overlay);
  document.addEventListener('keydown', _imgPreviewKeyHandler);
}
function closeImgPreview() {
  const el = document.getElementById('img-preview-overlay');
  if (el) el.remove();
  document.removeEventListener('keydown', _imgPreviewKeyHandler);
}
function _imgPreviewKeyHandler(e) {
  if (e.key === 'Escape') closeImgPreview();
}
window.openImgPreview = openImgPreview;
window.closeImgPreview = closeImgPreview;

function removeChatFile(idx) {
  pendingChatFiles.splice(idx, 1);
  renderChatFilePills();
}

async function stageFiles(fileList) {
  const promises = Array.from(fileList).map(file => new Promise(resolve => {
    const ext = (file.name.split('.').pop() || '').toLowerCase();
    if (TEXT_EXTENSIONS.has(ext)) {
      const reader = new FileReader();
      reader.onload = e => resolve({ file, name: file.name, ext, text: e.target.result, dataUrl: null, binary: false });
      reader.onerror = () => resolve({ file, name: file.name, ext, text: null, dataUrl: null, binary: false });
      reader.readAsText(file);
    } else if (IMAGE_EXTENSIONS.has(ext)) {
      // Read as DataURL — enables thumbnail preview and vision attachment
      const reader = new FileReader();
      reader.onload = e => resolve({ file, name: file.name, ext, text: null, dataUrl: e.target.result, binary: false, isImage: true });
      reader.onerror = () => resolve({ file, name: file.name, ext, text: null, dataUrl: null, binary: true, isImage: true });
      reader.readAsDataURL(file);
    } else if (VIDEO_EXTENSIONS.has(ext) || BINARY_EXTENSIONS.has(ext)) {
      // Binary — upload to server as base64, AI reads by path
      resolve({ file, name: file.name, ext, text: null, dataUrl: null, binary: true, base64: null, isVideo: VIDEO_EXTENSIONS.has(ext) });
    } else {
      resolve({ file, name: file.name, ext, text: null, dataUrl: null, binary: true });
    }
  }));
  const stagingPromise = Promise.all(promises).then((staged) => {
    pendingChatFiles.push(...staged);
    renderChatFilePills();
    return staged;
  }).finally(() => {
    pendingChatFileStagingPromises = pendingChatFileStagingPromises.filter((p) => p !== stagingPromise);
  });
  pendingChatFileStagingPromises.push(stagingPromise);
  return stagingPromise;
}

async function waitForChatFileStaging() {
  while (pendingChatFileStagingPromises.length) {
    await Promise.allSettled(pendingChatFileStagingPromises.slice());
  }
}

function onChatFileInputChange(event) {
  const files = event.target.files;
  if (!files || !files.length) return;
  stageFiles(files);
  // Reset input so same file can be re-added after removal
  event.target.value = '';
}

function getClipboardFileExtension(mimeType = '', fallbackName = '') {
  const fallbackExt = String(fallbackName || '').split('.').pop().toLowerCase();
  if (fallbackExt && fallbackExt !== fallbackName.toLowerCase()) return fallbackExt;
  const type = String(mimeType || '').toLowerCase();
  if (type.includes('pdf')) return 'pdf';
  if (type.includes('wordprocessingml')) return 'docx';
  if (type.includes('msword')) return 'doc';
  if (type.includes('spreadsheetml')) return 'xlsx';
  if (type.includes('ms-excel')) return 'xls';
  if (type.includes('presentationml')) return 'pptx';
  if (type.includes('ms-powerpoint')) return 'ppt';
  if (type.includes('zip')) return 'zip';
  if (type.includes('json')) return 'json';
  if (type.startsWith('text/')) return 'txt';
  if (type.includes('jpeg') || type.includes('jpg')) return 'jpg';
  if (type.includes('webp')) return 'webp';
  if (type.includes('gif')) return 'gif';
  if (type.includes('bmp')) return 'bmp';
  if (type.includes('svg')) return 'svg';
  if (type.includes('mp4')) return 'mp4';
  if (type.includes('quicktime')) return 'mov';
  if (type.includes('x-m4v')) return 'm4v';
  if (type.includes('webm')) return 'webm';
  if (type.includes('x-msvideo')) return 'avi';
  if (type.includes('x-matroska')) return 'mkv';
  if (type.includes('mpeg')) return 'mpeg';
  if (type.includes('3gpp')) return '3gp';
  return '';
}

function getClipboardImageExtension(mimeType = '') {
  return getClipboardFileExtension(mimeType) || 'png';
}

function getClipboardFileKind(file) {
  const type = String(file?.type || '').toLowerCase();
  const ext = getClipboardFileExtension(type, file?.name);
  if (type.startsWith('image/') || IMAGE_EXTENSIONS.has(ext)) return 'image';
  if (type.startsWith('video/') || VIDEO_EXTENSIONS.has(ext)) return 'video';
  return 'file';
}

function makePastedAttachmentName(file, index = 0) {
  const rawName = String(file?.name || '').trim();
  if (rawName && rawName !== 'image.png' && rawName !== 'video.mp4' && /\.[a-z0-9]+$/i.test(rawName)) return rawName;
  const kind = getClipboardFileKind(file);
  const ext = getClipboardFileExtension(file?.type, rawName) || (kind === 'image' ? 'png' : kind === 'video' ? 'mp4' : 'bin');
  const stamp = new Date().toISOString()
    .replace(/\.\d+Z$/, '')
    .replace(/[^\dT]/g, '')
    .replace('T', '-');
  const suffix = index > 0 ? `-${index + 1}` : '';
  const prefix = kind === 'image' ? 'pasted-screenshot' : kind === 'video' ? 'pasted-video' : 'pasted-file';
  return `${prefix}-${stamp}${suffix}.${ext}`;
}

function makePastedImageName(file, index = 0) {
  return makePastedAttachmentName(file, index);
}

function normalizePastedAttachmentFile(file, index = 0) {
  if (!file) return null;
  const type = String(file.type || '').toLowerCase();
  const kind = getClipboardFileKind(file);
  if (kind === 'file' && !String(file.name || '').trim()) return null;
  const name = makePastedAttachmentName(file, index);
  const ext = getClipboardFileExtension(type, name);
  const mimeType = file.type || (kind === 'image' ? `image/${ext}` : kind === 'video' ? getMimeType(ext) : '');
  try {
    return new File([file], name, {
      type: mimeType,
      lastModified: file.lastModified || Date.now(),
    });
  } catch {
    file.name = file.name || name;
    return file;
  }
}

function normalizePastedImageFile(file, index = 0) {
  const normalized = normalizePastedAttachmentFile(file, index);
  return getClipboardFileKind(normalized) === 'image' ? normalized : null;
}

function getClipboardAttachmentFiles(clipboardData) {
  if (!clipboardData) return [];
  const files = [];
  const seen = new Set();
  const addFile = (file) => {
    const normalized = normalizePastedAttachmentFile(file, files.length);
    if (!normalized) return;
    const key = `${normalized.name}:${normalized.size}:${normalized.type}`;
    if (seen.has(key)) return;
    seen.add(key);
    files.push(normalized);
  };

  Array.from(clipboardData.files || []).forEach(addFile);
  Array.from(clipboardData.items || []).forEach((item) => {
    if (!item || item.kind !== 'file') return;
    try { addFile(item.getAsFile()); } catch {}
  });

  return files;
}

function getClipboardImageFiles(clipboardData) {
  return getClipboardAttachmentFiles(clipboardData)
    .filter((file) => getClipboardFileKind(file) === 'image');
}

function isChatPasteTarget(target) {
  const input = document.getElementById('chat-input');
  const chatView = document.getElementById('chat-view');
  const inputArea = document.querySelector('.chat-input-area');
  if (target === input || inputArea?.contains(target) || chatView?.contains(target)) return true;
  const active = document.activeElement;
  if (active === document.body || active === document.documentElement) return !!chatView;
  return false;
}

function isNonChatEditableTarget(target) {
  if (!target || target === document.getElementById('chat-input')) return false;
  const editable = target.closest?.('input, textarea, select, [contenteditable="true"]');
  return !!editable && editable.id !== 'chat-input';
}

function handleChatPaste(event) {
  if (!isChatPasteTarget(event.target) || isNonChatEditableTarget(event.target)) return;
  const files = getClipboardAttachmentFiles(event.clipboardData);
  if (!files.length) return;

  const pastedText = event.clipboardData?.getData?.('text/plain') || '';
  if (!pastedText.trim()) event.preventDefault();
  stageFiles(files);
  const videoCount = files.filter((file) => getClipboardFileKind(file) === 'video').length;
  const imageCount = files.filter((file) => getClipboardFileKind(file) === 'image').length;
  const title = files.length === 1
    ? (videoCount ? 'Video staged' : imageCount ? 'Screenshot staged' : 'Attachment staged')
    : `${files.length} attachments staged`;
  showToast(
    title,
    'Press Send when you are ready.',
    'success'
  );
}

function readFileAsBase64(file) {
  return new Promise((resolve, reject) => {
    if (!file) {
      reject(new Error('No file bytes available'));
      return;
    }
    const reader = new FileReader();
    reader.onload = (event) => {
      const dataUrl = String(event.target?.result || '');
      const base64 = dataUrl.replace(/^data:[^;]+;base64,/, '');
      if (!base64) reject(new Error('Could not read file bytes'));
      else resolve(base64);
    };
    reader.onerror = () => reject(new Error('Could not read file bytes'));
    reader.readAsDataURL(file);
  });
}

// Upload staged files to workspace/uploads/ and open them in canvas.
// Returns an array of { name, workspacePath, isImage, base64, mimeType } for context injection.
async function uploadStagedFilesToCanvas(stagedFiles = pendingChatFiles) {
  if (!stagedFiles.length) return [];
  const results = [];
  for (const sf of stagedFiles) {
    if (sf.text !== null) {
      try {
        const r = await fetch('/api/canvas/upload', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ filename: sf.name, content: sf.text })
        });
        const d = await r.json();
        if (d.success) {
          await canvasPresentFile(d.absPath, d.filename, { autoOpen: false });
          results.push({ name: sf.name, ext: sf.ext, workspacePath: d.absPath, relPath: d.relPath });
        } else {
          results.push({ name: sf.name, ext: sf.ext, workspacePath: null, error: d.error });
        }
      } catch (e) {
        results.push({ name: sf.name, ext: sf.ext, workspacePath: null, error: e.message });
      }
    } else if (sf.isImage && sf.dataUrl) {
      const mimeType = sf.dataUrl.split(';')[0].replace('data:', '') || `image/${sf.ext}`;
      const pureBase64 = sf.dataUrl.replace(/^data:[^;]+;base64,/, '');
      try {
        const r = await fetch('/api/canvas/upload-binary', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ filename: sf.name, base64: pureBase64, mimeType })
        });
        const d = await r.json();
        if (d.success) {
          await canvasPresentFile(d.absPath, d.filename, { autoOpen: false });
          results.push({ name: sf.name, ext: sf.ext, workspacePath: d.absPath, relPath: d.relPath, isImage: true, base64: pureBase64, mimeType });
        } else {
          results.push({ name: sf.name, ext: sf.ext, workspacePath: null, isImage: true, base64: pureBase64, mimeType, error: d.error });
        }
      } catch (e) {
        results.push({ name: sf.name, ext: sf.ext, workspacePath: null, isImage: true, base64: pureBase64, mimeType, error: e.message });
      }
    } else if (sf.base64 || sf.binary) {
      const mimeType = getMimeType(sf.ext);
      let base64 = sf.base64;
      try {
        if (!base64) base64 = await readFileAsBase64(sf.file);
        const r = await fetch('/api/canvas/upload-binary', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ filename: sf.name, base64, mimeType })
        });
        const d = await r.json();
        if (d.success) {
          await canvasPresentFile(d.absPath, d.filename, { autoOpen: false });
          results.push({ name: sf.name, ext: sf.ext, workspacePath: d.absPath, relPath: d.relPath, binary: true, isVideo: !!sf.isVideo, mimeType });
        } else {
          results.push({ name: sf.name, ext: sf.ext, workspacePath: null, binary: true, isVideo: !!sf.isVideo, mimeType, error: d.error });
        }
      } catch (e) {
        results.push({ name: sf.name, ext: sf.ext, workspacePath: null, binary: true, isVideo: !!sf.isVideo, mimeType, error: e.message });
      }
    } else {
      results.push({ name: sf.name, ext: sf.ext, workspacePath: null, binary: true });
    }
  }
  return results;
}

function stagedFilesToAttachmentPreviews(stagedFiles) {
  if (!Array.isArray(stagedFiles) || !stagedFiles.length) return [];
  return stagedFiles.map((sf) => {
    if (sf.isImage && sf.dataUrl) {
      return {
        kind: 'image',
        name: sf.name,
        ext: sf.ext || '',
        workspacePath: '',
        dataUrl: sf.dataUrl,
      };
    }
    return {
      kind: sf.isVideo ? 'video' : 'file',
      name: sf.name,
      ext: sf.ext || '',
      workspacePath: '',
      mimeType: sf.binary || sf.isVideo ? getMimeType(sf.ext) : '',
      binary: !!sf.binary,
    };
  });
}

function uploadResultsToAttachmentPreviews(uploadResults) {
  if (!Array.isArray(uploadResults) || !uploadResults.length) return [];
  return uploadResults.map((r) => {
    if (r.isImage && r.base64 && r.mimeType) {
      return {
        kind: 'image',
        name: r.name,
        ext: r.ext || '',
        workspacePath: r.workspacePath || '',
        dataUrl: `data:${r.mimeType};base64,${r.base64}`,
      };
    }
    return {
      kind: r.isVideo ? 'video' : 'file',
      name: r.name,
      ext: r.ext || '',
      workspacePath: r.workspacePath || '',
      mimeType: r.mimeType || '',
      binary: !!r.binary,
    };
  });
}
function getMimeType(ext) {
  const map = {
    pdf: 'application/pdf', docx: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    doc: 'application/msword', xlsx: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    xls: 'application/vnd.ms-excel', pptx: 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
    ppt: 'application/vnd.ms-powerpoint', zip: 'application/zip',
    png: 'image/png', jpg: 'image/jpeg', jpeg: 'image/jpeg', webp: 'image/webp', gif: 'image/gif',
    mp4: 'video/mp4', m4v: 'video/x-m4v', mov: 'video/quicktime', webm: 'video/webm',
    avi: 'video/x-msvideo', mkv: 'video/x-matroska', mpeg: 'video/mpeg', mpg: 'video/mpeg', '3gp': 'video/3gpp',
  };
  return map[(ext || '').toLowerCase()] || 'application/octet-stream';
}

// Build the context snippet appended to the user message describing uploaded files.
function buildFileContextNote(uploadResults) {
  if (!uploadResults.length) return '';
  const lines = uploadResults.map(r => {
    if (r.isVideo && r.workspacePath) return `  - "${r.name}" (video) -> saved to: ${r.workspacePath}`;
    if (r.isVideo && !r.workspacePath) return `  - "${r.name}" (video) - upload failed or unavailable`;
    if (r.isImage && r.workspacePath) return `  • "${r.name}" (image) → saved to: ${r.workspacePath}`;
    if (r.isImage && !r.workspacePath) return `  • "${r.name}" (image) — attached for vision analysis`;
    if (r.workspacePath) return `  • "${r.name}" → copied to workspace at: ${r.workspacePath}`;
    if (r.binary) return `  • "${r.name}" — binary file (not copied; view your original)`;
    return `  • "${r.name}" — upload failed: ${r.error || 'unknown error'}`;
  });
  const hasImages = uploadResults.some(r => r.isImage && r.base64);
  const hasVideos = uploadResults.some(r => r.isVideo && r.workspacePath);
  const imageNote = hasImages ? '\nImages above are attached directly — you can see them.' : '';
  const videoNote = hasVideos ? '\nVideos above are saved in the workspace. Use analyze_video when the visual/audio content matters, and in Creative Video mode place them as editable video layers with creative_add_asset or creative_add_element type="video".' : '';
  return `\n\n[UPLOADED FILES]\n${lines.join('\n')}${imageNote}${videoNote}\nUse the exact workspace paths above to read, edit, place, or process files. In Creative Image/Video mode, uploaded images and videos can become editable asset layers with normal x/y/width/height/rotation/opacity/style/animation controls.`;
}

function chatFileUploadInit() {
  const inputArea = document.querySelector('.chat-input-area');
  if (!inputArea) return;

  // Expand drag target to the full chat column (#chat-view covers messages + input)
  const chatView = document.getElementById('chat-view') || inputArea;

  // Drag-over visual feedback on the full chat column
  chatView.addEventListener('dragover', (e) => {
    e.preventDefault();
    e.stopPropagation();
    chatView.classList.add('drag-over');
  });
  chatView.addEventListener('dragleave', (e) => {
    if (!chatView.contains(e.relatedTarget)) chatView.classList.remove('drag-over');
  });
  chatView.addEventListener('drop', (e) => {
    e.preventDefault();
    e.stopPropagation();
    chatView.classList.remove('drag-over');
    const files = e.dataTransfer?.files;
    if (files && files.length) stageFiles(files);
  });

  if (!window.__prometheusChatPasteInit) {
    window.__prometheusChatPasteInit = true;
    document.addEventListener('paste', handleChatPaste);
  }
}

function canvasInitDrop() {
  const panel = document.getElementById('canvas-panel');
  if (!panel) return;
  panel.addEventListener('dragover', (e) => { e.preventDefault(); panel.classList.add('canvas-drag-over'); });
  panel.addEventListener('dragleave', (e) => { if (!panel.contains(e.relatedTarget)) panel.classList.remove('canvas-drag-over'); });
  panel.addEventListener('drop', async (e) => {
    e.preventDefault();
    panel.classList.remove('canvas-drag-over');
    const files = Array.from(e.dataTransfer.files || []);
    if (!files.length) return;
    if (files.some((file) => file.webkitRelativePath)) {
      await canvasImportDirectory(files);
    } else {
      await canvasImportLooseFiles(files);
    }
  });
}

function sanitizeCanvasImportSegment(value) {
  return String(value || '').replace(/[^a-zA-Z0-9._\-() ]/g, '_');
}

function getCanvasNativeFilePath(file) {
  return normalizeCanvasPath(file?.path || file?.webkitRelativePathNative || '');
}

function inferCanvasNativeFolderPath(files) {
  const file = Array.from(files || []).find((candidate) => getCanvasNativeFilePath(candidate) && candidate.webkitRelativePath);
  if (!file) return '';
  const nativePath = getCanvasNativeFilePath(file);
  const relPath = normalizeCanvasPath(file.webkitRelativePath || '');
  const relSegments = relPath.split('/').filter(Boolean);
  if (!nativePath || relSegments.length < 2) return '';
  const nestedPath = relSegments.slice(1).join('/');
  if (!nativePath.endsWith(nestedPath)) return '';
  return normalizeCanvasPath(nativePath.slice(0, nativePath.length - nestedPath.length).replace(/\/+$/, ''));
}

async function readCanvasImportFile(file) {
  const fullName = file.name || 'file';
  const ext = String(fullName).split('.').pop().toLowerCase();
  const textExts = new Set(['txt', 'md', 'json', 'js', 'ts', 'jsx', 'tsx', 'css', 'html', 'htm', 'xml', 'svg', 'py', 'sh', 'yml', 'yaml', 'toml', 'ini', 'env', 'csv']);
  if (textExts.has(ext)) {
    return await new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (event) => resolve({ name: fullName, ext, text: event.target.result, base64: null });
      reader.onerror = () => resolve({ name: fullName, ext, text: null, base64: null });
      reader.readAsText(file);
    });
  }
  return await new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const bytes = new Uint8Array(event.target.result);
      let binary = '';
      for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
      resolve({ name: fullName, ext, text: null, base64: btoa(binary) });
    };
    reader.onerror = () => resolve({ name: fullName, ext, text: null, base64: null });
    reader.readAsArrayBuffer(file);
  });
}

async function uploadCanvasImportFiles(files, options = {}) {
  const imported = [];
  for (const file of files) {
    const parsed = await readCanvasImportFile(file);
    const relativePath = normalizeCanvasPath(options.relativePathForFile ? options.relativePathForFile(file) : '');
    try {
      let response;
      if (parsed.text !== null) {
        response = await fetch('/api/canvas/upload', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ filename: parsed.name, content: parsed.text, relativePath }),
        });
      } else if (parsed.base64) {
        response = await fetch('/api/canvas/upload-binary', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ filename: parsed.name, base64: parsed.base64, mimeType: getMimeType(parsed.ext), relativePath }),
        });
      } else {
        imported.push({ success: false, name: parsed.name, error: 'Unsupported file type' });
        continue;
      }
      const data = await response.json();
      if (!response.ok || !data.success) {
        imported.push({ success: false, name: parsed.name, error: data.error || `HTTP ${response.status}` });
        continue;
      }
      imported.push({ success: true, name: parsed.name, absPath: data.absPath, relPath: normalizeCanvasPath(data.relPath) });
    } catch (err) {
      imported.push({ success: false, name: parsed.name, error: err.message });
    }
  }
  return imported;
}

async function canvasImportLooseFiles(files) {
  if (!files.length) return;
  const nativePaths = files.map(getCanvasNativeFilePath).filter(Boolean);
  if (nativePaths.length === files.length) {
    for (let i = 0; i < nativePaths.length; i += 1) {
      await canvasPresentFile(nativePaths[i], files[i]?.name || getCanvasProjectDisplayName(nativePaths[i]));
    }
    addProcessEntry('info', `Canvas: connected ${nativePaths.length} file${nativePaths.length === 1 ? '' : 's'} without copying.`);
    return;
  }
  const uploads = await uploadCanvasImportFiles(files);
  const successful = uploads.filter((item) => item.success);
  for (const item of successful) {
    await canvasPresentFile(item.absPath, item.name);
  }
  if (successful.length > 0) {
    await canvasLoadWorkspaceFiles();
    addProcessEntry('info', `Canvas: imported ${successful.length} file${successful.length === 1 ? '' : 's'} into workspace/uploads.`);
  }
}

async function canvasImportDirectory(files) {
  if (!files.length) return;
  const firstRelPath = normalizeCanvasPath(files.find((file) => file.webkitRelativePath)?.webkitRelativePath || '');
  const rootNameRaw = firstRelPath.split('/').filter(Boolean)[0] || 'project';
  const nativeFolderPath = inferCanvasNativeFolderPath(files);
  if (nativeFolderPath) {
    await canvasConnectFolderPath(nativeFolderPath, rootNameRaw);
    return;
  }
  const rootSlug = `${sanitizeCanvasImportSegment(rootNameRaw) || 'project'}_${Date.now()}`;
  const basePrefix = normalizeCanvasPath(`projects/${rootSlug}`);
  const uploads = await uploadCanvasImportFiles(files, {
    relativePathForFile: (file) => {
      const rel = normalizeCanvasPath(file.webkitRelativePath || file.name);
      const segments = rel.split('/').filter(Boolean);
      const nested = segments.length > 1
        ? segments.slice(1).map(sanitizeCanvasImportSegment).join('/')
        : sanitizeCanvasImportSegment(file.name);
      return `${basePrefix}/${nested}`;
    },
  });
  const successful = uploads.filter((item) => item.success);
  if (successful.length === 0) {
    showToast('Folder import failed.', 'error');
    return;
  }
  const firstFile = successful[0];
  const absNorm = normalizeCanvasPath(firstFile.absPath);
  const relNorm = normalizeCanvasPath(firstFile.relPath);
  const workspacePrefix = relNorm && absNorm.endsWith(relNorm)
    ? absNorm.slice(0, absNorm.length - relNorm.length).replace(/\/+$/, '')
    : '';
  const projectRootRel = normalizeCanvasPath(`uploads/${basePrefix}`);
  const projectRootAbs = workspacePrefix ? `${workspacePrefix}/${projectRootRel}` : '';
  try {
    const saved = await persistCanvasProjectRoot(projectRootAbs, rootNameRaw);
    setCanvasProjectState(saved?.projectRoot, saved?.projectLabel);
  } catch (err) {
    showToast(`Canvas project root error: ${err.message}`, 'error');
  }
  await canvasLoadWorkspaceFiles(projectRootAbs);
  await canvasPresentFile(firstFile.absPath, firstFile.name, { skipTreeFocus: true });
  addProcessEntry('info', `Canvas: imported folder "${rootNameRaw}" (${successful.length} files).`);
}

function canvasHasNativePathPicker() {
  return !!(window.prometheusFiles && typeof window.prometheusFiles.selectCanvasFiles === 'function' && typeof window.prometheusFiles.selectCanvasFolder === 'function');
}

async function canvasPickFiles() {
  if (!canvasHasNativePathPicker()) {
    document.getElementById('canvas-file-input')?.click();
    return;
  }
  const paths = await window.prometheusFiles.selectCanvasFiles().catch((err) => {
    showToast(`Could not open file picker: ${err.message || err}`, 'error');
    return [];
  });
  const selectedPaths = Array.isArray(paths) ? paths.filter(Boolean) : [];
  for (const filePath of selectedPaths) {
    await canvasPresentFile(filePath, getCanvasProjectDisplayName(filePath));
  }
  if (selectedPaths.length > 0) {
    addProcessEntry('info', `Canvas: connected ${selectedPaths.length} file${selectedPaths.length === 1 ? '' : 's'} without copying.`);
  }
}

async function canvasConnectFolderPath(folderPath, label = '') {
  const normalizedFolderPath = normalizeCanvasPath(folderPath);
  if (!normalizedFolderPath) return;
  try {
    const saved = await persistCanvasProjectRoot(normalizedFolderPath, label || getCanvasProjectDisplayName(normalizedFolderPath));
    setCanvasProjectState(saved?.projectRoot, saved?.projectLabel);
    canvasFolderExpanded.clear();
    await canvasLoadWorkspaceFiles(saved?.projectRoot || normalizedFolderPath);
    addProcessEntry('info', `Canvas: connected folder ${saved?.projectLabel || label || normalizedFolderPath} without copying.`);
  } catch (err) {
    if (/outside workspace|allowed|invalid project root/i.test(String(err?.message || ''))) {
      const added = await addCanvasAllowedDirectory(
        normalizedFolderPath,
        `Prometheus can't browse this folder yet because it is outside the workspace.\n\nAllow directory:\n${normalizedFolderPath}\n\nThis will add it to Settings > Security > Allowed Paths.`
      );
      if (added) {
        await canvasConnectFolderPath(normalizedFolderPath, label);
        return;
      }
    }
    showToast(`Could not connect folder: ${err.message || err}`, 'error');
  }
}

async function canvasPickFolder() {
  if (!canvasHasNativePathPicker()) {
    document.getElementById('canvas-folder-input')?.click();
    return;
  }
  const paths = await window.prometheusFiles.selectCanvasFolder().catch((err) => {
    showToast(`Could not open folder picker: ${err.message || err}`, 'error');
    return [];
  });
  const folderPath = Array.isArray(paths) ? paths.find(Boolean) : '';
  if (folderPath) await canvasConnectFolderPath(folderPath);
}

// Handle files selected via the "Add File" button (OS file picker)
async function canvasHandleFileInput(input) {
  const files = Array.from(input.files || []);
  if (!files.length) return;
  await canvasImportLooseFiles(files);
  input.value = '';
}

async function canvasHandleFolderInput(input) {
  const files = Array.from(input.files || []);
  if (!files.length) return;
  await canvasImportDirectory(files);
  input.value = '';
}

// ---- Canvas Workspace Integration ----

// Present a workspace file in the canvas (called from SSE handler or "Open in Canvas" button).
// Fetches content from the server and opens/updates a tab.
// Notify the server which files are open in the canvas so the AI always
// knows exact paths without guessing.
function canvasNotifyOpen(diskPath) {
  if (!diskPath || !window.agentSessionId) return;
  fetch('/api/canvas/open', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sessionId: window.agentSessionId, path: diskPath }),
  }).catch(() => {});
}
function canvasNotifyClose(diskPath) {
  if (!diskPath || !window.agentSessionId) return;
  fetch('/api/canvas/close', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sessionId: window.agentSessionId, path: diskPath }),
  }).catch(() => {});
}

async function canvasPresentFileLegacy(diskPath, label) {
  if (!diskPath) return;
  const name = label || diskPath.split('/').pop() || diskPath;
  let tab = canvasTabs.find(t => t.diskPath === diskPath);
  if (tab) {
    try {
      const r = await fetch(`/api/canvas/file?path=${encodeURIComponent(diskPath)}`);
      const d = await r.json();
      if (d.success) {
        if (d.isImage) {
          const dataUrl = `data:${d.mimeType};base64,${d.base64}`;
          tab.content = dataUrl;
          tab.savedContent = dataUrl;
          tab.isImage = true;
          tab.isBinary = false;
          tab.mimeType = d.mimeType;
        } else if (d.isBinary) {
          tab.content = '';
          tab.savedContent = '';
          tab.isImage = false;
          tab.isBinary = true;
          tab.mimeType = d.mimeType;
          tab.ext = d.ext || (name.split('.').pop() || '').toLowerCase();
          tab.size = d.size || 0;
          tab.mode = 'preview';
        } else {
          tab.content = d.content;
          tab.savedContent = d.content;
          tab.isImage = false;
          tab.isBinary = false;
          tab.mode = (name.endsWith('.html') || name.endsWith('.htm') || name.endsWith('.md')) ? 'preview' : 'code';
          if (canvasEditor && activeCanvasTabId === tab.id) {
            canvasEditor.setValue(d.content);
            canvasEditor.setOption('mode', getCanvasLang(name));
          }
        }
        tab.dirty = false;
      }
	    } catch {}
	    if (!canvasOpen) toggleCanvas();
	    canvasOpenTab(tab.id);
	    await ensureCanvasTreeFocusedForFile(diskPath);
	    const tree = document.getElementById('canvas-project-tree');
	    if (tree && canvasWorkspaceTree.length) tree.innerHTML = canvasRenderWorkspaceTree(canvasWorkspaceTree, 0);
	    return;
	  }
  try {
    const r = await fetch(`/api/canvas/file?path=${encodeURIComponent(diskPath)}`);
    const d = await r.json();
    if (!d.success) { addProcessEntry('error', `Canvas: could not load ${diskPath} â€” ${d.error}`); return; }
    const id = 'ctab_' + Math.random().toString(36).slice(2);
    const ext = name.split('.').pop().toLowerCase();
    if (d.isImage) {
      const dataUrl = `data:${d.mimeType};base64,${d.base64}`;
      canvasTabs.push({
        id, name, content: dataUrl, savedContent: dataUrl,
        diskPath, dirty: false,
        mode: 'preview',
        language: 'null',
        isImage: true,
        mimeType: d.mimeType,
      });
    } else if (d.isBinary) {
      canvasTabs.push({
        id, name, content: '', savedContent: '',
        diskPath, dirty: false,
        mode: 'preview',
        language: 'null',
        isBinary: true,
        mimeType: d.mimeType,
        ext: d.ext || ext,
        size: d.size || 0,
      });
    } else {
      const autoPreview = ext === 'html' || ext === 'htm' || ext === 'md';
      canvasTabs.push({
        id, name, content: d.content, savedContent: d.content,
        diskPath, dirty: false,
        mode: autoPreview ? 'preview' : 'code',
        language: getCanvasLang(name),
      });
    }
    if (!canvasOpen) toggleCanvas();
    canvasOpenTab(id);
    canvasNotifyOpen(diskPath);
    addProcessEntry('info', `Canvas: opened ${diskPath}`);
    const tree = document.getElementById('canvas-project-tree');
    if (tree && canvasWorkspaceTree.length) tree.innerHTML = canvasRenderWorkspaceTree(canvasWorkspaceTree, 0);
    persistActiveChat();
  } catch (e) {
    addProcessEntry('error', `Canvas: fetch error â€” ${e.message}`);
  }
}

async function canvasPresentFile(diskPath, label, options = {}) {
  if (!diskPath) return;
  const shouldAutoOpen = options.autoOpen !== false;
  const notifyWhenClosed = options.notifyWhenClosed !== false;
  const markCanvasHasHiddenFile = () => {
    if (canvasOpen || !notifyWhenClosed) return;
    const dot = document.getElementById('canvas-notify-dot');
    if (dot) dot.style.display = 'block';
  };
  const name = label || diskPath.split('/').pop() || diskPath;
  let tab = canvasTabs.find((candidate) => candidate.diskPath === diskPath);
  if (tab) {
    try {
      const response = await fetch(`/api/canvas/file?path=${encodeURIComponent(diskPath)}`);
      const data = await response.json();
      if (data.success) {
        if (data.isImage) {
          const dataUrl = `data:${data.mimeType};base64,${data.base64}`;
          tab.content = dataUrl;
          tab.savedContent = dataUrl;
          tab.isImage = true;
          tab.isBinary = false;
          tab.mimeType = data.mimeType;
        } else if (data.isBinary) {
          tab.content = '';
          tab.savedContent = '';
          tab.isImage = false;
          tab.isBinary = true;
          tab.mimeType = data.mimeType;
          tab.ext = data.ext || (name.split('.').pop() || '').toLowerCase();
          tab.size = data.size || 0;
          tab.mode = 'preview';
        } else {
          tab.content = data.content;
          tab.savedContent = data.content;
          tab.isImage = false;
          tab.isBinary = false;
          tab.mode = (name.endsWith('.html') || name.endsWith('.htm') || name.endsWith('.md')) ? 'preview' : 'code';
          if (canvasEditor && activeCanvasTabId === tab.id) {
            canvasEditor.setValue(data.content);
            canvasEditor.setOption('mode', getCanvasLang(name));
          }
        }
        tab.dirty = false;
      }
    } catch {}
    if (!canvasOpen && shouldAutoOpen) toggleCanvas();
    else markCanvasHasHiddenFile();
    canvasOpenTab(tab.id);
    if (!options.skipTreeFocus) await ensureCanvasTreeFocusedForFile(diskPath);
    const tree = document.getElementById('canvas-project-tree');
    if (tree && canvasWorkspaceTree.length) tree.innerHTML = canvasRenderWorkspaceTree(canvasWorkspaceTree, 0);
    return;
  }
  try {
    const response = await fetch(`/api/canvas/file?path=${encodeURIComponent(diskPath)}`);
    const data = await response.json();
    if (!data.success) {
      if (response.status === 403 && /allowed directories/i.test(String(data.error || ''))) {
        try {
          const added = await promptAllowCanvasDirectory(diskPath);
          if (added) {
            await canvasPresentFile(diskPath, label, options);
            return;
          }
        } catch (err) {
          showToast(`Could not add allowed directory`, err.message || 'Unknown error', 'error');
        }
      }
      addProcessEntry('error', `Canvas: could not load ${diskPath} - ${data.error}`);
      return;
    }
    const id = 'ctab_' + Math.random().toString(36).slice(2);
    const ext = name.split('.').pop().toLowerCase();
    if (data.isImage) {
      const dataUrl = `data:${data.mimeType};base64,${data.base64}`;
      canvasTabs.push({
        id, name, content: dataUrl, savedContent: dataUrl,
        diskPath, dirty: false,
        mode: 'preview',
        language: 'null',
        isImage: true,
        mimeType: data.mimeType,
      });
    } else if (data.isBinary) {
      canvasTabs.push({
        id, name, content: '', savedContent: '',
        diskPath, dirty: false,
        mode: 'preview',
        language: 'null',
        isBinary: true,
        mimeType: data.mimeType,
        ext: data.ext || ext,
        size: data.size || 0,
      });
    } else {
      const autoPreview = ext === 'html' || ext === 'htm' || ext === 'md';
      canvasTabs.push({
        id, name, content: data.content, savedContent: data.content,
        diskPath, dirty: false,
        mode: autoPreview ? 'preview' : 'code',
        language: getCanvasLang(name),
      });
    }
    if (!canvasOpen && shouldAutoOpen) toggleCanvas();
    else markCanvasHasHiddenFile();
    canvasOpenTab(id);
    if (!options.skipTreeFocus) await ensureCanvasTreeFocusedForFile(diskPath);
    canvasNotifyOpen(diskPath);
    addProcessEntry('info', `Canvas: opened ${diskPath}`);
    const tree = document.getElementById('canvas-project-tree');
    if (tree && canvasWorkspaceTree.length) tree.innerHTML = canvasRenderWorkspaceTree(canvasWorkspaceTree, 0);
    persistActiveChat();
  } catch (err) {
    addProcessEntry('error', `Canvas: fetch error - ${err.message}`);
  }
}

async function canvasClearProjectRoot() {
  try {
    const saved = await persistCanvasProjectRoot('', '');
    setCanvasProjectState(saved?.projectRoot, saved?.projectLabel);
    canvasWorkspaceTree = [];
    canvasWorkspaceRootPath = '';
    canvasFolderExpanded.clear();
    await canvasLoadWorkspaceFiles();
    const activeTab = canvasTabs.find((tab) => tab.id === activeCanvasTabId) || null;
    applyCanvasViewMode(activeTab?.mode || 'code', activeTab);
    canvasRenderTabs();
    addProcessEntry('info', 'Canvas: returned to the full workspace browser.');
  } catch (err) {
    showToast(`Could not clear project root: ${err.message}`, 'error');
  }
}

function toggleCanvasWorkspaceSidebar() {
  canvasBrowserCollapsed = !canvasBrowserCollapsed;
  updateCanvasWorkspaceChrome();
}

function toggleCanvasFolder(folderPath) {
  const nextPath = normalizeCanvasPath(folderPath);
  if (!nextPath) return;
  if (canvasFolderExpanded.has(nextPath)) canvasFolderExpanded.delete(nextPath);
  else canvasFolderExpanded.add(nextPath);
  const tree = document.getElementById('canvas-project-tree');
  if (tree) tree.innerHTML = canvasRenderWorkspaceTree(canvasWorkspaceTree, 0);
}

async function canvasUseFolderAsProject(folderPath, folderName, ev) {
  if (ev) ev.stopPropagation();
  try {
    const saved = await persistCanvasProjectRoot(folderPath, folderName || getCanvasProjectDisplayName(folderPath));
    setCanvasProjectState(saved?.projectRoot, saved?.projectLabel);
    canvasFolderExpanded.clear();
    await canvasLoadWorkspaceFiles(saved?.projectRoot);
    addProcessEntry('info', `Canvas: project root set to ${saved?.projectLabel || folderName || folderPath}.`);
  } catch (err) {
    showToast(`Could not set project root: ${err.message}`, 'error');
  }
}

// Load workspace file list. Callers can opt into expanding the browser panel.
async function canvasLoadWorkspaceFiles(rootOverride = null, options = {}) {
  const tree = document.getElementById('canvas-project-tree');
  if (!tree) return;
  tree.innerHTML = '<div style="padding:12px;color:var(--muted);font-size:11px">Loading…</div>';
  try {
    const sid = String(window.activeChatSessionId || window.agentSessionId || '').trim();
    const qs = new URLSearchParams();
    if (sid) qs.set('sessionId', sid);
    if (rootOverride) qs.set('root', normalizeCanvasPath(rootOverride));
    const r = await fetch(`/api/canvas/files?${qs.toString()}`);
    const d = await r.json();
    if (!d.success) { tree.innerHTML = `<div style="padding:12px;color:var(--err)">${escHtml(d.error)}</div>`; return; }
    const nextRoot = normalizeCanvasPath(d.rootAbsPath || d.rootPath || '');
    if (canvasWorkspaceRootPath !== nextRoot) canvasFolderExpanded.clear();
    canvasWorkspaceRootPath = nextRoot;
    canvasWorkspaceTree = Array.isArray(d.files) ? d.files : [];
    if (d.projectRoot || canvasProjectRoot) {
      setCanvasProjectState(d.projectRoot || canvasProjectRoot, d.projectLabel || canvasProjectLabel, {
        persist: false,
        expandBrowser: options.expandBrowser !== false,
      });
    } else {
      updateCanvasWorkspaceChrome();
    }
    tree.innerHTML = canvasRenderWorkspaceTree(canvasWorkspaceTree, 0);
    updateCanvasWorkspaceChrome();
  } catch (e) {
    tree.innerHTML = `<div style="padding:12px;color:var(--err)">${escHtml(e.message)}</div>`;
  }
}

function canvasHideFileBrowser() {
  canvasBrowserCollapsed = true;
  updateCanvasWorkspaceChrome();
}

function canvasRenderFileTree(nodes, depth) {
  if (!Array.isArray(nodes) || !nodes.length) return '';
  const icons = { html:'\uD83D\uDCC4', htm:'\uD83D\uDCC4', md:'\uD83D\uDCDD', ts:'\uD83D\uDCBB', js:'\uD83D\uDCBB', json:'{ }', css:'\uD83C\uDFA8', py:'\uD83D\uDC0D', txt:'\uD83D\uDCCB', sh:'\u25BA' };
  let html = '';
  const sorted = [...nodes].sort((a, b) => {
    if (a.type !== b.type) return a.type === 'dir' ? -1 : 1;
    return a.name.localeCompare(b.name);
  });
  for (const node of sorted) {
    const pad = depth * 12;
    if (node.type === 'dir') {
      html += `<div class="canvas-file-tree-dir" style="padding-left:${pad + 12}px">📁 ${escHtml(node.name)}</div>`;
      if (node.children && node.children.length) html += canvasRenderFileTree(node.children, depth + 1);
    } else {
      const ext = node.name.split('.').pop().toLowerCase();
      const icon = icons[ext] || '\uD83D\uDCC4';
      html += `<div class="canvas-file-tree-item" style="padding-left:${pad + 12}px" onclick="canvasPresentFile('${escHtml(node.path).replace(/'/g, '\\&apos;')}', '${escHtml(node.name).replace(/'/g, '\\&apos;')}')">${icon} ${escHtml(node.name)}</div>`;
    }
  }
  return html;
}

function canvasRenderWorkspaceTree(nodes, depth) {
  if (!Array.isArray(nodes) || !nodes.length) return '';
  const icons = { html:'\uD83D\uDCC4', htm:'\uD83D\uDCC4', md:'\uD83D\uDCDD', ts:'\uD83D\uDCBB', js:'\uD83D\uDCBB', json:'{ }', css:'\uD83C\uDFA8', py:'\uD83D\uDC0D', txt:'\uD83D\uDCCB', sh:'\u25BA' };
  const sorted = [...nodes].sort((a, b) => {
    if (a.type !== b.type) return a.type === 'dir' ? -1 : 1;
    return a.name.localeCompare(b.name);
  });
  return sorted.map((node) => {
    const pad = depth * 12;
    if (node.type === 'dir') {
      const folderPath = normalizeCanvasPath(node.path);
      const isOpen = canvasFolderExpanded.has(folderPath);
      const isProjectRoot = !!canvasProjectRoot && normalizeCanvasPath(canvasProjectRoot) === folderPath;
      return `
        <div>
          <div class="canvas-file-tree-dir" style="display:flex;align-items:center;gap:6px;padding:7px 8px;padding-left:${pad + 12}px;border-radius:8px;cursor:pointer;background:${isProjectRoot ? 'rgba(249,115,22,0.14)' : 'transparent'}" onclick="toggleCanvasFolder('${escHtml(folderPath).replace(/'/g, '\\&apos;')}')">
            <span style="color:var(--muted);font-size:10px;width:10px;flex-shrink:0">${isOpen ? '▼' : '▶'}</span>
            <span>📁</span>
            <span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-weight:${isProjectRoot ? '800' : '700'}">${escHtml(node.name)}</span>
            ${isProjectRoot ? `<span style="font-size:10px;color:#fb923c;font-weight:800">ROOT</span>` : `<button onclick="canvasUseFolderAsProject('${escHtml(folderPath).replace(/'/g, '\\&apos;')}', '${escHtml(node.name).replace(/'/g, '\\&apos;')}', event)" style="border:1px solid var(--line);background:var(--panel);color:var(--muted);border-radius:6px;padding:1px 6px;font-size:10px;cursor:pointer">Use</button>`}
          </div>
          ${isOpen && node.children && node.children.length ? `<div style="margin-left:${pad + 18}px;border-left:1px solid rgba(255,255,255,0.08)">${canvasRenderWorkspaceTree(node.children, depth + 1)}</div>` : ''}
        </div>`;
    }
    const ext = node.name.split('.').pop().toLowerCase();
    const icon = icons[ext] || '\uD83D\uDCC4';
    const filePath = normalizeCanvasPath(node.path);
    const isActive = canvasTabs.some((tab) => normalizeCanvasPath(tab.diskPath) === filePath);
    return `<div class="canvas-file-tree-item" style="padding:7px 8px;padding-left:${pad + 12}px;border-radius:8px;cursor:pointer;background:${isActive ? 'rgba(249,115,22,0.14)' : 'transparent'}" onclick="canvasPresentFile('${escHtml(filePath).replace(/'/g, '\\&apos;')}', '${escHtml(node.name).replace(/'/g, '\\&apos;')}')">${icon} ${escHtml(node.name)}</div>`;
  }).join('');
}

const SESSION_APPROVAL_RISK_COLORS = {
  low: { bg: '#eefbf3', border: '#a7e3be', badge: '#dbf4e5', text: '#1f7a47', strongText: '#14532d' },
  medium: { bg: '#eff5ff', border: '#bfd3f4', badge: '#dce9ff', text: '#335d99', strongText: '#1e3a5f' },
  high: { bg: '#fff4ec', border: '#fdc9a8', badge: '#ffe3d0', text: '#b35d14', strongText: '#7c2d12' },
};

function getApprovalRiskLevel(score) {
  if (score >= 7) return 'high';
  if (score >= 4) return 'medium';
  return 'low';
}

function renderSessionApprovalCard(item) {
  const risk = getApprovalRiskLevel(item.riskScore ?? 0);
  const palette = SESSION_APPROVAL_RISK_COLORS[risk] || SESSION_APPROVAL_RISK_COLORS.medium;
  const systems = Array.isArray(item.affectedSystems) ? item.affectedSystems : [];
  const status = String(item.status || 'pending').toLowerCase();
  const isProposal = item.approvalType === 'proposal';
  const approveEndpoint = isProposal ? `/api/proposals/${item.id}/approve` : `/api/approvals/${item.id}/approve`;
  const denyEndpoint = isProposal ? `/api/proposals/${item.id}/deny` : `/api/approvals/${item.id}/deny`;
  return `<div class="approval-card" style="background:${palette.bg};border-color:${palette.border};padding:10px 12px">
    <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px;margin-bottom:6px">
      <div style="font-size:12px;font-weight:700;color:${palette.strongText || palette.text};flex:1;line-height:1.3">${escHtml(item.title || 'Action requires review')}</div>
      <div style="display:flex;gap:4px;flex-shrink:0">
        <span style="font-size:9px;font-weight:800;padding:2px 6px;border-radius:999px;background:${palette.badge};color:${palette.text};text-transform:uppercase;letter-spacing:0.05em">${escHtml(status)}</span>
        <span style="font-size:9px;font-weight:800;padding:2px 6px;border-radius:999px;background:${palette.badge};color:${palette.text};text-transform:uppercase;letter-spacing:0.05em">risk ${item.riskScore ?? '?'}</span>
      </div>
    </div>
    ${item.summary ? `<div style="font-size:11px;color:${palette.text};margin-bottom:6px;line-height:1.4;opacity:0.9">${escHtml(String(item.summary).slice(0, 180))}</div>` : ''}
    ${item.command ? `<pre style="margin:0 0 8px;background:rgba(255,255,255,0.82);border:1px solid ${palette.border};border-radius:8px;padding:8px;font-size:10px;color:${palette.strongText || palette.text};white-space:pre-wrap;word-break:break-word;font-family:'IBM Plex Mono',monospace">${escHtml(String(item.command).slice(0, 300))}</pre>` : ''}
    ${item.scopedTarget ? `<div style="font-size:10px;color:${palette.text};margin:-3px 0 7px;line-height:1.3">Scope: ${escHtml(String(item.scopedTarget).slice(0, 140))}</div>` : ''}
    ${systems.length ? `<div style="display:flex;flex-wrap:wrap;gap:3px;margin-bottom:7px">${systems.map((s) => `<span style="font-size:9px;background:rgba(255,255,255,0.74);color:${palette.strongText || palette.text};border:1px solid ${palette.border};border-radius:4px;padding:1px 5px;font-family:monospace">${escHtml(s)}</span>`).join('')}</div>` : ''}
    ${isProposal
      ? `<div style="display:flex;gap:6px">
          <button onclick="resolveSessionApproval('${item.id}','approve','${approveEndpoint}')" style="flex:1;border:none;background:#16a34a;color:#fff;border-radius:6px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer">Approve</button>
          <button onclick="resolveSessionApproval('${item.id}','deny','${denyEndpoint}')" style="flex:1;border:1px solid ${palette.border};background:transparent;color:${palette.text};border-radius:6px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer">Deny</button>
        </div>`
      : `<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
          <button onclick="resolveSessionApproval('${item.id}','approve','${approveEndpoint}')" style="border:none;background:#16a34a;color:#fff;border-radius:6px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer">Approve Once</button>
          <button onclick="resolveSessionApproval('${item.id}','approve_session','${approveEndpoint}','session')" style="border:none;background:#0f766e;color:#fff;border-radius:6px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer">This Session</button>
          <button onclick="resolveSessionApproval('${item.id}','approve_always','${approveEndpoint}','always')" style="border:none;background:#2563eb;color:#fff;border-radius:6px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer">Always Allow</button>
          <button onclick="resolveSessionApproval('${item.id}','deny','${denyEndpoint}')" style="border:1px solid ${palette.border};background:transparent;color:${palette.text};border-radius:6px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer">Deny</button>
        </div>`}
  </div>`;
}

async function loadSessionApprovals() {
  const list = document.getElementById('session-approvals-list');
  const badge = document.getElementById('session-approvals-badge');
  if (!list || !badge) return;
  const currentSessionId = String(window.activeChatSessionId || '').trim();
  try {
    const [approvalData, proposalData] = await Promise.all([
      api('/api/approvals?status=pending').catch(() => ({ approvals: [] })),
      api(`/api/proposals?status=pending&sessionId=${encodeURIComponent(currentSessionId)}`).catch(() => ({ proposals: [] })),
    ]);
    const approvalItems = (approvalData.approvals || [])
      .filter((a) => String(a.sourceSessionId || a.sessionId || '').trim() === currentSessionId)
      .map((a) => ({
        id: a.id,
        title: a.toolName === 'run_command' ? 'Command approval' : 'Tool approval',
        summary: a.reason || a.summary || '',
        riskScore: a.riskScore ?? 0,
        affectedSystems: a.affectedSystems || [],
        command: a.command || a.scopedAction || '',
        scopedTarget: a.scopedTarget || '',
        status: a.status || 'pending',
        approvalType: 'command',
      }));
    const proposalItems = (proposalData.proposals || [])
      .filter((p) => String(p.sourceSessionId || p.sessionId || '').trim() === currentSessionId)
      .map((p) => ({
      id: p.id,
      title: p.title,
      summary: p.summary,
      riskScore: p.priority === 'critical' ? 10 : p.priority === 'high' ? 7 : p.priority === 'medium' ? 4 : 2,
      affectedSystems: (p.affectedFiles || []).map((f) => f.path?.split(/[\\/]/).pop() || f.path || '').filter(Boolean),
      status: p.status || 'pending',
      approvalType: 'proposal',
    }));
    const all = [...approvalItems, ...proposalItems];
    if (!all.length) {
      list.innerHTML = '<div style="font-size:11px;color:var(--muted);text-align:center;padding:12px 0;opacity:0.6">No pending actions</div>';
      badge.style.display = 'none';
      return;
    }
    list.innerHTML = all.map(renderSessionApprovalCard).join('');
    badge.style.display = 'inline-block';
    badge.textContent = String(all.length);
  } catch (err) {
    list.innerHTML = `<div style="font-size:11px;color:var(--err);padding:8px 0">${escHtml(err.message || 'Load failed')}</div>`;
  }
}

async function resolveSessionApproval(id, action, endpoint, grantScope = '') {
  try {
    const method = 'POST';
    const body = JSON.stringify(grantScope ? { grantScope } : {});
    await api(endpoint, { method, body });
    await loadSessionApprovals();
    if (window.currentMode === 'proposals' && typeof window.loadProposals === 'function') window.loadProposals();
    if (window.currentMode === 'approvals' && typeof window.loadApprovals === 'function') window.loadApprovals();
    if (typeof window.checkPendingProposalsBadge === 'function') window.checkPendingProposalsBadge();
    const label = action === 'deny' ? 'Denied' : grantScope === 'always' ? 'Always allowed' : grantScope === 'session' ? 'Allowed this session' : 'Approved';
    addProcessEntry('info', `${label}: ${id}`);
  } catch (err) {
    showToast('Error', err.message || 'Could not resolve action', 'error');
  }
}

if (typeof window.loadSessionApprovals !== 'function') window.loadSessionApprovals = loadSessionApprovals;
if (typeof window.resolveSessionApproval !== 'function') window.resolveSessionApproval = resolveSessionApproval;

// ---- Context Pinning ----
const MAX_PINS = 3;
let contextPinMode = false;
let pinnedMessageIndices = new Set();
let confirmedPins = []; // Array of { role, content } sent with each request

function toggleContextPinMode() {
  const pop = document.getElementById('context-pin-popover');
  if (!pop) return;
  const isOpen = pop.classList.contains('open');
  // Close other popovers
  document.getElementById('quick-mode-popover')?.classList.remove('open');
  if (isOpen) {
    cancelContextPin();
  } else {
    contextPinMode = true;
    pop.classList.add('open');
    document.body.classList.add('context-pin-active');
    // Reset selection to currently confirmed pins
    pinnedMessageIndices = new Set();
    for (const pin of confirmedPins) {
      const idx = window.chatHistory.findIndex(m => m.content === pin.content && m.role === pin.role);
      if (idx >= 0) pinnedMessageIndices.add(idx);
    }
    updatePinUI();
    renderChatMessages();
  }
}

function cancelContextPin() {
  contextPinMode = false;
  pinnedMessageIndices = new Set();
  document.getElementById('context-pin-popover')?.classList.remove('open');
  document.body.classList.remove('context-pin-active');
  renderChatMessages();
}

function confirmContextPin() {
  confirmedPins = [];
  for (const idx of pinnedMessageIndices) {
    const msg = window.chatHistory[idx];
    if (msg) confirmedPins.push({ role: msg.role === 'user' ? 'user' : 'assistant', content: msg.content });
  }
  contextPinMode = false;
  document.getElementById('context-pin-popover')?.classList.remove('open');
  document.body.classList.remove('context-pin-active');
  updatePinBadge();
  renderChatMessages();
  if (confirmedPins.length > 0) {
    addProcessEntry('info', `${confirmedPins.length} message(s) pinned to context.`);
  } else {
    addProcessEntry('info', 'Context pins cleared.');
  }
}

function togglePinMessage(index) {
  if (!contextPinMode) return;
  if (pinnedMessageIndices.has(index)) {
    pinnedMessageIndices.delete(index);
  } else if (pinnedMessageIndices.size < MAX_PINS) {
    pinnedMessageIndices.add(index);
  }
  updatePinUI();
  renderChatMessages();
}

function removePinFromList(index) {
  pinnedMessageIndices.delete(index);
  updatePinUI();
  renderChatMessages();
}

function updatePinUI() {
  const countEl = document.getElementById('context-pin-count');
  const listEl = document.getElementById('context-pin-list');
  if (countEl) countEl.textContent = `${pinnedMessageIndices.size}/${MAX_PINS} selected`;
  if (listEl) {
    if (pinnedMessageIndices.size === 0) {
      listEl.innerHTML = '<div style="font-size:11px;color:var(--muted);text-align:center;padding:8px">Click messages in chat to select them</div>';
    } else {
      listEl.innerHTML = Array.from(pinnedMessageIndices).map(idx => {
        const msg = window.chatHistory[idx];
        if (!msg) return '';
        const icon = msg.role === 'user' ? '👤' : '<img src="/assets/Prometheus.png" style="width:20px;height:20px;object-fit:contain;">';
        const text = msg.content.slice(0, 60) + (msg.content.length > 60 ? '...' : '');
        return `<div class="pin-card">
          <span>${icon}</span>
          <div class="pin-card-text">${escHtml(text)}</div>
          <button class="pin-card-remove" onclick="removePinFromList(${idx})">&times;</button>
        </div>`;
      }).join('');
    }
  }
}

function updatePinBadge() {
  const label = document.getElementById('context-pin-label');
  if (label) {
    label.textContent = confirmedPins.length > 0 ? `Context (${confirmedPins.length})` : 'Context';
  }
  const btn = document.getElementById('context-pin-btn');
  if (btn) {
    btn.style.borderColor = confirmedPins.length > 0 ? '#86d4a8' : '';
    btn.style.background = confirmedPins.length > 0 ? '#f0faf4' : '';
    btn.style.color = confirmedPins.length > 0 ? '#0a6b3d' : '';
  }
}


