wsEventBus.on('boot_greeting', (msg) => {
  if (msg?.automatedSession && typeof window.upsertAutomatedSession === 'function') {
    window.upsertAutomatedSession(msg.automatedSession, { markUnread: true });
    showToast('Startup update available in a new chat');
    return;
  }
  // Backward-compatible fallback for older payloads without automatedSession.
  if (msg?.sessionId && msg?.text && typeof window.upsertAutomatedSession === 'function') {
    window.upsertAutomatedSession({
      id: msg.sessionId,
      title: msg.title || '🌅 Startup',
      history: [{ role: 'assistant', content: msg.text }],
      createdAt: Date.now(),
      automated: true,
    }, { markUnread: true });
    showToast('Startup update available in a new chat');
    return;
  }

  const bootSess = (window.chatSessions || []).find(s => s.id === window.activeChatSessionId);
  if (bootSess && (!bootSess.history || bootSess.history.length === 0)) {
    bootSess.history = [{ role: 'assistant', content: msg.text }];
    bootSess.updatedAt = Date.now();
    saveChatSessions();
    syncActiveChat();
    renderChatMessages();
  }
});

wsEventBus.on('main_chat_goal_updated', async (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (!sid) return;
  let sess = window.chatSessions.find(s => s.id === sid);
  if (!sess) {
    sess = createEmptyChatSession(sid);
    window.chatSessions.unshift(sess);
  }
  sess.mainChatGoal = msg.goal || null;
  sess.updatedAt = Date.now();
  if (sid === window.activeChatSessionId) {
    renderMainGoalStrip();
    if (['judged', 'summarized', 'runner_idle', 'runtime_failure'].includes(String(msg?.event || ''))) {
      sess._needsServerLoad = true;
      await _loadSessionFromServer(sid);
      syncActiveChat();
    }
  } else {
    sess.unread = true;
  }
  saveChatSessions();
});

wsEventBus.on('session_notification', (msg) => {
  if (!msg) return;
  const appendToPreviousSession = () => {
    const prevId = String(msg.previousSessionId || '').trim();
    const text = String(msg.text || '');
    if (!prevId || !text) return;
    const prev = (window.chatSessions || []).find((s) => s.id === prevId);
    if (!prev) return;
    prev.history = Array.isArray(prev.history) ? prev.history : [];
    const last = prev.history.length > 0 ? prev.history[prev.history.length - 1] : null;
    if (!last || String(last.role || '') !== 'assistant' || String(last.content || '') !== text) {
      prev.history.push({ role: 'assistant', content: text });
    }
    prev.updatedAt = Date.now();
    saveChatSessions();
    if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
    if (window.activeChatSessionId === prevId) renderChatMessages();
  };
  const ack = () => {
    if (msg.notificationId) {
      wsSend({ type: 'startup_notification_ack', notificationId: String(msg.notificationId) });
    }
  };
  if (msg.automatedSession && typeof window.upsertAutomatedSession === 'function') {
    window.upsertAutomatedSession(msg.automatedSession, { markUnread: true });
    appendToPreviousSession();
    const title = msg.automatedSession.title || msg.title || 'Automated session';
    bgtToast('💬 New automated session', String(title).slice(0, 100));
    ack();
    return;
  }

  // Backward-compatible fallback for additive session_notification payload.
  if (msg.sessionId && msg.text && typeof window.upsertAutomatedSession === 'function') {
    window.upsertAutomatedSession({
      id: msg.sessionId,
      title: msg.title || 'Automated session',
      history: [{ role: 'assistant', content: msg.text }],
      createdAt: Date.now(),
      automated: true,
      source: String(msg.source || ''),
    }, { markUnread: true });
    appendToPreviousSession();
    ack();
  }
});

function appendTelegramMessageToSession(sessionId, message) {
  const sid = String(sessionId || '').trim();
  if (!sid || !message || !message.role) return;
  const idx = (window.chatSessions || []).findIndex((s) => s.id === sid);
  if (idx < 0) return;
  const sess = window.chatSessions[idx];
  sess.history = Array.isArray(sess.history) ? sess.history : [];
  const next = {
    role: message.role === 'ai' ? 'assistant' : (message.role === 'assistant' ? 'assistant' : 'user'),
    content: String(message.content || ''),
    timestamp: Number(message.timestamp) || Date.now(),
    channel: 'telegram',
    channelLabel: 'telegram',
  };
  if (isSessionTitleCommandMessage(next)) return;
  const last = sess.history.length > 0 ? sess.history[sess.history.length - 1] : null;
  if (
    last
    && String(last.role || '') === String(next.role || '')
    && String(last.content || '') === String(next.content || '')
    && String(last.channel || '').toLowerCase() === 'telegram'
  ) {
    return;
  }
  sess.history.push(next);
  sess.updatedAt = Date.now();
  sess.title = makeSessionTitle(sess.history);
  if (sid !== window.activeChatSessionId) sess.unread = true;
}

function appendTimerMessageToSession(sessionId, message) {
  const sid = String(sessionId || '').trim();
  if (!sid || !message || !message.role) return;
  let sess = (window.chatSessions || []).find((s) => s.id === sid);
  if (!sess) {
    sess = {
      id: sid,
      title: 'Timer chat',
      history: [],
      processLog: [],
      createdAt: Date.now(),
      updatedAt: Date.now(),
      unread: sid !== window.activeChatSessionId,
    };
    window.chatSessions.push(sess);
  }
  sess.history = Array.isArray(sess.history) ? sess.history : [];
  const next = {
    role: message.role === 'ai' ? 'assistant' : (message.role === 'assistant' ? 'assistant' : 'user'),
    content: String(message.content || ''),
    timestamp: Number(message.timestamp) || Date.now(),
    channel: 'system',
    channelLabel: 'timer',
  };
  const last = sess.history.length > 0 ? sess.history[sess.history.length - 1] : null;
  if (
    last
    && String(last.role || '') === String(next.role || '')
    && String(last.content || '') === String(next.content || '')
    && String(last.channelLabel || '').toLowerCase() === 'timer'
  ) {
    return;
  }
  sess.history.push(next);
  sess.updatedAt = Date.now();
  sess.title = makeSessionTitle(sess.history);
  if (sid !== window.activeChatSessionId) sess.unread = true;
  saveChatSessions();
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
  if (sid === window.activeChatSessionId) {
    syncActiveChat();
    renderChatMessages();
  }
}

function appendTimerProcessEntry(sessionId, type, content) {
  const sid = String(sessionId || '').trim();
  const text = String(content || '').trim();
  if (!sid || !text) return;
  const sess = (window.chatSessions || []).find((s) => s.id === sid);
  if (!sess) return;
  sess.processLog = Array.isArray(sess.processLog) ? sess.processLog : [];
  sess.processLog.push({
    type,
    content: text,
    timestamp: Date.now(),
    actor: 'Timer',
  });
  sess.updatedAt = Date.now();
  saveChatSessions();
  if (sid === window.activeChatSessionId) {
    syncActiveChat();
    renderProcessLog();
  }
}

wsEventBus.on('timer_created', (msg) => {
  const timer = msg?.timer || {};
  const sid = String(msg?.sessionId || timer.sessionId || '').trim();
  const due = timer.dueAt ? new Date(timer.dueAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : 'later';
  appendTimerProcessEntry(sid, 'info', `Timer set: ${String(timer.label || timer.id || 'timer')} at ${due}.`);
});

wsEventBus.on('timer_waiting', (msg) => {
  const timer = msg?.timer || {};
  const sid = String(msg?.sessionId || timer.sessionId || '').trim();
  appendTimerProcessEntry(sid, 'info', `Timer due and waiting for the current turn: ${String(timer.label || timer.id || 'timer')}.`);
});

wsEventBus.on('timer_cancelled', (msg) => {
  const timer = msg?.timer || {};
  const sid = String(msg?.sessionId || timer.sessionId || '').trim();
  appendTimerProcessEntry(sid, 'info', `Timer cancelled: ${String(timer.label || timer.id || 'timer')}.`);
});

wsEventBus.on('timer_fired', (msg) => {
  const sid = String(msg?.sessionId || msg?.timer?.sessionId || '').trim();
  appendTimerProcessEntry(sid, 'info', `Timer fired: ${String(msg?.timer?.label || msg?.timerId || 'timer')}.`);
});

wsEventBus.on('timer_sse', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  const eventType = String(msg?.eventType || '').trim();
  if (eventType === 'tool_call') {
    appendTimerProcessEntry(sid, 'tool', `Timer: ${formatToolCallForLog(String(msg.action || msg.name || 'tool'), msg.args || {}, null)}`);
  } else if (eventType === 'tool_result') {
    appendTimerProcessEntry(sid, 'info', `Timer result: ${String(msg.result || '').slice(0, 160)}`);
  } else if (eventType === 'info' && msg.message) {
    appendTimerProcessEntry(sid, 'info', String(msg.message).slice(0, 220));
  }
});

wsEventBus.on('timer_done', (msg) => {
  const sid = String(msg?.sessionId || msg?.timer?.sessionId || '').trim();
  appendTimerMessageToSession(sid, msg?.message);
  appendTimerProcessEntry(sid, 'info', `Timer complete: ${String(msg?.timer?.label || msg?.timerId || 'timer')}.`);
});

wsEventBus.on('timer_failed', (msg) => {
  const sid = String(msg?.sessionId || msg?.timer?.sessionId || '').trim();
  appendTimerMessageToSession(sid, msg?.message);
  appendTimerProcessEntry(sid, 'warn', `Timer failed: ${String(msg?.error || '').slice(0, 220)}`);
});

wsEventBus.on('telegram_message', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (!sid) return;
  const sessionExists = (window.chatSessions || []).some((s) => s.id === sid);
  if (!sessionExists) {
    window.chatSessions.push({
      id: sid,
      title: 'Telegram chat',
      history: [],
      processLog: [],
      createdAt: Date.now(),
      updatedAt: Date.now(),
      automated: true,
      source: 'telegram_manual',
      unread: sid !== window.activeChatSessionId,
    });
  }
  appendTelegramMessageToSession(sid, msg.message);
  appendTelegramMessageToSession(sid, msg.responseMessage);
  saveChatSessions();
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
  if (sid === window.activeChatSessionId) {
    syncActiveChat();
    renderChatMessages();
  }
});

wsEventBus.on('task_notification', (msg) => {
  if (!msg.sessionId) return;
  const notifMessage = msg.message || '';
  const notifSessionId = msg.sessionId;

  const sess = (window.chatSessions || []).find(s => s.id === notifSessionId);
  if (sess) {
    sess.history = sess.history || [];
    sess.history.push({ role: 'assistant', content: notifMessage });
    sess.updatedAt = Date.now();
    sess.unread = notifSessionId !== window.activeChatSessionId;
    saveChatSessions();
    if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
    if (notifSessionId === window.activeChatSessionId) renderChatMessages();
    return;
  }

  if (notifSessionId === window.agentSessionId || notifSessionId === window.activeChatSessionId) {
    const activeSess = (window.chatSessions || []).find(s => s.id === window.activeChatSessionId);
    if (activeSess) {
      activeSess.history = activeSess.history || [];
      activeSess.history.push({ role: 'assistant', content: notifMessage });
      activeSess.updatedAt = Date.now();
      saveChatSessions();
      renderChatMessages();
      return;
    }
  }

  const taskTitle = msg.taskTitle || `Task — ${new Date().toLocaleTimeString()}`;
  const newSess = {
    id: notifSessionId, title: taskTitle,
    history: [{ role: 'assistant', content: notifMessage }],
    processLog: [], createdAt: Date.now(), updatedAt: Date.now(),
    automated: true, unread: true,
  };
  if (window.chatSessions) window.chatSessions.push(newSess);
  saveChatSessions();
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
  bgtToast('💬 Task message', notifMessage.slice(0, 80));
});

wsEventBus.on('creative_mode_changed', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (!sid) return;
  applySessionCreativeMode(sid, msg.creativeMode);
});

wsEventBus.on('creative_command', (msg) => {
  handleCreativeCommandMessage(msg).catch((err) => {
    sendCreativeCommandResult(msg, {
      success: false,
      error: String(err?.message || err || 'Creative command failed.'),
    });
  });
});

wsEventBus.on('creative_extract_layers_progress', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (sid && sid !== String(window.activeChatSessionId || '').trim() && sid !== String(window.agentSessionId || '').trim()) return;
  canvasApplyExtractProgressEvent(msg);
});

wsEventBus.on('browser:open', (msg) => {
  applyBrowserEventState(msg, { autoOpen: true });
});

wsEventBus.on('browser:status', (msg) => {
  applyBrowserEventState(msg, { autoOpen: !!msg.active });
  if (msg?.source === 'user' && msg?.clickHighlight?.bounds && isBrowserEventForActiveSession(msg, { scope: 'visible' })) {
    triggerBrowserTransientHighlight(msg.clickHighlight);
  }
  if (msg?.source === 'user' && isBrowserEventForActiveSession(msg, { scope: 'visible' }) && normalizeBrowserInteractionMode(getBrowserCanvasState().interactionMode) === 'teach') {
    finalizeBrowserTeachExecution(msg);
  }
  if (msg?.source === 'user' && msg?.userAction?.summary && isBrowserEventForActiveSession(msg, { scope: 'visible' })) {
    addProcessEntry('info', `Browser: ${String(msg.userAction.summary || '').trim()}`);
  }
});

wsEventBus.on('browser:agent_registered', (msg) => {
  upsertBrowserSessionRecord(msg);
  renderBrowserCanvasSurface();
  persistActiveChat();
});

wsEventBus.on('browser:frame', (msg) => {
  upsertBrowserSessionRecord({
    ...msg,
    active: true,
    streamActive: true,
    streamTransport: msg?.transport,
    streamFocus: msg?.focus,
  });
  if (!isBrowserEventForActiveSession(msg, { scope: 'visible' })) {
    renderBrowserCanvasSurface();
    persistActiveChat();
    return;
  }
  const state = getBrowserCanvasState();
  const allowInteractionSync = !isFollowingDetachedBrowserCanvasSession(state) || String(msg?.sessionId || '').trim() === getBrowserCanvasPrimarySessionId();
  state.sessionId = String(msg?.sessionId || state.sessionId || '').trim();
  if (typeof msg?.active === 'boolean') state.active = msg.active === true;
  if (msg?.url) state.url = String(msg.url || '').trim() || state.url;
  if (msg?.title) state.title = String(msg.title || '').trim() || state.title;
  rememberBrowserCanvasRestorablePage(state.url, state.title, state);
  if (allowInteractionSync && msg?.mode) state.interactionMode = normalizeBrowserInteractionMode(msg.mode);
  if (allowInteractionSync && typeof msg?.captured === 'boolean') state.controlCaptured = msg.captured === true;
  if (allowInteractionSync && msg?.controlOwner) state.controlOwner = String(msg.controlOwner || '').trim().toLowerCase() === 'user' ? 'user' : 'agent';
  if (typeof msg?.frameBase64 === 'string' && msg.frameBase64.trim()) state.frameBase64 = msg.frameBase64;
  if (Number.isFinite(Number(msg?.frameWidth))) state.frameWidth = Number(msg.frameWidth);
  if (Number.isFinite(Number(msg?.frameHeight))) state.frameHeight = Number(msg.frameHeight);
  state.frameFormat = String(msg?.frameFormat || state.frameFormat || 'png').trim().toLowerCase() === 'jpeg' ? 'jpeg' : 'png';
  state.streamActive = true;
  state.streamTransport = String(msg?.transport || state.streamTransport || 'snapshot').trim().toLowerCase();
  state.streamFocus = String(msg?.focus || state.streamFocus || 'passive').trim().toLowerCase() === 'interactive' ? 'interactive' : 'passive';
  state.streamStatus = `${String(state.streamTransport || 'stream').toUpperCase()} feed active`;
  state.streamLastFrameAt = Number(msg?.timestamp || Date.now()) || Date.now();
  renderBrowserCanvasSurface();
});

wsEventBus.on('browser:agent_cursor', (msg) => {
  receiveBrowserAgentCursor(msg);
});

wsEventBus.on('browser:mode', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'primary' })) return;
  const state = getBrowserCanvasState();
  if (msg?.mode) state.interactionMode = normalizeBrowserInteractionMode(msg.mode);
  if (typeof msg?.captured === 'boolean') state.controlCaptured = msg.captured === true;
  if (msg?.controlOwner) state.controlOwner = String(msg.controlOwner || '').trim().toLowerCase() === 'user' ? 'user' : 'agent';
  state.updatedAt = Number(msg?.timestamp || Date.now()) || Date.now();
  renderBrowserCanvasSurface();
  persistActiveChat();
});

wsEventBus.on('browser:stream_status', (msg) => {
  upsertBrowserSessionRecord({
    ...msg,
    active: msg?.active === true || undefined,
    streamActive: msg?.active === true,
  });
  if (!isBrowserEventForActiveSession(msg, { scope: 'visible' })) return;
  const state = getBrowserCanvasState();
  const allowInteractionSync = !isFollowingDetachedBrowserCanvasSession(state) || String(msg?.sessionId || '').trim() === getBrowserCanvasPrimarySessionId();
  state.sessionId = String(msg?.sessionId || state.sessionId || '').trim();
  if (allowInteractionSync && msg?.mode) state.interactionMode = normalizeBrowserInteractionMode(msg.mode);
  if (allowInteractionSync && typeof msg?.captured === 'boolean') state.controlCaptured = msg.captured === true;
  if (allowInteractionSync && msg?.controlOwner) state.controlOwner = String(msg.controlOwner || '').trim().toLowerCase() === 'user' ? 'user' : 'agent';
  state.streamActive = msg?.active === true;
  state.streamTransport = String(msg?.transport || '').trim().toLowerCase();
  state.streamFocus = String(msg?.focus || state.streamFocus || 'passive').trim().toLowerCase() === 'interactive' ? 'interactive' : 'passive';
  state.streamStatus = String(msg?.status || '').trim();
  if (!state.streamActive) {
    clearBrowserCanvasStreamHeartbeat();
  }
  renderBrowserCanvasSurface();
});

wsEventBus.on('browser:control', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'primary' })) return;
  const state = getBrowserCanvasState();
  if (msg?.mode) state.interactionMode = normalizeBrowserInteractionMode(msg.mode);
  if (typeof msg?.captured === 'boolean') state.controlCaptured = msg.captured === true;
  if (msg?.controlOwner) state.controlOwner = String(msg.controlOwner || '').trim().toLowerCase() === 'user' ? 'user' : 'agent';
  if (msg?.statusLabel) state.statusLabel = String(msg.statusLabel || '').trim();
  state.updatedAt = Number(msg?.timestamp || Date.now()) || Date.now();
  renderBrowserCanvasSurface();
  persistActiveChat();
  if (msg?.waitingTool) {
    addProcessEntry('info', `Browser control: ${String(msg.statusLabel || `Prometheus is waiting before ${msg.waitingTool}.`).trim()}`);
  }
});

wsEventBus.on('browser:selection', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'visible' })) return;
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  state.selectionPending = false;
  if (msg?.selection && typeof msg.selection === 'object') {
    state.selectedElement = {
      selector: String(msg.selection.selector || '').trim(),
      tagName: String(msg.selection.tagName || '').trim(),
      id: String(msg.selection.id || '').trim(),
      text: String(msg.selection.text || '').trim(),
      bounds: msg.selection.bounds || null,
    };
    state.elementNameDraftKey = '';
    if (isBrowserTeachRecording(state) && teach.pendingSelectionIntent?.action === 'click') {
      const staged = createBrowserTeachClickStep(state.selectedElement, teach.pendingSelectionIntent, state);
      teach.pendingSelectionIntent = null;
      teach.pendingStep = refreshBrowserTeachStepMetadata(staged, state);
      state.statusLabel = 'Teach step staged. Rename or save it if you want, then continue.';
      addProcessEntry('info', `Teach: staged ${teach.pendingStep.summary || 'browser click step'}.`);
    } else {
      teach.pendingSelectionIntent = null;
      addProcessEntry('info', `Browser: selected ${state.selectedElement.selector || state.selectedElement.tagName || 'element'} in teach mode.`);
    }
  } else {
    state.selectedElement = null;
    state.elementNameDraft = '';
    state.elementNameDraftKey = '';
    teach.pendingSelectionIntent = null;
    addProcessEntry('warn', 'Browser: no selectable element found at that point.');
  }
  state.updatedAt = Number(msg.timestamp || Date.now()) || Date.now();
  renderBrowserCanvasSurface();
  persistActiveChat();
});

wsEventBus.on('browser:knowledge', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'visible' })) return;
  const state = getBrowserCanvasState();
  const allowInteractionSync = !isFollowingDetachedBrowserCanvasSession(state) || String(msg?.sessionId || '').trim() === getBrowserCanvasPrimarySessionId();
  const currentHost = getBrowserKnowledgeHost(state.url);
  const incomingHost = String(msg?.site || getBrowserKnowledgeHost(msg?.url)).trim().toLowerCase();
  if (currentHost && incomingHost && currentHost !== incomingHost) return;
  state.sessionId = String(msg?.sessionId || state.sessionId || '').trim();
  if (typeof msg?.active === 'boolean') state.active = msg.active === true;
  if (allowInteractionSync && msg?.mode) state.interactionMode = normalizeBrowserInteractionMode(msg.mode);
  if (allowInteractionSync && typeof msg?.captured === 'boolean') state.controlCaptured = msg.captured === true;
  if (allowInteractionSync && msg?.controlOwner) state.controlOwner = String(msg.controlOwner || '').trim().toLowerCase() === 'user' ? 'user' : 'agent';
  if (typeof msg?.streamActive === 'boolean') state.streamActive = msg.streamActive === true;
  if (typeof msg?.streamTransport === 'string') state.streamTransport = String(msg.streamTransport || '').trim().toLowerCase();
  if (typeof msg?.streamFocus === 'string') state.streamFocus = String(msg.streamFocus || 'passive').trim().toLowerCase() === 'interactive' ? 'interactive' : 'passive';
  if (state.interactionMode !== 'copilot' && state.interactionMode !== 'teach' && state.controlCaptured) {
    state.controlCaptured = false;
    state.controlOwner = 'agent';
    clearQueuedBrowserControlInputs();
  }
  if (msg?.url) state.url = String(msg.url || '').trim() || state.url;
  if (msg?.title) state.title = String(msg.title || '').trim() || state.title;
  rememberBrowserCanvasRestorablePage(state.url, state.title, state);
  if (typeof msg?.frameBase64 === 'string' && msg.frameBase64.trim()) {
    state.frameBase64 = msg.frameBase64;
    if (Number.isFinite(Number(msg?.frameWidth))) state.frameWidth = Number(msg.frameWidth);
    if (Number.isFinite(Number(msg?.frameHeight))) state.frameHeight = Number(msg.frameHeight);
    state.frameFormat = String(msg?.frameFormat || 'png').trim().toLowerCase() === 'jpeg' ? 'jpeg' : 'png';
  }
  const elements = Array.isArray(msg?.elements)
    ? msg.elements.map((entry) => ({
        name: String(entry?.name || '').trim(),
        selector: String(entry?.selector || '').trim(),
        tagName: String(entry?.tagName || '').trim(),
        id: String(entry?.id || '').trim(),
        text: String(entry?.text || '').trim(),
        url: String(entry?.url || '').trim(),
        savedAt: Number(entry?.savedAt || entry?.updatedAt || 0) || 0,
      })).filter((entry) => entry.name)
    : (Array.isArray(state.namedElements) ? state.namedElements : []);
  const itemRoots = Array.isArray(msg?.itemRoots)
    ? msg.itemRoots.map((entry) => ({
        name: String(entry?.name || '').trim(),
        selector: String(entry?.selector || '').trim(),
        tagName: String(entry?.tagName || '').trim(),
        id: String(entry?.id || '').trim(),
        text: String(entry?.text || '').trim(),
        url: String(entry?.url || '').trim(),
        savedAt: Number(entry?.savedAt || entry?.updatedAt || 0) || 0,
      })).filter((entry) => entry.name)
    : (Array.isArray(state.itemRoots) ? state.itemRoots : []);
  const extractionSchemas = Array.isArray(msg?.extractionSchemas)
    ? msg.extractionSchemas.map((entry) => ({
        name: String(entry?.name || '').trim(),
        itemRoot: String(entry?.itemRoot || '').trim(),
        containerSelector: String(entry?.containerSelector || '').trim(),
        dedupeKey: String(entry?.dedupeKey || '').trim(),
        limit: Number(entry?.limit || 0) || 0,
        fields: entry?.fields && typeof entry.fields === 'object' ? { ...entry.fields } : {},
        savedAt: Number(entry?.savedAt || entry?.updatedAt || 0) || 0,
      })).filter((entry) => entry.name)
    : (Array.isArray(state.extractionSchemas) ? state.extractionSchemas : []);
  state.namedElements = elements;
  state.itemRoots = itemRoots;
  state.extractionSchemas = extractionSchemas;
  state.knowledgeSite = incomingHost || currentHost;
  state.knowledgeRequestedFor = incomingHost || currentHost;
  if (msg?.saved?.name) {
    const savedKindRaw = String(msg?.savedKind || 'element').trim().toLowerCase();
    const savedKind = savedKindRaw === 'item_root' ? 'item root' : (savedKindRaw === 'schema' ? 'schema' : 'element');
    state.statusLabel = `Saved "${String(msg.saved.name || '').trim()}" as a browser ${savedKind}`;
  }
  state.updatedAt = Number(msg.timestamp || Date.now()) || Date.now();
  renderBrowserCanvasSurface();
  persistActiveChat();
  if (msg?.saved?.name) {
    const savedName = String(msg.saved.name || '').trim();
    const savedKindRaw = String(msg?.savedKind || 'element').trim().toLowerCase();
    const savedKind = savedKindRaw === 'item_root' ? 'item root' : (savedKindRaw === 'schema' ? 'schema' : 'element');
    addProcessEntry('info', `Browser memory: saved ${savedKind} "${savedName}" for ${incomingHost || 'this site'}.`);
    showToast(`Saved browser ${savedKind}: ${savedName}`);
  }
});

wsEventBus.on('browser:knowledge:error', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'visible' })) return;
  const state = getBrowserCanvasState();
  state.updatedAt = Number(msg.timestamp || Date.now()) || Date.now();
  renderBrowserCanvasSurface();
  showToast(String(msg?.error || 'Browser memory action failed.'), 'error');
});

wsEventBus.on('browser:input:error', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'visible' })) return;
  const state = getBrowserCanvasState();
  if (normalizeBrowserInteractionMode(state.interactionMode) === 'teach') {
    markBrowserTeachExecutionError(String(msg?.error || 'Teach step failed.'));
  }
  state.updatedAt = Number(msg.timestamp || Date.now()) || Date.now();
  state.statusLabel = String(msg?.error || 'Browser input failed.');
  renderBrowserCanvasSurface();
  showToast(String(msg?.error || 'Browser input failed.'), 'error');
});

wsEventBus.on('browser:teach:verification_started', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'primary' })) return;
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  if (!teach.active) return;
  teach.phase = 'verifying';
  teach.verification = null;
  state.active = true;
  state.url = String(msg?.url || state.url || '').trim();
  state.title = String(msg?.title || state.title || '').trim();
  state.statusLabel = String(msg?.statusLabel || 'Watching the detached Teach verifier tab.').trim();
  followBrowserCanvasSession(String(msg?.verifierSessionId || '').trim(), {
    statusLabel: state.statusLabel,
    render: false,
    requestData: false,
  });
  setBrowserCanvasSurface('browser');
  renderBrowserCanvasSurface();
  persistActiveChat();
  requestBrowserKnowledge(true);
  syncBrowserCanvasStream({ force: true });
  addProcessEntry('info', 'Teach: switched the browser canvas to the detached verifier tab.');
});

wsEventBus.on('browser:teach:verification', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'primary' })) return;
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  if (!teach.active) return;
  teach.phase = normalizeBrowserTeachPhase(msg?.phase || 'verified');
  teach.verification = msg?.verification && typeof msg.verification === 'object'
    ? {
        status: String(msg.verification.status || '').trim(),
        mode: String(msg.verification.mode || '').trim(),
        boundaryLabel: String(msg.verification.boundaryLabel || '').trim(),
        stopBeforeStep: Number(msg.verification.stopBeforeStep || 0) || 0,
        verifierSessionId: String(msg.verification.verifierSessionId || '').trim(),
        executedCount: Number(msg.verification.executedCount || 0) || 0,
        totalRecordedSteps: Number(msg.verification.totalRecordedSteps || 0) || 0,
        riskyStepIndexes: Array.isArray(msg.verification.riskyStepIndexes)
          ? msg.verification.riskyStepIndexes.map((value) => Number(value || 0) || 0).filter(Boolean)
          : [],
        failedStep: Number(msg.verification.failedStep || 0) || 0,
        failureSummary: String(msg.verification.failureSummary || '').trim(),
        finalUrl: String(msg.verification.finalUrl || '').trim(),
        finalTitle: String(msg.verification.finalTitle || '').trim(),
        startedAt: Number(msg.verification.startedAt || 0) || 0,
        completedAt: Number(msg.verification.completedAt || 0) || 0,
      }
    : null;
  state.statusLabel = teach.verification
    ? `Teach verification ${String(teach.verification.status || 'completed').trim().toLowerCase()}.`
    : 'Teach verification completed.';
  state.updatedAt = Number(msg?.timestamp || Date.now()) || Date.now();
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
});

wsEventBus.on('ws:open', () => {
  requestBrowserKnowledge(true);
  syncBrowserCanvasStream({ force: true });
  syncBrowserTeachSessionToBackend();
});

wsEventBus.on('canvas_project_changed', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (!sid) return;
  const session = (window.chatSessions || []).find((s) => s.id === sid);
  if (session) {
    session.canvasProjectRoot = normalizeCanvasPath(msg.projectRoot) || null;
    session.canvasProjectLabel = msg.projectLabel || null;
    if (!msg.projectRoot) session.canvasProjectLink = null;
  }
  if (sid === window.activeChatSessionId || sid === window.agentSessionId) {
    setCanvasProjectState(msg.projectRoot, msg.projectLabel);
    canvasLoadWorkspaceFiles(msg.projectRoot || null).catch(() => {});
  } else {
    saveChatSessions();
  }
});

wsEventBus.on('canvas_publish_state', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (!sid) return;
  const session = (window.chatSessions || []).find((s) => s.id === sid);
  if (session && msg.state?.explicitLink) {
    session.canvasProjectLink = normalizeCanvasProjectLink(msg.state.explicitLink);
  }
  if (sid === window.activeChatSessionId || sid === window.agentSessionId) {
    canvasPublishState = msg.state || null;
    canvasProjectLink = normalizeCanvasProjectLink(msg.state?.explicitLink);
    renderCanvasPublishControls();
  } else {
    saveChatSessions();
  }
});

['creative_scene_saved', 'creative_export_saved'].forEach((eventName) => {
  wsEventBus.on(eventName, (msg) => {
    const sid = String(msg?.sessionId || '').trim();
    if (!sid || (sid !== window.activeChatSessionId && sid !== window.agentSessionId)) return;
    const mode = normalizeCreativeMode(msg?.creativeMode || window.currentCreativeMode);
    const storageRoot = normalizeCanvasPath(msg?.storageRoot || '');
    if (storageRoot && !canvasProjectRoot) {
      setCanvasProjectState(storageRoot, getCreativeWorkspaceLabel(mode), { refreshPublish: false, expandBrowser: false });
    }
    if (storageRoot) {
      canvasLoadWorkspaceFiles(storageRoot, { expandBrowser: false }).catch(() => {});
    }
    loadCreativeAssets({ force: true, silent: true, renderStart: false, mode }).catch(() => {});
  });
});

wsEventBus.on('creative_html_motion_export_progress', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (!sid || (sid !== window.activeChatSessionId && sid !== window.agentSessionId)) return;
  if (!creativeActiveExport || creativeActiveExport.renderer !== 'html-motion') return;
  const phase = String(msg?.phase || '').trim().toLowerCase();
  const status = phase === 'encode' ? 'encoding' : 'capturing';
  const frame = Math.max(0, Number(msg?.frame) || 0);
  const totalFrames = Math.max(0, Number(msg?.totalFrames) || 0);
  const percent = Number.isFinite(Number(msg?.percent)) ? Number(msg.percent) : null;
  const progress = percent !== null
    ? clamp(percent / 100, 0, 0.98)
    : (totalFrames > 0 ? clamp(frame / totalFrames, 0, 0.98) : getCreativeActiveExportProgress());
  const label = status === 'encoding'
    ? 'Encoding HTML motion MP4'
    : (totalFrames > 0 ? `Capturing HTML motion frame ${frame}/${totalFrames}` : 'Capturing HTML motion frames');
  refreshCreativeExportChrome({
    progress,
    elapsedMs: Math.max(0, Number(msg?.atMs) || 0),
    status,
    progressLabel: label,
  });
});

wsEventBus.on('creative_render_job_updated', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (!sid || (sid !== window.activeChatSessionId && sid !== window.agentSessionId)) return;
  const mode = normalizeCreativeMode(msg?.creativeMode || window.currentCreativeMode);
  const storageRoot = normalizeCanvasPath(msg?.storageRoot || '');
  if (storageRoot && !canvasProjectRoot) {
    setCanvasProjectState(storageRoot, getCreativeWorkspaceLabel(mode), { refreshPublish: false, expandBrowser: false });
  }
  if (msg?.job) {
    mergeCreativeRenderJobEntry(msg.job, { render: false });
  }
  if (msg?.job?.id && creativeActiveExport?.serverJobId && msg.job.id === creativeActiveExport.serverJobId && creativeActiveExport?.renderer === 'server-browser') {
    const jobStatus = normalizeCreativeRenderJobStatus(msg.job.status);
    const exportStatus = jobStatus === 'queued'
      ? 'queued'
      : jobStatus === 'running'
      ? 'recording'
      : jobStatus === 'uploading'
      ? 'uploading'
      : jobStatus === 'cancel_requested'
      ? 'canceling'
      : jobStatus === 'completed'
      ? 'completed'
      : jobStatus === 'canceled'
      ? 'canceled'
      : 'failed';
    updateCreativeActiveExportState({
      progress: clamp(Number(msg.job.progress) || 0, 0, 1),
      status: exportStatus,
      progressLabel: msg.job.progressLabel || creativeActiveExport.progressLabel || 'Rendering export',
      cancelRequested: msg.job.cancelRequested === true,
    }, { render: true });
    if (msg?.terminal) {
      const completed = jobStatus === 'completed';
      const exportLabel = String(msg.job.format || creativeActiveExport.format || 'render').toUpperCase();
      if (completed) {
        showToast(`${exportLabel} export complete`, String(msg.job.outputFilename || 'The server render is ready.'), 'success');
      } else if (jobStatus === 'canceled') {
        showToast(`${exportLabel} export canceled`, 'The server render stopped before writing a file.', 'info');
      } else {
        showToast(`${exportLabel} export failed`, String(msg.job.error || 'The server render worker did not finish successfully.'), 'error');
      }
      creativeActiveExport = null;
      renderCreativeWorkspace();
    }
  }
  if (msg?.job?.id && creativeActiveExport?.serverJobId && msg.job.id === creativeActiveExport.serverJobId && !msg?.terminal && !msg?.exportSaved) {
    return;
  }
  if (msg?.terminal || msg?.exportSaved) {
    loadCreativeAssets({ force: true, silent: true, renderStart: false, mode }).catch(() => {});
    return;
  }
  renderCreativeWorkspace();
});

wsEventBus.on('creative_library_registry_updated', (msg) => {
  const sid = String(msg?.sessionId || '').trim();
  if (!sid || (sid !== window.activeChatSessionId && sid !== window.agentSessionId)) return;
  const mode = normalizeCreativeMode(msg?.creativeMode || window.currentCreativeMode);
  loadCreativeLibraries({ force: true, silent: true, renderStart: false, mode }).catch(() => {});
});

wsEventBus.on('agent_spawned', (msg) => {
  const agentId = spawnAgentExecution(msg.name || 'Subagent', msg.task || '', msg.isSubagent);
  if (msg.serverAgentId) {
    if (!window.agentIdMap) window.agentIdMap = {};
    window.agentIdMap[msg.serverAgentId] = agentId;
  }
});
wsEventBus.on('agent_log', (msg) => {
  const agentId = window.agentIdMap?.[msg.serverAgentId] || msg.agentId;
  if (agentId) addAgentLog(agentId, msg.logType || 'info', msg.content);
});
wsEventBus.on('agent_completed', (msg) => {
  const agentId = window.agentIdMap?.[msg.serverAgentId] || msg.agentId;
  if (agentId) completeAgentExecution(agentId);
});
wsEventBus.on('agent_paused', (msg) => {
  const agentId = window.agentIdMap?.[msg.serverAgentId] || msg.agentId;
  if (agentId) pauseAgentExecution(agentId, msg.reason);
});

// ─── Background agent late-completion injection ───────────────
// When a background agent finishes AFTER the main turn's finalization gate
// already ran (or during the turn but after the done event), the server
// sends bg_agent_done via WebSocket with the full result. We inject it into
// the last AI message as a proper inner panel so it's visible to the user.
wsEventBus.on('bg_agent_done', (msg) => {
  if (msg.state !== 'completed' || !msg.result) return;
  if (window.isThinking) {
    addProcessEntry('info', `Background Agent ${msg.bgId}: result ready; merging into final reply.`, { actor: 'Background Agent' });
    renderProcessLog();
    return;
  }
  // Only inject into the currently active session's history
  const activeSession = window.chatSessions?.find(s => s.id === window.activeChatSessionId);
  if (!activeSession) return;
  const history = activeSession.history || [];
  // Find the last AI message
  let lastAiIdx = -1;
  for (let i = history.length - 1; i >= 0; i--) {
    if (history[i].role === 'ai' || history[i].role === 'assistant') { lastAiIdx = i; break; }
  }
  if (lastAiIdx === -1) return;
  const lastMsg = history[lastAiIdx];
  const existingContent = String(lastMsg.content || '');
  // Don't double-inject — skip if already contains a background agent section
  if (/background agent response:/i.test(existingContent)) return;
  // Append the background agent inner panel marker
  history[lastAiIdx] = {
    ...lastMsg,
    content: existingContent.trim() + '\n\nBackground agent response:\n' + String(msg.result || ''),
  };
  persistActiveChat();
  renderChatMessages();
  addProcessEntry('info', `Background Agent ${msg.bgId}: result injected into reply.`, { actor: 'Background Agent' });
});

// ─── Coordinator progress: show team coordinator activity in process log ───
// When ask_team_coordinator runs (or the team coordinator is working), the backend
// broadcasts coordinator_progress WS events so the process log shows activity
// instead of appearing to hang silently.
wsEventBus.on('coordinator_progress', (msg) => {
  const matchesSession = msg.sessionId && msg.sessionId === window.activeChatSessionId;
  const isActiveRun = window.isThinking || matchesSession;
  if (!isActiveRun) return;
  const teamTag = msg.teamId ? ` [team:${msg.teamId}]` : '';
  addProcessEntry('info', `[coordinator${teamTag}] ${formatForwardedToolMessageForLog(msg.message).slice(0, 200)}`, { actor: 'Coordinator' });
  renderProcessLog();
});

// ─── State sync: ensure window.* stays in sync ────────────────
// Wrap key functions to sync state before/after execution



['approval_created', 'approval_approved', 'approval_denied', 'approval_executing', 'approval_executed', 'approval_failed', 'approval_expired'].forEach((eventName) => {
  wsEventBus.on(eventName, (msg) => {
    const matchesSession = String(msg.sessionId || '').trim() === String(window.activeChatSessionId || '').trim();
    if (typeof window.loadApprovals === 'function') window.loadApprovals();
    if (matchesSession && typeof window.loadSessionApprovals === 'function') {
      window.loadSessionApprovals();
    } else if (eventName === 'approval_created') {
      const badge = document.getElementById('approvals-badge');
      if (badge) {
        badge.style.display = 'inline-block';
        badge.textContent = '+';
      }
    }
  });
});

if (isCreativeRenderWorkerMode()) {
  setTimeout(() => {
    bootCreativeRenderWorkerMode().catch((err) => {
      console.error('[creative render worker]', err);
    });
  }, 250);
}
